REPLACE INTO `blog` (`id`, `user_id`, `title`, `description`, `image`, `author_name`, `author_image`, `status`, `schedule`, `created_at`, `updated_at`) VALUES (2,1,'Hvordan bli en forfatter?','<p style=\"padding-left: 270px; text-align: justify;\"><img src=\"/laravel-filemanager/photos/1/Blogg.jpg\" alt=\"\" width=\"559\" height=\"397\" /></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 12pt;\">Hvem kan kalle seg en forfatter? Hva skal til for &aring; lykkes? Og hvordan takle refusjonene underveis?</span></p>\r\n<p><span style=\"font-size: 12pt;\"><em>Forfatter</em> er ikke en beskyttet tittel. Det betyr at hvem som helst kan kalle seg en forfatter. Men de f&aelig;rreste vil gj&oslash;re dette f&oslash;r de har gitt ut en bok, kanskje to, p&aring; et respektabelt forlag.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Men f&oslash;rst m&aring; boken skrives. &Aring; skrive en bok er en prestasjon i seg selv &ndash; &aring; st&aring; l&oslash;pet ut og komme i m&aring;l med historien sin, gjennom skrivesperrer, nye ideer (som alltid virker mye bedre enn den du hadde), hanglende skriveselvtillit, indre kritiker og mye mer.</span></p>\r\n<p><span style=\"font-size: 12pt;\">S&aring; hvordan skriver du en bok?</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>H&aring;ndverk og mengdetrening</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">En metode er &aring; bare starte og se hvor det b&aelig;rer hen. Mange har fors&oslash;kt dette, uten hell (inkludert meg selv). Hvorfor? Fordi skriving er et h&aring;ndverk, som alt annet. Du m&aring; gjerne bare begynne &aring; male, men du blir trolig ikke den neste Leonardo da Vinci uten et minimum av teknikk. Sjansen er stor for at du ender opp ute p&aring; skauen et sted, kanskje med en refusjon fra et forlag eller flere, og m&aring; starte p&aring; nytt &ndash; med halvert skriveselvtillit.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Dessuten er skriving ensomt. Det vil v&aelig;re timer med usikkerhet, kjedsomhet og frustrasjon. Det kan jeg skrive under p&aring; (bokstavelig talt).</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Gradvis god</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">Selv ville jeg ikke gi ut bare en bok. Jeg ville gi ut mange b&oslash;ker, i flere sjangre, p&aring; ulike forlag. Det lignet min dr&oslash;m nummer to &ndash; &aring; bli skuespiller. P&aring; en m&aring;te g&aring;r disse to profesjonene ut p&aring; det samme; &aring; leve seg inn i en karakter og v&aelig;re med p&aring; &aring; skape en historie. N&aring;r du er forfatter er du p&aring; en m&aring;te regiss&oslash;r ogs&aring; &ndash; du skaper historien selv og fyller alle rollene.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Enda morsommere, sp&oslash;r du meg. Og selvsagt mer krevende. Nettopp derfor krever forfatteryrket at du kan h&aring;ndverket og trener mye. Slik blir du gradvis god.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Du m&aring; ogs&aring; ha en god porsjon stahet og viljestyrke. For det dukker gjerne opp noen refusjoner p&aring; veien.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Stahet og arbeidsvilje</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">Selv regnet jeg med &aring; bli genierkl&aelig;rt da jeg sendte inn mitt f&oslash;rste manus til landets tre st&oslash;rste forlag, og endte selvsagt opp med &aring; bli skuffet. Men jeg ga meg ikke, og den fandenivoldske staheten fikk jeg god bruk for. Jeg fortsatte &aring; skrive, og fikk etter hvert konsulentuttalelser. N&aring; visste jeg i det minste hva jeg hadde gjort feil, og forlaget gadd &aring; bruke penger p&aring; meg. Det var et stort skritt i riktig retning &ndash; st&oslash;rre enn jeg visste den gangen.</span></p>\r\n<p><span style=\"font-size: 12pt;\">I likhet med de fleste andre har jeg aldri v&aelig;rt noe litter&aelig;rt geni. Jeg hadde et visst skrivetalent, mye fantasi og enda st&oslash;rre fortellertrang. Men f&oslash;rst og fremst hadde jeg en fandenivoldsk stahet og masse arbeidsvilje. Disse to faktorene er langt viktigere enn det andre.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Fra refusjoner til manusm&oslash;te</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">Arbeidsvilje handler om &aring; gj&oslash;re jobben. Ikke vente p&aring; inspirasjon, men sette deg ned og f&aring; ordene ut, ogs&aring; n&aring;r du ikke vil eller orker, hver eneste dag. Slik pusher du deg selv videre &ndash; det blir som en trenings&oslash;kt som gradvis g&aring;r lettere, jo varmere du blir, og til slutt har du innarbeidet en vane som vil f&aring; deg i m&aring;l med manuset.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Den fandenivoldske staheten handler om &aring;&nbsp;ville&nbsp;det, ikke gi seg i oppoverbakkene, tenke <em>jeg skal vise dem. </em></span></p>\r\n<p><span style=\"font-size: 12pt;\">Og til slutt kommer bel&oslash;nningen. For meg kom den i form av en sirlig, tynn konvolutt fra Gyldendal. Nok en refusjon, tenkte jeg, og denne gangen har de ikke giddet &aring; returnere manuset en gang.</span></p>\r\n<p><span style=\"font-size: 12pt;\">I stedet sto det i brevet: Vil du komme p&aring; et m&oslash;te hos oss? De syntes manuset mitt var interessant.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Leste jeg riktig? Mitt manus &ndash; <em>interessant?</em></span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Inn i slottet</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">N&aring; var det g&aring;tt en tid siden jeg var 22 &aring;r og selverkl&aelig;rt forfattergeni. Jeg var i ferd med &aring; miste selvtilliten. Jeg syntes alt jeg skrev var makkverk. Og n&aring; ville landets st&oslash;rste forlag ha meg p&aring; bes&oslash;k.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Jeg f&oslash;lte meg som en dronning da jeg gikk inn d&oslash;rene. Det er h&oslash;yt under taket hos Gyldendal, og p&aring; veggene henger bilder av Ibsen og andre storheter. Men jeg kom meg fort ned p&aring; jorden da m&oslash;tet startet. For manus blir sjelden utgitt uten mye bearbeidelse. Jeg m&aring;tte skrive om historien flere ganger. Da fikk jeg bevist at jeg kunne bearbeide min egen tekst ogs&aring; &ndash; og dette er viktig for forlaget. Etter 11 runder med en kyndig redakt&oslash;r, var det tid for spr&aring;kvask og korrektur. S&aring; det morsomste av alt: Omslag og kontrakt. N&aring; ble alt s&aring; virkelig: Dette ble en bok &ndash; og endelig var jeg en ekte forfatter!</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Nye stjerner &aring; strekke seg etter</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">I dag kan jeg stolt si at jeg har klart &aring; realisere dr&oslash;mmen. Jeg har gitt ut romaner i de fleste sjangre, og sakprosa, p&aring; Gyldendal, Cappelen Damm, Vigmostad &amp; Bj&oslash;rke, Juritzen og Flux, og debutboken ble oversatt til tysk og polsk.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Og enn&aring; fortsetter jeg &aring; klatre &ndash; jeg vil bli en enda bedre forfatter, jeg vil n&aring; ut til flere land, jeg er sulten p&aring; (en) st&oslash;rre suksess. Og jeg digger &aring; inspirere andre til &aring; f&oslash;lge sin dr&oslash;m og stadig utvide den. Hva hadde livet v&aelig;rt uten nye stjerner &aring; strekke seg etter?</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Hva skal du gi verden?</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">Mange sp&oslash;r seg ogs&aring;: Hva er mitt budskap til verden? Har jeg noe &aring; melde?</span></p>\r\n<p><span style=\"font-size: 12pt;\">Ja, det meste er skrevet om utallige ganger: Kj&aelig;rlighet, svik, krig, sykdom, d&oslash;d, skilsmisser, ungdomsoppr&oslash;r, oppvekstproblematikk, mobbing, mishandling, livets mysterier.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Likevel: Skriver du noe du brenner for, med&nbsp;din&nbsp;unike stemme, blir det en s&aelig;regen historie. Alle har en unik stemme, men kanskje m&aring; du gjennom noen lag for &aring; finne den. Og du m&aring; ha selvtillit nok til &aring; bruke stemmen med rak rygg.</span></p>\r\n<p><span style=\"font-size: 12pt;\">N&aring;r du skriver med selvtillit f&aring;r teksten egenart og fortellingen energi. Du skriver med autoritet, og slik leier du leseren gjennom fortellingen med st&oslash; h&aring;nd. Tenk deg selv:</span></p>\r\n<p><span style=\"font-size: 12pt;\">Hvem lytter du mest til &ndash; hun som st&aring;r midt i rommet og proklamerer med h&oslash;y stemme, eller hun som sitter i kroken og stotrer ordene frem?</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Verkt&oslash;y, veiledning og vennegjeng</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\">Har du ikke skriveselvtillit, sier du? V&aring;rt beste tips er: Fake it until you make it. Og l&aelig;r deg verkt&oslash;yet, tren litt hver dag, skaff deg en skrivefamilie.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Hos Forfatterskolen vet vi hva du m&aring; ha for &aring; skrive og fullf&oslash;re en roman: H&aring;ndverket for &aring; bygge opp en historie, profesjonell veiledning som holder deg p&aring; riktig vei og en heiagjeng som er med deg helt inn til m&aring;l.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Med et slikt litter&aelig;rt kinderegg har du langt st&oslash;rre sjanse for &aring; lykkes. Neste gang er det kanskje deg som g&aring;r inn p&aring; landets st&oslash;rste forlag med et manus under armen? Skrittet over terskelen kjennes gigantisk. Men det st&oslash;rste og viktigste steget kan du ta akkurat n&aring;: Bestemme deg for &aring; starte.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Har <strong>du</strong> bestemt deg?</span></p>\r\n<p><span style=\"font-size: 12pt;\">Hilsen rektor Kristine,</span></p>\r\n<p><span style=\"font-size: 12pt;\">Forfatterskolen</span></p>\r\n<p><span style=\"font-size: 12pt;\">kristine@forfatterskolen.no</span></p>\r\n<p><span style=\"font-size: 12pt;\"><img src=\"/laravel-filemanager/photos/1/11739670_10152879507672540_553471638_n.jpg\" alt=\"\" width=\"151\" height=\"193\" /></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em>En forfatter har aldri fri - heldigvis</em></span></p>\r\n<p><span style=\"font-size: 12pt;\">PS! Nysgjerrig p&aring; h&oslash;stens kurs hos Forfatterskolen? Her kan du lese mer om v&aring;rt rykende ferske tilbud p&aring; roman- og krimkurs: <a href=\"https://www.forfatterskolen.no/course\">Forfatterskolens skrivekurs</a></span></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>','/storage/blog/1534938801.jpeg','Kristine S. Henningsen','/storage/blog/author/1534938852.jpeg',1,NULL,'2018-08-14 01:51:43','2018-08-27 11:22:41'),(3,1346,'Betydningen av en heiagjeng','<div class=\"page\" title=\"Page 1\">\r\n<div class=\"layoutArea\">\r\n<div class=\"column\">\r\n<p style=\"text-align: justify;\"><img src=\"/laravel-filemanager/photos/1346/1.jpg\" alt=\"\" width=\"559\" height=\"397\" /></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Dr&oslash;mmen</strong></span></h2>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Det er deg og tastaturet. Noen klarer å skrive med andre rundt seg, men de fleste trenger å v&aelig;re alene. Finne ro til å plotte, planlegge, skrive og forsvinne inn i sin egen, lille fantasiverden. Det er dr&oslash;mmen om å skrive en bok som lokker der fremme.</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Forfatterskolens skriveforum</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">For mange av dere er forumet et velkjent sted, et sted hvor vi kan samles, st&oslash;tte hverandre, komme med tips og råd og hjelpe hverandre på veien. Dere har den samme dr&oslash;mmen, om enn i varierende grad, og mottoet er enkelt: Vi snakker hverandre opp, ikke ned.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Det er sårbart å pr&oslash;ve og feile i en slik prosess, så fokuset ligger på st&oslash;tte og konstruktiv veiledning.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Hver eneste gang jeg logger meg inn i forumet, så er det med stor respekt - For alle de som kommer igjen og igjen, for alle de som engasjerer seg i en post, tar imot nye elever eller starter en samtale. Det f&oslash;rste som slår meg, er hvor ekte det er. I skriving snakker vi ofte om det som ligger mellom linjene, men det kan også overf&oslash;res til forumet. En elev sa det på denne måten: &laquo;Forfatterskolen er den andre familien min.&raquo; En annen elev sa at Forfatterskolen er den eneste familien h*n har. Og det er nettopp det vi &oslash;nsker å v&aelig;re. En litter&aelig;r familie, hvor det også er fokus på hver enkelt elev. Det er mangfoldet som gj&oslash;r forumet. Og samholdet.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>Samskriving</strong></span></h2>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Med jevne mellomrom har vi også konkurranser, rett og slett for å motivere til skriving. For noen ganger er det greit å ha noe å strekke seg etter. En av disse konkurransene ga uante effekter, og viste i praksis betydningen av en heiagjeng. Tonje Brantenberg, moderator og selvutnevnt cheerleader, kom med initiativ til samskriving litt utover det vanlige. </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Når kvelden kom, var invitasjonen klar: &laquo;Hvem skriver nå&raquo;? Det ga motivasjon, det ga diskusjoner i kommentarfeltet, og invitasjonene ble stadig mer fantasifulle. Snart var KBF, Kommende Bestselgende Forfattere, et velkjent begrep langt utenfor forumets vegger. En fiktiv verden, full av forfattere og historier som kom til liv kveld etter kveld.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Det å vite at det akkurat nå sitter femten andre og skriver samtidig med deg, gir en f&oslash;lelse av fellesskap, selv om dere sitter på hver deres tue i dette langstrakte landet. Det gir lyst til å fortsette.</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Skriveutfordringer</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">På samme måte som det kan v&aelig;re vanskelig å komme i gang, så kan det også v&aelig;re vanskelig å finne noe å skrive om, eller t&oslash;rre å la noen lese det du har skrevet. I hvert fall i starten. Noen&nbsp;</span><span style=\"font-weight: 400; font-size: 12pt;\">syns det er g&oslash;y, andre igjen syns det er skummelt. Eller kanskje du er en av dem som er redd for at noen skal stjele ideene dine? </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Skrivestemmen din er unik, det samme er tankene dine. Selv om plagiat av og til kan forekomme, så er ikke det en vanlig problemstilling på et f&oslash;rsteutkast eller en ide. Norge er et lite land, og med måten vi bruker sosiale medier på, er det også gjennomsiktig. Risikoen er generelt sett for stor til at noen vil ta sjansen, og de aller fleste mennesker er tross alt til å stole på. Men for noen er redselen allikevel til stede, og det skal man ha respekt for.<br /></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">L&oslash;sningen ble jevnlige skriveutfordringer. På den måten kunne alle få noen oppgaver å bryne seg på, enten til inspirasjon eller ettertanke, uten å måtte ta stilling til eget manus. En etter en begynte å legge ut resultatene i forumet, og de andre så at det ikke var farlig, torde å hive seg med. Det er også betydningen av en heiagjeng i praksis. Å l&oslash;fte hverandre frem, gj&oslash;re hverandre bedre, trene på å lese og bli lest. For det er tross alt en skrivers hverdag. I hvert fall om du &oslash;nsker å bli publisert.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Og det er en mye morsommere måte å avslutte uken på, enn å bare si &laquo;god helg&raquo;.</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Engasjement</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Skriving er for mange en ensom aff&aelig;re, og det er en av grunnene til at Forfatterskolen har så stort fokus på forum og fellesskap som en del av kurstilbudet. Din litter&aelig;re familie. Det er et oppriktig begrep, det betyr noe. Nå har en del av jobben min v&aelig;rt å f&oslash;lge opp Forfatterskolens skriveforum i flere år, og for et privilegium det har v&aelig;rt &ndash; alle disse mailene, meldingene og postene som har kommet, om nye vennskap som har oppstått ... Enten det er gode eller dårlige dager, så er det godt å ha et sted å gå til når man står fast eller trenger en pause. Ikke alle forstår denne lidenskapen eller iveren etter å hamre ned bokstav etter bokstav på tastaturet, så skuffelsen kan fort bli stor når du endelig har fått skrevet ferdig det kapittelet du har slitt med i to uker og viser det til samboeren. &laquo;Så fint!&raquo; Så fint ...? Ja, det er fint. Men det er ikke alltid man får h&oslash;re mer enn nettopp det. De vil jo tross alt si at du er flink, at det er bra &ndash; men det er ikke alltid så lett å si så mye mer enn det om man ikke skriver selv, for det er ikke alle som forstår denne fascinasjonen for ord. For det er jo bare ord, er det ikke? Du kan jo bare skrive en bok. (Sa alle de som ikke har fors&oslash;kt selv.) Det er på sånne dager jeg merker hvor mye forumet betyr for den enkelte elev, det er da de kommer, de postene som er preget av litt frustrasjon. Helt til st&oslash;tteerkl&aelig;ringene og heiaropene kommer, og frustrasjonen blir snudd til glede over alle som engasjerer seg, bryr seg, oppmuntrer deg til å fortsette. De har selv kjent det på kroppen, de vet hva du snakker om: At du trenger mer spenning i historien, at tidslinjen trenger en finpuss, gleden over brevet som dumper ned i postkassen fra forlaget og ordet antatt ... Det sitter dypt hos mange å skryte av seg selv, det er kanskje noe typisk norsk over det. Men i et forum fullt av likesinnede, der du vet at de blir glade på dine vegne, der er det også aksept for å si &laquo;se, så flink jeg har v&aelig;rt!&raquo;</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>En familie på kj&oslash;pet</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Du bygger ikke bare et manus, du bygger en utvidet familie. Jeg har mange ganger fått kommentarer på at jeg har merkelige arbeidstider, siden jeg svarer i forumet til alle d&oslash;gnets tider. Svaret jeg gir er det samme hver gang: Dette er ikke en vanlig jobb, det er en lidenskap, det er ikke for hvem som helst. Men for de rette personene er det en berikelse. Det å få f&oslash;lge en elev fra starten er noe vi setter uendelig pris på, og det gj&oslash;r også elevene.</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Dr&oslash;mmen i bokhylla</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Det blir noe helt spesielt den dagen du står der og skal handle b&oslash;ker og plutselig får &oslash;ye på et kjent navn i mengden. Det er en forfatter du kjenner, en du har v&aelig;rt med på å heie frem. En som også vil heie på deg, helt til du når målet ditt. En annen gang dumper det ned en invitasjon til lanseringsfest i innboksen. Nok en utgitt elev, en du har v&aelig;rt pilotleser for, kanskje? Når vi tilbyr medlemskap i det store skriveforumet, så er det på livstid. Og grunnen er enkel: Det betyr noe. Du fortjener det.</span></p>\r\n</div>\r\n</div>\r\n</div>','/storage/blog/1535641436.jpeg','Hanne Einang',NULL,1,NULL,'2018-08-30 15:03:56','2018-08-31 07:29:44'),(4,1346,'Din indre (skrive)stemme','<p style=\"text-align: justify;\"><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><img src=\"/laravel-filemanager/photos/1346/Forfatter_Petter_Fergestad_Armageddonalgoritmen_075_high-2.jpg\" alt=\"\" width=\"600\" /><br /><br />Min kones lille s&oslash;nn hadde l&aelig;rt p&aring; s&oslash;ndagsskolen om v&aring;r indre stemme. P&aring; et juleselskap ble han bedt om &aring; synge en sang. Han klatret opp p&aring; en stol, og sto der andektig en stund. Leppene beveget seg. S&aring; klatret han ned igjen. - Men du sang jo ikke, sa en av gjestene. - Jeg sang med den indre stemmen min, svarte han. Det er det vi sliter med, vi som skriver. &Aring; formidle v&aring;r indre stemme p&aring; en s&aring;nn m&aring;te at vi blir h&oslash;rt. &laquo;Dessverre &hellip; men takk for at du &hellip;&raquo;, sier forlagene. &nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">LETT &Aring; MISTE MOTET&nbsp;</span></strong><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\">Mangler vi talent, og burde finne p&aring; noe annet &aring; bruke tiden v&aring;r til? Det fikk J.K. Rowling h&oslash;re. Stephen King fikk tretti refusjoner p&aring; Carrie. Walt Disney fikk h&oslash;re at han manglet kreativitet. Selv om vi vet at vi er i godt selskap, er det lett &aring; miste motet n&aring;r refusjonene kommer. Siden vi nesten aldri f&aring;r h&oslash;re hva vi gj&oslash;r galt, vet vi ikke hvordan vi skal gj&oslash;re det bedre. For det kan det garantert bli. Hver enkelt har sin egen vei fram til utgivelse, jeg kan si et par ord om min. Noen fellestrekk er det nok. &nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">BEGYNTE SOM PENSJONIST<br /></span></strong><span style=\"font-weight: 400;\">Min skrivereise begynte f&oslash;rst etter at jeg hadde pensjonert meg og hadde tiden p&aring; min side. F&oslash;rst skrev jeg et essay. Om de store sp&oslash;rsm&aring;l i livet, hva er bevissthet, hva skjer etterp&aring; osv. En vandring i gr&aring;sonen mellom vitenskap og religion. &laquo;Kunnskapsrikt og interessant, men for smalt&raquo; fra ett forlag. &laquo;Morsomt, men bibelkritisk&raquo;, fra et annet &laquo;Vi tar ikke inn essays&raquo;, fra et tredje. Jeg fors&oslash;kte &aring; lure inn refleksjonene mine i en roman i stedet. Det kunne jo ikke g&aring; bra. &laquo;Vanskelig &aring; skrive en roman om en id&eacute;&raquo;, fikk jeg h&oslash;re. &nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">FRA ESSAY TIL SPENNINGSROMAN<br /></span></strong><span style=\"font-weight: 400;\">Dette begynte &aring; bli utfordrende. Meg mot forlagene. Jeg la bort budskapet til menneskeheten, og gikk i gang med en spenningsroman. P&aring; dette stadiet hadde jeg blitt bitt av skrivebasillen. Jeg oppdaget det spilte liten rolle hva jeg skrev, selve skriveprosessen ble viktigere og viktigere. M&oslash;tet med karakterene og utfoldelsen av plottet ble en kilde til stadig overraskelse. Om det ble utgitt var det selvsagt fint, men det kom mer i bakgrunnen. Et par utmerkede pilotlesere l&aelig;rte meg mye om hva som fungerte og ikke. &laquo;Du skriver bedre p&aring; e-mailene til meg enn n&aring;r du skriver manus&raquo;, sa en av dem. Jeg ba henne utdype det, og fikk til svar at det virket som om jeg hadde en oppfatning av hva som var &laquo;romanspr&aring;k&raquo;. Jeg skj&oslash;nte ikke forskjellen da, men n&aring; gj&oslash;r jeg det. &nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">OVERD&Oslash;VET INDRE STEMME MED &rdquo;LURE&rdquo; PLANER<br /></span></strong><span style=\"font-weight: 400;\">N&aring;r jeg ser tilbake p&aring; disse formende erfaringene, skj&oslash;nner jeg hvilken grunnleggende feil jeg gjorde. Jeg overd&oslash;vet min indre stemme med snedige planer jeg hadde i hodet. Karakterene ble sjakkbrikker som pent m&aring;tte flytte dit jeg ville. Det falt meg ikke inn &aring; sp&oslash;rre dem hva de ville (Kanskje den hvite dronningen dr&oslash;mte om et lidenskapelig stevnem&oslash;te med den svarte kongen i det hvite t&aring;rnet?). Det hele ble sinnrikt, men blodfattig. Det var en aha-opplevelse da jeg forsto dette. Og at den indre stemmen &ndash; det ukontrollerbare, inspirerte, kreative &ndash; m&aring; komme til uttrykk gjennom karakterene, ikke gjennom meg. Det er en nesten euforisk f&oslash;lelse n&aring;r dette flyter ut. Jeg f&oslash;ler meg som en observat&oslash;r, en formidler. </span><span style=\"font-weight: 400;\"><br /></span> <span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">TILGJENGELIG FOR ALLE<br /></span></strong><span style=\"font-weight: 400;\">&laquo;Jeg skriver s&aring; godt jeg kan&raquo;, sa Hemingway. &laquo;Noen ganger bedre&raquo;. &laquo;Det som gj&oslash;res av det som kalles meg selv&raquo;, sa den store fysikeren Maxwell, &laquo;f&oslash;ler jeg gj&oslash;res av noe som er st&oslash;rre enn meg selv i meg&raquo;. &laquo;Hellig&aring;nden taler gjennom meg&raquo;, sa Hamsun. Ja vel, sier du kanskje, men dette er folk med helt spesielle talenter. S&aring;nn er ikke jeg. Si ikke det. Det er noe som er verdt &aring; merke seg i disse vitnesbyrdene. Utover at de forteller om en mystisk kilde. De er ikke unike i kraft av sine egne talenter, men i kraft av sin evne til &aring; slippe til noe utenfor seg selv. Eller snarere noe inni seg selv. En indre stemme. Og dette noe (kanskje det Jung kalte &laquo;det felles ubevisste&raquo;) tror jeg er tilgjengelig for oss alle. Som eteren vi puster i. Det er umulig &aring; forutsi n&aring;r kontakten oppst&aring;r. Kanskje etter tretti refusjoner, kanskje etter femti. &nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">FINN DIN X-FAKTOR<br /></span></strong><span style=\"font-weight: 400;\">Men du m&aring; v&aelig;re der n&aring;r det skjer. Du m&aring; holde p&aring; &ndash; hva om Stephen King hadde stoppet etter tjueni? Ta det heller ikke for gitt at det i det hele tatt er noe &laquo;galt&raquo; med manuset ditt. Kan hende er det bare en uheldig kjemi mellom deg og den som leser for forlaget. Andre forlag har andre lesere. Stephen King endret ikke manuset tretti ganger. S&aring; hva gj&oslash;r du for &aring; finne din indre stemme? Komme p&aring; talefot med den, kjenne den igjen n&aring;r den er der, og skj&oslash;nne n&aring;r den ikke er der. &Aring; l&aelig;re grunnprinsippene i skriftspr&aring;ket er en n&oslash;dvendig, men ikke tilstrekkelig forutsetning. Mest trolig vil du, som jeg, trenge noe mer. En x-faktor. Jeg fant den p&aring; Forfatterskolen. Uten at jeg kan peke p&aring; akkurat n&aring;r det skjedde, s&aring; oppdaget jeg et sted underveis at n&aring; skriver jeg fra hjertet. Og n&aring; skriver jeg fra hodet. &nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">V&AElig;R FORBEREDT P&Aring; REFUSJONER<br /></span></strong><span style=\"font-weight: 400;\">Mye skyldtes Kristine Storli Henningsens eksepsjonelle evne til &aring; inspirere og l&oslash;fte fram et talent. I Armageddon-algoritmen er det en karismatisk sektleder som ogs&aring; l&oslash;fter menigheten sin til uante h&oslash;yder. N&aring;r du leser boken vil du se at Kristine kan v&aelig;re glad for at hun ikke deler ogs&aring; de andre av pastorens sider. Tretti refusjoner? Eller femti? Kanskje m&aring; du v&aelig;re forberedt p&aring; det. Jeg ville komme i tidsn&oslash;d med det perspektivet, men du er kanskje en ungdom p&aring; femtini. For deg er det uproblematisk. &nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><strong><span style=\"font-size: 14pt;\">V&AElig;R T&Aring;LMODIG MED DEG SELV<br /></span></strong><span style=\"font-weight: 400;\">Jeg har l&aelig;rt meg &aring; v&aelig;re t&aring;lmodig med meg selv. Noen ganger klatrer jeg opp p&aring; stolen og mimer min indre stemme. Andre ganger kommer ordene ut. Skriv s&aring; godt du kan, noen ganger vil du skrive bedre.&nbsp;&nbsp;<br /><br /><strong>PS!</strong>&nbsp;Her kan du lese litt av spenningsromanen som kom etter denne prosessen, og som gjorde at Forfatterskolen valgte meg som sin Dr&oslash;mmeforfatter: <a href=\"http://www.petterfergestad.no/wp-content/themes/petter-fergestad/Armageddon-algoritmen_trykk_sample.pdf\">Armageddon-algoritmen</a><br /><br />Dette blogginnlegget ble opprinnelig publisert p&aring; <a href=\"http://www.petterfergestad.no/din-indre-skrivestemme/\">Petter Fergestad sin hjemmeside.&nbsp;</a></span></span></p>','/storage/blog/1536260586.jpeg','Petter Fergestad',NULL,1,NULL,'2018-09-06 18:54:01','2018-09-06 19:20:55'),(5,1,'Kan man lære å skrive en roman?','<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/1/blogg.jpg\" alt=\"\" width=\"559\" height=\"397\" /></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 12pt;\">Dette sp&oslash;rsm&aring;let f&aring;r jeg ofte, gjerne stilt med en viss skepsis. Alle kan jo fortelle en historie, det gj&oslash;r vi hele tiden. <em>I g&aring;r, mens jeg stod og ventet p&aring; bussen, kom det plutselig &hellip; </em></span></p>\r\n<p><span style=\"font-size: 12pt;\">Da jeg selv begynte &aring; skrive som voksen, visste jeg ikke at det var et h&aring;ndverk som kunne l&aelig;res. Jeg fikk alltid skryt for stilene mine p&aring; skolen, s&aring; hvorfor skulle jeg ikke kunne skrive en roman? Den f&oslash;rste scenen i mitt tenkte bokprosjekt var vidunderlig (om jeg skal si det selv), det var bare snakk om &aring; skrive den ut. Men p&aring; veien til papiret forsvant klarheten, skj&oslash;nnheten og magien, og igjen stod noen platte, banale setninger.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Det var ikke det verste. De f&oslash;rste sidene kom raskt, men s&aring; var det full stopp. Hva skulle skje videre?</span></p>\r\n<p><span style=\"font-size: 12pt;\">Det jeg ikke forstod den gangen, var at ideen min ikke holdt til en hel roman, knapt nok en novelle. Jeg hadde bare en l&oslash;srevet situasjon, n&aelig;rmest et tabl&aring;. Jeg visste ikke hva en historie egentlig er.</span></p>\r\n<h2><span style=\"font-size: 14pt;\">Jakten p&aring; kunnskap</span></h2>\r\n<p><span style=\"font-size: 12pt;\">&Aring;rene gikk, inntil jeg en sommerdag fl&oslash;t p&aring; rygg i et basseng i Portugal og tenkte <em>Jeg vil ikke tilbake til jobben min, dette er ikke det livet jeg &oslash;nsker &aring; leve. Jeg m&aring; skifte retning. N&aring;.</em> Med internett tilgjengelig, var det plutselig mulig &aring; stille sp&oslash;rsm&aring;let <em>Hvordan skriver jeg en roman?</em> &ndash; og f&aring; svar. Mange svar. Da jeg googlet det p&aring; engelsk i dag, fikk jeg 676&nbsp;millioner resultater. S&aring; mange meninger, men finnes det en fasit?&nbsp;</span></p>\r\n<p><span style=\"font-size: 12pt;\">Jeg bestilte fagb&oslash;ker og slukte artikler p&aring; nettet. Det holdt ikke &aring; lese en l&aelig;rebok eller to, jeg ville fordype meg i hvert eneste emne, finne ulike metoder og utforske motstridende meninger. Jeg leste ulike sjangre, gjorde notater og analyser. Favorittb&oslash;kene ble lest i filler, og saumfart for magiske ingredienser.</span></p>\r\n<h2><span style=\"font-size: 14pt;\">Den indre kritikeren</span></h2>\r\n<p><span style=\"font-size: 12pt;\">Fortellingen jeg hadde begynt &aring; skrive ti &aring;r tidligere l&aring; fremdeles i bakhodet og surret. Den tok form og vokste seg st&oslash;rre og st&oslash;rre. Men jeg skrev ikke et ord, jeg ville beherske h&aring;ndverket f&oslash;rst, forst&aring;, ha kontroll.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Et eksempel til etterf&oslash;lgelse?</span></p>\r\n<p><span style=\"font-size: 12pt;\">Absolutt ikke.</span></p>\r\n<p><span style=\"font-size: 12pt;\">For &aring; l&aelig;re &aring; skrive, m&aring; du f&oslash;rst og fremst skrive &ndash; og lese. &Aring; studere h&aring;ndverket kommer i tillegg.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Det skj&oslash;nte jeg etterp&aring;.</span></p>\r\n<p><span style=\"font-size: 12pt;\">For meg handlet det om frykt. Dette var s&aring; viktig for meg, det f&oslash;ltes som min siste sjanse. Joda, jeg er den f&oslash;rste til &aring; innr&oslash;mme at det var en smule melodramatisk. Men hva om jeg feilet og ikke v&aring;get &aring; pr&oslash;ve igjen? Den indre kritikeren satt ikke bare p&aring; skulderen, han styrte hele meg.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Det var ikke f&oslash;r jeg ble kjent med andre som skrev og fikk et st&oslash;ttende milj&oslash; rundt meg, at jeg klarte &aring; tvinge kritikeren i kne og l&aring;se ham inn i en liten celle. Han er en urolig fyr som roper litt for h&oslash;yt gjennom sprinklene i blant, men han skal f&aring; lov &aring; bo der. Innimellom slipper jeg ham l&oslash;s p&aring; det jeg skriver. Det er jobben hans.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Og n&aring; er min jobb &aring; l&aelig;re andre &aring; skrive en god historie. Men sitter jeg p&aring; fasiten?</span></p>\r\n<p>&nbsp;</p>\r\n<blockquote>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 14pt;\"><em>For &aring; l&aelig;re &aring; skrive, m&aring; du f&oslash;rst og fremst skrive &ndash; og lese. <br />&Aring; studere h&aring;ndverket kommer i tillegg.</em></span></p>\r\n<p>&nbsp;</p>\r\n</blockquote>\r\n<h2><span style=\"font-size: 14pt;\">Hva er skriveh&aring;ndverk?</span></h2>\r\n<p><span style=\"font-size: 12pt;\">De fleste kan synge en melodi eller male et bilde, men resultatet har ikke n&oslash;dvendigvis verdi for andre. Se for deg to jazzmusikere p&aring; en scene. Den ene har l&aelig;rt seg de helt grunnleggende teknikkene, mens den andre behersker instrumentet sitt fullkomment. Hvem har st&oslash;rst sjanse for &aring; ber&oslash;re publikum med det han &oslash;nsker &aring; formidle? Det er selvf&oslash;lgelig han som vet n&oslash;yaktig hvilken tone som kommer n&aring;r han legger fingeren p&aring; kontrabassens hals. Han som styrer lytterens opplevelse gjennom bruk av crescendo og diminuendo, vibrato, stakkato og legato. Teknikken gir ham mulighet til &aring; kommunisere med publikum. Men teknikk er ikke kunst, det er kun et verkt&oslash;y alle kan ta i bruk. Kunsten er det han formidler, hans unike stemme.</span></p>\r\n<p>&nbsp;</p>\r\n<blockquote>\r\n<p style=\"text-align: center;\"><span style=\"font-size: 14pt;\">&Aring; l&aelig;re skriveh&aring;ndverket betyr &aring; l&aelig;re hvordan du skal f&aring; frem det <br />du &oslash;nsker &aring; si &ndash;&nbsp;<em>p&aring; en m&aring;te som er interessant for andre.</em></span></p>\r\n<p>&nbsp;</p>\r\n</blockquote>\r\n<p><span style=\"font-size: 12pt;\">For noen f&aring; er det et instinkt. De fleste av oss m&aring; g&aring; den lange veien gjennom pr&oslash;ving og feiling, &oslash;ving, studier og atter mer &oslash;ving.</span></p>\r\n<h2><span style=\"font-size: 14pt;\">Men blir ikke alle historier like?</span></h2>\r\n<p><span style=\"font-size: 12pt;\">Noe av det mest fantastiske ved &aring; undervise p&aring; Forfatterskolen, er &aring; se hvordan tekstene blir mer og mer unike etter hvert som elevene l&aelig;rer og utvikler seg. Det kan virke som et paradoks. Hvordan kan den samme kunnskapen skape st&oslash;rre ulikheter?</span></p>\r\n<p><span style=\"font-size: 12pt;\">Det handler om &aring; beherske instrumentet, kunne spr&aring;ket, slik at det du har inni deg kan bli forst&aring;tt og verdsatt av andre. Om &aring; utforske flere muligheter, grave dypere, finne sin egen vei. Oppdage teknikkene som forfattere har utviklet gjennom &aring;rtusener og eie dem, lage sin egen vri p&aring; dem. Det handler ikke om &eacute;n metode, men om &aring; forst&aring; de ulike mulighetene, hvilke verkt&oslash;y du har til disposisjon og hvordan de fungerer. <em>Hvorfor </em>de fungerer. Utforske hva slags skribent <em>du </em>er og hvilke litter&aelig;re verkt&oslash;y som passer for ditt prosjekt.</span></p>\r\n<h2><span style=\"font-size: 14pt;\">Tre typiske \"feil\"</span></h2>\r\n<p><span style=\"font-size: 12pt;\">Vi som jobber p&aring; Forfatterskolen leser mange manus. Helt ferske forfatterspirer faller ofte inn i en av tre kategorier:</span></p>\r\n<ol>\r\n<li>\r\n<p><span style=\"font-size: 12pt;\">Historien er <em>for </em>personlig og presentert p&aring; en m&aring;te som gj&oslash;r den lite attraktiv &aring; lese. Forfatteren &oslash;nsker &aring; fortelle sin historie akkurat slik det var, men livet er ikke strukturert som en roman.</span></p>\r\n</li>\r\n<li>\r\n<p><span style=\"font-size: 12pt;\">Historien mangler personlighet og sjel, en unik stemme. Vi sitter igjen med f&oslash;lelsen av &aring; ha lest det samme mange ganger f&oslash;r. Spr&aring;ket kan v&aelig;re kjedelig eller for svulstig og historien mangler originalitet.</span></p>\r\n</li>\r\n<li>\r\n<p><span style=\"font-size: 12pt;\">Historien er ikke en historie i det hele tatt, men en serie l&oslash;srevne episoder som kan fortsette i det uendelige. Eller som har stoppet opp fordi forfatteren skj&oslash;nner at noe ikke fungerer.</span></p>\r\n</li>\r\n</ol>\r\n<p><span style=\"font-size: 12pt;\">Selv var jeg en typisk nummer 3, ikke uvanlig for en fantasyforfatter. Det var ikke m&aring;te p&aring; hvor mange fantastiske elementer og episoder jeg hadde planer om, men det var faktisk ingen historie der. N&aring; har jeg l&aelig;rt, b&aring;de &aring; skape en historie og hvordan jeg skal gj&oslash;re den god. Jeg har l&aelig;rt at jeg er en langsom skribent, at jeg liker &aring; skrive i mange lag, at mine historier m&aring; modnes. Jeg har l&aelig;rt at jeg m&aring; v&aring;ge &aring; hente karakterer og erfaringer fra mitt indre, stole p&aring; at det menneskelige er allmenngyldig uansett i hvilken form det kommer i.</span></p>\r\n<p><span style=\"font-size: 12pt;\">For n&aring; vet jeg at det er den typen historier <em>jeg</em> m&aring; skrive.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Jeg har l&aelig;rt at filmen i hodet mitt ikke kan overf&oslash;res til papiret, men hvis jeg skriver ned ordene som kommer, kan jeg etterp&aring; ta i bruk verkt&oslash;yene jeg har tilegnet meg og forme dem til noe som kan gi andre glede. Det tar tid. Det krever innsats. Men det er mulig.</span></p>\r\n<h2><span style=\"font-size: 14pt;\">Kan man l&aelig;re &aring; skrive en roman?</span></h2>\r\n<p><span style=\"font-size: 12pt;\">Det finnes ingen vanntett metode som fungerer for alle. Selv har jeg fremdeles flere sp&oslash;rsm&aring;l enn svar. Heldigvis. Den dagen jeg begynner &aring; tro at jeg sitter p&aring; fasiten, er den dagen jeg gir meg.&nbsp;</span></p>\r\n<p><span style=\"font-size: 12pt;\">Jeg opptatt av &aring; vise ulike m&aring;ter &aring; arbeide p&aring;, presentere mange forskjellige verkt&oslash;y og f&aring; frem ulike syn p&aring; litter&aelig;r kvalitet. Rektor Kristine og jeg er rake motsetninger, derfor er det viktig for meg at begge kommer til orde i kursmodulene. Kristine er en spontan og intuitiv skribent, jeg er analytisk og trenger en plan. Hanne deler sin erfaring i forumene. Vi inviterer kjente forfattere, redakt&oslash;rer og andre fra bokbransjen til &aring; presentere sitt syn hver mandagskveld p&aring; webinar. Du finner ikke &eacute;n metode hos oss, men vi skal gi deg verkt&oslash;yene du trenger og hjelpe deg med &aring; finne&nbsp;<em>din</em> metode.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Ja, &aring; skrive en god bok kan l&aelig;res. H&aring;ndverk kan l&aelig;res. Det lille ekstra &ndash; en unik litter&aelig;r snert &ndash; m&aring; du tilf&oslash;re selv. Men vi skal f&oslash;lge deg hele veien.<br /><br /><a href=\"https://www.forfatterskolen.no/course/24\">PS: Vi har &aring;pnet p&aring;meldingen til Forfatterskolens store romankurs!</a></span></p>','/storage/blog/1536829275.jpeg','Elin S. Rotevatn','/storage/blog/author/1536829275.jpeg',1,NULL,'2018-09-13 02:01:15','2019-08-13 10:59:53'),(6,1346,'Idéenes tyranni','<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 14pt;\">Av Thomas K. Solbakken:&nbsp;<img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/1/Thomas_2.jpg\" alt=\"\" width=\"400\" height=\"228\" /></span></p>\r\n<p style=\"text-align: left;\"><span style=\"font-weight: 400; font-size: 14pt;\"><br /></span><span style=\"font-weight: 400; font-size: 14pt;\">Jeg har ingen mangel p&aring; id&eacute;er. Og det er til og med et hinder for &aring; fullf&oslash;re det jeg burde fullf&oslash;re. Tror jeg, da. Det er fint &aring; ha noe &aring; skylde p&aring; n&aring;r manuset havner uferdig i skuffen (les mappa), er det ikke? For id&eacute;enes stadige inntog og manglende respekt for p&aring;g&aring;ende prosjekter er et tyranni. Samtidig som det stjeler all oppmerksomhet fra de prosjektene som mest sannsynlig har fortjent det, er tyranniet ogs&aring; et tveegget sverd.</span></p>\r\n<h2><span style=\"font-weight: 400;\">Dr&oslash;mme ideer</span></h2>\r\n<p><span style=\"font-weight: 400; font-size: 14pt;\">Selvsagt er jeg jo glad for den l&oslash;pske fantasien og id&eacute;ene som kommer str&oslash;mmende, og som like gjerne kan dukke opp i en dr&oslash;m som i k&oslash;en p&aring; Kiwi, rett og slett trigget av den underlige personen foran meg. Og her om dagen dr&oslash;mte jeg faktisk et helt skrekkfilmmanus. Jeg, som egentlig ikke er s&aring; glad i skrekkfilmer. P&aring; den annen side, begynner filomr&aring;det p&aring; PC&rsquo;en min &aring; bli full av korte, spirende synopsis som aldri kommer til &aring; vokse seg til et ferdig manus.</span></p>\r\n<h2><span style=\"font-weight: 400;\">T&oslash;mme harddisken</span></h2>\r\n<p><span style=\"font-weight: 400; font-size: 14pt;\">En av b&oslash;kene som fikk meg til &aring; begynne &aring; skrive selv, var &laquo;Sirkusdirekt&oslash;rens datter&raquo; av Jostein Gaarder. Jeg ble s&aring; fascinert av alle de sm&aring; historiene som ble spunnet av Edderkoppen. &laquo;Edderkoppen&raquo; lever av &aring; inspirere andre, og selge dem sine id&eacute;er slik at de kunne skrive manuset ferdig, og gi det ut. P&aring; en m&aring;te var det som om Jostein Gaarder hadde t&oslash;mt harddisken med sm&aring; synopsis inn i en bok, og bundet dem sammen med en rammefortelling. Genialt! Kanskje jeg skal gj&oslash;re det samme? Lage en samleplate p&aring; papir med id&eacute;er?</span></p>\r\n<h2><span style=\"font-weight: 400;\">En dag</span></h2>\r\n<p><span style=\"font-weight: 400; font-size: 14pt;\">S&aring; er ikke jeg Jostein Gaarder. Hvis jeg var heldig kunne jeg kanskje pusse skoene hans. Men kanskje id&eacute;en ikke er s&aring; dum? (Ops! Der kom det en til). Sm&aring; historier som spinner i hverandre, og til sammen blir de til en tornado av fortellinger. &laquo;Sirksdirekt&oslash;rens datter&raquo; er for meg en av de beste b&oslash;ker jeg har lest, og den er ogs&aring; en av mine st&oslash;rste inspirasjoner. S&aring; mens jeg fors&oslash;ker &aring; skape min egen manesje, f&aring;r id&eacute;ene komme. En dag skal jeg nok gj&oslash;re oppr&oslash;r.</span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 14pt;\"><a href=\"https://www.forfatterskolen.no/course/24\">PS: Vi har &aring;pnet p&aring;meldingen til Forfatterskolens store romankurs!</a> </span></p>','/storage/blog/1537469570.jpeg','Thomas K. Solbakken',NULL,1,NULL,'2018-09-20 18:35:02','2018-09-21 08:13:44'),(7,1346,'Frykten for å feile','<p style=\"text-align: center;\"><strong>Av: Sosiale medier-ansvarlig Silje Reistad</strong><br /><br /><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/bloggsilje.jpg\" alt=\"\" width=\"326\" height=\"179\" /></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Du liker &aring; skrive. Du har ideer p&aring; blokka, skisser til romaner og noveller i hodet. Du elsker &aring; dr&oslash;mme deg bort i b&oslash;ker, tenker ut egne historier du vil skrive, karakterer du vil skape og f&oslash;lge over tid. Kanskje skrev du da du var yngre? Fikk skryt av l&aelig;reren, av venner eller foreldre.&nbsp;</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Kanskje gjorde du som meg; satte sammen A4-ark med stiftemaskin og skrev dine egne b&oslash;ker. Jeg var 5 &aring;r og stod for tekst og illustrasjoner selv. Ordene var feilstavet og dyrene s&aring; kanskje ikke ut som de dyrene de egentlig skulle v&aelig;re, men &eacute;n ting var sikkert allerede da. </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Jeg ville bli forfatter.</span></p>\r\n<p><span style=\"font-size: 18.6667px;\"><strong>N&Aring;R DET SIER STOPP</strong></span></p>\r\n<p><span style=\"font-size: 12pt;\">S&aring; hvordan kan det bli s&aring; vanskelig &aring; skrive? N&aring;r dr&oslash;mmen st&aring;r s&aring; sterkt? Og noen ganger s&aring; lenge av gangen? Jeg har gode skriveperioder hvor tastene g&aring;r av seg selv. Men s&aring; stopper det opp. Spesielt n&aring;r det bare er f&aring; sider igjen av en historie. N&aring;r det begynner &aring; n&aelig;rme seg slutten. Alle bremsene st&aring;r plutselig p&aring;, og skriveselvtillitten? Forsvunnet.</span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\">Frykt. Det m&aring; v&aelig;re frykt. Frykten for &aring; f&aring; nei. For at det ikke er godt nok. For at man ikke er den forfatteren man kanskje dr&oslash;mte om at man var.<br /><br />Men her, dere. Her m&aring; vi kjempe imot. Denne f&oslash;lelsen er helt normal, men ikke noe som fortjener tiden og tankene v&aring;re. For den harde sannheten er; skriver vi ikke, blir vi ikke forfattere. Og f&aring;r man nei fra forlag? Det er en del av veien mot dr&oslash;mmen, og noe vi skal bli motivert av.<br /><br /></span><span style=\"font-weight: 400;\"><span style=\"font-size: 12pt;\">Alle dere skribenter som kjenner dere igjen i skrivesperren og mangelen p&aring; skriveselvtillit; Vi er n&oslash;dt til &aring; sette oss foran de blanke arkene likevel, trykke ned tastene eller pennen - om det s&aring; bare er for &aring; skrive at man er tom for ord.&nbsp;</span><br /><br /><span style=\"font-size: 18.6667px;\"><strong>TRE TRINN SOM KAN HJELPE:<br /></strong></span><br /><span style=\"font-size: 12pt;\">* OK, s&aring; er du tom for ord. V&aelig;r en journalist som stiller deg selv sp&oslash;rsm&aring;l. Hvorfor tror du at du er det? Skriv svaret. La journalisten fortsette &aring; stille sp&oslash;rsm&aring;l. Er det noe med historien din, f&oslash;ler du at du mangler noe? </span><br /><span style=\"font-size: 12pt;\">* N&aring; er du i gang. Still flere sp&oslash;rsm&aring;l til deg selv. Hva liker du best med historien/ideen din? Kommer du p&aring; noe ved ideern du er forn&oslash;yd med? Skriv.</span><br /><span style=\"font-size: 12pt;\">* Glem din planlagte utvikling i historien, om du har det. Hva ville du gjort med historien om du kunne begynt p&aring; nytt? Kanskje kommer du p&aring; ideer som kan puttes inn.&nbsp;</span><br /><span style=\"font-size: 12pt;\">* Gj&oslash;r dette hver gang du f&aring;r skrivestopp. Du kan eventuelt lage en ferdig mal med disse sp&oslash;rsm&aring;lene, som du fyller inn f&oslash;r du g&aring;r tilbake til skrivingen igjen. Du \"tvinger\" deg selv til &aring; skrive uten at det er direkte knyttet til historien din, og det kan l&oslash;sne opp.&nbsp;</span><br /><br /><span style=\"font-size: 12pt;\">&Aring; skrive er som mye annet, det m&aring; bli en vane. Og det skal vi klare - sammen!</span><br /><br /><span style=\"font-size: 12pt;\">Sett deg et skrivem&aring;l sammen med meg n&aring;. Skriv det p&aring; en postit-lapp, eller p&aring; mobilen. Les det ofte. Mitt skrivem&aring;l er at jeg skal lage en ny vane, hvor jeg hver dag skriver p&aring; morgenen med kaffekoppen. F&oslash;r jeg sjekker mobil, mail og hva som har skjedd i verden. En halv side holder, men hvis jeg kommer inn i en god flyt er det bare &aring; fortsette.</span><br /><br /><span style=\"font-size: 12pt;\">Jeg har troa p&aring; deg. Og det b&oslash;r du ha ogs&aring;. Lykke til med skrivingen!</span><br /><br /><strong style=\"font-weight: 400;\">PS:&nbsp;</strong></span><span style=\"font-weight: 400;\">For meg har det hjulpet mye &aring; v&aelig;re en del av Forfatterskolen og ha en litter&aelig;r familie.&nbsp;</span><a style=\"font-size: 12pt;\" href=\"https://www.forfatterskolen.no/course/24\">P&aring;meldingen til Forfatterskolens store romankurs er &aring;pen!</a></span></p>','/storage/blog/1538078016.jpeg','Silje Reistad',NULL,1,NULL,'2018-09-28 02:53:36','2018-09-28 16:29:16'),(8,1346,'Beretning om en varslet drukning','<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><em>Av: Kristin Hauge, tidligere elev hos Forfatterskolen og debutant med novellesamlingen &laquo;Tiggerne&raquo;.</em></span></p>\r\n<h2 style=\"text-align: center;\"><img src=\"/laravel-filemanager/photos/1346/debutant2.jpg\" alt=\"\" width=\"509\" height=\"275\" /></h2>\r\n<p><span style=\"font-size: 12pt;\">Jeg debuterte for f&aring; uker siden, men boken min lider allerede av &aring;nden&oslash;d, er i ferd med &aring; drukne i en flodb&oslash;lge av utgivelser, i ferd med &aring; bli skyllet inn i de innerste avkroker i kjedebutikkene og forvist til et usynlig liv i den digitale himmel.</span></p>\r\n<p><span style=\"font-size: 12pt;\">En tilreisende venninne, bosatt i utlandet, gikk nylig innom en rekke bokhandlere i Oslo sentrum og p&aring; Oslo Lufthavn f&oslash;r hun fikk tak debutbok en min, Tiggerne (Vigmostad og Bj&oslash;rke). Den ble omsider hentet frem fra butikkens lager og overrakt henne med en gul lapp p&aring;klistret; Til vurdering.&nbsp;<br /><br /><strong><span style=\"font-size: 14pt;\">B&oslash;r ta tak</span></strong><br /></span><span style=\"font-size: 12pt;\">Butikkene f&aring;r gjerne tilsendt et leseeksemplar, som ikke alltid n&aring;r butikkens salgshyller, og hvis den gj&oslash;r det; ikke blir erstattet hvis den blir solgt.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Gro J&oslash;rstad Nilsen sier i et innlegg i Bergens Tidende nylig at forlagene b&oslash;r finne frem til m&aring;ter &aring; sikre at debutanter og nye stemmer kan f&aring; lov &aring; skinne en liten stund. Hun hevdet at forlagene p&oslash;ser ut flere b&oslash;ker enn de vet vil selge, fordi innkj&oslash;psordningen for skj&oslash;nnlitteratur minimerer risikoen.&nbsp;</span></p>\r\n<p><br /><span style=\"font-size: 12pt;\">Jeg er selvsagt glad for &aring; ha kommet gjennom n&aring;l&oslash;yet i et etablert forlag, og blitt antatt og utgitt, men det hjelper lite med fine ordninger som innkj&oslash;psordningen, hvis ukjente debutanter i realiteten drukner i andre utgivelser og forvises til usynlighet etter kort tid.&nbsp;</span><br /><span style=\"font-size: 12pt;\">Hva som er &aring;rsakene til dette kan v&aelig;re flere. Jeg drister meg til &aring; komme med noen refleksjoner.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Forfatter Tove Nilsen uttalte f&oslash;r forrige &aring;rs debutanttreff, i en artikkel i Dagsavisen i desember ifjor, at det tidligere var mye mer oppmerksomhet om debutanter. &ndash; Om det ikke blir en merkbar mottakelse av f&oslash;rste bok, blir det vanskelig &aring; g&aring; videre. Man blir hengende i et ingenmannsland, sa hun.&nbsp;</span></p>\r\n<p><br /><span style=\"font-size: 12pt;\">Ogs&aring; fjor&aring;rets debutant Zeshan Shakar uttalte i samme artikkel at det er bedre &aring; f&aring; en negativ omtale, enn ingen; - Det er jo synlighet det handler om, og det er et paradoks at ikke debutanter f&aring;r mer plass og oppmerksomhet, sa han.<br /><br /></span></p>\r\n<p><span style=\"font-size: 12pt;\"><strong><span style=\"font-size: 14pt;\">Innf&oslash;re debutanthylle?</span></strong><br />Siden boken min ble lansert 20. august, har jeg av nysgjerrighet fulgt med en rekke av landets kjedebokhandlere p&aring; Instagram. Det har v&aelig;rt en foruroligende &oslash;velse, de samme b&oslash;kene &laquo;bokfjeses&raquo; p&aring; likt&ndash; omtrent med de samme formuleringene hentet fra forlagsmaterialet - over det ganske land. Og det er stort sett et frav&aelig;r av debutanter.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Alle butikker burde klare &aring; ha i hvert fall ett eksemplar til salgs hele tiden av alle debutanter. Og gjerne ogs&aring; &oslash;vrige forfattere selvf&oslash;lgelig, men mitt hovedanliggende her er &aring; rette fokus mot de ukjente debutantene.&nbsp;<br /></span><br /><span style=\"font-size: 12pt;\">Hva med en egen debutanthylle med b&oslash;ker for salg, slik at debutanter f&aring;r st&oslash;rre synlighet?&nbsp;<br /></span><br /><span style=\"font-size: 12pt;\">Selvf&oslash;lgelig finnes b&oslash;kene i nettbokhandlene og det er bra. Men b&oslash;kene m&aring; likevel anmeldes og markedsf&oslash;res, f&oslash;r noen kj&oslash;per dem. Bokshoppere er som andre shoppere, vi liker ofte &aring; se noe nytt i butikk, f&oslash;r vi kj&oslash;per p&aring; nett. I dag fylles i stedet bokhandlene opp med veldig mye annet enn b&oslash;ker.<br /></span></p>\r\n<p><span style=\"font-size: 12pt;\">Mye blir overlatt til ulike bloggere, og det er bra at det er mange stemmer som fors&oslash;ker &aring; fange opp og spre kjennskap til skj&oslash;nnlitteraturen. Men jeg savner mer systematisk presentasjon og kritikk av de ukjente debutantene. <br /><br />En del nettsteder har vokst frem, som Bok365.no og&nbsp;<a href=\"https://l.facebook.com/l.php?u=http%3A%2F%2FBokmerker.org%2F&amp;h=AT29vlZ_cDU3whQJ20ELLk8I25tah4IV-AGjZd8pToffsqYvmCy7UCKH0nWj8W2dzKHNa0mQXrWqThnTnFgT7C3B9ZEtfEEx5gsK1pYCSDJAoX508Hjqh9OLBPiuM4q2IbULNdshElstB4AKIqCuHYg14v6A8QMVkd6z_g\" target=\"_blank\" rel=\"noopener nofollow\" data-ft=\"{\" data-lynx-mode=\"async\">Bokmerker.org</a>, og jeg er selv blitt anmeldt der. (Kristin Hauge skriver oppslukende om mennesker som venter). Bok365.no har allerede laget en oversikt over &aring;rets debutanter.&nbsp;<br /></span><br /><strong><span style=\"font-size: 14pt;\">Bel&oslash;nne synliggj&oslash;ring</span></strong><br /><span style=\"font-size: 12pt;\">Bred og god litteraturkritikk er viktig, b&aring;de for de skrivende og de lesende. Samtidig vet vi at bransjen preges av sv&aelig;rt endrede betingelser og utfordringer i mange ledd.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Hva med en pris for den beste skj&oslash;nnlitter&aelig;re debutantanmeldelsen finansiert av bransjen (Bokhandlerforeningen og forlagene) i fellesskap? Form&aring;l; &aring; synliggj&oslash;re god kritikervirksomhet og bel&oslash;nne de mediene/kritikerne som faktisk tar seg tid til &aring; presentere nye stemmer.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Det fines heller ingen debutantpris for skj&oslash;nnlitter&aelig;re forfattere. Vesaas-prisen kommer med en aldersgrense, og er kun for debutanter under 35 &aring;r. Det er ogs&aring; debutantpriser begrenset til forfattere p&aring; ulike forlag.&nbsp;</span><br /><span style=\"font-size: 12pt;\">Norsk litteratur trenger et mangfold, kanskje ogs&aring; i alder p&aring; debutanter.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Hva med en generell pris for skj&oslash;nnlitter&aelig;re debutanter, som er &aring;pen for alle aldre? Form&aring;l; &aring; synliggj&oslash;re ukjente debutanter og f&aring; mer blest i en tidlig og viktig periode av et forfatterskap</span></p>\r\n<p><span style=\"font-size: 12pt;\">Forfatter Oluf Lagerkrantz skriver s&aring; vakkert i boken &laquo;Om kunsten &aring; lese og skrive&raquo;;&nbsp;</span><br /><br /><span style=\"font-size: 12pt;\">&laquo;Alle b&oslash;ker er barn som foreldrene har sendt ut til verden, og disse barna er som dem, av kj&oslash;tt og blod, d&oslash;mt til &aring; d&oslash; og glemmes. I den store bokgraven er det stille og ingen leser lenger de ordene som en gang ble sammenstillet med slit og strev.&raquo;</span></p>\r\n<p><span style=\"font-size: 12pt;\">Og noen b&oslash;ker blir borte f&oslash;r du har f&aring;tt anledning til &aring; oppdage dem.</span></p>\r\n<p><span style=\"font-size: 12pt;\">Men kj&aelig;re leser, kan du gj&oslash;re meg en tjeneste? G&aring; innom en bokhandel og sp&oslash;r etter boken min. Og hvis de ikke har den, sp&oslash;r gjerne etter en annen ukjent debutant du er nysgjerrig p&aring; og. Du trenger ikke kj&oslash;pe b&oslash;kene, men butikkene skal bestille det kundene ber om, men da gj&oslash;r du b&oslash;kene fysisk tilgjengelig for andre.</span><br /><span style=\"font-size: 12pt;\">&nbsp;</span><br /><span style=\"font-size: 12pt;\">Og send meg en melding p&aring; Facebook eller Instagram, s&aring; skal jeg invitere til heidundrende grav&oslash;l, n&aring;r jeg f&aring;r restopplaget av mine usolgte b&oslash;ker i retur. Jeg lover.<br /><br /><em>Dette blogginnlegget ble f&oslash;rst&nbsp;trykket som en kronikk i <a href=\"https://www.bt.no/kultur/i/EoMLRG/Beretning-om-en-varslet-drukning\">Bergens Tidende 23. september.</a></em></span> <br /><br /><span style=\"font-size: 12pt;\"><strong><a href=\"https://www.norli.no/webapp/wcs/stores/servlet/ProductDisplay?storeId=10651&amp;urlLangId=-101&amp;productId=3074457345616879748&amp;urlRequestType=Base&amp;langId=-101&amp;catalogId=10001\" target=\"_blank\" rel=\"noopener\">Her finner du Kristins bok.</a></strong></span></p>','/storage/blog/1538678366.jpeg','Kristin Hauge',NULL,1,NULL,'2018-10-04 18:23:41','2018-10-12 11:32:20'),(9,1346,'Hvem tror jeg at jeg er?','<p class=\"p1\" style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><span class=\"s1\">Av: Marit Reiersg&aring;rd, forfatter.</span></span></p>\r\n<h2><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/Marit2.jpg\" alt=\"\" width=\"563\" height=\"274\" /></h2>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">Jeg er midt i en boklansering. En ny kriminalroman er i butikkene, en del lesere har allerede sendt meg tilbakemeldinger, og det har s&aring; langt kommet to gode avisanmeldelser. Det er festdager. Det er signeringer, avisomtaler, gratulasjoner, blomster og livet p&aring; sosiale medier viser en aktiv forfatter som har det s&aring; fint, s&aring; fint. </span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">Likevel st&aring;r gr&aring;ten i heisen og trenger bare et lite trykk p&aring; en f&oslash;lsom knapp s&aring; stiger den til toppetasjen. Jeg f&oslash;ler meg s&aring;rbar og alene fordi denne tanken sl&aring;r meg &ndash; hvem tror jeg at jeg er? </span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\"><em>Hvorfor er ikke glad n&aring;r alt g&aring;r s&aring; bra? </em></span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">Jeg har kommet langt, oppn&aring;dd mer enn det jeg som debutant for over ti &aring;r siden turte &aring; dr&oslash;mme om. Eller, det er ikke helt sant, jeg hadde store dr&oslash;mmer allerede f&oslash;r jeg var publisert forfatter. Jeg <em>s&aring;</em> det virkelig. Det <em>f&oslash;ltes</em> virkelig. Jeg <em>trodde </em>virkelig p&aring; det &ndash; at jeg en dag skulle st&aring; p&aring; den samme scenen som mine forfatterforbilder. Sammen med hardt arbeid og en stahet som gjorde at jeg ikke ga meg etter den tiende refusjonen kan jeg i dag kalle meg kollega av de forfatterne jeg beundret.</span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">Jeg har oppn&aring;dd mye &ndash; hvorfor f&oslash;ler jeg meg ikke st&oslash;rre? Kanskje fordi en mindre utgave av meg selv sitter p&aring; skulderen og hvisker meg i &oslash;ret: <em>Hvem tror jeg egentlig at jeg er ...</em></span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\"><em>Du er faktisk ikke s&aring; unik.</em></span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">I dag hadde jeg en kaffeprat med datteren min som blogger. Hun fortalte at hun plutselig ikke hadde tillit til egen tekst lenger, og vurderte &aring; slutte og skrive. Det til tross for at hun har oppn&aring;dd store lesertall, har f&aring;tt ting p&aring; trykk i Aftenposten og til og med v&aelig;rt p&aring; God Morgen Norge.</span></p>\r\n<ul class=\"ul1\">\r\n<li class=\"li1\"><span class=\"s1\" style=\"font-size: 12pt;\">Mamma, hva skal jeg gj&oslash;re for &aring; t&oslash;rre og fortsette med &aring; skrive? Jeg er redd for at n&aring;r andre leser vil de tenke: Hvem tror hun at hun er? Tror hun at hun er bedre enn andre? Og jeg er redd for at mine tanker er s&aring; rare og spesielle at de bare vil tenke at jeg pr&oslash;ver &aring; gj&oslash;re meg interessant&raquo;</span></li>\r\n<li class=\"li1\"><span class=\"s1\" style=\"font-size: 12pt;\">Jenta mi, sa jeg, &ndash; slapp av, s&aring; spesiell er du nok ikke! </span></li>\r\n<li class=\"li1\"><span class=\"s1\" style=\"font-size: 12pt;\">Takk for &laquo;tr&oslash;sten&raquo;, sa hun med et lite smil. </span></li>\r\n</ul>\r\n<p class=\"p3\"><span class=\"s1\" style=\"font-size: 12pt;\">Hun forsto heldigvis hva jeg mente. Tankene hennes var ikke unike, jeg kjente de s&aring; altfor godt igjen. Frykten for hva andre kan komme til &aring; mene om noe jeg har skrevet eller sagt. Janteloven kan sl&aring; hardt ned p&aring; den som ser ut til &aring; lykkes. </span></p>\r\n<ul class=\"ul1\">\r\n<li class=\"li1\"><span class=\"s1\" style=\"font-size: 12pt;\">Hvis du klarer &aring; sette ord p&aring; dette, fortsatte jeg, - vil det garantert v&aelig;re andre der ute som kjenner seg igjen. Du er ikke den eneste som er usikker og redd for at andre skal mene at du tror for godt om deg selv. </span></li>\r\n</ul>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\"><em>S&aring; du tror at du kan skrive?</em> </span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">Det slo meg da, i det samme jeg fors&oslash;kte &aring; f&aring; henne til &aring; gjenvinne skrivetilliten, at jeg samtidig hjalp meg selv. </span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">Men br&aring;tt sl&aring;r den til igjen &ndash; jeg kjenner p&aring; frykt for &aring; skrive dette innlegget, for hvem tror jeg at jeg er? Jeg som f&aring;r utgitt b&oslash;ker, jeg har da ikke lov til &aring; sitte her &aring; v&aelig;re usikker p&aring; egne ord? Men selvtilliten har ikke steget med antall utgivelser. Jeg h&oslash;rer fortsatt stemmen slik den var da jeg begynte &aring; skrive: So you think you can write! Hvem tror du at du er? </span></p>\r\n<p class=\"p1\"><span class=\"s1\" style=\"font-size: 12pt;\">Antageligvis m&aring; jeg leve med den stemmen p&aring; nakken, men jeg kommer til &aring; fortsette &aring; skrive likevel. Uansett hvor redd jeg er for hva andre skal mene. Uansett hva som skjer. Uansett hvordan jeg f&oslash;ler meg, og uansett om jeg lykkes, eller ikke med det jeg gj&oslash;r fremover. Jeg vil skrive selv om selvbildet rakner, kanskje er det nettopp da det er viktig at jeg gj&oslash;r det. </span></p>\r\n<p class=\"p1\"><strong><span class=\"s1\" style=\"font-size: 12pt;\">Det synes jeg du ogs&aring; skal. </span></strong></p>','/storage/blog/1539343546.jpeg','Silje Reistad','/storage/blog/author/1539343193.jpeg',1,NULL,'2018-10-12 11:19:53','2018-10-12 13:36:11'),(10,1346,'Hvordan engasjere leseren (og deg selv)','<p><span style=\"font-size: 14pt;\"><strong><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/1/ideer-2.jpg\" alt=\"\" width=\"750\" height=\"450\" /><br /><br />1. &Aring; komme i gang</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">&Aring; skrive skj&oslash;nnlitteratur er &aring; gj&oslash;re som Alice, vandre inn i det ubevisstes Wonderland, gi seg dets frodige kaos i vold. Dit inn kommer du bare hvis du holder bevissthetens kritiske logikk unna. Dens tid i rampelyset kommer senere. Begynn med &aring; skrive om noe som engasjerer deg. Ikke tenk s&aring; mye fremover, eller om det kan brukes til noe, ikke lag faste rammer for deg selv.</span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Begynn &aring; skrive, og bry deg minst mulig om hva. Forestill deg at </span><em><span style=\"font-weight: 400;\">du ikke</span></em> <em><span style=\"font-weight: 400;\">tenker for &aring; skrive, du skriver for &aring; tenke</span></em><span style=\"font-weight: 400;\">. N&aring;r du skriver om noe som engasjerer deg, masserer du fram ideene. Er du som meg, f&aring;r du ofte en id&eacute; du tenker kan v&aelig;re en kime til noe, men du kommer ikke videre. Jeg har erfart igjen og igjen at det som bringer meg videre i et manus er &aring; sette meg til &aring; skrive. Uten &aring; vite hvor jeg skal.<br /><br /></span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\">- Cheshire puss, would you tell me, please, </span></em></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\"> &nbsp;which way I ought to go from here? said Alice. </span></em></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\">- That depends a good deal on where </span></em></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\"> &nbsp;you want to get to, said the Cat.</span></em></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\">- I don&rsquo;t much care where, &hellip; said Alice</span></em></span></p>\r\n<p><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\">- Then it doesn&rsquo;t matter which way you go<br /><br /></span></em></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">N&aring;r du ikke er s&aring; n&oslash;ye p&aring; hvor du skal, blomstrer gjerne ideene opp, folder seg ut og blir til noe. Du m&oslash;ter Alices flora av besynderlige karakterer og hendelser. Selv om du senere kanskje forkaster dem, har du uansett l&aelig;rt noe. Og det kan starte en annen id&eacute;. Som gjerne kan komme under en pause i skrivingen. Ideer siver inn fra det ubevisste n&aring;r som helst og hvor som helst. De tre B&rsquo;er: Bed-Bus-Bathroom. Da gjelder det &aring; gripe dem og f&aring; festet dem til et egnet medium. Det v&aelig;re seg en serviett eller en nettsky. Ha tillit til deg selv, og behandle alle ideer med respekt. Det er en grunn til at de er der.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">La deg ikke skremme av at det kan virke langt fram og uoverkommelig &aring; skrive et helt manus. I Elmore Leonards herlige bok, og film, &lsquo;Get Shorty&rsquo;, beskriver en av de mer suspekte karakterene de enkle stegene:</span></p>\r\n<p><span style=\"font-size: 12pt;\"><em><span style=\"font-weight: 400;\">- Du f&aring;r en id&eacute;, du skriver den ned slik du vil ha den, s&aring; hyrer du p&aring; noen til &aring; stave vanskelige ord og slenge p&aring; &lsquo;commas and shit&rsquo;, du fader ut &ndash; The end. Det er det hele</span></em><span style=\"font-weight: 400;\">.</span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Det er ingen d&aring;rlig sammenfatning, men p&aring; en seri&oslash;s forfatterskole, f&oslash;ler jeg det er p&aring; sin plass med litt utdypning. Som jeg gir fra mitt subjektive st&aring;sted. For la meg si det med &eacute;n gang, det er ikke ett svar p&aring; hvordan en roman blir til. Og jeg tenker roman her. Poesi har jeg liten erfaring med (Trolig er det likheter p&aring; det overordnete plan). Den enkelte forfatters skapelsesprosess er utvilsomt like individuell og personavhengig som sluttproduktet. Jeg kan bare beskrive det som er naturlig for meg. Ta det som en trigger for &aring; finne fram til </span><em><span style=\"font-weight: 400;\">din</span></em><span style=\"font-weight: 400;\"> m&aring;te. Din skrivestemme. &nbsp;</span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">I forrige blogg skrev jeg om det siste, &aring; finne sin skrivestemme. Denne gangen har jeg lyst til &aring; reflektere litt rundt det f&oslash;rste punktet i Elmore Leonards fortreffelige beskrivelse. Alts&aring;:</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>2. Du f&aring;r en id&eacute;.</strong></span></h2>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Jeg tror ikke den gode Elmore har ment &aring; v&aelig;re dypsindig her, men jeg velger likevel &aring; ta ham p&aring; ordet og understreke at du </span><em><span style=\"font-weight: 400;\">f&aring;r</span></em><span style=\"font-weight: 400;\"> en id&eacute;. Det vil si: du </span><em><span style=\"font-weight: 400;\">har</span></em><span style=\"font-weight: 400;\"> den ikke, du </span><em><span style=\"font-weight: 400;\">jobber den ikke fram</span></em><span style=\"font-weight: 400;\">, du </span><em><span style=\"font-weight: 400;\">f&aring;r den</span></em><span style=\"font-weight: 400;\">. Eller dem. For du trenger ikke bare &eacute;n id&eacute;, ikke bare et startpunkt p&aring; et manus. Gjennom hele skriveprosessen er du avhengig av &aring; f&aring; ideer. Spennende ting skal skje, karakterbeskrivelser skal engasjere, omgivelser skal skildres, utfordringer skal l&oslash;ses p&aring; overraskende m&aring;ter. Helst overraskende for deg selv ogs&aring;. For de er ikke ditt produkt, ideene.</span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">De er ikke ditt produkt. </span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Hadde du levd for to-tre tusen &aring;r siden &ndash; f&oslash;r mennesket fikk bevissthet &ndash; ville det v&aelig;rt selvsagt. Det ville ikke falt deg inn &aring; tro at det var du, </span><em><span style=\"font-weight: 400;\">forfatteren</span></em><span style=\"font-weight: 400;\">, som diktet. Det var heller ikke </span><em><span style=\"font-weight: 400;\">maleren </span></em><span style=\"font-weight: 400;\">som malte, ikke </span><em><span style=\"font-weight: 400;\">h&aelig;rf&oslash;reren</span></em><span style=\"font-weight: 400;\"> som vant slaget. Du ville v&aelig;re overbevist om at det er noe g&aring;tefullt der ute et sted, en</span><em><span style=\"font-weight: 400;\"> &aring;nd</span></em><span style=\"font-weight: 400;\"> &ndash; en </span><em><span style=\"font-weight: 400;\">genie</span></em><span style=\"font-weight: 400;\"> &ndash; som gj&oslash;r dette. Gjennom deg. Du bare skriver ned det hun kommer med. Er ikke det befriende? Ingen prestasjonsangst. Blir det d&aring;rlig, er det ikke din skyld, det er din </span><em><span style=\"font-weight: 400;\">genie</span></em><span style=\"font-weight: 400;\"> som har en d&aring;rlig dag. Blir det bra, skader det ikke ditt image at du ikke tar hele &aelig;ren for det. </span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Slik var det den gangen, i den ubevisste &aelig;raen. Da vi senere ble bevisste, kvittet vi oss med den oppfatningen. Det bevisste mennesket tar selv ansvaret og &aelig;ren for sine handlinger. N&aring; er det mennesket som er </span><em><span style=\"font-weight: 400;\">geniet</span></em><span style=\"font-weight: 400;\">. Som jubler n&aring;r det g&aring;r bra, og som depper n&aring;r det g&aring;r d&aring;rlig. </span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Hva om det var litt forhastet &aring; kaste de gamles forestilling over bord? Hva om de var inne p&aring; noe? Vitnesbyrd fra en rekke kunstnere og vitenskapsmenn gir oss hint om det.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Ja vel, sier du, og hva s&aring;? Spiller det noen rolle for meg?</span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Det kan hende det gj&oslash;r det. Kanskje vil du oppleve at det &aring; skifte fokus fra </span><em><span style=\"font-weight: 400;\">&aring; prestere</span></em><span style=\"font-weight: 400;\"> til </span><em><span style=\"font-weight: 400;\">&aring; respondere</span></em><span style=\"font-weight: 400;\">, endrer din holdning til skriveprosessen. Du trer inn i rollen som en respektfull sekret&aelig;r for noe stort og g&aring;tefullt</span> <span style=\"font-weight: 400;\">inni deg. Du skriver, skriver, skriver, og er i alarmberedskap for &aring; gripe ideene du f&aring;r utlevert gjennom eteren. Din jobb er &aring; utvikle dem og f&aring; dem publisert. Kanskje opplever du at en slik holdning t&oslash;yler kritikeren i deg, prestasjonsangsten, denne knugende demperen p&aring; din fabulerende evne, som hindrer deg i &aring; bli den beste forfatterutgaven av deg selv. Den utgaven som f&aring;r deg til &aring; skape og oppleve tekstens magi. Du som skriver, er den f&oslash;rste til &aring; m&oslash;te den. Du kjenner at det ikke lenger bare er hodet som styrer skrivingen, du skriver med hele kroppen. Hjertet sl&aring;r fortere, &oslash;ynene blir t&oslash;rre, for du glemmer &aring; blunke, du puster fortere. Du f&oslash;ler deg vibrerende levende. </span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Det er den f&oslash;lelsen du m&aring; jakte p&aring;. G&aring; inn i den verden du skaper, opplev den med alle sanser, se, h&oslash;r, lukt. Det er viktig &aring; gi seg hen til skapergleden n&aring;r den er der, gripe den og videreformidle den. Da engasjeres du og engasjerer du. Da er det g&oslash;y &aring; skrive. Og det m&aring; da v&aelig;re derfor du gj&oslash;r det?</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Noen eksempler:</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">&ndash; Den amerikanske poeten Ruth Stone pleide &aring; arbeide ute p&aring; marken p&aring; sm&aring;bruket sitt. Hun forteller at hun h&oslash;rte det dundret, og kjente jorden skjelve, n&aring;r et dikt kom farende mot henne. Hun l&oslash;p inn for &aring; finne blyant og papir, s&aring; hun kunne skrive det ned straks det n&aring;dde henne og str&oslash;mte gjennom henne. Ble hun for sen, for diktet gjennom henne, forsvant og fant seg en annen poet, sier hun. Noen ganger fikk hun s&aring; vidt tak i halen p&aring; det, og dro det tilbake til seg mens hun skrev det ned. Da kom diktet ut baklengs, det siste ordet f&oslash;rst, p&aring;st&aring;r hun. Ruth Stone skrev hele livet, men fikk sitt store gjennombrudd f&oslash;rst i en alder av 86. </span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">&ndash; Den</span> <span style=\"font-weight: 400;\">amerikanske l&aring;tskriveren og visesangeren</span> <span style=\"font-weight: 400;\">Tom Waits</span> <span style=\"font-weight: 400;\">forteller om en episode mens han</span> <span style=\"font-weight: 400;\">kj&oslash;rte p&aring; motorveien i LA. Han kjente en strofe komme inn i hodet. Uten mulighet til &aring; skrive den ned, var han redd han kom til &aring; miste den. Han ropte opp mot himmelen: &lsquo;Unnskyld, ser du ikke at jeg kj&oslash;rer bil? Ser det ut som jeg kan ta ned en sang n&aring;? Hvis du virkelig eksisterer, kom tilbake ved en mer passende anledning! Eller plag en annen. G&aring; og plag Leonard Cohen&rsquo;.</span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">&ndash; Den amerikanske forfatteren Elizabeth Gilbert (med kjempesuksessen </span><em><span style=\"font-weight: 400;\">Eat, pray, love</span></em><span style=\"font-weight: 400;\">) forteller at hun kan sitte og skrive og skrive og ikke f&aring; til noe st&oslash;rre. Da hender det hun l&oslash;fter hodet, ser bort i et dunkelt hj&oslash;rne i rommet og sier h&oslash;yt: &lsquo;Hvis du har noe p&aring; hjertet, f&aring;r du komme med det. Du ser vel at jeg sitter her og gj&oslash;r s&aring; godt jeg kan, </span><em><span style=\"font-weight: 400;\">jeg</span></em><span style=\"font-weight: 400;\"> gj&oslash;r </span><em><span style=\"font-weight: 400;\">min </span></em><span style=\"font-weight: 400;\">jobb, n&aring; f&aring;r </span><em><span style=\"font-weight: 400;\">du</span></em><span style=\"font-weight: 400;\"> gj&oslash;re </span><em><span style=\"font-weight: 400;\">din</span></em><span style=\"font-weight: 400;\">&rsquo;.</span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\"><strong>For &aring; gjenta meg selv fra forrige blogginnlegg:</strong> </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">* Hemingway sa at han skrev s&aring; godt han kunne. Og f&oslash;yde til: &laquo;Noen ganger bedre&raquo;.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">* Hamsun sa at Hellig&aring;nden talte gjennom ham.</span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">* Den store vitenskapsmannen</span> <span style=\"font-weight: 400;\">Maxwell</span> <span style=\"font-weight: 400;\">sa: &lsquo;Det som er gjort av det jeg kaller meg selv, &nbsp;</span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\"> &nbsp;&nbsp;f&oslash;ler jeg er gjort av noe st&oslash;rre enn meg selv i meg&rsquo;.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Vitnesbyrd om deres kontakt med sine Genies. </span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Jeg gjentar at det selvsagt er andre tiln&aelig;rmingsm&aring;ter til &aring; skrive enn dette, men for meg er det gjenkjennbart. Jeg setter meg til skrivebordet med et &aring;pent sinn, forventningsfullt beredt til &aring; samarbeide med mine karakterer om &aring; f&oslash;re handlingen videre. &lsquo;God morgen, hvem av dere vil ha ordet f&oslash;rst i dag?&rsquo;. Noen ganger dukker det opp en karakter jeg ikke visste om da jeg satte meg. &lsquo;Hallo, hvem er du? Hvilken rolle har </span><em><span style=\"font-weight: 400;\">du</span></em><span style=\"font-weight: 400;\"> tenkt &aring; spille?&rsquo;</span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Hvis du vil ha noe mer konkret omkring ideenes opphav enn mytiske genies, tenk p&aring; f&oslash;lgende. Hjernen er et instrument som kan lagre og formidle ufattelige mengder med informasjon. Hvert sekund tar den inn gjennom sansene 11 millioner informasjonsenheter. Eller bits. Den skyfler dem unna et eller annet sted. Inn i det ubevisste for det meste. Hvis vi sammenligner hjernen med en videoopptaker, ville den kunne lagre 300 &aring;r med videooptak fra kontinuerlige tv-sendinger. (2500 milliarder bytes, for den som liker &aring; sette tall p&aring; ting). Dette enorme reservoaret st&aring;r til din disposisjon, det kan du h&oslash;ste fra n&aring;r du skriver. Et m&oslash;rklagt, gigantisk bibliotek. Alle har vi dette. Forskjellen ligger i evnen til &aring; utnytte det.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Og hvem vet om ikke ogs&aring; andres &ndash; kanskje alles &ndash; tanker og opplevelser er registrert der inne. Et st&oslash;rre, mer grunnleggende fellesskap, et g&aring;tefullt medium som Jung kalte det felles ubevisste. </span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Tidligere tiders </span><em><span style=\"font-weight: 400;\">genies</span></em><span style=\"font-weight: 400;\"> ser jeg for meg som personifikasjoner av dette mediet. Der inne danser de rundt til tonene av en sf&aelig;renes musikk, herfra kommer de dundrende til Ruth Stone s&aring; jorden skjelver. Dette g&aring;tefulle mediet ser jeg for meg som et b&oslash;lgende kraftfelt, skapt av alle &ndash; n&aring;levende og historiske &ndash; menneskers tanker og gjerninger. Vi er knyttet sammen i dette mediet som perler i himmelguden Indras grensel&oslash;se nettverk. <br /><br /><strong>Hver enkelt perle speiler alle andre, r&oslash;rer du &eacute;n r&oslash;rer du alle.</strong><br /><br /><em><strong><a href=\"http://www.petterfergestad.no/#produkt\">Petter Fergestads b&oslash;ker finner du her.&nbsp;</a></strong><br /><br />Gikk du glipp av Petters forrige blogginnlegg hos oss? <strong><a href=\"https://www.forfatterskolen.no/blog/4\">Det finner du her!</a></strong></em></span></span></p>','/storage/blog/1539885264.jpeg','Silje Reistad','',1,NULL,'2018-10-18 17:44:37','2018-10-18 20:14:27'),(11,1346,'10 tips for deg som vil komme gjennom hos forlagene','<p class=\"p1\"><span style=\"font-size: 12pt;\"><strong>Av: Rektor og forfatter Kristine Storli Henningsen<br /><br /><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/bloggkristine2.jpg\" alt=\"\" width=\"810\" height=\"450\" /></strong></span><span class=\"s2\" style=\"font-size: 12pt;\"><br />Tenk om jeg hadde hatt en trylleformel for hvordan du skulle bli en antatt forfatter? Det har jeg dessverre ikke. Men jeg har noen stalltips som &oslash;ker muligheten din for &aring; komme gjennom hos forlagene. For det er det du dr&oslash;mmer om, ikke sant? &Aring; dele fortellingen din med hele verden, berike og ber&oslash;re. </span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">R&aring;dene er basert p&aring; egne erfaringer, veien fra refusert og motl&oslash;s til antatt forfatter med 27 b&oslash;ker p&aring; samvittigheten. Jeg deler ogs&aring; tips som jeg &aelig;rlig og redelig har rappet fra et knippe suksessforfattere, redakt&oslash;rer og dramaturger. Som nybakt forlegger vet jeg ogs&aring; selv hva jeg ser etter i et manus. Hva m&aring; et manus inneholde for &aring; v&aelig;re godt og salgbart, og hva &oslash;ker sjansen for &aring; f&aring; det antatt?</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>1. G&aring; p&aring; jakt etter din unike skrivestemme</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">Du m&aring; gjerne la deg inspirere av store og anerkjente forfattere. Men for &aring; finne din unike stemme, er det lurere &aring; lete innover enn utover. Mange tror de ikke har en unik skrivestemme. Men alle har en, i st&oslash;rre eller mindre grad. Det er bare s&aring; vanskelig &aring; se det selv. Jo mer du klarer &aring; g&aring; innover i deg selv, lag for lag, og skrive intuitivt &ndash; jo mer vil du f&aring; kontakt med din unike stemme. Dette er en treningssak &ndash; s&aring; skriv mye og fors&oslash;k &aring; holde indre kritiker p&aring; avstand. Kanskje trenger du stillhet, kanskje trenger du musikk, kanskje trenger du noe helt annet &ndash; for &aring; komme inn i en tilstand som bringer deg n&aelig;rmere din egen stemme. Og de er dette forlagene ser etter &ndash; den unike stemmen. Det meste er skrevet f&oslash;r, tenk p&aring; hvor mange b&oslash;ker det finnes om kj&aelig;rlighet. Det er likevel alltid rom for flere, med nye stemmer og vinklinger.</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>2. Fake it till you make it</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">For &aring; fenge leseren, og gj&oslash;re fortellingen troverdig, m&aring; du skrive med autoritet. Du skal leie leseren fra f&oslash;rste til siste side, med en overbevisning om at dette er en god reise. For &aring; skrive med autoritet er det viktig &aring; ha skriveselvtillit. Dette er enklere sagt enn gjort &ndash; indre sabot&oslash;r kommer ofte inn og stikker kjepper i skrivehjulene. Mitt beste r&aring;d: Fake it till you make it. Innbill deg selv at dette blir verdens beste bok. Da kommer du mye lengre enn hvis du sitter og snakker deg selv ned. Og sjansen er st&oslash;rre for at du holder koken hele veien inn til m&aring;l (for det blir jo verdens beste bok!). F&oslash;rst n&aring;r du er i m&aring;l med kladden, kan du hente frem indre kritiker &ndash; se p&aring; teksten med et strengt blikk og starte redigeringsprosessen.</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>3. Les d&aring;rlige b&oslash;ker og uferdige tekster</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">Det er lurt &aring; lese mye for &aring; utvikle seg som forfatter &ndash; ja. Men det er ogs&aring; lett &aring; miste selvtilliten av &aring; lese mange gode b&oslash;ker. Hvordan i all verden skal du kunne konkurrere med dette? Men husk at en ferdig bok er en redigert bok. Den har v&aelig;rt gjennom utallige runde med redakt&oslash;rer og spr&aring;kvaskere og korrekturleseren. Ved &aring; lese uferdige tekster, og se &laquo;feil&raquo; og utviklingspotensial, er det lettere &aring; se hvordan du kan jobbe med din egen. Les gjerne d&aring;rlige b&oslash;ker fra tid til annen ogs&aring; (&laquo;Herlighet, dette kan jeg gj&oslash;re mye bedre! Alts&aring;, hvis <em>denne</em> boka ble antatt &hellip;&raquo;)</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>4. Streb etter det originale</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">Forlagene ser etter den originale skrivestemmen. Den originale fortellingen. Den originale vinklingen. Det originale spr&aring;ket. Minst en av disse komponentene b&oslash;r v&aelig;re p&aring; plass, ellers blir boken din bare en blek kopi av noe annet. Leserne ser etter det som er nytt og annerledes, det som p&aring; godt norsk heter &aring; <em>stand out in the crowd</em>. Dermed er det dette som er salgbart for forlagene. Tilstreb alltid det originale &ndash; finn inn til din unike stemme, fortell det som er viktig for akkurat deg &aring; fortelle, jobb med metaforer (dette tar tid!) fremfor &aring; bruke enkle klisjeer, og lek deg med nye m&aring;ter &aring; fortelle en historie p&aring;. Kanskje skal du begynne med slutten? Er det katten som blir hovedpersonen? Skal du skrive p&aring; dialekt? Legge fortellingen til et helt annet sted? Eksperimenter deg frem.</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>5. De fire H-ene</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\"><span style=\"font-size: 12pt;\">P&aring; Forfatterskolen stiller vi elevene f&oslash;lgende sp&oslash;rsm&aring;l: <em>Hva</em> vil du skrive, <em>hvorfor</em> vil du skrive det, til <em>hvem</em> vil du skrive det for og <em>hvordan </em>skal du skrive det. Ved &aring; lage noen setninger om dette blir alt klarere for deg selv. Du har et navigasjonspunkt mens du skriver, du har en dr&oslash;mmeleser foran deg (som kan ta plassen til &laquo;den strenge professoren&raquo;), og du har et klart budskap. For at redakt&oslash;ren &ndash;og fremtidige lesere &ndash; skal oppleve boken din som viktig, m&aring; du ha et budskap. Hvorfor skriver du dette &ndash; hva vil du leseren skal f&oslash;le og l&aelig;re? Dette er ogs&aring; med p&aring; &aring; skape undertekst &ndash; alt som st&aring;r mellom linjene, som kan tolkes av leseren og skape engasjement.</span> </span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>6. Start med et brak!</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">Redakt&oslash;ren vil bli forf&oslash;rt med en gang hun leser manuset ditt &ndash; hekta! Det hjelper ikke at manuset begynner &aring; bli bra p&aring; side 70, da har hun ramlet av for lengst. Du konkurrerer med mange andre forfatterspirer, i bunken av papirer p&aring; redakt&oslash;rens pult. Som regel leser hun litt i starten, litt p&aring; slutten og litt midt i. De 20 f&oslash;rste sidene av en tekst er viktigst, og de fire f&oslash;rste er aller viktigst. Start med et smell, enten det er en dramatisk scene, en fengende karakter, en spennende milj&oslash;beskrivelse, hva som helst som pirrer nysgjerrigheten og f&aring;r henne til &aring; bla videre til neste ark. Og neste. Og neste &hellip; </span></p>\r\n<p class=\"p3\"><span class=\"s2\"><strong><span style=\"font-size: 14pt;\">7. G&aring; mange runder</span> </strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">Som sagt har du mange<span class=\"Apple-converted-space\">&nbsp; </span>konkurrenter p&aring; redakt&oslash;rens pult. Hvis du bare har sendt inn en id&eacute; som du har bygget l&oslash;st videre p&aring;, er sjansen stor for at du taper mot en som har gjort en grundigere jobb. Skriv gjerne gjennom manuset fire ganger f&oslash;r du sender inn: En kladderunde, en runde der du grovredigerer deg selv, en gang du finredigerer og en siste pirkerunde. Ta gjerne en pause mellom rundene, s&aring; du ser manuset med friske &oslash;yne hver gang.</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>8. Bruk gode pilotlesere</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">Det er lett &aring; bli blind p&aring; egen tekst. Derfor er det lurt &aring; bruke et par gode pilotlesere f&oslash;r du sender inn til forlag. Bruk noen som er gode p&aring; &aring; vurdere tekst, og som t&oslash;r &aring; gi deg en &aelig;rlig tilbakemelding, samtidig som de trekker frem det som er bra. Gi gjerne pilotleseren et skjema, s&aring; tilbakemeldingen blir s&aring; konkret som mulig. Hvor faller hun av? Hvilke partier synes han er spesielt spennende eller godt skrevet? Er dialogene levende og troverdige? Kommer hun under huden p&aring; hovedpersonen? Sitter starten? Er slutten logisk? Hvordan er spr&aring;ket, flyten, metaforene?</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>9. Ikke unnskyld manuset ditt</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 12pt;\">Ikke bruk tid p&aring; &aring; unnskylde manuset ditt overfor forlaget. Da jobber du heller med det til du synes det er godt nok. Du trenger heller ikke fortelle hele livshistorien din til redakt&oslash;ren, eller beskrive fortellingen i detalj. Fortell kort og komprimert om deg selv, hva slags ambisjoner du har med fortellingen, og skriv et lite sammendrag om hva fortellingen handler om. S&aring; vil fortellingen selge seg selv, hvis den er god nok.</span></p>\r\n<p class=\"p3\"><span class=\"s2\" style=\"font-size: 14pt;\"><strong>10. Reis deg etter refusjonen &ndash; hver eneste gang</strong></span></p>\r\n<p class=\"p3\"><span class=\"s2\"><span style=\"font-size: 12pt;\">&hellip; for ja, de vil trolig komme. Akkurat som de gjorde flere titalls ganger for Sigrid Undset, Levi Henriksen, Knut Hamsun, J.K. Rowlings, Stephen King. Den som gir seg er en lort. Den som ikke gir seg, kan f&aring; oppfylt forfatterdr&oslash;mmen. Og du? Det er slett ikke sikkert fortellingen din er d&aring;rlig selv om den ikke g&aring;r gjennom. Kanskje har de en forfatter med en lignende fortelling. Kanskje passer ikke manuset ditt inn i deres utgivelsesplaner. Og sp&oslash;r gjerne om hvorfor du ble refusert &ndash; det har du ingenting &aring; tape p&aring;. Snarere tvert i mot, du kan l&aelig;re av refusjonen. Eller vite at du var n&aelig;r p&aring; &aring; bli antatt. Og har du f&aring;tt en konsulentuttalelse, er det bare &aring; juble. Det betyr at du har utmerket deg i manusbunken, og at de derfor har sendt manuset til en ekstern konsulent for vurdering. <br /><br />Da er det ingen grunn til &aring; gi seg &ndash; du har talent og fortellingen din har potensial. Fortsett &aring; skrive!</span><br /></span></p>\r\n<div class=\"clearfix _o46 _3erg _29_7 direction_ltr text_align_ltr _ylc\">\r\n<div id=\"js_6z\" class=\"_5z-5 _3058 _ui9 _hh7 _s1- _52mr _3oh-\" data-tooltip-content=\"22:24\" data-hover=\"tooltip\" data-tooltip-position=\"left\">\r\n<div class=\"_4kf7 preview\">\r\n<div class=\"_aou _aov\">&nbsp;</div>\r\n</div>\r\n</div>\r\n</div>\r\n<div class=\"clearfix _o46 _3erg _29_7 direction_ltr text_align_ltr\">\r\n<div id=\"js_69\" class=\"_3058 _ui9 _hh7 _s1- _52mr _3oh-\" data-tooltip-content=\"22:24\" data-hover=\"tooltip\" data-tooltip-position=\"left\">\r\n<div class=\"_aok\" tabindex=\"0\" aria-label=\"Den har tidligere v&aelig;rt p&aring; trykk i Stemmer, ubetalt, s&aring; jeg menr vi kan bruke denigjen\"><em><span class=\"_3oh- _58nk\">Teksten har tidligere v&aelig;rt p&aring; trykk i Stemmer.<br /><br /></span></em></div>\r\n</div>\r\n</div>','/storage/blog/1540499902.jpeg','Kristine Storli Henningsen','/storage/blog/author/1540499902.jpeg',1,NULL,'2018-10-25 20:38:22','2018-10-25 20:59:20'),(12,1346,'Ikke skriv om noe du vet …','<p style=\"text-align: center;\"><em>Av: Romanserieforfatter Ida S. Skjelbakken</em><br /><br /><img src=\"/laravel-filemanager/photos/shares/Ida Skjelbakken-23.jpg\" width=\"690\" height=\"421\" /></p>\r\n<p class=\"p3\"><span class=\"s1\" style=\"font-size: 12pt;\"><strong><br />Skriv om noe du vet, noe du kan, sies det.</strong> Nei, nei &ndash; skriv om noe du <em>vil</em> vite! Som, for eksempel, romanserieforfatter skal det godt gj&oslash;res at man faktisk <em>vet</em> hvordan det er &aring; jobbe p&aring; en fyrstikkfabrikk i 1863, v&aelig;re skjoldm&oslash;y i 901 eller storg&aring;rdsdatter i 1716. Eller prostituert i Kristianias slumstr&oslash;k i 1891, slik jeg skriver om i den nye serien min, <em>Nattergalen</em>, som akkurat har kommet ut.<br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\"><strong>Jeg visste lite eller ingenting</strong> om livet i 1800-tallets m&oslash;rke underverden. Om bondefangere, h&oslash;kere, surrere og fillepellere. Men <em>oi!</em> s&aring; lyst jeg fikk til &aring; finne ut mer da jeg begynte &aring; gj&oslash;re research! Ideen til milj&oslash;et jeg skriver om n&aring;, ble f&oslash;dt da jeg h&oslash;rte om den mytiske Abelone Kristensen, bordellinnhaver p&aring; det som etter hvert ble kalt &rdquo;Abelones morderr&oslash;nne&rdquo; i gamle Vaterland. Jeg mener, hvordan kan man ikke bli inspirert av slikt! En karakter, basert p&aring; Abelone, prikket meg straks p&aring; skulderen.<br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\">Med andre ord, finn deg dine &rdquo;teltstenger&rdquo;, steder eller ting du vil ha med i boken, som du kan &rdquo;spenne opp teltduken&rdquo; &ndash; historien &ndash;<span class=\"Apple-converted-space\">&nbsp; </span>din med.<br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\"><strong>En av de tingene jeg liker best</strong> ved &aring; skrive serier, er at man kan boltre seg noe helt vanvittig med universet man skaper. For i hvilken annen sjanger har man samme mulighet til &aring; virkelig vise karakterenes utvikling? Slynge ut s&aring; mange tr&aring;der, og vite at man ikke beh&oslash;ver &aring; n&oslash;ste opp alle i l&oslash;pet av noen kapitler? Eller boltre seg slik med research. <img src=\"/laravel-filemanager/photos/Nattergalen1.jpg\" alt=\"\" width=\"50\" height=\"50\" /></span></p>\r\n<p class=\"p3\"><span class=\"s1\" style=\"font-size: 12pt;\"><strong>&Aring;h, s&aring; mye nytt jeg l&aelig;rte</strong> da jeg skrev p&aring; den forrige serien min! Visste dere for eksempel at man p&aring; 1700-tallet trodde man kunne redde folk som hadde druknet ved &aring; bl&aring;se r&oslash;yk opp i endetarmen deres? Eller at det i England var en kvinne som ble ber&oslash;mt for &aring; f&oslash;de kaniner? Hele 17 stykker! Eller at &aring;rsaken til hysteri kunne v&aelig;re at livmoren hadde l&oslash;snet og vandret rundt i kroppen? <br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\"><strong>Research inneb&aelig;rer ikke bare</strong> &aring; g&aring; seg vill i Internetts krattskog av informasjon, eller plage livet av historieprofessorer. Det kan ofte v&aelig;re nyttig &aring; reise til steder. Selv kjenne lukten i en tj&aelig;rebredd t&oslash;mmerkoie en sommernatt, h&oslash;re klangen i et sakristi, eller telle hvor mange skritt det faktisk er fra festningsmuren til krutt&aring;rnet. Ta med deg diktafon, notatbok, fotoapparat og videokamera. Men beveg deg f&oslash;rst omkring uten. Opplev stedet som karakteren din, uten tanke p&aring; notatene. <br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\"><strong>Det &aring; ro en hel bok i land,</strong> for ikke &aring; snakke om en hel romanserie, krever som regel mange &aring;r med intenst, hardt arbeid. Svette og t&aring;rer og utallige frustrasjoner. Men hvis du skriver om noe du vil vite, har du en motor hjelper deg i havn.<br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\">Du beh&oslash;ver slett ikke ha gjort all research ferdig f&oslash;r du begynner &aring; skrive. Gj&oslash;r nok til &aring; vite hvilket milj&oslash; du vil plassere karakterene dine i, og s&aring; tar du resten etter hvert som behovet dukker opp. <br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\"><strong>Hvis jeg er i den etterlengtede</strong> (og sjeldne) skriveflyten, bryter jeg ikke av for &aring; begi meg ut i Internettkrattet. I stedet skriver jeg XXXXX, markerer teksten i r&oslash;dt, eller legger inn en kommentar til meg selv. S&aring; finner jeg senere ut om den lille fontenen ved lysthuset p&aring; Oscarshall hadde bronseliljer i 1891, hva en avis kostet, og hva symptomene er p&aring; syfilis. <br /><br /></span><span class=\"s1\" style=\"font-size: 12pt;\"><strong>Det er nok mange som antar</strong> at man m&aring; f&oslash;lge en streng sjangermal som romanserieforfatter, men tvert imot. Det er som &aring; v&aelig;re thrillerforfatter, krimforfatter, romantikkforfatter, erotikkforfatter og historiebokforfatter, alt i ett! Man m&aring; t&aring;le &aring; leve med et enormt press 365 dager i &aring;ret, &aring;r etter &aring;r. Brekker du armene skriver du med t&aelig;rne, for levere m&aring; du &ndash; minimum seks b&oslash;ker i &aring;ret. Men til gjengjeld s&aring; f&aring;r du s&aring; mye mer igjen enn bare et levebr&oslash;d.<br /><br /></span></p>\r\n<p class=\"p3\"><em><span class=\"s1\" style=\"font-size: 12pt;\">Nysgjerrig p&aring; Idas nye romanserie? Mer info om <strong><a href=\"https://www.bladkompaniet.no/Nattergalen,-abonnement/I9788233405847\">Nattergalen her.&nbsp;</a></strong></span></em></p>','/storage/blog/1541698791.jpeg','Ida S. Skjelbakken','/storage/blog/author/1541698791.jpeg',1,NULL,'2018-11-09 00:39:51','2018-11-09 01:29:22'),(13,1346,'Hvordan synes i sosiale medier?','<p style=\"text-align: center;\"><span style=\"font-weight: 400; font-size: 12pt;\">Av: Sosiale medier-ansvarlig Silje Reistad<br /><br /><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/SoMetekst.jpg\" alt=\"\" width=\"757\" height=\"450\" /></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Enten du er utgitt forfatter, selvpublisert eller bare &oslash;nsker &aring; dele dikt eller utdrag av tekstene dine - sosiale medier er et smart sted &aring; vise frem arbeidet sitt. Men hvordan tar man de f&oslash;rste stegene for &aring; dele, og hvordan synes man i mylderet av alle profiler? &nbsp;</span></p>\r\n<p><span style=\"font-size: 12pt;\"><strong>HVOR?</strong><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\">Facebook, Twitter, Instagram og Snapchat er noen av de st&oslash;rste sosiale medier-plattformene. For tekst vil jeg t&oslash;rre &aring; p&aring;st&aring; at Instagram er det beste stedet for &aring; dele, i tillegg til Facebook hvor man har muligheten til &aring; dele i grupper. Facebook-grupper er gull. Man har mulighet til &aring; vise seg frem, bygge et lite samfunn hvor man deler sammen, og andre kan bli glad i din unike skrivem&aring;te. Se for deg at du har delt sm&aring; tekster i lang tid, kanskje flere &aring;r, og en vakker dag deler du nyheten om at du skal utgi bok - hvem tror du er de f&oslash;rste som tropper opp p&aring; bokhandelen? Jeg tror nok mange av disse er fra skriveforumet. Du st&oslash;tter dem, de st&oslash;tter deg. Dere deler - sammen.</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\">Grunnen til at jeg ogs&aring; mener Instagram er et bra sted &aring; dele tekst, er at det kan deles som bilder, og bryte opp litt med hva vi vanligvis ser i Instagram-feeden v&aring;r. Se p&aring; Instagramprofilen til <a href=\"https://www.instagram.com/trygveskaug/\">@trygveskaug</a> for inspirasjon. </span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Det viktigste er at du finner en plattform som passer deg. Gjerne g&aring; for begge!&nbsp;</span></p>\r\n<p><span style=\"font-size: 12pt;\"><strong>&Aring; DELE</strong><strong><br /></strong><span style=\"font-weight: 400;\">Tibake til Trygve Skaug sin Instagram-profil. Det g&aring;r nesten ikke &eacute;n dag uten at jeg ser </span><em><span style=\"font-weight: 400;\">andre </span></em><span style=\"font-weight: 400;\">dele hans tekster p&aring; Instagram. Det deles som innlegg, eller p&aring; &ldquo;Stories&rdquo;. Du kan ogs&aring; f&aring; tak i kopper og T-skjorter med Skaug sine tekster p&aring;, som folk ogs&aring; deler bilder av.</span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Og hvorfor deler andre det han skriver? For det f&oslash;rste er han sjeldent god med ord, det m&aring; nevnes. Men ogs&aring; fordi Trygve </span><em><span style=\"font-weight: 400;\">har delt f&oslash;rst.</span></em><span style=\"font-weight: 400;\"> Han har &aring;pnet seg, han t&oslash;r &aring; dele. Han har bestemt seg for &aring; dele tekster jevnlig p&aring; Instagram, slik at de som f&oslash;lger ham vet hva de f&aring;r, og hele tiden f&aring;r noe nytt. Det &aring; t&oslash;rre &aring; dele tekster er kneik &aring; komme over for de fleste av oss. For det kan v&aelig;re skikkelig skummelt.&nbsp;</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\">Gj&oslash;r det mulig for andre &aring; dele det du skriver (dersom du &oslash;nsker &aring; n&aring; ut til mange), ved &aring; ha en &aring;pen profil og sjekke under Innstillinger at du har gjort det mulig for andre &aring; dele tekst-bildene dine. Det kan v&aelig;re mange der ute som kan bli ber&oslash;rt av akkurat din tekst, og som f&aring;r lyst til &aring; dele det med sine f&oslash;lgere.</span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><br /></span><strong>HVORDAN SYNES?</strong><strong><br /></strong><span style=\"font-weight: 400;\">For &aring; synes i sosiale medier m&aring; du s&aring; klart gjennom stegene 1) T&oslash;rre &aring; dele 2) Gjerne ha en &aring;pen profil, slik at folk ser hva du deler f&oslash;r de f&oslash;lger deg.<br /><br />Synes du det skjer lite rundt deg og bokutgivelsen din, eller tekstene du deler? Skap noe. Lag et event i n&aelig;rmilj&oslash;et slik at folk ser at du finnes - og at du skriver. Del dette med alle lokalaviser, blogger eller influencere du tror kunne ha interesse av &aring; komme p&aring; eventet ditt. Skap blest rundt arbeidet ditt, om du ikke har et forlag som gj&oslash;r det.&nbsp;</span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><br /></span><strong>HOLD FOKUS<br /></strong>Ikke bli opphengt i f&oslash;lgerantall eller sammenligne deg med andre. Sistnevnte kan du gj&oslash;re om det motiverer deg - men kun da. Hold fokuset ditt, om du har bestemt deg for &aring; dele tekstbilder for eksempel. &Aring; ha en nisje er lurt, da er sannsynligheten st&oslash;rre for at du f&aring;r en dedikert f&oslash;lgerskare. Engasjer deg i andre profiler med samme fokus som deg, da f&aring;r man ofte st&oslash;tte tilbake.<br /><br />Om du har bestemt deg for at du vil dele arbeidet ditt i sosiale medier, er det viktig med selvtillit til eget arbeid. Hvis ikke er det vanskelig &aring; trykke&nbsp;<em>publiser.&nbsp;</em>Alle skribenter vet at skriveselvtilliten kommer og g&aring;r, men finn et fellesskap hvor du kan f&aring; st&oslash;tte. Kanskje du kan teste tekstene i Facebookgruppa f&oslash;r du deler p&aring; Instagram eller andre steder?&nbsp;<br /><br />Husk at du skriver for en grunn. Du har noe p&aring; hjertet, noe som m&aring; ut. Om det er p&aring; sosiale medier, i en bok, eller i en dagbok for deg selv, er det bare <em>du</em> som vet. Og vet du ikke enn&aring;, s&aring; er vi i Forfatterskolen her for &aring; skape et trygt sted for deg &aring; dele. Vi heier p&aring; <em>akkurat deg</em>!</span></p>\r\n<p><span style=\"font-size: 12pt;\">- Silje<br /><br /><em><a href=\"https://www.forfatterskolen.no/workshop\">Klikk for info: Bli med p&aring; v&aring;re neste workshoper i Oslo, Arendal, Bergen og Bod&oslash;!</a></em></span></p>','/storage/blog/1542311183.jpeg','Silje Reistad',NULL,1,NULL,'2018-11-16 02:46:23','2018-11-16 03:15:48'),(14,1346,'Om å leve drømmen','<p style=\"text-align: center;\">Av: Barnebokforfatter Karin Moe Hennie, tidligere elev ved Forfatterskolen<br /><br /><img src=\"/laravel-filemanager/photos/shares/Karin-blogg4.jpg\" alt=\"\" width=\"5486\" height=\"3561\" /></p>\r\n<p><span style=\"font-weight: 400;\"><span style=\"font-size: 12pt;\"><em><span style=\"font-size: 8pt;\">Foto: Nina Nordb&oslash;</span></em><br /><br />\"I dag har jeg danset en bok for dere\", forteller jeg barna etter forfatterbes&oslash;k med \"Dingle som en kringle\". Barna kikker rart p&aring; meg. De har da ikke sett meg &aring;pne en bok. Men s&aring; tar jeg fram boken min. Den har st&aring;tt der hele tiden, men jeg har ikke r&oslash;rt den. Jeg &aring;pner den og leser litt av teksten. Da g&aring;r det opp for barna at jeg innimellom dansetrinnene med skjelettet &Aring;smund, hadde fortalt en historie de kunne kjenne igjen i ordene jeg n&aring; leste.</span> </span><span style=\"font-weight: 400;\"><br /><br /></span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Min f&oslash;rste bok</strong></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Jeg skrev min f&oslash;rste bok da jeg gikk i femte klasse. &nbsp;Da tok jeg to A4 ark og stiftet de sammen. P&aring; de blanke arkene skrev jeg mitt f&oslash;rste eventyr. Jeg ga boken til l&aelig;reren min, Svein. Svein kunne ha lest den kjapt for s&aring; &aring; bare legge den til siden. I stedet satt han seg ned sammen med meg. Han fortalte meg at jeg kunne bli akkurat det jeg ville. At jeg en dag kunne bli en ekte forfatter om jeg &oslash;nsket det.</span><span style=\"font-weight: 400;\"><br /><br /></span></span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Livet tok en ny retning</strong></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Jeg begynte &aring; danse ballett da jeg var fem &aring;r. Dansen kom f&oslash;r skrivingen, og det var ikke plass til de begge i travle ungdoms&aring;r. &nbsp;Jeg tok fatt p&aring; tre &aring;r ved Statens balletth&oslash;gskole, og hadde mer enn nok med &aring; pleie mine s&aring;re dansef&oslash;tter.</span><span style=\"font-weight: 400;\"><br /><br /></span><span style=\"font-weight: 400;\">Det var f&oslash;rst da jeg satt meg ned med opptakspr&oslash;ven til Westerdals School Of Communications en del &aring;r senere, at jeg skj&oslash;nte hvor mye skrivingen egentlig betydde for meg. </span><span style=\"font-weight: 400;\"><br /></span></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Dermed tok livet mitt en ny retning. Skriving ble like viktig for meg som dansen. Kombinasjonen dans og tekst ble min greie, og det har betydd mer enn jeg noen gang kunne ha forestilt meg. </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">N&aring;r jeg skriver og lager forestillinger, tenker jeg alltid bok parallelt. N&aring;r jeg skriver en ny bok tenker jeg forestilling. Det har resultert i at jeg f&aring;r leve ut dr&oslash;mmen min. Jeg har to hobbyer og begge har blitt jobb. Jeg er n&aring; i en posisjon der jeg faktisk kan si nei til jobber jeg ikke har lyst til &aring; ta. Det er luksus, og jeg vet at jeg er heldig.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Jeg har fem ulike forestillinger som jeg i perioder reiser rundt med. Alle med utgangspunkt i mine id&eacute;er, skrevet av meg, koreografert av meg og formidlet av meg. Av disse fem forestillingene, tar tre utgangspunkt i barneb&oslash;ker jeg har skrevet. &nbsp;Noen ganger er jeg ute som danser/skuespiller i en sceneproduksjon, mens jeg andre ganger er ute p&aring; forfatterbes&oslash;k. Uansett hvilken rolle jeg har i klasserommet, s&aring; st&aring;r b&aring;de tekst og dans alltid sentralt. Jeg bruker min erfaring som danser og formidler n&aring;r jeg presenterer b&oslash;kene mine.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Det tok 15 &aring;r fra den dagen jeg sendte inn mitt f&oslash;rste manus til forlag, til boken faktisk kom i butikken. Jeg &nbsp;syntes selv at jeg hadde en genial id&eacute;. Hvorfor var det ingen andre som s&aring; det? Min nev&oslash; p&aring; 4 &aring;r hadde akkurat f&aring;tt p&aring;vist pollenallergi. Han kl&oslash;dde i &oslash;ynene og de ble r&oslash;de og hovne. Jeg hadde lyst til &aring; hjelpe, men hvordan forklare en 4-&aring;ringer hva pollen er? Jeg begynte &aring; skrive og skapte mitt eget pollenkorn. Jeg sendte pollenkornet ut p&aring; en spennende og strabasi&oslash;s reise i pollensesongen. Min hensikt var at barna skulle sitte igjen med en forst&aring;else av hva pollen og pollenallergi var, samtidig som de skulle f&aring; en viss sympati for Pollus. For han ville jo ingen noe vondt. Han ville bare finne seg en jenteblomst &aring; v&aelig;re sammen med.</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Refusjonshaggel</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Jeg sendte manus til diverse forlag, store og sm&aring;. Refusjonene haglet inn, og jeg skj&oslash;nte ingenting. Denne historien var jo genial. Jeg skrev om, jeg byttet m&aring;lgruppe mang en gang, jeg hentet inn illustrat&oslash;r, jeg kuttet tekst og s&aring; sendte jeg inn p&aring; ny. Det var ingen som s&aring; det jeg s&aring;. Dette gadd jeg ikke, s&aring; jeg ga pollenkornet mitt et liv p&aring; scenen i stedet. Jeg skrev en teater-/danseforestilling med pollenkorn, tissemaur, marih&oslash;ner og en to meter h&oslash;y nese i skumgummi. </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Barna gikk ut fra teateret &nbsp;med ny kunnskap. Jeg m&oslash;tte p&aring; barn som ropte etter Pollus i skogen, barna mine kikket etter Pollus p&aring; vannpytter og p&aring; frontruta p&aring; bilen v&aring;r. Jeg ble motivert til &aring; pr&oslash;ve meg p&aring; forlagene igjen. S&aring; etter 15 &aring;r var det et forlag som endelig s&aring; potensiale i pollenkornet mitt.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">N&aring; har jeg gitt ut tre barneb&oslash;ker. Jeg har gitt de ut p&aring; sm&aring; forlag, og de gj&oslash;r en ypperlig jobb for meg. De gir meg frihet til &aring; lage forestillinger av b&oslash;kene mine, og for meg er det viktig. </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Denne h&oslash;sten har jeg v&aelig;rt 10 uker p&aring; turn&eacute; i regi av Den kulturelle skolesekken og Den kulturelle b&aelig;remeisen. Jeg har ogs&aring; bes&oslash;kt kulturhus og bibliotek &nbsp;flere steder i landet. For meg finnes det ikke en mer givende jobb. Jeg m&oslash;ter nye grupper barn hver dag. Jeg m&oslash;ter ett&aring;ringer som slipper h&oslash;ylytte bleiefiser p&aring; de roligste partiene i forestillingen. Jeg m&oslash;ter f&oslash;rsteklassinger som gr&aring;ter n&aring;r jeg presenterer boken min &rdquo; Fra stor til liten&rdquo;. Som syns det er godt &aring; f&aring; satt ord p&aring; den t&oslash;ffe overgangen fra barnehage til skole. Jeg m&oslash;ter undrende barn som lurer p&aring; om skjelettet jeg har med meg i klasserommet har v&aelig;rt meg f&oslash;r. Eller har det kanskje v&aelig;rt Jesus? Jeg drikker lunken kaffe p&aring; l&aelig;rerv&aelig;relser, jeg danser i gymsaler der gradestokken viser 11 grader, jeg opplever at l&aelig;rere sitter og retter pr&oslash;ver mens jeg danser for barna. Jeg har blitt stoppet i politikontroll p&aring; E18 med skjelettet, &Aring;smund sittende i passasjersetet. Han hadde setebeltet p&aring;, og rosa fj&aelig;r p&aring; hodet. </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">En gang danset jeg for et publikum p&aring; 10 stk. &nbsp;Greit nok med et lite publikum, men ikke n&aring;r alle sover. Sykehjemmet hadde glemt at jeg skulle komme, s&aring; de hadde satt alle beboerne med beina h&oslash;yt og pleddet godt opp under haka. Det var tid for middagshvil! S&aring; der hoppet jeg rundt i mitt Can Can nummer i fullt kostyme til null respons. Det er 10 &aring;r siden, men jeg blir enda varm i kinnene av &aring; tenke p&aring; denne episoden. Jeg opplever mye rart, men jeg opplever mest fint. Jeg &nbsp;f&aring;r gj&oslash;re det g&oslash;yeste i hele verden. Jeg lever av &aring; danse, av &aring; skrive, av &aring; formidle historier, av &aring; m&oslash;te mennesker i alle aldre. </span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Stabeis</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Jeg har jobbet beinhardt for dette, og jeg har v&aelig;rt t&aring;lmodig. Jeg gj&oslash;r mye forskjellig, men alt bygger videre p&aring; det jeg allerede kan. At jeg n&aring; blir kontaktet for mentoroppdrag, er et resultat av erfaring og kunnskap jeg har tilegnet meg gjennom &aring;r &nbsp;med medgang og motgang. </span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Jeg er tidligere elev ved Forfatterskolen, og tiden jeg hadde der har hatt enorm betydning for meg. Det &aring; t&oslash;rre &aring; dele tekster, lese andres tekster og ikke minst det &aring; ta imot kritikk. Det er viktig det! Det aller viktigste var m&oslash;tene med forfatterspirer fra hele landet. &nbsp;</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>Historien om Svein</strong></span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">Da jeg fikk min f&oslash;rste bok i hendene, gikk tankene mine tilbake til Svein. Min kj&aelig;re barneskolel&aelig;rer som motiverte meg til &aring; skrive, og som s&oslash;rget for at jeg fikk en god mestringsf&oslash;lelse allerede i femte klasse . Det er ingen selvf&oslash;lge at dette skjer i norske skoler, og mange l&aelig;rer er nok ikke klar over hvor stor p&aring;virkningskraft de har p&aring; v&aring;re sm&aring;. Derfor forteller jeg historien om Svein i hvert et klasserom jeg kommer til. For &aring; minne alle p&aring; dette ansvaret.</span></p>\r\n<p><span style=\"font-weight: 400; font-size: 12pt;\">I dag skal jeg verken bes&oslash;ke barnehager eller skoler. Jeg har &rdquo; barnefri&rdquo; for f&oslash;rste gang p&aring; nesten en m&aring;ned. I dag skal jeg ha skrivedag. Jeg skal skrive p&aring; min nye barnebok, Ninjana, som kommer ut til v&aring;ren. </span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><strong>Skriv folkens. Bygg hard hud av refusjonene som kommer, og send inn p&aring; ny. En dag treffer dere blink!<br /></strong></span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><em>Karin&nbsp;</em><br /><br />Vil du f&oslash;lge Karin Moe Hennie p&aring; sosiale medier, finner du kanalene hennes her:<br /><a href=\"https://www.instagram.com/karinmoehennie/\">Instagram&nbsp;@karinmoehennie</a><br /><a href=\"https://www.facebook.com/K.M.Hennie/\">Facebook&nbsp;</a></span><a href=\"https://www.facebook.com/K.M.Hennie/\">K.M.Hennie</a></span></p>\r\n<div class=\"\"><span style=\"font-size: 12pt;\"><a class=\"\" href=\"http://www.kmhennie.no/\">www.kmhennie.no</a></span></div>\r\n<div class=\"\">&nbsp;</div>\r\n<div class=\"\"><span style=\"font-size: 12pt;\"><strong>Hennies barneb&oslash;ker:</strong></span><br /><span style=\"font-size: 12pt;\">Dingle som en kringle (Fortellerforlaget)</span></div>\r\n<div class=\"\"><span style=\"font-size: 12pt;\">Pollus- Den lille pollenplagen (Fortellerforlaget)</span></div>\r\n<div class=\"\"><span style=\"font-size: 12pt;\">Fra stor til liten (Abup forlag)</span></div>','/storage/blog/1543506948.jpeg','Karin Moe Hennie',NULL,1,NULL,'2018-11-29 22:55:48','2018-11-30 07:27:31'),(15,1346,'Suksessforfatterens beste skrivetips','<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><em>Blogginnlegg, &oslash;nskereprise fra 2014</em></span></p>\r\n<p><span style=\"font-size: 12pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/reprise2maja.jpg\" width=\"500\" height=\"288\" /><br /></span></p>\r\n<p style=\"text-align: left;\"><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><em style=\"font-size: 12pt;\">Forfatter og manusforfatter Maja Lunde har suksess med alt hun skriver. I 2011 vant hun Kosmoramas &laquo;pitchekonkurranse&raquo; med manus til dansefilmen Battle. I 2015 mottok hun Bokhandlerprisen for Bienes Historie, og i &aring;r fikk romanen Fabelprisen. Klart vi vil ha skrivetips fra henne!</em></span><span style=\"font-weight: 400;\"><br /><br /></span><strong><span style=\"font-size: 14pt;\">1. BLI KJENT MED KARAKTEREN DIN</span></strong><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\">Bruk tid p&aring; &aring; skape en levende karakter. Tenk at han/hun er et ekte menneske. Hvordan ser hun/han ut? Hvordan oppleves karakteren av andre? Hva er karakterens svake og sterke sider? Innerste redsler? Viktigste m&aring;l?<br /></span></span><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>2. FINN KARAKTERENS UFORL&Oslash;STE POTENSIAL<br /></strong></span><span style=\"font-weight: 400;\">Alle mennesker har feil og uforl&oslash;st potensial &ndash; derfor m&aring; ogs&aring; alle karakterer ha det. Hva trenger karakteren &aring; l&aelig;re om seg selv? Og hvordan vil eventuelt historien bringe karakteren n&aelig;rmere denne erkjennelsen? Det er slett ikke sikkert karakteren faktisk skal l&aelig;re noe, men forfatteren m&aring; likevel vite hva karakterens uforl&oslash;ste potensiale faktisk er. &nbsp;For slik blir karakteren din sannere.</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>3. LA KARAKTEREN TA VALG<br /></strong></span><span style=\"font-weight: 400;\">N&aring;r du har skapt karakteren din, la handlingen drives av at han eller hun tar valg. Gj&oslash;r karakteren aktiv. La karakteren skape handling, ikke omstendigheter.</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>4. OPPLEV &ndash; IKKE BESKRIV<br /></strong></span><span style=\"font-weight: 400;\">Tenk at alt som skjer skal oppleves gjennom hovedkarakteren din. Ikke bare beskriv handling, beskriv hvordan handlingen oppleves.</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>5. DISPONER STOFFET<br /></strong></span><span style=\"font-weight: 400;\">Begynnelse, midtdel, slutt. Hva er hva? Hvor starter historien din for alvor? Hva setter den i gang? Hva er midtpartiet? Og hvordan og hvorfor slutter den? Tenk fremdrift og spenningskurve. Tenk scener og vendepunkt som snur p&aring; handlingen. Fra positiv til negativ og tilbake igjen. Tenk samtidig at spenningen hele tiden skal stige.</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>6. FINN INSPIRASJON<br /></strong></span><span style=\"font-weight: 400;\">Hvis du setter deg ned og bare venter p&aring; den gode historien, kan det ta tid. V&aelig;r aktiv letende etter inspirasjon. Les, lytt, l&aelig;r. Og gj&oslash;r research. Gjennom research kan du f&aring; et vell av ideer. Levende bilder kan ogs&aring; v&aelig;re inspirerende. Hvis du &oslash;nsker &aring; skrive klassisk fortellende historier er det mye &aring; l&aelig;re av film. Se p&aring; oppbygging, tenk at du skal fors&oslash;ke &aring; skape samme type fremdrift. Se hvordan de enkelte scenene driver handlingen og alltid slutter med et sp&oslash;rsm&aring;l &ndash; hva skjer n&aring;?</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>7. DREP DARLINGS<br /></strong></span><span style=\"font-weight: 400;\">Skriv fort og mye &ndash; ikke sensurer deg selv. N&aring;r teksten er p&aring; plass m&aring; du redigere. Det inneb&aelig;rer alltid at noe m&aring; bort. Flotte setninger du er stolt av m&aring; strykes. S&aring;nn er det bare. F&oslash;les brutalt i begynnelsen, men blir lettere og lettere for hver gang.</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>8. VRI P&Aring; KLISJEENE<br /></strong></span><span style=\"font-weight: 400;\">Grunnen til at noe har blitt en klisj&eacute; er at det finnes en kjerne av sannhet i den. Men skriver vi en klisj&eacute; rett frem, blir den bare det, en klisj&eacute;. Ved &aring; vri p&aring; klisjeen kan du gj&oslash;re den til noe originalt. En kvinne som sier til en mann, rett frem, at hun elsker ham, har vi lest f&oslash;r. Hvordan kan hun si det p&aring; en m&aring;te som er helt ny? Kanskje sier hun ingenting? Kanskje gir hun ham noe eller gj&oslash;r en handling som viser det?</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>9. DISPONER TIDEN DIN<br /></strong></span><span style=\"font-weight: 400;\">Skriving er hardt arbeid. Mange gode prosjekter har d&oslash;dd av for mye surfing p&aring; nett eller plutselig fristende husarbeid. Sett deg m&aring;l. Skru av internett. Sjekk gjerne ut programvare som hjelper deg &aring; disponere tiden &ndash; for eksempel: http://anti-social.cc/</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-size: 14pt;\"><strong>10. FANTASER!<br /></strong></span><span style=\"font-weight: 400;\">&Aring; fortelle historier er dypt menneskelig og noe vi har drevet med til alle tider. De aller fleste av oss fyller hele barndommen med historiefortelling gjennom lek, &aring; fortelle er en grunnleggende menneskelig egenskap. Gode historier finnes overalt, mange av oss b&aelig;rer p&aring; hundrevis, bare vi t&oslash;r &aring; &aring;pne opp for dem. Ikke v&aelig;r redd for &aring; fantasere vilt og hemningsl&oslash;st. Bruk dine forestillingsevner, ikke bare dine evner til &aring; gjengi. V&aring;g &aring; skape en historie som er l&oslash;srevet fra ditt eget liv. Dine egne erfaringer vil likevel snike seg inn i stoffet og gj&oslash;re det sant. </span></span></p>\r\n<p><span style=\"font-size: 12pt;\"><span style=\"font-weight: 400;\">Og ikke minst: Ha det g&oslash;y mens du skriver. Le, gr&aring;t, lev med stoffet. Din skriveglede smitter over p&aring; det du skriver. Du har en enorm erfaringsbase i ditt eget liv. Bruk den, men sett den gjerne inn i en annen kontekst. Ikke v&aelig;r redd for &aring; fantasere vilt og hemningsl&oslash;st. V&aring;g &aring; skape en historie som er helt l&oslash;srevet fra ditt eget liv. Dine egne erfaringer vil likevel snike seg inn i stoffet og gj&oslash;re det sant.</span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><br /></span><span style=\"font-weight: 400;\"><strong>Ps.</strong> Vil du bli bedre kjent med Maja Lunde og hennes prosjekter? G&aring; inn p&aring; majalunde.com<br /><br /><em>Maja Lunde holdt webinar hos Forfatterskolen i h&oslash;st, 2018, og delte enda flere gode skrivetips. F&aring; tilgang p&aring; alle webinar-repriser (og kommende) <a href=\"https://www.forfatterskolen.no/course/17\">ved &aring; klikke her!&nbsp;</a></em></span></span></p>','/storage/blog/1544118573.jpeg','Maja Lunde',NULL,1,NULL,'2018-12-07 00:49:33','2019-01-24 20:31:59'),(16,1346,'Å skrive om sorgen: Fra idé til ferdig bok','<p class=\"p4\" style=\"text-align: center;\"><strong><span class=\"s1\" style=\"font-size: 14pt; color: #000000;\"><span style=\"font-size: 12pt;\">Gjesteinnlegg av: Wenche F. Spjelkavik<br /></span></span></strong><span style=\"font-size: 10pt;\"><em><img src=\"/laravel-filemanager/photos/shares/BLogg-4.jpg\" alt=\"\" width=\"620\" height=\"383\" /><br />Foto portrettbilde:&nbsp;Ellen Jarli</em></span></p>\r\n<p class=\"p4\"><span class=\"s1\" style=\"font-size: 14pt; color: #000000;\">Hvor skal jeg begynne?<span class=\"Apple-converted-space\">&nbsp;</span>Alt ble feil da Morten (24) d&oslash;de fra oss i en trafikkulykke i 2014. Verden falt sammen. &Aring; miste et barn er som &aring; miste seg selv. En psykolog sa til meg: &laquo;sorg er r&egrave;definering av fremtiden&raquo;. Han hadde rett. Hvilken fremtid? tenkte jeg.</span></p>\r\n<p class=\"p4\"><span style=\"font-size: 12pt;\"><strong><span class=\"s1\"> Dagene var sorte, men all kj&aelig;rligheten fra omgivelsene r&oslash;rte oss. Etter begravelsen sa eldstemann Trond: &ndash; Mamma, du m&aring; skrive om Morten. </span></strong></span></p>\r\n<p class=\"p4\"><span style=\"font-size: 12pt;\"><span class=\"s1\">Rune husbond var enig. Skrive har jeg alltid gjort, men det var f&oslash;rst i voksen alder jeg kastet meg p&aring; b&aring;de foredrag, kurs og skrivereiser. En stund var jeg usikker p&aring; om jeg skulle fortsette, men det var f&oslash;r min f&oslash;rste skrivereise til Italia. &Aring;ret var 2011 og vi bodde en uke i kloster. Nonnelivet kledte meg egentlig godt </span><span class=\"s2\">?</span><span class=\"s1\"> Jeg ble s&aring; overrumplet over den gode responsen p&aring; tekstene mine at jeg begynte &aring; skrive p&aring; en barnebok da jeg kom hjem. Men det gikk som det ofte g&aring;r n&aring;r tiden ikke strekker til og det hele ble liggende &laquo;i skrivebordsskuffen&raquo;. </span></span></p>\r\n<p class=\"p6\"><span style=\"font-size: 12pt;\"><strong><span class=\"s1\"><em>Mamma.. Du b&oslash;r i alle fall pr&oslash;ve.</em>&nbsp;Trond kikket alvorlig p&aring; meg. Skrive n&aring;? I&nbsp;denne situasjonen, midt i den verste sorgen? Jeg greide knapt &aring; ta vare p&aring; meg selv og hadde isolert meg fra omverden. Nei, dette var hverken tid eller sted for s&aring;nt. </span></strong></span></p>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">Men sp&oslash;rsm&aring;let hadde nok s&aring;dd noe i meg, for etter begravelsen gjorde jeg et fors&oslash;k. Jeg &oslash;ste ut f&oslash;lelsene ned p&aring; papiret. Hvem Morten var.. Hvor mye han betydde for oss..<span class=\"Apple-converted-space\">&nbsp;</span>Etter noen runder gav jeg opp. T&aring;rene ville ikke stoppe. S&aring;ret var for &aring;pent. Jeg hadde heller behov for &aring; lese om andre med lignende opplevelser. Noen som hadde g&aring;tt foran og kunne forklare mine reaksjoner og f&oslash;lelser. Det fantes enkelthistorier, men hjernen min greide ikke &aring; favne over en hel bok. Jeg s&oslash;kte en samling av historier &aring; sammenligne meg med. Det fant jeg ikke.</span></p>\r\n<h2 class=\"p3\"><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">IDEEN</span></strong></span></h2>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">Ett &aring;r senere meldte jeg meg p&aring; et ti ukers skj&oslash;nnlitter&aelig;rt kurs i regi av Forfatterskolen. Det skulle vise seg &aring; v&aelig;re et smart valg. I mellomtiden hadde jeg f&aring;tt innpass i en s&aring;kalt &laquo;mistet-gruppe&raquo; p&aring; Facebook, som bestod av hundrevis av mennesker hvor alle hadde alle mistet et &laquo;voksent&raquo; barn. Noe s&aring; grusomt, men for en befrielse. Vi delte det meste og forstod hverandre. Jeg skj&oslash;nte at &aring; dele historier var viktig og kunne v&aelig;re avgj&oslash;rende for mange av oss.<span class=\"Apple-converted-space\">&nbsp; </span></span></p>\r\n<p class=\"p6\"><span style=\"font-size: 12pt;\"><strong><span class=\"s1\">Da jeg startet kurset hos Kristine Storli Henningsen var konsentrasjonen d&aring;rlig, men jeg fullf&oslash;rte. Det ble en slags terapi. Et lite friminutt. N&aring; m&aring;tte jeg fokusere p&aring; skrivingen. For &aring; presse meg ut av isolasjonen reiste jeg til Forfatterskolens workshop i Drammen. Der m&oslash;tte jeg andre elever og opplevde flotte foredrag og gode samtaler. Spesielt husker jeg forfatter Mariann Youmans som fortalte at det var mulig &aring; sende inn en bokid&egrave; til et forlag. &ndash; Skriv en prosjektbeskrivelse av ideen din og send inn, sa hun. </span></strong></span></p>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">P&aring; flyet hjemover falt plutselig puslespillet p&aring; plass og jeg skj&oslash;nte hva jeg skulle gj&oslash;re. Selvf&oslash;lgelig. Hvorfor hadde jeg ikke tenkt p&aring; det? Jeg skulle jo skrive boken jeg selv hadde savnet siden Morten d&oslash;de. Vi skulle dele historier med hverandre. Sorg er fremdeles tabu. Vi m&aring; ha mer &aring;penhet om temaet som ber&oslash;rer alle. Da jeg delte ideen med familien ble de ogs&aring; begeistret.<span class=\"Apple-converted-space\">&nbsp; </span>Jeg kastet meg over pc&egrave;n og skrev<span class=\"Apple-converted-space\">&nbsp; </span>&laquo;Invitasjon til bokprosjekt&raquo; som jeg publiserte for mistet-gruppen p&aring; Facebook. Responsen var overveldende. Jeg var r&oslash;rt og full av takknemlighet.<span class=\"Apple-converted-space\">&nbsp; </span>Alle var positive og &oslash;nsket &aring; delta. </span></p>\r\n<p class=\"p6\"><strong><span class=\"s1\" style=\"font-size: 12pt;\">N&aring;r vi mister et barn blir det maktp&aring;liggende at navnet og minnet deres lever videre. Det var en stor drivkraft.<span class=\"Apple-converted-space\">&nbsp; </span>Men det ville bli t&oslash;ft.<span class=\"Apple-converted-space\">&nbsp; </span>Det viste seg at flere av dem ogs&aring; hadde savnet en slik bok. En stund lurte jeg p&aring; om jeg hadde tatt p&aring; meg for mye.<span class=\"Apple-converted-space\">&nbsp; </span>Hva om jeg m&aring;tte si nei til noen? Hvem skulle det v&aelig;re,<span class=\"Apple-converted-space\">&nbsp;</span>og hvorfor? Burde det v&aelig;re variasjoner i d&oslash;ds&aring;rsak? Heldigvis slapp jeg disse problemstillingene. Det viste seg at noen m&aring;tte melde pass &ndash; av forst&aring;elige grunner. Vi endte opp med tolv foreldre, inkludert meg selv. Min historie skulle ogs&aring; v&aelig;re med. Fortellingene dreide seg om sykdom, selvmord, forsvinning, ulykker og Ut&oslash;ya. Jeg foreslo ulike temaer vi burde innom, som budskapet, de f&oslash;rste dagene, begravelsen, mestring, s&oslash;sken, hjelpeapparat, parforhold, omgivelsene, tilbake i arbeid og NAV. Enkelte var skeptiske til egne skriveferdigheter, andre ikke. </span></strong></p>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">&ndash; Skriv som du tenker, sa jeg. &ndash;<span class=\"Apple-converted-space\">&nbsp;</span>Jeg ordner resten. Alle tekstene ville uansett m&aring;tte omskrives og bearbeides mye for at alt skulle smelte sammen til slutt. Det passet meg godt da jeg synes redigeringen er det beste i hele skriveprosessen. De skulle sende mail n&aring;r de var klar.&nbsp;</span></p>\r\n<h2 class=\"p3\"><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">PROSJEKTSKISSE</span></strong></span></h2>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">I mellomtiden husket jeg Mariann Youmans ord og skrev en prosjektskisse som jeg sendte til flere forlag. Arbeidstittelen var &laquo;En stol st&aring;r tom&raquo;. Etter 10 minutter kom det svar - fra et lite forlag - og det var positivt. I alle dager? S&aring; enkelt kan det ikke v&aelig;re, tenkte jeg. Det var det selvsagt ikke, men den hyggelige redakt&oslash;ren var blitt ber&oslash;rt av prosjektet p&aring; grunn av egne opplevelser og &oslash;nsket &aring; vite mer om fremdriften. De &oslash;nsket manus tilsendt og spurte samtidig hva de kunne gj&oslash;re for &aring; hjelpe til i prosessen. Men jeg hadde jo ikke noe ferdig manus. Bare prosjektskissen.</span></p>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\"> Etter &aring; ha mailet frem og tilbake en stund skj&oslash;nte jeg at de ikke &oslash;nsket &aring; g&aring; videre f&oslash;r jeg hadde skrevet ferdig manus. Forst&aring;elig nok. Selv om de var sv&aelig;rt hyggelige og im&oslash;tekommende sendte jeg aldri det ferdige manuset til dem etterp&aring;. Jeg vet &aelig;rlig talt ikke hvorfor. S&aring; kom avslagene fra de andre forlagene. </span></p>\r\n<p class=\"p6\"><span style=\"font-size: 12pt;\"><strong><span class=\"s1\">Alle var positive til b&aring;de ideen og viktigheten av tema, men oppmuntret meg til &aring; ferdigstille manus f&oslash;rst. I stedet for &aring; bli skuffet fikk jeg heller mer p&aring;gangsmot. Hjernen hadde forberedt seg p&aring; dette. Som debutant kunne de jo ikke vite om jeg var i stand til &aring; skrive eller fullf&oslash;re noe som helst. </span></strong></span></p>\r\n<h2><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">PROSESSEN</span></strong></span></h2>\r\n<p class=\"p7\"><span class=\"s1\" style=\"font-size: 12pt;\">Da historiene begynte &aring; komme startet den lange prosessen. En prosess som skulle ta to &aring;r og tre omskrivninger - f&oslash;r boken kom ut. Det viktigste for meg i denne fasen var &aring; beholde foreldrenes skrivestemme. Den m&aring;tte ikke forsvinne. I tillegg skulle jeg skrive min egen historie. Det meldte seg noen bekymringer. Hvordan skulle jeg disponere stoffet? Ville jeg ha flere m&aring;lgrupper?<span class=\"Apple-converted-space\">&nbsp; </span>Da var det viktig at b&aring;de spr&aring;k, faglig niv&aring; og innhold m&aring;tte treffe leserne med budskapet. Jeg ville f&oslash;rst og fremst skrive for andre i samme situasjon som meg, men &oslash;nsket i tillegg at hjelpeapparatet kunne ha nytte av en slik bok. For &aring; f&aring; til dette ble jeg r&aring;det &aring; skrive s&aring; n&oslash;kternt som mulig. </span></p>\r\n<p class=\"p7\"><span style=\"font-size: 12pt;\"><strong><span class=\"s1\">Da vi var flere i prosjektet var det viktig &aring; oppdatere foreldrene jevnlig om utviklingen. Innholdet var i tillegg s&aring; s&aring;rbart og intimt at jeg, i redsel for &aring; tr&aring;kke feil, muligvis sendte teksten tilbake for godkjenning i overkant mye. Vi hadde god relasjon til hverandre gjennom hele prosessen. Kommunikasjonen foregikk hovedsakelig p&aring; mail og Messenger.</span></strong></span></p>\r\n<p class=\"p7\"><span style=\"font-size: 12pt;\"><span class=\"s1\"> For ekstra tyngde &oslash;nsket jeg en fagperson med p&aring; laget. Den f&oslash;rste jeg tenkte p&aring; var psykolog Atle Dyregrov. Han startet Senter for Krisepsykiatri, har forfattet en rekke b&oslash;ker, artikler, og annet innenfor sitt fagomr&aring;de. Jeg sendte foresp&oslash;rsel og fikk positivt svar. Han ville skrive forordet i boken. For en gave. Det ble sendt ny oppdatering med beskjed om den gledelige nyheten. Da f&oslash;rsteutkastet var ferdig, og alle detaljene godkjent av de andre, lot jeg manuset hvile en stund. I mellomtiden begynte jeg &aring; bekymre meg p&aring; nytt. Hva om jeg ikke greide &aring; f&aring; boken utgitt? Et slikt prosjekt skaper selvsagt forventninger og jeg &oslash;nsket ikke &aring; skuffe dem. Eller barna vi mistet. Eller meg selv. Da sendte jeg fellesmelding med garanti til alle om at boken skulle utgis<span class=\"Apple-converted-space\">&nbsp; </span>&ndash; uansett hva som skjedde. Om forlagene ikke ville ha den ville jeg betale for selvpublisering. Jeg kjente stor lettelse etterp&aring;. Senere skulle det vise seg at jeg ikke hadde beh&oslash;vd &aring; bekymre meg. Da manuset hadde hvilt seg ferdig leste jeg gjennom p&aring; nytt. Det var tydelig at det hadde hatt godt av en pause. Her oste det feil, mangler og alskens uhyrligheter. Det var bare &aring; brette opp ermene. Jada, jeg er klar over at jeg skriver haugevis med klisjeer i dette blogginnlegget, men dere f&aring;r b&aelig;re over med meg. Der kom det en til</span><span class=\"s2\">?</span><span class=\"s1\"> Det viktigste er &aring; ikke gj&oslash;re det samme i et manus. OBS OBS. </span></span></p>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">N&aring; ble teksten kuttet, og kuttet igjen, f&oslash;r det hele ble redigert p&aring; nytt. Deretter ny godkjenning av foreldrene. I februar 2016 sendte jeg teksten til rektor Kristine p&aring; Forfatterskolen og spurte om hun kunne gi meg tilbakemelding. Hun var velvilligheten selv og ga uttrykk for at hun hadde stor tro p&aring; prosjektet. Hun gav gode utfyllende tilbakemeldinger og r&aring;d for prosessen videre. Dette var selvsagt gull verdt og ble viktig i det videre arbeidet.<span class=\"Apple-converted-space\">&nbsp; </span></span></p>\r\n<p class=\"p6\"><span style=\"font-size: 12pt;\"><strong><span class=\"s1\">I tillegg kunne jeg fortsette &aring; r&aring;df&oslash;re meg med henne om jeg &oslash;nsket det. Jeg er fremdeles medlem av Forfatterskolen som best&aring;r av et fantastisk team og et unikt skrivefelleskap. Uten denne fellesskapsf&oslash;lelsen i ryggen hadde jeg nok ikke greid &aring; fullf&oslash;re. Tusen takk Kristine! Dere ga meg tryggheten til &aring; fortsette. </span></strong></span></p>\r\n<h2 class=\"p3\"><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">SENDE TIL FORLAG</span></strong></span></h2>\r\n<p class=\"p6\"><strong><span class=\"s1\" style=\"font-size: 12pt;\">Tiden var kommet for &aring; sende manus til forlag. Jeg sendte bare til de tre store. Det manglet i alle fall ikke p&aring; ambisjoner. I tillegg sendte jeg teksten til Atle Dyregrov som skulle skrive forordet. Etter gjennomlesningen foreslo han &aring; videresende det hele til en redakt&oslash;r han kjente i Vigmostad &amp; Bj&oslash;rke, om det var greit for meg? Greit..? Det var overgreit. Tenk &aring; v&aelig;re s&aring; heldig. I mellomtiden kom det refusjon fra alle de tre store. </span></strong></p>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">Senere kom det avslag fra Vigmostad &amp; Bj&oslash;rke ogs&aring;, men sammen med refusjonen fulgte en lang fantastisk konsulentuttalelse. Den skulle vise seg &aring; bli avgj&oslash;rende for hele prosjektet. For en gave. N&aring; startet jeg helt p&aring; nytt og fulgte r&aring;dene slavisk. Samtidig kuttet jeg omtrent halve teksten. S&aring;, etter tredje omskriving, sendte jeg inn til flere forlag, inklusive Pax. Denne gangen droppet jeg de tre store. N&aring; var spenningen stor og skuffelsen enda st&oslash;rre da de f&oslash;rste refusjonene kom. </span></p>\r\n<h2 class=\"p3\"><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">ANTATT</span></strong></span></h2>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">For &aring; gi oss selv pusterom i hverdagen begynte Rune og jeg &aring; reise mer etter at vi mistet Morten. Det var november 2016. Vi satt p&aring; Gardermoen, p&aring; vei ut av landet, da mailen fra Pax forlag tikket inn p&aring; mobilen. Ett og et halvt &aring;r tidligere hadde jeg sendt dem prosjektskissen. Jeg husker jeg fikk mail fra en redakt&oslash;r som ville ta ideen opp p&aring; neste redaksjonsm&oslash;te, men det viste det seg at det kolliderte med et lignende kontraktfestet prosjekt. Likevel trodde de at en slik bok ville bli viktig, at den tenkte strukturen var god og at jeg ikke m&aring;tte gi meg f&oslash;r boken ble utgitt. De var s&aring; hyggelige. Dette var i august 2015. N&aring; hadde de f&aring;tt tilsendt det ferdige manuset og var begeistret. En fantastisk f&oslash;lelse. Men dette var bare f&oslash;rste skritt. </span></p>\r\n<p class=\"p6\"><strong><span class=\"s1\" style=\"font-size: 12pt;\">N&aring; fulgte en lang mailutveksling med sp&oslash;rsm&aring;l og svar. Manuset m&aring;tte gjennom flere forlagsm&oslash;ter f&oslash;r den endelige beskjeden kom. I slutten av desember 2016 fikk jeg gr&oslash;nt lys. Boka var antatt. Min gode redakt&oslash;r spurte samtidig om det var greit med bokutgivelse allerede i april? Kan dere gjette hva jeg svarte? Om det var greit? Halleluja. Jeg var lettet og glad p&aring; vegne av alle som var med i prosjektet. Dette hadde v&aelig;rt terapi. Selv om innholdet i historiene fra de flotte foreldrene var hjerteskj&aelig;rende, greide jeg &aring; holde fokuset p&aring; prosjektet. Noe som hjalp meg gjennom min egen sorgprosess. </span></strong></p>\r\n<h2 class=\"p3\"><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">FORLAGSAMARBEID</span></strong></span></h2>\r\n<p class=\"p6\"><span style=\"font-size: 12pt;\"><span class=\"s1\">N&aring; begynte samarbeidet med forlaget. F&oslash;rst var det spr&aring;kvask. Jeg ble overrasket da det kom mail fra redakt&oslash;ren med beskjed om at de sendte meg hele manus for gjennomlesning etter spr&aring;kvask, i stedet for ett og ett kapittel som var vanlig n&aring;r det er snakk om flere tekstsamlinger i samme bok. Endringene var s&aring; sm&aring; at det bare dreide seg om tegnsetting.<span class=\"Apple-converted-space\">&nbsp; </span>Tenk &aring; v&aelig;re s&aring; heldig. N&aring; fikk jeg bel&oslash;nning for &aring; ha gjennomarbeidet stoffet en rekke ganger. Etter spr&aring;kvask ble manuset sendt til ombrekking.</span> <span class=\"s1\">Det vil si at boka f&aring;r sin endelige grafiske utforming,</span> <span class=\"s1\">Forlagene har vanligvis et sett med maler for layout, som definerer skrifttype p&aring; br&oslash;dtekst og overskrifter, marger og andre visuelle uttrykk.</span> <span class=\"s1\">Min oppgave var &aring; p&aring;se at all tekst var kommet med og stod der den skulle.</span> <span class=\"s1\">P&aring; dette stadiet var det bare anledning til &aring; rette faktiske feil, for eksempel om noe var stavet feil, og ikke blitt rettet i spr&aring;kvasken. &Aring; se konturene av hvordan boken kom til &aring; se ut var veldig stas. </span></span></p>\r\n<p class=\"p6\"><strong><span class=\"s1\" style=\"font-size: 12pt;\">Etterp&aring; diskuterte vi omslag og baksidetekst. Jeg er glad vi endte opp med deres id&egrave; om bokomslag. En vakker forglemmegei med gr&oslash;nn bakgrunn. Vi elsket det. Forlaget foreslo ny tittel p&aring; boka. &laquo;&Aring; miste et barn&raquo;. Selvf&oslash;lgelig. Det enkle er ofte det beste og jeg kunne ikke v&aelig;rt mer forn&oslash;yd. S&aring; gikk boka i trykken. En liten panikkf&oslash;lelse meldte seg da jeg observerte at de hadde lanseringer b&aring;de titt og ofte. Ville de ha lansering?<span class=\"Apple-converted-space\">&nbsp; </span>Hadde det v&aelig;rt en annen type bok, en roman eller noe, ville det v&aelig;rt greit. Men &aring; p&aring; nytt begynne &aring; snakke om det vonde var mer enn jeg kunne t&aring;le. Jeg var sliten. Til min store lettelse ba redakt&oslash;ren meg kun p&aring; lunchm&oslash;te for &aring; presentere meg for resten av forlaget.<span class=\"Apple-converted-space\">&nbsp; &nbsp;</span></span></strong></p>\r\n<h2 class=\"p3\"><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">ETTER BOKUTGIVELSEN</span></strong></span></h2>\r\n<p class=\"p7\"><span class=\"s1\" style=\"font-size: 12pt;\">Da flyet landet p&aring; Gardermoen p&aring; vei til forlagsm&oslash;tet i slutten av mars, gikk jeg som vanlig innom Tanum bokhandel for &aring; titte p&aring; b&oslash;ker. Der &ndash; i bokhylla -<span class=\"Apple-converted-space\">&nbsp; </span>stod boka.<span class=\"Apple-converted-space\">&nbsp; </span>Men den skulle jo komme ut i april?<span class=\"Apple-converted-space\">&nbsp; </span>Rune og jeg hadde planlagt &aring; reise p&aring; hytta p&aring; utgivelsesdagen. Jeg var ikke forberedt p&aring; dette &ndash; eller det som skulle komme. Men jeg kj&oslash;pte boka og bladde i den for f&oslash;rste gang p&aring; flytoget inn til Oslo. En mektig opplevelse. </span></p>\r\n<p class=\"p6\"><strong><span class=\"s1\" style=\"font-size: 12pt;\">Under m&oslash;tet ringte God Morgen Norge og spurte om jeg kunne stille p&aring; sending f&oslash;rstkommende mandag. Jeg kjente meg utakknemlig da jeg feiget ut og takket nei. I stedet stilte to av de modige bidragsyterne og gjorde et flott intervju. Det har senere blitt mange intervjuer i ukeblad og aviser. Det g&aring;r fint n&aring;, men jeg var nok for naiv i forhold til mediafokuset i kj&oslash;lvannet av boken. Jeg er jo stolt og burde v&aelig;rt henrykt over oppmerksomheten. Fikk en l&aelig;repenge der alts&aring;. </span></strong></p>\r\n<h2 class=\"p3\"><span style=\"font-size: 18pt;\"><strong><span class=\"s1\">I DAG</span></strong></span></h2>\r\n<p class=\"p6\"><span class=\"s1\" style=\"font-size: 12pt;\">Jeg &oslash;nsker ikke &aring; tjene penger p&aring; sorgen min. I stedet g&aring;r bokinntektene til foreningen &laquo;Et barn for lite&raquo;. De har allerede f&aring;tt tilsendt royalty for 2017 og har &oslash;remerket pengene til en samling for foreldre som har mistet voksne barn. Det f&oslash;les godt. Jeg er ogs&aring; glad for at boken blir brukt i undervisning om sorg. Jeg griner og blir r&oslash;rt av tilbakemeldingene jeg f&aring;r. Foreldre som kjenner seg igjen og forst&aring;r at deres f&oslash;lelser er normale. </span><span style=\"font-size: 12pt;\"><span class=\"s1\">En mor skrev: &laquo;Jeg f&oslash;lte meg alene om &aring; ha mistet barnet mitt, men boka ga meg et nytt perspektiv&raquo;. <br /><br /><strong>Morten studerte sosiologi og hadde et &oslash;nske om &laquo;&aring; gj&oslash;re en forskjell&raquo;, som det heter. Det ble dessverre p&aring; en annen m&aring;te enn han hadde tenkt.</strong></span><strong> <span class=\"s1\">&Aring; hedre han, og de andre barna med denne boken, betyr mye. Morten har gjort en forskjell. Han var, og er, med meg hele veien. </span></strong></span></p>\r\n<p class=\"p6\"><strong><span style=\"font-size: 12pt;\"><span class=\"s1\">Ser ham for meg der han st&aring;r og smiler..</span><span class=\"s1\"><br /></span><span class=\"s1\">Og sier -&nbsp;<em>bra mamma, vi greide det..</em></span></span></strong></p>\r\n<p class=\"p9\"><span class=\"s1\"><span style=\"font-size: 12pt;\">Wenche</span></span><strong><span class=\"s1\"><br /><br /><span style=\"text-decoration: underline;\"><a href=\"https://www.pax.no/a-miste-et-barn.5962721-331609.html\">Boken &laquo;&Aring; miste et barn&raquo; finner du hos Pax forlag her.&nbsp;</a><br /><br /></span><span style=\"color: #3366ff; font-size: 12pt;\"><a style=\"color: #3366ff;\" href=\"https://www.forfatterskolen.no/course\">Nysgjerrig p&aring; v&aring;re skrivekurs? Her finner du oversikten.</a></span></span></strong></p>','/storage/blog/1547731848.jpeg','Wenche F. Spjelkavik','/storage/blog/author/1547728739.jpeg',1,NULL,'2019-01-17 17:08:59','2019-01-19 19:41:25'),(17,1346,'Å gi ut selv: « I did it my way »','<p class=\"p1\"><span style=\"font-size: 14pt; color: #000000;\"><em><span style=\"font-family: tahoma, arial, helvetica, sans-serif;\"><img src=\"/laravel-filemanager/photos/shares/blog2-.jpg\" alt=\"\" width=\"701\" height=\"450\" /></span></em></span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><em>Ektefellen og eg sat med kaffien i handa og kika i dagens post. &laquo;Eg har lova &aring; skrive ein blogg om mine erfaringar med &aring; gi ut bok, med vekt p&aring; korleis eg marknadsf&oslash;rte og solte boka.&raquo; Stemma mi var s&aring; likegyldig eg kunne.</em></span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><em>Ho s&aring;g p&aring; meg med eit blikk eg kjenner altfor godt, &laquo;og kor mange bloggar har du lese?&raquo;</em></span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><em>&laquo;Det kan vel ikkje vere s&aring; vanskeleg &aring; fortelje korleis eg gjorde det vel,&raquo; argumenterte eg imot. Men skaden var allereie skjedd. D&aring; ho kledde seg for trening, begynte eg &aring; s&oslash;ke p&aring; bloggar. Det skulla eg aldri ha gjort. Ei ukjend verden med kremmar og ansiktsmasker, trutmunnar og syltronge kle openberra seg. Og overlegne blikk. Eg makta ikkje lese meir enn ei og anna linje, f&oslash;r eg m&aring;tte hoppe ut. &laquo;Om det er slik &aring; blogge, vert det ikkje med meg&raquo; slo eg fast for meg sj&oslash;lv.</em></span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>Som 30-&aring;ring trudde eg ikkje eg kunne skrive meir enn namnet mitt.</strong> S&aring; tok eg p&aring; meg redakt&oslash;ransvar for eit medlemsblad. Eg tenkte det var &aring; sy saman artiklar andre skreiv, men etter kort tid vart eg tvinga til &aring; skrive sj&oslash;lv. Det gjekk tregt. Men eg likte &aring; h&oslash;yre andre fortelje, og eg f&oslash;lte sj&oslash;lv at eg klarte &aring; formidle p&aring; ein m&aring;te som lesaren likte. S&aring; vart det fleire faktaartiklar fr&aring; arktisk, selfangst og Svalbard, forlis og storturar. Sidan vart eg med p&aring; forskingsprosjektet PetroArctic, der eg sto for innsamling og systematisering av kunnskapen til gamle ishavsfolk i Noreg, resultatet vart boka &laquo;Ishavsfolk si erfaring&raquo;.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>I det arbeidet m&oslash;tte eg a-laget av attlevande ishavsfolk i landet.</strong> &Aring; skrive biografi om ein av ishavsskipperane eg m&oslash;tte, synets eg var ein kjempegod ide. Vi dr&oslash;fta b&aring;de innhald og vinkling, men dessverre drukna eg meg i arbeid og skipperen d&oslash;de uten denne ideen vart realisert.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\">For tre &aring;r sidan hadde ein tanke lagt &aring; kverna ei tid. Dersom eg skreiv ishavshistorie som roman, ville eg d&aring; m&oslash;te eit nytt og utvida publikum? Svaret var tja. Det var berre eit problem, eg kunne ikkje skrive skj&oslash;nnlitter&aelig;rt. Men eg hadde trua. Eg brukte litt tid p&aring; &aring; klekke ut ein ide om ein ishavsroman (selfangst) som eg tykte var ei god historie, alts&aring; den fiktive delen - inspirert av livet til den nemnte skipperen. Vidare hadde eg mange gode historier eg ville flette inn. Den siste berebjelken skulle vere den norske ishavshistoria fr&aring; 1950 og fram til tusen&aring;rsskiftet.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>Eg kalla det eit fors&oslash;k og gjekk i gang.</strong> Plutseleg var eg inne i skrivebobla, ei boble eg hadde h&oslash;yrt om og flira av. Men eg var inne i den og produserte 60&nbsp;000 ord p&aring; 40 dagar, ved sidan av full jobb og andre gjerem&aring;l. N&aring;r historia var p&aring; plass, sendte eg den ikkje til norskl&aelig;raren min eller andre med skj&oslash;nnlitter&aelig;r kunnskap. Nei, eg sendte til ein ishavsskipper og ein stuert, med ordre om &aring; kvalitetssjekke det ishavsfaglege og synse om historia var leseverdig. Begge kom med positive og klare attendemeldingar. P&aring; eit tidspunkt sendte eg manus til eit forlag. Brev i posten kom, alts&aring; i postkassa &ndash; ikkje den digitale, med svaret &laquo;nei takk&raquo;.</span><br /><span style=\"font-size: 14pt; color: #000000;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/Ishavsfolk_2.jpg\" alt=\"\" width=\"324\" height=\"456\" /> </span><br /><span style=\"font-size: 14pt; color: #000000;\"><strong>Frua hadde trua, og eg held fram, las og reviderte.</strong> N&aring;r eg var tilfreds, kj&oslash;pte eg korrektur- og spr&aring;kvask. Eg fekk mala eit maleri som skulle vere framsida p&aring; boka og omsider vart boka sett opp og trykt. Marknadsf&oslash;ring og sal hadde eg ikkje tenkt noko vidare p&aring;. Plakatar og roll-up hadde eg bestilt saman med trykkinga. Vidare vart ei eiga Facebookside til boka FANGSTMANN laga. Lansering p&aring; Ishavsmuseet p&aring; Brandal vart arrangert. Oppslag i Sunnm&oslash;rsposten fekk eg. Oppslag og omtale av boka i to lokalaviser. Men eg ville ha omtale av boka i Troms&oslash; ogs&aring;, sidan historia var inspirert av ein skipper fr&aring; byen. S&aring; eg booka konferanserom p&aring; eit hotell i byen, reiste opp og med hjelp av gode venar fekk eg oppslag i ei avis i byen. Vidare sendte eg kort info om boka til mange aviser. Lokalavisene tok denne stort sett inn. Maritimt Magasin tok turen til Brandal og Ishavsmuseet og skreiv ein fire-siders artikkel om skrivehobbyen og boka. Og eg solte b&oslash;ker. Mange b&oslash;ker. Via Facebook, p&aring; julemarknad, boksigneringar p&aring; bokhandlar og via andre bokhandlarar. Eg sj&oslash;lv var overvelda.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>Eg hadde l&aelig;rt masse,</strong> samstundes hadde eg aldri tenkt at dette skulle verte noko meir enn eit &laquo;One Night Stand&raquo;. Men attendemeldingane var fine, med forventning om ein oppf&oslash;lgjar. Det hadde aldri vore i mine tankar, d&aring; hadde eg sj&oslash;lvsagt ikkje teke livet av hovudpersonen i f&oslash;rste boka. Vidare skj&oslash;nte eg at om eg skulle skrive meir skj&oslash;nnlitter&aelig;rt m&aring;tte eg hente meir kunnskap. I jakt p&aring; denne kunnskapen kom eg over Forfatterskolen. Eg meldte meg p&aring; kurs, og slukte all kunnskap med stor appetitt. N&aring;r s&aring; oppg&aring;va om &aring; lage karakterar og bygge ei historie kom, m&aring;tte eg gjere nokre val. Eg let meg rive med av dei gode attendemeldingane og gjekk med stor iver inn for &aring; starte p&aring; ein oppf&oslash;lgjar til &laquo;FANGSTMANN &ndash; ei forteljing fr&aring; ishavet&raquo;.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>Det var ein langt meir reflektert mann som gjekk i gang &aring; skrive denne.</strong> Energiniv&aring;et var l&aring;gare, kunnskapsniv&aring;et h&oslash;gare og prestasjonsangsten lura. Tre forlag las manus, utan at dei kasta seg over min smale sjanger. Men det vart bok, &laquo;EVENTYRET &ndash; med &laquo;Fangstmann&raquo; til Svalbard&raquo;. Malen ikkje ulik den f&oslash;rst, korrekt geografi og historiske hendingar, med ei fiktiv spenningshistorie. Same korrekturlesar, illustrasjonar fr&aring; same illustrat&oslash;r som sist og same oppsett/trykkeri.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>Korleis tenkte eg s&aring; om marknadsf&oslash;ring?</strong> For det f&oslash;rste, sist gong gav eg ut bok ein m&aring;nad f&oslash;r jul. Denne gongen var det ein og ein halv m&aring;nad tidlegare. Plakatar og roll-up var p&aring; plass f&oslash;r boka. Eg presenterte boka p&aring; Ishavsmuseet p&aring; Brandal, i Troms&oslash; og sidan det er ei Svalbardbok, i Longyearbyen. Biblioteket i Troms&oslash; har tradisjon for bokpresentasjonar, s&aring; der fekk eg kome gratis, ja dei annonserte og organiserte til. Eg tok kontakt med same journalisten i Troms&oslash; som sist, og oppslag fekk boka. I Longyearbyen vart boka presentert p&aring; utestaden Stationen. Dei reklamerte og der kom mange folk, ja s&aring; mange at eg kjente eit snev av prestasjonsangst. Svalbardposten hadde notis om boka. Til alle presentasjonane kom det godt med folk og eg solte b&oslash;ker. Redakt&oslash;ren i lokalavisa kontakta eg, der fekk eg merksemd, med dekking av bokpresentasjonen, laurdagsportrett av meg og sidan omtale av boka. Eg kontakta ein journalist NRK M&oslash;re og Romsdal, resultatet vart eit flott innslag om boka som nyhende i fjernsynssendinga klokka 1845. Maritimt Magasin skreiv ogs&aring; om boka. Vidare hadde eg ein invitasjon fr&aring; Rotary i nabokommunen, den passa eg p&aring; &aring; f&aring; kome etter boka var ute. Vidare tok eg del p&aring; to julemarknad, der b&oslash;kene solte godt. Og sj&oslash;lvsagt signering i dei lokale bokhandlane.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>Facebook erfarte eg sist var ein nyttig kanal,</strong> den har eg bruka denne gongen og, b&aring;de til &aring; legge ut bokpresentasjonane som arrangement, nyhender, omtaler og sal av boka. Eg &oslash;nska &aring; gjere noko som vart lagt merke til, s&aring; via ein avdelingsleiar eg kom i kontakt med ein student p&aring; medialina p&aring; h&oslash;gskulen i Volda. Han laga ein reklamefilm av EVENTYRET til bruk I sosiale media.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\">Og ja, ogs&aring; boka &laquo;EVENTYRET &ndash; med &laquo;Fangstmann&raquo; til Svalbard&raquo; har seld godt. Ein god del har ogs&aring; kj&oslash;pt FANGSTMANN samstundes, det har vore ei hyggeleg overrasking.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\"><strong>Erfaringane eg har gjort:</strong> </span><br /><span style=\"font-size: 14pt; color: #000000;\">Det er fullt mogleg &aring; gi ut bok sj&oslash;lv og lande p&aring; beina, men rekn ikkje timar! Produktet kan ikkje verte for godt gjennomarbeidd, bruk pengar p&aring; korrektur og spr&aring;kvask, kanskje ogs&aring; ein redakt&oslash;r om du har mange pengar. Eg brukte fleire testlesarar. Tittel og omslag er viktig for &aring; selje boka, i dag meiner eg at FANGSTMANN er ein betre tittel enn EVENTYRET, like eins er eit dramatisk maleri av ei ishavsskute meir seljande enn fjordis, bre, fjell og bl&aring; himmel. Og du m&aring; eksponere b&aring;de boka og deg sj&oslash;lv for &aring; selje den.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #0000ff;\"><a style=\"color: #0000ff;\" href=\"https://www.facebook.com/1962526067307677/videos/325404111570036/\">VIDEO: Se Johannes fortelle om boka&nbsp;</a></span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\">&Aring; gje ut bok sj&oslash;lv krev mykje arbeid, det er viktig &aring; vere kritisk med omsyn til kostnader, i den grad eg har brukt &laquo;un&oslash;dvendige&raquo; kostnader har det vore p&aring; marknadsf&oslash;ring, med kj&oslash;p av annonser i aviser og fremjing p&aring; Facebook. Den viktigaste suksessfaktoren er du sj&oslash;lv, du m&aring; ha tru p&aring; produktet og virkeleg brenne for &aring; presentere og selje boka. D&aring; g&aring;r det bra!</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\">Eg har gjort det p&aring; min m&aring;te, du m&aring; gjere det p&aring; din.</span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\">Lykke til!</span></p>\r\n<p><span style=\"color: #000000;\"><strong><span style=\"font-size: 14pt;\">Og det viktigaste, hugs &aring; ha det kjekt p&aring; vegen.</span></strong></span></p>\r\n<p><span style=\"font-size: 14pt; color: #000000;\">Johannes Alme<br /><br /><span style=\"color: #0000ff;\"><strong><a style=\"color: #0000ff;\" href=\"https://tv.nrk.no/serie/distriktsnyheter-moere-og-romsdal/DKMR99102418/24-10-2018?fbclid=IwAR0iBXU6UMaWe7VgP4Tni-kc6RgU0DI4SbeWe8rV4KQV2J9a_40BfJQ724g#t=6m9s\">Se NRK-intervju med Johannes her!</a></strong></span></span></p>\r\n<p><strong><span style=\"font-size: 14pt; color: #000000;\"><span style=\"color: #0000ff;\"><a href=\"https://www.facebook.com/Boka-Fangstmann-ei-forteljing-fr%C3%A5-Ishavet-1962526067307677/\">F&oslash;lg eventyret p&aring; Facebook:</a> <a style=\"color: #0000ff;\" href=\"https://www.facebook.com/Boka-Fangstmann-ei-forteljing-fr%C3%A5-Ishavet-1962526067307677/\">Boka Fangstmann - ei forteljing fr&aring; Ishavet</a></span></span></strong></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/Bok2.jpg\" alt=\"\" width=\"338\" height=\"215\" /></p>','/storage/blog/1548348670.jpeg','Johannes Alme',NULL,1,NULL,'2019-01-24 23:35:06','2019-01-29 16:25:08'),(18,1346,'SLIK BLE ANTOLOGIEN «DRØM» TIL','<p style=\"text-align: center;\"><span style=\"font-size: 12pt;\"><strong>Gjesteinnlegg av:<br /></strong></span><strong style=\"font-size: 12pt;\">Svanhild Fosback Larsen</strong></p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/Dr&oslash;mIMG_0900.jpg\" alt=\"\" width=\"302\" height=\"373\" /></p>\r\n<p><span style=\"font-size: 14pt;\">Jeg har skrevet tekster siden jeg var sju. Etter fylte femten kom innleggene mine, opptil flere dikt og en novelle, p&aring; trykk i aviser og magasiner. Mesteparten signert med forbokstavene mine, eller et fiktivt navn. I voksen alder drev jeg Festsangspesialisten.no noen &aring;r, ved siden av jobben som sykepleier. I 2015 m&aring;tte jeg ufrivillig bytte ut en aktiv arbeidshverdag med Pc-en hjemme, grunnet pasientskade. Da surfet jeg inn p&aring; Forfatterskolen.no.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Januar 2017 begynte jeg p&aring; kurs, og en litter&aelig;r verden &aring;pnet seg. Jeg l&aelig;rte &aring; se egne tekster p&aring; en ny m&aring;te, fikk tilbakemelding og gode r&aring;d. Ikke bare traff jeg fine folk i skolens nettforum og fikk nye venner, men gjennom forfatterskolen.no fikk jeg kontakt med likesinnede i eget n&aelig;rmilj&oslash;. Folk jeg ellers antageligvis aldri hadde truffet.&nbsp;</span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong>&Aring; v&aelig;re en del av forfatterskolemilj&oslash;et</strong> gav meg energi. Energi til &aring; skrive, og fullf&oslash;re. Jeg fikk tekster antatt i antologier: Vilje, Alea (2017), Det var en gang. Alea (2018).</span></p>\r\n<p><span style=\"font-size: 14pt;\">I 2017-2018 sendte jeg tekst til enda en skrivekonkurranse, i et nystartet forlag, og fikk positivt svar. Jeg fikk ogs&aring; lov til &aring; male forsiden til boka. Hildegunn Bjelland, Aslaug Tidemann og jeg var kjente via forfatterskolen. De fikk ogs&aring; tekster antatt i den kommende antologien. </span></p>\r\n<p><span style=\"font-size: 14pt;\">Utgivelsen dro ut, og i den lange venteprosessen begynte jeg &aring; leke med tanken om &aring; gi ut en antologi selv med tekstene v&aring;re hvis boka ble annullert. Hildegunn tenkte samme tanken. Da forlaget i september 2018 m&aring;tte trekke seg fra utgivelsen grunnet personlige &aring;rsaker, var vi forberedt psykisk. </span></p>\r\n<p><span style=\"font-size: 14pt;\">Jeg reagerte spontant, spurte og fikk tillatelse til &aring; videref&oslash;re tittelen DR&Oslash;M. Forsiden var allerede min, og Hildegunn og jeg bestemte oss for &aring; gi ut boka f&oslash;r jul. Da involverte vi Aslaug i planene, og bestemte at alle inntekter skulle g&aring; til Kreftforeningen, merket forskning.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Impulsivt, men jeg hadde tenkt igjennom alt p&aring; forh&aring;nd. Satt opp tolv punkter.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>1. &Oslash;KONOMI</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">&Aring; gi ut bok koster. B&aring;de ombrekking, design, trykking, frakt, og skatt. </span></p>\r\n<p><span style=\"font-size: 14pt;\">Vi tre valgte &aring; stille med l&aring;n fra v&aring;r private &oslash;konomi. Risikoen for &aring; tape pengene var tilstede.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>2. ENKELTMANNSFORETAK</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">For &aring; f&aring; organisasjonsnummer, og deretter s&oslash;ke om IBSN nummer, m&aring; man opprette forlag. Jeg p&aring;tok meg ansvaret.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>3. DOMENE, NETTSIDE</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">For &aring; registrere et forlag m&aring; man ha domene (Navn). Man betaler en registreringssum, og deretter en fast sum i &aring;ret. I pakken f&aring;r man tilgang p&aring; nettside og egen mail (Helst b&oslash;r man ha bachelor i IT for &aring; skj&oslash;nne hvordan man h&aring;ndterer verkt&oslash;yene). </span></p>\r\n<p><span style=\"font-size: 14pt;\">&Aring; finne et ledig domene er vanskelig. Min ide var navnene v&aring;re: AS fra Aslaug, HILD fra Hildegunn og Svanhild, pluss en K = ASKHILD. </span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>4. TEKSTER.</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Vi skriver alle tre. Samtidig f&oslash;lte vi ansvar overfor forfatterne som hadde sendt bidrag til den avlyste antologien, og bestemte oss for &aring; be om at tekstene ble videresendt til ASKHILD forlag for ny vurdering. Jeg la ut invitasjon p&aring; det andre forlagets facebookside. Responsen var positiv, og godt over halvparten sendte tekstene p&aring; nytt. Noen andre benyttet ogs&aring; sjansen til &aring; sende.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Jeg ble valgt til redakt&oslash;r for antologien DR&Oslash;M, og sammen med Hildegunn og Aslaug &oslash;nsket jeg &aring; vurdere alle tekster, ogs&aring; v&aring;re egne, for &aring; kunne st&aring; for bokutgivelsen faglig. </span></p>\r\n<p><span style=\"font-size: 14pt;\">Alle tre hadde dessuten favoritter blant medelever som torde &aring; legge ut tekstsnutter p&aring; Forfatterskolens interne forum. Vi rekrutterte dem, pluss et par til utenfor milj&oslash;et. Alle sa ja.</span></p>\r\n<p><span style=\"font-size: 14pt;\">I tillegg hadde Lisette Ask&oslash; sendt tekst til den avlyste antologien, og igjen til oss. Jeg fikk ogs&aring; overtalt forfatterskolens Hanne Einang til &aring; sende oss dikt.<br /><br /></span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>5. HVA VILLE F&Aring; V&Aring;R ANTOLOGI TIL &Aring; SKINNE</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Det blir utgitt mange antologier hvert &aring;r. Vi var ikke store litter&aelig;re navn. Jeg jobbet &laquo;undercover&raquo; med en ide: Sendte foresp&oslash;rsel til store forfattere. Var de interessert i &aring; hjelpe tre forfatterspirer med dr&oslash;mmen? Tenk &aring; bli publisert sammen med Petter Fergestad, Tom Egeland, Gro Dahle, Knut N&aelig;rum, Marit Reiersg&aring;rd, Gunnar Staalesen og Ingar Johnsrud! Velviljen var overveldende! Fantastiske mennesker!</span></p>\r\n<p><span style=\"font-size: 14pt;\">Morsomt var det ogs&aring; &aring; f&aring; melding fra Ingvar Ambj&oslash;rnsen, selv etter at antologien var utgitt. Med beklagelse om at han ikke hadde sett den f&oslash;r. </span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>6. MANUSVURDERING, SPR&Aring;KVASK</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Vi gjorde det selv. Aslaug Tidemann er utdannet journalist, og har jobbet som redakt&oslash;r i et magasin. Hildegunn Bjelland er en erfaren skriver som debuterer med barnebok i mars. Selv er jeg som nevnt en evig skribent, har drevet med sanger, dikt og taler, og v&aelig;rt veileder for studenter.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>7. OMBREKKING OG DESIGN</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Lisette Ask&oslash; i ASK&Oslash; kreative/Alea forlag tilb&oslash;d oss hjelp til jobben, og en meget god deal.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>8. TRYKKERI</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Lisette formidlet kontakt med riktig trykkeri.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>9. BOKLANSERING</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Finne lokaler, skaffe gjester, underholdning og mat.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>10. REKLAMERE OG SELGE</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Facebook og Instagram! Vi solgte alt selv, samt et par eksemplarer p&aring; Galleri Ohlsen i Arendal.</span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>11. FAKTURERING OG REGNSKAP</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Jeg opprettet konto for forlaget ASKHILD i mitt navn. Jeg f&oslash;rer regnskap og har oversikt. Vi tok/tar imot bestillinger, pakker og sender. </span></p>\r\n<h2><span style=\"font-size: 14pt;\"><strong>12. SKATTEMYNDIGHETENE</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Ny skattemelding for n&aelig;ringsdrivende.</span></p>\r\n<h1><span style=\"font-size: 14pt;\"><strong>KONKLUSJON</strong></span></h1>\r\n<p><span style=\"font-size: 14pt;\">Antologien ble en suksess. Vi ferdigstilte boka p&aring; tre uker! Travelt, til tider kaotisk, men utrolig l&aelig;rerikt. Vi er s&aring; stolte.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Mange sp&oslash;rsm&aring;l under trykking skulle besvares, om st&oslash;rrelse p&aring; bokrygg og fargetoner. Jeg var til tider svett, men l&aelig;rte underveis. Mailene gikk varme fra meg til t&aring;lmodige Lisette Ask&oslash;. </span></p>\r\n<p><span style=\"font-size: 14pt;\">P&aring; boklanseringen kom det 20 stk. fra Forfatterskolen. Til sammen kom rundt 80 mennesker. Dr&oslash;mmeforfatter Petter Fergestad kom, ble intervjuet og leste fra sin novelle. Andre Tjelde kom fra Sverige og leste dikt. Hildegunn, Aslaug og jeg leste fra egne tekster. Greta Moland sang vakkert, en god venn spilte piano til, og musikeren Egil S. &Oslash;deg&aring;rd underholdt med sang og gitarspill fra sine utgitte album. Kr&oslash;genesl&aring;ven leverte, og folk koste seg.&nbsp;Salget har g&aring;tt over all forventning.&nbsp;</span></p>\r\n<p><span style=\"font-size: 14pt;\">S&aring; kan dr&oslash;mmer bli virkelighet? Ja, hvis du jobber hardt nok.<br /></span></p>\r\n<p><span style=\"font-size: 18pt;\"><strong><a href=\"http://www.ASKHILD.no\">www.ASKHILD.no</a><br /></strong></span><span style=\"font-size: 14pt;\"><strong><em>F&oslash;lg oss p&aring; Facebook: <span style=\"font-size: 18pt;\"><a href=\"https://www.facebook.com/groups/267795563867132/\">Forlaget ASKHILD</a></span></em></strong></span></p>\r\n<p><span style=\"font-size: 14pt;\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/SvanhildIMG_0400.jpg\" alt=\"\" width=\"264\" height=\"520\" /></span></p>','/storage/blog/1548958738.jpeg','Svanhild Fosback Larsen','/storage/blog/author/1548958394.jpeg',1,NULL,'2019-02-01 01:13:14','2019-02-01 01:52:12'),(19,1346,'VANSKELIG – MEN LANGT FRA UMULIG','<p class=\"meta\" style=\"text-align: center;\"><em>Opprinnelig postet: 2. august 2016</em></p>\r\n<p class=\"meta\"><em><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/laravel-filemanager/photos/shares/Frykten for å feile (14).jpg\" alt=\"\" width=\"360\" height=\"200\" /></em></p>\r\n<p><span style=\"font-size: 14pt;\">Jeg har aldri dr&oslash;mt om &aring; bli forfatter, det har ikke sl&aring;tt meg som en mulighet en gang. Og selv om jeg alltid har lest mye, har jeg ikke ofret menneskene som har skrevet b&oslash;kene en tanke.</span></p>\r\n<section class=\"post_content clearfix\">\r\n<div id=\"tve_flt\" class=\"tve_flt\">\r\n<div id=\"tve_editor\" class=\"tve_shortcode_editor\">\r\n<div class=\"thrv_paste_content thrv_wrapper\">\r\n<p><span style=\"font-size: 14pt;\">Ikke f&oslash;r v&aring;ren 2014.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Da skjedde det noe merkelig. Hjernen min begynte &aring; produsere historier: Mord og mysterier,&nbsp;drama og intriger. Jeg kunne ikke begripe det. Hvor kom det fra? Det var rett og slett irriterende, for historiene var b&aring;de intense og masete. Og de ville skrives, ned p&aring; papiret og ut i verden.</span></p>\r\n<h2><span style=\"font-size: 18pt;\"><strong>Aldri skrevet noe som helst​</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Skrive? Jeg? Som hadde jobbet med tall hele livet, og som aldri hadde skrevet noe som helst. Ikke s&aring; mye som et dikt p&aring; en serviett eller tale til en jubilant.</span></p>\r\n<p><span style=\"font-size: 14pt;\">S&aelig;rlig.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Problemet var bare at historiene fortsatte &aring; plage meg gjennom v&aring;ren og sommeren, og da h&oslash;sten kom ga jeg etter for presset.</span></p>\r\n<p><span style=\"font-size: 14pt;\">&laquo;Jeg m&aring; skive en bok,&raquo; sa jeg til mannen min. &laquo;Jeg er redd det kommer til &aring; g&aring; med skrekkelig mye tid, men det er ingen vei utenom.&raquo;</span></p>\r\n<h2><span style=\"font-size: 18pt;\"><strong>Hvordan skriver man en roman?​</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">Men hvordan skriver man en roman? Er det slik at man starter med det f&oslash;rste ordet og tar det derfra? Jeg hadde lest at skriving er et h&aring;ndverk, og at det kan l&aelig;res som et hvilket som helst annet fag. Kanskje et kurs hadde v&aelig;rt smart? Jeg googlet meg frem til Forfatterskolen og sjekket kursoversikten.&nbsp;Skj&oslash;nnlitter&aelig;rt skrivekurs,skreddersydd&nbsp;for deg som &oslash;nsker &aring; skrive et skj&oslash;nnlitter&aelig;rt manus.&nbsp;Du verden! Midt i blinken for meg.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Skrivingen tok meg fullstendig. For en utfordring! Jeg har aldri&nbsp;v&aelig;rt s&aring; oppsatt p&aring; &aring; gjennomf&oslash;re noe. Jeg tenkte karakterer og plott mens jeg sto i k&oslash;en p&aring; REMA eller vasket gulv. Jeg leste faglitteratur om skriving og analyserte romaner til langt p&aring; natt, og&nbsp;etterp&aring; skrev jeg fingertuppene &oslash;mme.</span></p>\r\n<h2><span style=\"font-size: 18pt;\"><strong>Babyen forlater redet​</strong></span></h2>\r\n<p><span style=\"font-size: 14pt;\">H&oslash;sten 2015 skulle jeg levere en oppgave til Forfatterskolen; De 20 f&oslash;rste sidene av et skj&oslash;nnlitter&aelig;rt manus. Noen skulle lese det jeg hadde skrevet, de skulle vurdere teksten min og gi&nbsp;tilbakemelding. Det var skummelt, men ogs&aring;&nbsp;inspirerende. Og da oppgaven var levert skrev jeg de neste 20 sidene, og s&aring; de neste ... Historien fosset videre, og seks m&aring;neder senere var den ferdig.&nbsp;Nesten&nbsp;ferdig. Jeg sendte manuskriptet til Forfatterskolen for en siste vurdering, og i retur fikk jeg gode tips om hvordan jeg kunne gj&oslash;re manuset enda litt bedre.</span></p>\r\n<p><span style=\"font-size: 14pt;\">S&aring; var babyen klar til &aring; forlate redet.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Det var bare en hake. Jeg visste det var nesten umulig &aring; bli antatt av et seri&oslash;st forlag, og sannsynligheten for at manuset mitt noen gang skulle bli til&nbsp;bok var s&aring; godt som null.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Vel, jeg m&aring;tte i det minste gj&oslash;re et fors&oslash;k. Jeg sendte manuset til flere forlag, og belaget meg p&aring; en lang og pinefull v&aring;r og en bunke refusjonsbrev i postkassa.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Slik ble det ikke. Bare noen dager senere fikk jeg en telefon fra et st&oslash;rre forlag:&nbsp;Har du inng&aring;tt en avtale vedr&oslash;rende manuset ditt enn&aring;?&nbsp;</span></p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Flere forlag var interessert​</strong></span></p>\r\n<p><span style=\"font-size: 14pt;\">Det skulle&nbsp;vise seg at flere forlag var interessert, og innen&nbsp;tre uker hadde jeg kontrakt med et av de store forlagene i landet.</span></p>\r\n<p><span style=\"font-size: 14pt;\">Det var uvirkelig. Jeg var m&aring;ll&oslash;s. Forundret. Svimmel. Jeg klarte det!</span></p>\r\n<p><span style=\"font-size: 14pt;\">Etter at jeg begynte &aring; skrive har jeg lest utallige historier om forfatterspirer som har blitt refusert nord og ned, i &aring;revis. Det skader ikke &aring; ha realistiske forventinger, tvert om, men det skader heller ikke &aring; vite at det&nbsp;er&nbsp;mulig. N&aring;l&oslash;yet er trangt, men noen kommer gjennom. Og det er ikke bare erfarne journalister,&nbsp;forfatterstudenter i B&oslash; og kjente rosabloggere. Manuset mitt ble lagt merke til i bunken. I flere bunker! Det skjedde&nbsp;meg, en uerfaren skribent uten et kjent navn eller kontakter i bransjen. Da kan det skje deg ogs&aring;!</span></p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Ville aldri klart det uten fellesskapet​</strong></span></p>\r\n<p><span style=\"font-size: 14pt;\">Hvis alt g&aring;r etter planen kommer boken min ut p&aring; Gyldendal forlag i&nbsp;2017. Og med h&aring;nden p&aring; hjertet: Jeg vet ikke om jeg hadde klart det uten Forfatterskolen, og uten den st&oslash;tten det ligger i &aring; v&aelig;re en del av et skrivefellesskap.</span></p>\r\n<p><span style=\"font-size: 14pt;\">N&aring; ser jeg frem til skrivereisen til Ronda i oktober! Jeg vil fortsette &aring; la&nbsp;meg inspirere&nbsp;av Rektor Kristine og hennes medarbeidere&nbsp;p&aring; Forfatterskolen og ikke minst: Elevene. For en ting er sikkert: Jeg skal skrive flere b&oslash;ker, mange, jeg skal fylle en hel bokhylle. Og jeg skal skrive dem slik jeg liker; med lun humor og originale karakterer. Sm&aring;byidyll med hvite trehus og trange gater. Og selvsagt: Et mysterium.</span></p>\r\n<p><span style=\"font-size: 14pt;\">&Oslash;nsker deg en god skriveh&oslash;st!</span></p>\r\n<p><span style=\"font-size: 14pt;\">Alt godt,</span></p>\r\n<p><span style=\"font-size: 14pt;\">Linda​ Skomakerstuen<br /></span></p>\r\n<p><span style=\"font-size: 14pt;\"><strong><a href=\"https://www.forfatterskolen.no/course/31\">Vil du ogs&aring; g&aring; romankurs? Her finner du all info!</a></strong></span></p>\r\n<p><a href=\"https://www.gyldendal.no/Skjoennlitteratur/Romaner-og-noveller/Uten-vesentlige-feil-eller-mangler\"><span style=\"font-size: 14pt;\">Her finner du Linda sin f&oslash;rste bok (Gyldendals nettside)</span></a></p>\r\n<p><a href=\"https://www.gyldendal.no/Skjoennlitteratur/Romaner-og-noveller/Uten-innkommende-ordre\"><span style=\"font-size: 14pt;\">Her er bok nummer to som kommer i juni! (Gyldendals nettside)</span></a></p>\r\n<p><a href=\"https://www.gyldendal.no/Forfattere/Skomakerstuen-Linda\"><span style=\"font-size: 14pt;\"><img src=\"/laravel-filemanager/photos/shares/skomaker_.jpg\" alt=\"\" width=\"297\" height=\"220\" /></span></a></p>\r\n</div>\r\n</div>\r\n</div>\r\n</section>','/storage/blog/1550164486.jpeg','Linda Skomakerstuen',NULL,1,NULL,'2019-02-15 00:14:46','2019-02-17 03:12:54'),(21,1064,'Hva er ditt skrivemål for 2020?','<p dir=\"ltr\">Jeg gjetter at du har som m&aring;l &aring; skrive en bok i l&oslash;pet av &aring;ret? Da er det store sp&oslash;rsm&aring;let: Hva skal til for at du lykkes?&nbsp;</p>\r\n<h3>Ikke legg lista for h&oslash;yt</h3>\r\n<p>Noen har som m&aring;l &aring; skrive hver dag, om s&aring; bare er en setning. Jeg vil tro at du m&aring; skrive <em>litt</em> mer enn det for &aring; fullf&oslash;re et helt manus. Samtidig er det viktig &aring; ikke legge lista for h&oslash;yt. Du m&aring; sette et m&aring;l som er oppn&aring;elig &ndash; ellers risikerer du &aring; bli sliten, motl&oslash;s og frustrert.</p>\r\n<h3>Hva vil du oppn&aring;?</h3>\r\n<p dir=\"ltr\">Her er noen sp&oslash;rsm&aring;l du b&oslash;r reflektere over f&oslash;r du setter det endelige m&aring;let:</p>\r\n<ul>\r\n<li dir=\"ltr\">Hva &oslash;nsker du &aring; oppn&aring;?</li>\r\n<li dir=\"ltr\">Hvilke steg m&aring; du ta for &aring; oppn&aring; dette?</li>\r\n<li dir=\"ltr\">Hva er tidsfristen?</li>\r\n<li dir=\"ltr\">Hvor mye m&aring; du skrive hver dag?</li>\r\n<li dir=\"ltr\">Hvor realistisk er det at du klarer &aring; gjennomf&oslash;re dette?</li>\r\n<li dir=\"ltr\">Hvilke hindringer kan du m&oslash;te p&aring; veien?</li>\r\n<li dir=\"ltr\">Hvordan ser m&aring;let ut med tanke p&aring; &oslash;vrige livsm&aring;l og planer?</li>\r\n<li dir=\"ltr\">Er dette den rette tiden &aring; fors&oslash;ke &aring; n&aring; m&aring;let?</li>\r\n<li dir=\"ltr\">Har du ferdighetene som kreves (ellers m&aring; du bruke tid p&aring; &aring; l&aelig;re deg skriveh&aring;ndverket, for eksempel gjennom <a href=\"https://www.forfatterskolen.no/course\">skrivekurs</a> innenfor sjangeren du skriver i)</li>\r\n<li dir=\"ltr\">Hvor fort kan du n&aring; m&aring;let <em>uten</em> at det g&aring;r ut over kvaliteten?&nbsp;</li>\r\n</ul>\r\n<h3>Fokus og kondis</h3>\r\n<p dir=\"ltr\">Et &aring;rsm&aring;l b&oslash;r deles opp i mindre biter &ndash; s&aring; du har m&aring;nedsm&aring;l, ukesm&aring;l og dagsm&aring;l. Da vil det f&oslash;les mer overkommelig, samtidig som du har det store bildet: Skrive et manus i l&oslash;pet av 2020. Dette vil kreve fokus og kondis, akkurat som et maratonl&oslash;p, s&aring; v&aelig;r forberedt p&aring; dette. Du vil bli sliten og lei underveis &ndash; og det vil f&oslash;les berusende &aring; komme i m&aring;l.&nbsp;&nbsp;</p>\r\n<p dir=\"ltr\">Husk at det tar tid &aring; skape en ny vane, &Aring; skrive gjennom et helt &aring;r gir deg ikke bare gode resultater, det l&aelig;rer deg ogs&aring; &aring; jobbe som en profesjonell forfatter.&nbsp;&nbsp;</p>\r\n<h3>Sett ditt m&aring;l for 2020</h3>\r\n<h3><strong>F&oslash;rst b&oslash;r du sp&oslash;rre deg selv:</strong></h3>\r\n<p dir=\"ltr\">1. Hvorfor skriver du? Hva er din motivasjon (ditt store&nbsp;<em>hvorfor</em>)? Hva vil du fortelle? Skriv det ned p&aring; en lapp og heng den opp p&aring; veggen. Da har du et begeistringsnotat som motiverer deg underveis &ndash; og minner deg p&aring; hvorfor du gj&oslash;r dette.</p>\r\n<p>Deretter lager du en liste:</p>\r\n<h3 dir=\"ltr\"><strong>Mine topp 3 prioriterte skriveprosjekter er ...</strong></h3>\r\n<p dir=\"ltr\">1.</p>\r\n<p dir=\"ltr\">2.</p>\r\n<p dir=\"ltr\">3.</p>\r\n<h3 dir=\"ltr\"><strong>Grunnen til at akkurat disse prosjektene er viktige for meg:</strong></h3>\r\n<p dir=\"ltr\">&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<h3 dir=\"ltr\"><strong>S&aring; mange timer skal jeg skrive hver uke:</strong></h3>\r\n<p><br /><br /></p>\r\n<p>&nbsp;</p>\r\n<h3><strong>Vil du h&oslash;re om mine m&aring;l?</strong></h3>\r\n<p dir=\"ltr\">Jeg har selvsagt ogs&aring; laget meg noen m&aring;l. Her deler jeg m&aring;lene (s&aring; jeg forplikter meg enda mer &ndash; n&aring; har jeg jo sagt det h&oslash;yt):&nbsp;</p>\r\n<p dir=\"ltr\"><span style=\"text-decoration: underline;\">Januar</span>:&nbsp;</p>\r\n<ul>\r\n<li dir=\"ltr\">Evighetsprosjektet (skrive 5-6 kapitler)</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">Hemmelig prosjekt (dette h&oslash;rer dere kanskje noe om i framtiden)</p>\r\n</li>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">&nbsp;Skrive ned hva jeg dr&oslash;mmer om, som forfatter, s&aring; jeg senere kan planlegge hvordan jeg kan realiserer dette.</p>\r\n</li>\r\n</ul>\r\n<ul>\r\n<li dir=\"ltr\">\r\n<p dir=\"ltr\">Legge ut bok p&aring; pilotleser (et unikt, og gratis, system for alle som skriver kreativt:&nbsp;<a title=\"Pilotleser\" href=\"https://www.pilotleser.no/\">www.pilotleser.no</a>)</p>\r\n</li>\r\n</ul>\r\n<p dir=\"ltr\"><span style=\"text-decoration: underline;\">Februar:</span></p>\r\n<ul>\r\n<li dir=\"ltr\">Krimbok for barn</li>\r\n<li dir=\"ltr\">Hemmelig prosjekt&nbsp;</li>\r\n</ul>\r\n<p dir=\"ltr\">M&aring;lene vil bli oppdatert og tilpasset underveis, s&aring; det alltid passer inn i livet mitt. Hele tiden vil jeg strekke meg, samtidig som jeg ikke brenner meg ut. Smart, ikke sant?</p>\r\n<p dir=\"ltr\">Sett deg m&aring;l, du ogs&aring; &ndash; og fortell meg gjerne om dem. Hva vil du oppn&aring; med skrivingen i 2020? Del i kommentarfeltet, da vel! Og masse lykke til :-)</p>\r\n<p dir=\"ltr\"><em>Skriveglad hilsen fra Heidi</em></p>\r\n<p dir=\"ltr\"><em>Forfatterskolen</em></p>','/storage/blog/1578822824.jpeg','Heidi Anett Øglend','/storage/blog/author/1578822824.png',1,'2020-01-12','2020-01-12 09:53:44','2020-01-12 11:04:49'),(22,1064,'10 tips som setter fart på skrivemotoren','<p>G&aring;r det tregt med skrivingen om dagen? V&aelig;r s&aring; god, her skal du f&aring; 10 knalltips som vil sette fyr p&aring; skrivemotoren:</p>\r\n<p style=\"padding-left: 240px;\"><img src=\"/photos/Skjermbilde 2020-02-10 kl. 09.47.15.png\" alt=\"\" width=\"202\" height=\"152\" /></p>\r\n<p style=\"padding-left: 180px;\"><strong>10 tips for &aring; f&aring; skrivehjulene i gang</strong></p>\r\n<ol>\r\n<li>Skriv litt hver dag (motoren m&aring; holdes i gang, ellers blir den rusten)</li>\r\n<li>La skriving v&aelig;re det f&oslash;rste du gj&oslash;r om morgenen. Da er hodet og kreativiteten p&aring; topp &ndash; og du forteller deg selv at skrivingen er &oslash;verst p&aring; agendaen.</li>\r\n<li>F&oslash;lg Ray Radburys utfordring: Skriv 52 noveller i l&oslash;pet av et &aring;r (&eacute;n hver uke). Som han sier s&aring; treffende: <em>Du kan ikke skrive 52 d&aring;rlige noveller.</em>&nbsp;Kanskje du vil skrive 52 dikt i stedet? Prosjektet er lystbetont, fordi du hele tiden skriver noe nytt, og gir en f&oslash;lelse av fremgang, fordi du fullf&oslash;rer noe hver eneste uke.&nbsp;</li>\r\n<li>Delta i skriveutfordringene som vi &ndash; <a title=\"Forfatterskolen\" href=\"https://www.forfatterskolen.no/\" target=\"_blank\" rel=\"noopener\">Forfatterskolen</a> &ndash; arrangerer i l&oslash;pet av &aring;ret (det vil komme flere &ndash; vi gleder oss skrivevilt til &aring; dele)</li>\r\n<li>Lag en liste over skriverelaterte aktiviteter som du vil v&aelig;re med p&aring;. Her kan du m&oslash;te andre skriveglade, f&aring; inspirasjon og tips.</li>\r\n<li>Skriv ned alt du m&aring; gj&oslash;re som ikke har noe med manuset &aring; gj&oslash;re. Hvordan effektivisere dette s&aring; du skaper mer rom for skriving i hverdagen?</li>\r\n<li>Evaluer skriveprosessen din i slutten av hver m&aring;ned. Hvordan er fremgangen? Er det noe som m&aring; justeres, eller g&aring;r alt p&aring; skinner? <strong>NB!&nbsp;</strong>Hvis du er registrert i v&aring;rt gratis \"skrivesystem\" &ndash; <a title=\"Pilotleser\" href=\"https://www.pilotleser.no/auth/login\" target=\"_blank\" rel=\"noopener\">Pilotleser</a> &ndash; vil alt du skriver automatisk bli lagret. Du kan ogs&aring; sette opp en detaljert skriveplan. P&aring; den m&aring;ten er det superenkelt &aring; n&aring; dine skrivem&aring;l (!)</li>\r\n<li>Fors&oslash;k &aring; gj&oslash;re noe kreativt hver dag, selv om det ikke har noe med skriving &aring; gj&oslash;re. G&aring; p&aring; en kunstutstilling, lytt til ny musikk, se en smal film. Dette kan b&aring;de inspirere og utvide horisonten.&nbsp;&nbsp;</li>\r\n<li><strong>Viktig!</strong> L&aelig;r deg &aring; like skriveprosessen. Det er lett &aring; bli opphengt i sluttproduktet, men veien dit er enda viktigere. Hvordan gj&oslash;re den best mulig for deg selv? Som forfatter m&aring; du skrive <em>mye</em>, i ensomhet, og da er det viktig &aring; motivere seg selv.&nbsp;</li>\r\n<li>Del det du skriver med kompetente lesere. Pr&oslash;v for eksempel det unike, og gratis, pilotsystemet v&aring;rt &ndash; spesialutviklet for kreativt skrivende: <a title=\"Pilotleser\" href=\"https://www.forfatterskolen.no/\" target=\"_blank\" rel=\"noopener\">Pilotleser</a>. Her kan du finne den perfekte pilotleser for akkurat ditt manus, testlese manus (hvis du &oslash;nsker), finne skrivevenner &ndash; og lagre manuset ditt som en profesjonell.&nbsp;Genialt, ikke sant?&nbsp;</li>\r\n</ol>\r\n<p>Lykke til &ndash; og del gjerne i kommentarfeltet. Hvilke tips likte du best? Har du kanskje et skrivetips &aring; tilf&oslash;ye? Vi blir glade for innspill :-)</p>\r\n<p><em>Glade skrivestr&aring;ler fra Heidi Anett,</em></p>\r\n<p><em>Forfatterskolen</em></p>','/storage/blog/1581324713.jpeg','Heidi Anett Øglend','/storage/blog/author/1578826960.png',1,'2020-01-17','2020-01-12 11:02:40','2020-02-10 08:57:42'),(23,1064,'Nyantatt foratterelev: Aldri gi opp','<div>\r\n<div class=\"_1t_p clearfix\">\r\n<div class=\"_41ud\">\r\n<div class=\"clearfix _o46 _3erg _29_7 _8lma direction_ltr text_align_ltr\">\r\n<div id=\"js_ov\" class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">I slutten av mars kommer debutromanen min, \"Fritt fall\", ut. Da har det g&aring;tt fem &aring;r siden f&oslash;rste gang jeg sendte den inn til et forlag, og &aring;tte &aring;r siden jeg gjorde mine f&oslash;rste rotete fors&oslash;k p&aring; &aring; skrive noe skj&oslash;nnlitter&aelig;rt. Det aller viktigste jeg har l&aelig;rt p&aring; disse &aring;rene er &aring; ikke gi opp.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"/photos/7c605e5855368f4f_9788203265778.jpg\" width=\"279\" height=\"425\" /></div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\"><strong>Begynte bra</strong></div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">For min del begynte det bra, og s&aring; stagnerte det i flere &aring;r f&oslash;r det endelig l&oslash;snet. Nedenfor f&oslash;lger en langversjon av min vei til m&aring;let. Kanskje kan min historie inspirere andre som f&oslash;ler skrivingen g&aring;r tr&aring;tt?</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*V&aring;r 2015: Like f&oslash;r p&aring;ska 2015 sender jeg f&oslash;rste gang inn manuset Fritt fall. Jeg sender bare inn til ett forlag &ndash; og hele p&aring;ska er jeg et nervevrak. Hver gang mobilskjermen min lyser er jeg sikker p&aring; at det er fra en redakt&oslash;r: \"Hei, det manuset ditt var s&aring; bra at jeg bare m&aring;tte ta det med meg p&aring; p&aring;skefjellet, n&aring;r kan vi m&oslash;tes?\". Hvor denne selvsikkerheten kommer fra, m&aring; gudene vite. Riktignok har jeg brukt tre &aring;r p&aring; manuset, og det handler om et tema jeg er genuint opptatt av. Men bortsett fra meg er det kun min s&oslash;ster som har lest manuset, og jeg har ikke lest en eneste bok om skriving eller tatt noe kurs. Det g&aring;r en m&aring;ned. To m&aring;neder. Tre m&aring;neder.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*Sommer 2015: Jeg purrer p&aring; forlaget og f&aring;r mail fra en redakt&oslash;r. Grunnen til at det har tatt s&aring; lang tid er at jeg har havnet i kanskje-bunken, det vil si bunken for &laquo;her er det noe, men akkurat hva det er er usikkert, og det kommer til &aring; ta massevis av arbeid &aring; f&aring; det p&aring; plass&raquo;. Videre skriver hun at hun endelig har lest manuset, og det er <em>ikke</em> antatt. Det st&oslash;rste problemet er at historien mangler undertekst og dramaturgi. Likevel: Hun liker ideen og sier at <em>det er ingen tvil om at jeg kan skrive.</em> Hun sp&oslash;r om hun kan ringe meg, og vi har en hyggelig samtale p&aring; telefonen om hva som m&aring; fikses i manus. Til slutt blir vi enige om at jeg skal sende inn p&aring; nytt utp&aring; h&oslash;sten. Jeg avlyser alle sommerplaner, l&aring;ner alt som finnes av b&oslash;ker om skriveh&aring;ndverket p&aring; biblioteket, og hver dag etter jobb ligger jeg p&aring; plenen utenfor blokka i Bergen og pr&oslash;ver &aring; finne ut hva <em>undertekst</em> er &ndash; og hvordan jeg skal f&aring; det inn i manus.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*H&oslash;st 2015: Etter tre m&aring;neder som eremitt sender jeg forn&oslash;yd inn ny versjon. Denne gangen f&aring;r jeg en konsulentuttalelse som konkluderer med at det fortsatt er store problemer i manus, b&aring;de med historien og med spr&aring;ket. Redakt&oslash;ren legger konsulentuttalelsen ved en mail hvor hun skriver (denne gangen oppfatter jeg en mer lunken tone), at &laquo;dersom jeg finner ut av disse problemene er jeg hjertelig velkommen til &aring; sende inn p&aring; nytt&raquo;. Men ingen av dem skriver noe om hva disse problemene konkret <em>er</em>. Jeg tolker mailen som at jeg har kastet bort sjansen til &aring; vise dem hva jeg er god for. I et anfall av stormannsgalskap (\"dersom dette forlaget tok kontakt etter f&oslash;rsteutkastet, kommer garantert flere forlag til &aring; v&aelig;re interesserte\") sender jeg manus til en h&aring;ndfull forlag til. Etter &aring; ha f&aring;tt standardrefusjon fra alle sammen bestemmer jeg meg for &aring; bruke livet p&aring; andre ting. Ta jobben min mer seri&oslash;st, og ta opp igjen noen av vennskapene jeg satte p&aring; vent til fordel for skriving.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*V&aring;r 2016: Jeg ser en annonse for <strong>Forfatterskolen </strong><a title=\"Forfatterskolen\" href=\"https://www.forfatterskolen.no/\" target=\"_blank\" rel=\"noopener\">(www.forfatterskolen.no)</a>. I siste liten melder jeg meg p&aring; romankurset, og en ny verden &aring;pner seg. Jeg m&oslash;ter mennesker som er interesserte i skriving. Folk som snakker om skriving. Tilbakemelding p&aring; tekst! Jeg er s&aring; gira at da rektor Kristine inviterer til vin&ndash; og pratekveld p&aring; Litteraturhuset i Oslo, tar jeg fri fra jobb for &aring; ta toget fra Bergen til hovedstaden. Jeg tilbringer noen herlige timer med de f&oslash;rste folkene jeg har m&oslash;tt som skriver, tar nattoget tilbake og g&aring;r rett p&aring; jobb i Bergen dagen etter. Jeg bestemmer meg for &aring; bruke kurset p&aring; &aring; skrive p&aring; noe nytt. Der \"Fritt fall\" f&oslash;ltes mer og mer som kvikksand, kjennes det nye prosjektet som &aring; l&oslash;pe med vinden i ryggen. P&aring; seks m&aring;neder fullf&oslash;rer jeg et utkast til en krimroman. Ikke bare det: Jeg v&aring;ger &aring; be om pilotlesere (som av en eller annen grunn er mye skumlere enn &aring; sende inn til forlag). Deres lesinger av manus gir meg flere aha-opplevelser. P&aring; slutten av sommeren sender jeg inn manuset til en h&aring;ndfull forlag.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*Sommer/h&oslash;st 2016: Jeg flytter til Spania. Allerede p&aring; flyplassen skjer det noe: Erfaringen med &aring; skrive krimromanen (der jeg fortsatt venter p&aring; svar fra forlagene), har satt i gang noe i hodet. \"Fritt fall\", som tidligere var en kronologisk historie om to jenter som m&oslash;ttes p&aring; fallskjermkurs og tok st&oslash;rre og st&oslash;rre risiko helt til den ene d&oslash;de i et basehopp, begynner &aring; endre form. Hva om jeg begynner med d&oslash;dsfallet? Hva om en av jentene d&oslash;r i starten av boka, og s&aring; pr&oslash;ver den andre &aring; finne ut hva som har skjedd? Jeg sitter i avgangshallen p&aring; Flesland og knoter ned disse tankene, pluss en haug med sp&oslash;rsm&aring;l: Hvorfor gikk basehoppet galt? Vil jeg at dette skal v&aelig;re en krim? Kanskje. Jeg elsker jo mysterier. Skal baseulykken v&aelig;re et drap? Nei, helst ikke, det f&oslash;les spekulativt. Kan jeg skrive en krim uten et drap? Skal det v&aelig;re et drap likevel, eller kanskje noe annet? Gj&oslash;r jeg dette vanskelig for meg selv? Med disse tankene ankommer jeg Sevilla. Og for et utgangspunkt! Den <em>ene</em> personen jeg kjenner i byen er bortreist, og i to uker har jeg ingen forpliktelser. Det er 40 grader i gatene og hodet mitt koker. Jeg skriver f&oslash;r frokost, etter frokost, vandrer rundt i parken og p&oslash;nsker p&aring; plottet, om ettermiddagen sitter jeg p&aring; verandaen med laptopen i fanget og ser ned p&aring; byen, skriver til langt p&aring; natt. Det eneste jeg gj&oslash;r utenom skriving er &aring; lese b&oslash;ker av typen jeg pr&oslash;ver &aring; skrive: Spenningshistorier som ikke er krimb&oslash;ker, alts&aring; romaner bygget opp rundt et mysterium, men som er fri for politietterforskere, seriemordere og ny fortellervinkel i hvert kapittel (mine ungdoms&aring;rs favoritter: Donna Tartt &ndash; Den hemmelige historien, Marisha Pessl &ndash; Utvalgte emner i katastrofefysikk, Daphine du Maurier &ndash; Rebecca). Etter to uker har jeg fullf&oslash;rt et slags f&oslash;rsteutkast. Det finnes ikke litter&aelig;rt og kapitlene er mer som skisser, men plottet er der, fra start til slutt. Jeg skal bruke resten av h&oslash;sten og vinteren p&aring; &aring; finpusse det. I l&oslash;pet av denne tiden f&aring;r jeg ogs&aring; tilbakemeldinger p&aring; krimmanuset jeg nesten hadde glemt: Fire standardrefusjoner og &eacute;n mail fra en redakt&oslash;r i et av de store forlagene. Hun skriver konkret hva hun liker og hva som ikke fungerer, og oppfordrer meg til &aring; skrive om manus og sende det inn p&aring; nytt. P&aring; dette tidspunktet har jeg f&aring;tt krimmanuset s&aring;pass p&aring; avstand at jeg ser en haug med andre utfordringer med det, blant annet min egen entusiasme for prosjektet (note to self: G&aring; aldri l&oslash;s p&aring; et romanprosjekt som du ikke brenner nok for til &aring; redigere i ti utkast)</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*V&aring;r 2017: Jeg har flyttet til Sverige og endelig fullf&oslash;rt \"Fritt fall\". Jeg bruker <strong>Forfatterskolens</strong> manushjelp, og f&aring;r mye oppmuntring samt gode tips til hvordan jeg kan heve det enda et par hakk. Halvannet &aring;r etter at jeg fikk beskjed av redakt&oslash;ren om &aring; jobbe mer med manus og sende det inn p&aring; nytt, gj&oslash;r jeg nettopp det. Denne gangen synes hun manuset er bra nok til &aring; invitere meg p&aring; et m&oslash;te.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" style=\"text-align: center;\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\"><span style=\"color: #ff0000;\"><strong>HURRA!</strong></span></div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*V&aring;r 2018: Tre m&oslash;ter senere er det fortsatt ting &aring; fikse i manus. Plottet sitter, sier forlaget, men de mellommenneskelige relasjonene har mye &aring; g&aring; p&aring;. Alt m&aring; intensiveres: Kan jentene v&aelig;re s&oslash;stre istedenfor venninner? Kan de ha kjent hverandre lenger og betydd mer for hverandre? Kan handlingen finne sted over kortere tid? Det er et komplisert plott og mye som skal klaffe. Jeg begynner &aring; bli lei av hele boka. Jo flere forfatterspirer jeg snakker med, jo flere historier h&oslash;rer jeg om folk som har g&aring;tt flere runder med forlag for s&aring; &aring; bli dumpet fordi man ikke kommer noen vei.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*Sommer/h&oslash;st 2018: Kvikksand-f&oslash;lelsen er tilbake, og jeg trenger ny inspirasjon dersom jeg skal skrive mer. Men plutselig bor jeg i Oslo! Her finnes mange muligheter for en aspirerende forfatter, for eksempel skrivekurs. Jeg s&oslash;ker p&aring; skrivekurs/manusworkshops hos fire av de store forlagene. Jeg kommer inn p&aring; alle sammen, og jeg takker ja til samtlige. Det f&oslash;les ekstremt tilfredsstillende &ndash; riktignok er jeg ikke i Eliteserien enn&aring;, men kanskje har jeg karret meg opp til en slags 1. divisjon?</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*H&oslash;st 2018/v&aring;r 2019: Jeg drukner i forfatterskole-innleveringer. Jeg pr&oslash;ver meg p&aring; &aring; skrive litter&aelig;re noveller og krimplott-synopsis, l&aelig;re teknikker og ikke minst: Jeg m&oslash;ter en haug med bra folk. I tillegg overhaler jeg hele \"Fritt fall\" p&aring; ny og pr&oslash;ver &aring; ta i bruk det jeg har l&aelig;rt. For eksempel &aring; v&aelig;re mindre essayistisk og mer <em>i &oslash;yeblikket</em>. Og, som en observant leser p&aring;peker: Det er en hel plotlinje som mangler. Historien handler om ei jente som mister s&oslash;steren i et basehopp. Men hvor blir sorgen av? Her m&aring; jeg innr&oslash;mme at jeg, i frykt for det melodramatiske, har skydd reaksjonen og skyldt p&aring; at hovedpersonen er i sjokk. Men etter denne tilbakemeldingen skj&oslash;nner jeg at jeg gjennom hele boka m&aring; legge inn et emosjonelt lag. Og historien, som tidligere hadde g&aring;tt fra en essayistisk utforsking av risiko til &aring; bli et mysterium, blir n&aring; ogs&aring; en historie om &aring; miste noen.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*Sommer 2019: Manus blir antatt. Beskjeden gj&oslash;r meg paff. Kan det virkelig stemme, etter s&aring; mange &aring;r med venting? Jeg klarer ikke ta det inn over meg. Heldigvis er det fortsatt mye &aring; gj&oslash;re, s&aring; jeg konsentrerer meg om &aring; fikse p&aring; de scenene jeg har f&aring;tt beskjed om &aring; fikse, og forteller det kun til n&aelig;re venner og familie.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">*Januar 2020: Aschehoug presenterer v&aring;rlista - og der er jeg og boka mi (!). F&oslash;rst n&aring; begynner det &aring; g&aring; opp for meg: Dette kommer til &aring; skje. Forh&aring;pentligvis fordi boka er blitt god?</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">Men ogs&aring; fordi jeg er sta, disiplinert og aldri ga opp.</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">Hilsen Sunniva</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\"><img src=\"/photos/Skjermbilde 2020-02-04 kl. 17.30.30.png\" alt=\"\" width=\"211\" height=\"278\" /></div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\"><em>Sunniva Vagstad (f.1987) er fra F&oslash;rde. Hun er ingeni&oslash;r i undervannsteknologi og har ogs&aring; en mastergrad i russisk. I ti &aring;r var Sunniva aktiv i fallskjermmilj&oslash;et p&aring; Voss. Hun har over 500 fallskjermhopp og to fjerdeplasser i NM.</em></div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\">&nbsp;</div>\r\n<div class=\"_3058 _ui9 _hh7 _6ybn _s1- _52mr _3oh-\" data-tooltip-content=\"Sunday 10:42am\" data-hover=\"tooltip\" data-tooltip-position=\"left\"><span style=\"color: #ff0000;\"><strong>PS! Vi er s&aring; stolte av deg, Sunniva! Hilsen rektor og hele Forfatterskolen-gjengen :-) Hurra for deg!</strong></span></div>\r\n</div>\r\n</div>\r\n</div>\r\n</div>','/storage/blog/1580834014.jpeg','Sunniva Vagstad','/storage/blog/author/1580834014.jpeg',1,'2020-02-04','2020-02-04 16:32:09','2020-02-04 17:08:25'),(24,1064,'Dokumentar: Isolasjon som metode','<p>Jeg fulgte webinaret om distanse til egen tekst med Terje Dragseth. Forjettet av hans kloke ord, tolket jeg budskapet om distanse til &aring; v&aelig;re en slags frigj&oslash;ring fra hemninger og folkeskikk. Som forfattere trenger vi ikke &aring; st&aring; til regnskap for hva v&aring;re karakterer finner p&aring;, som kunstnere er vi frie til &aring; bruke de virkemidler som trengs for &aring; kommunisere med kunst.</p>\r\n<p>Dette er en dokumentar. Jeg har v&aelig;rt observat&oslash;r og gjengir her noen av feltnotatene mine. Dragseths budskap hjalp meg med &aring; fullf&oslash;re feltrapporten jeg skrev for instituttet, etter feltoppdraget mitt.</p>\r\n<p>Jeg har fulgt et omdiskutert undervisningsopplegg der isolasjon er vesentlig. Metoden ble s&aring; omdiskutert at instituttet som driver studiet, valgte isolasjon som bedriftsstrategi. De er ikke &aring; spore p&aring; internett og de har et kryptisk organisasjonsnavn i formelle registre. Du skal kjenne godt til dem, for &aring; finne dem. Allikevel har de fulle studier. Studentene h&aring;ndplukkes, og hittil har ingen som har f&aring;tt tilbud, takket nei, kanskje p&aring;virket av at studentene l&oslash;nnes godt fra et velbesl&aring;tt legat. Dette er et kunststudium. Instituttets filosofi bygger p&aring; en tro p&aring; at hver og en av oss har et opprinnelig &lsquo;jeg&rsquo; som er up&aring;virket av omgivelsene. Ved isolering fra omgivelsene mener de &aring; tiln&aelig;rme seg dette jeg-et, og i den tilstanden p&aring;st&aring;s det at enhver finner sitt personlige kunstuttrykk, skrivestemme, malerstil og s&aring; videre. De mener det s&aring; sterkt at de lover erstatning for den som fullf&oslash;rer opplegget og ikke finner sitt personlige uttrykk. If&oslash;lge instituttleder har de aldri betalt ut erstatning. P&aring; mitt sp&oslash;rsm&aring;l om det skyldtes at de som ikke fant sitt &lsquo;jeg&rsquo; heller ikke fullf&oslash;rte studiet, fikk jeg bare et blikk som sa sitt. Jeg var innenfor og ville observere fenomenet, og jeg ville for all del ikke bli kastet ut. Jeg spurte ikke mer.</p>\r\n<p>Forutsetningen for &aring; delta, var at jeg selv gikk i isolasjon. F&oslash;r jeg kom s&aring; langt i prosessen var jeg igjennom en lang rekke pr&oslash;velser for &aring; vise meg tilliten verdig, og jeg signerte en stabel dokumenter for beskyttelse av instituttet. Det sto ingenting om &aring; delta i skrivekonkurranser, s&aring; jeg tar sjansen p&aring; &aring; f&aring; formidlet det jeg har erfart p&aring; denne m&aring;ten. Skulle noe tilfalle meg, vil det komme e-post til rette instanser der jeg avsl&oslash;rer og deler hele feltrapporten. De er lagt til &laquo;send&raquo; p&aring; et gitt klokkeslett, en uke frem i tid. N&aring;r tiden n&aelig;rmer seg g&aring;r jeg inn og redigerer utsendingsdato til en ny uke fram i tid. Slik fortsetter jeg, uke etter uke, s&aring; lenge jeg er tilgjengelig og i live. Jeg har selvsagt en plan B om det skulle bli n&oslash;dvendig, men den kan jeg ikke r&oslash;pe her.</p>\r\n<p>Jeg kjente til instituttet da en n&aelig;r venn av meg avsl&oslash;rte oppskriften p&aring; suksess, mens han l&aring; p&aring; d&oslash;dsleiet. Hans ord forblir mellom oss, men de gjorde inntrykk. Min venn gjorde stor suksess som poet etter &aring; ha v&aelig;rt student der, og han uttrykte stor takknemlighet over &aring; ha f&aring;tt muligheten. Instituttet spurte, merkelig nok, ikke hvordan jeg kjente til dem og metoden deres, som om de visste.</p>\r\n<p>Instituttets ansatte er lidenskapelig opptatt av isolasjon som metode, men ogs&aring; underern&aelig;rt p&aring; smiger. Det, samt det at jeg sa meg villig til &aring; g&aring; i isolasjon under min observasjon, gjorde nok utslaget til at jeg smatt s&aring; lett inn. Jeg ble nok et friskt objekt i deres isolerte tilv&aelig;relse. Jeg er overbevist om at jeg ble observert hele tiden, og til tider f&oslash;les det som jeg fortsatt blir observert.</p>\r\n<p>Studentene blir isolert i &laquo;Big-Brother-hybler&raquo;. Vinduer har innsyn, men ikke utsynsmulighet. Hyblene har kunstig lys, og er sparsommelig og n&oslash;ytralt innredet. Ingen lyder eller andre inntrykk slipper inn. Kameraer filmer absolutt alle deler av hyblene. Studentene isoleres i perioder i disse hyblene. I korte mellomperioder er de utenfor hyblene for evaluering, veiledning, trening og helsemessig oppf&oslash;lging. Hver student er tatt inn for rendyrking av det personlige innenfor snevre kunstgreiner, multikunstnere som meg ville neppe f&aring;tt studietilbud. Kanskje var nettopp mitt mangfold med &aring; vekke nysgjerrighet hos instituttet, en annerledes student, et annerledes objekt; avviket.</p>\r\n<p>Jeg ble vennlig innlosjert i samme type hybel som studentene. I arbeidsstua mi var det et panel med skjermer fra studentenes hybler. Via datamaskinen kunne jeg selv dirigere hvem jeg ville f&oslash;lge og hvor detaljert jeg ville se. Jeg fikk tilgang til alt. De eneste impulsene jeg fikk inn var lyder og bilder fra de andre studentene. Jeg f&oslash;rte feltlogg og skrev notater. En av de ansatte p&aring; instituttet var min veileder. Jeg var i felt, sa hun, derav feltlogg. Jeg tror hun har milit&aelig;r bakgrunn, hun pratet i alle fall som gamle offiserer, hardt og stakkato: &laquo;Mellem, meld feltrapp. daglig klokken 12 null null, presis. Forst&aring;tt?&raquo; Jeg likte henne, klarheten ga meg trygghet. Studentene startet sin tredje isolasjonsperiode idet jeg startet min enm&aring;neds feltobservasjon fra &laquo;Big-Brother-hybel&raquo; K.</p>\r\n<p><strong>Utdrag fra daglig f&oslash;rt feltlogg:</strong></p>\r\n<p><strong>Dag 1</strong>: Jeg har brukt dagen til &aring; bli kjent med de 10 studentene som er i isolasjon n&aring;. Bestemt meg for &aring; f&oslash;lge tre av dem n&aelig;rmere: En kunstmaler, en sangerinne og en som lager ting av leire. Spennende &aring; grafse i privatlivene deres.</p>\r\n<p><strong>Dag 2</strong>: Kunstmaleren danser ballett n&aring;r han maler; at han ikke griser mer er meg en g&aring;te. Sangerinnen h&oslash;res ut som et klokkespill. Hun har brukt nesten hele dagen p&aring; &aring; &oslash;ve p&aring; tre toner. Mannen med leire har jobbet med samme klump siden tidlig i morges, og jeg klarer fortsatt ikke &aring; se hva han lager. Jeg er tr&oslash;tt og tar tidlig kvelden.</p>\r\n<p><strong>Dag 3</strong>: I dag mistet kunstmaleren paletten i gulvet, med malingen ned. Han s&aring; glad ut, og danset barbeint i malingen, p&aring; gulvet. Etter noen piruetter hadde han malt en nydelig rose p&aring; gulvet. Sangerinnen sang enda lysere i dag, som en engel, mennesker kan ikke ha s&aring; lys stemme. Mannen med leireklumpen er rar. I dag satte han seg p&aring; leireklumpen og fikk rumpeavtrykk i leira. Jeg fikk skjenn fra veileder da jeg rapporterte 2 minutter for seint.</p>\r\n<p><strong>Dag 4</strong>: Kunstmaleren har brukt hele dagen p&aring; &aring; grunne et lerret med gull-maling. Fra sangerinnen kom det fuglesang mens hun danset og fjernet h&aring;r fra leggene. Raringen med leiren har satt rumpeavtrykket i ramme. Jeg lurer stundevis p&aring; om jeg observerer rett.</p>\r\n<p><strong>Dag 5</strong>: Migrene. Medisinen hjemme. M&aring;tte sl&aring; av skjermene, og lyd da sangerinnen hadde motorsagstemme. Jeg orket ikke kontakte veileder.</p>\r\n<p><strong>Dag 6</strong>: Formen er mye bedre, tralala. Jeg startet dagen med &aring; omm&oslash;blere hybelen. Hang kunstmalerskjermen oppned, sangerinneskjermen p&aring; steikovnsd&oslash;ra og skjermen med leiremannen brukte jeg som telysfat. Hadde kosedag, helt til samtalen med veileder. Fikk tilsnakk. B&aring;de for &aring; unnlate &aring; melde dagen f&oslash;r, og for omm&oslash;bleringen, de hadde sett alt, absolutt alt jeg hadde foretatt meg. M&aring;tte omm&oslash;blere p&aring; plass igjen.</p>\r\n<p><strong>Dag 8</strong>: Merkelig dag. Kunstmaleren malte et bilde oppned. Sangerinnen sang med grillp&oslash;lse som mikrofon og leiremannen hadde stilt arbeidslampen sin rett mot kameraet mitt, s&aring; jeg ble</p>\r\n<p>blendet. Jeg klagde til veileder. Hun lo for f&oslash;rste gang siden vi m&oslash;ttes.</p>\r\n<p><strong>Dag 10</strong>: En malermester maler som en malermester kan, oh yeah, og sangerinner synger som tralletriller, tralala og leireri og leirera, tralala. En skikkelig fin dag, jeg har sett musikk p&aring; alle skjermer. Jeg trallet litt for veileder, som sa &laquo;hm, legg deg Mellem&raquo;.</p>\r\n<p><strong>Dag 13</strong>: Ballettdanseren med penslene, for et syn alts&aring;, jeg kan se p&aring; han heeeeele dagen, s&aring;&aring;&aring;&aring; vakker. Lurer forresten p&aring; om sangerinnen er min ukjente niese, hun er en skj&oslash;nnhet, og vi ligner skikkelig. Leiremannen var naken med leira i dag, s&aring;nt kan ikke en dame i isolasjon se p&aring;. Veileder virket forn&oslash;yd i dag.</p>\r\n<p><strong>Dag 17</strong>: &Aring; danse med maling</p>\r\n<p>v&aelig;re en darling</p>\r\n<p>synge til meg</p>\r\n<p>v&aelig;re som meg</p>\r\n<p>leire sin stas</p>\r\n<p>v&aelig;re bajas</p>\r\n<p>Veileder ba meg si fra om jeg ville ut av isolasjonen. Min tur til &aring; le.</p>\r\n<p><strong>Dag 20</strong>: I dag ville jeg. Har danset ballett og dekorert de kjedelige veggene med ketchup. Sang og spilte inn en ikke s&aring; verst musikkvideo. La den ut p&aring; Youtube under veileders navn. Avsluttet dagen inspirert av leiremannen og lagde avtrykk av nesen min i brunosten. Veileder svarte ikke. For en fantastisk dag det har v&aelig;rt!</p>\r\n<p><strong>Dag 23</strong>: Jeg er i flyt for tida, holder p&aring; med en statue. Dataskjermene ble perfekte som kropp. Og doringen ganske morsom som hode. Jeg har lyst til &aring; lage mer.</p>\r\n<p>&laquo;Mellem, har du glemt feltoppdraget?&raquo;</p>\r\n<p><strong>Dag 25</strong>: Det ble flere statuer i natt, senga gikk med til skjeletter. N&aring; er jeg tom for materialer. Vann lekker utover kj&oslash;kkengulvet, jeg trengte r&oslash;rene til armer. F&oslash;ler, s&aring; mye. Jeg er Therese Johaug p&aring; tur inn til tidenes seier.</p>\r\n<p>&laquo;Mellem, feltobservasjonen avbrytes, n&aring;!&raquo;<strong>&nbsp;</strong></p>\r\n<p><strong>Klipp fra mine notater i ettertid:</strong></p>\r\n<p>Jeg var ganske sikkert et interessant objekt, som hadde respondert kraftig p&aring; isolasjonsmetoden. Veileder dro ut proppen og skysset meg til et legeteam. Omgitt av eksperter som m&aring;lte og vurderte meg inn og ut, dr&oslash;mte jeg fortsatt om statuer. Selv med alle de menneskene rundt meg, gravende i min fysiske og psykiske helse, var jeg fortsatt isolert. Instituttet fant meg ikke, men jeg var der. Jeg tok farvel med veileder, mens instituttleder sa p&aring; gjensyn.</p>\r\n<p>Gradvis slapp trangen til &aring; bygge statuer og skrive syngende, heldigvis. Tilsynelatende som f&oslash;r, men det er nok bare en illusjon. Jeg har innredet et rom i huset mitt, sparsommelig og n&oslash;ytralt, jeg kaller det rom K. I rom K finner jeg raskt tilbake til mitt &lsquo;jeg&rsquo;, meg, og mine preg, som skrivestemmen min. Sitter i rom K n&aring;, og ordene sitter l&oslash;st, det virker, metoden isolasjon virker. Men f&oslash;lelsen av &oslash;yne i nakken hemmer meg litt, derfor m&aring; noe forbli mellom linjene her.</p>\r\n<p><strong>Fra feltrapporten, konklusjon:</strong></p>\r\n<p>Isolasjon som metode kan bidra til distanse til egen tekst. Isolasjon bidrar til frigj&oslash;ring fra hemninger og folkeskikk. I isolasjonen er det ingen &aring; st&aring; til regnskap for, og i isolasjonen utviskes grenser. Isolasjon gir frihet.</p>\r\n<p>Kildeliste er selvsagt utelatt.</p>\r\n<p>Rom K, 26.03.2020</p>\r\n<p>Jeg, meg, Mellem</p>','/storage/blog/1587129504.jpeg','Karin Rognmo Mellem','/storage/blog/author/1587129504.png',1,'2020-04-19','2020-04-17 13:18:24','2020-04-20 06:32:06'),(27,1064,'Isolasjon','<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som st&aring;r aleine</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">med ei diger b&oslash;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og einsam s&oslash;rgar og lengtar</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">til livet du hadde f&oslash;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som m&oslash;tte stengte vegar</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">der du helst ville g&aring;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">til deg som pr&oslash;vde alt</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og tilslutt ikkje visste r&aring;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som vart utsatt for noko</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">du gjekk heilt aleine med</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som ikkje vart trudd</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">d&aring; du fekk mot til &aring; dele det</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som s&aring;g klart f&oslash;r dei andre</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og sa kva for veg det bar</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">dei andre lo og smilte</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og kalla deg gal og rar</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som vart ramma av sjukdom</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">i dine beste &aring;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som ikkje kan hugse</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">det spira fordi det var v&aring;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som pleier eit barn som er sjukt</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og bruker all tida p&aring; det</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som m&aring; kjempe ei bitter strid</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">for &aring; f&aring; r&aring; til graut og ved</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som mista det menneske</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">du hadde s&aring; inderleg kj&aelig;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som f&oslash;ler at aldri igjen</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">kan nokon komme deg n&aelig;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som er gammal og sliten</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og synest at du har gitt alt</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">no er du gl&oslash;ymt av alle</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">dei er travle i livets tralt</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som er i eit m&oslash;rke</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">ingen heilt forst&aring;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som kjenner eksistensen</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">som ein pr&oslash;ve i harde k&aring;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Til deg som m&aring; finne din styrke</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">til &aring; leve kvar einaste dag</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">fordi det er ingen som seier</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">kom - me skal gjere det i lag</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">II</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">No skrik dei p&aring; redningspakkar</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">etter ein dag og to</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">dei som levde livet</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">mens ditt stod heilt i ro</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Regjeringa blar opp sedlar</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">gir midlar utan stans</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&ograve;g for &aring; redde maskineri</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">som er tufta p&aring; ignorans</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">III</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Men er det ikkje du</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">som er sterkast rusta no?</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Fordi du har vorte vant til</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&aring; ikkje vere to</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Og kanskje kan du nyte</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">det livet som veks fram</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">n&aring;r ingen hastar omkring meir</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og trafikken st&aring;r der lam</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Kan hende er det du</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">som kan merke aller f&oslash;rst</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">n&aring;r nokon har det tungt</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">og treng gode ord og tr&oslash;st</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">&nbsp;</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">Om mogleg kan du puste</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">litt friare enn f&oslash;r</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">n&aring;r det ikkje kun er du</p>\r\n<p style=\"padding-left: 30px; text-align: center;\">som ber ei diger b&oslash;r</p>','/storage/blog/1587392826.jpeg','Hanna With',NULL,1,'2020-04-20','2020-04-20 14:27:06','2020-04-20 14:28:10'),(28,1064,'Dype røtter','<p>Jeg leste avisartikkelen igjen, og stirret p&aring; summen som sto i fet skrift. Tre millioner, for tre uker i en hytte i skogen. Det eneste kravet var at man ikke snakket med noen i tre uker, og at man ikke fortalte om hva som skjedde der. Hadde det ikke v&aelig;rt multimillion&aelig;r August Abrahamsen som utlyste konkurransen, ville jeg trodd det var lureri. Men han var kjent for &aring; gj&oslash;re uvanlige ting. Jeg hadde h&oslash;rt navnet hans i sammenheng med farfar sitt, like etter at farfar forsvant, og det hadde festet seg. Farfar var den i familien som alltid skj&oslash;nte meg, som fikk meg til &aring; skj&oslash;nne meg selv.</p>\r\n<p>&Aring; ikke prate med noen p&aring; tre uker, det greide jeg lett. Jeg snakket knapt med noen n&aring; heller, hverken p&aring; lageret eller p&aring; fritiden. Men &aring; aldri fortelle noen om opplevelsen etterp&aring;? Hva var grunnen til det? Fikk August kj&oslash;pe tausheten min for tre millioner kroner?</p>\r\n<p>Det sto en ny artikkel om utlysningen neste morgen, men ikke noe om meg. Instruksjonene var korte; veibeskrivelse, en liste over hva jeg trengte &aring; ta med, en p&aring;minnelse om at tausheten var helt avgj&oslash;rende, og en ting til; det kom til &aring; ligge en notatbok p&aring; hytta. Jeg skulle skrive ned alt som skjedde i den, og la den ligge igjen n&aring;r jeg dro.</p>\r\n<p>Tre timer med bil inn i svarteste skogen, uten &aring; se annet tegn til mennesker enn den stadig d&aring;rligere veien. Jeg ante ikke at skogen var s&aring; dyp. Jeg stoppet for &aring; tisse. Tr&aelig;rne raget h&oslash;yt, som om de pr&oslash;vde &aring; stenge meg vekk fra himmelen, skjule meg, gjemme meg vekk. Fuktig luft fylte kup&eacute;en da jeg satt meg tilbake.</p>\r\n<p>Det f&oslash;rste jeg gjorde da jeg parkerte, var &aring; dobbeltsjekke at det var nok bensin p&aring; tanken til &aring; kj&oslash;re ut igjen. Fornemmelsen av &aring; ha kj&oslash;rt inn i magen p&aring; et enormt vesen, vokste hele tiden, og jeg hadde ingen planer om &aring; bli lenger enn n&oslash;dvendig. Hytta var av enkleste sort, og pipa var skeiv og sotete. D&oslash;ren var ul&aring;st, som beskrevet. Inne var alt i ett rom, og selv om det var midt p&aring; dagen, var det halvm&oslash;rkt, s&aring; h&oslash;ye var tr&aelig;rne p&aring; utsiden. Hva skulle en av landets rikeste menn med dette her? Det hadde v&aelig;rt noen der nylig. Vinduskarmene var frie for d&oslash;de fluer, ved l&aring; pent stablet ved peisen, og en gr&oslash;nn notatbok l&aring; p&aring; spisebordet. Jeg skulle greie &aring; v&aelig;re her i tre uker. Det kom til &aring; g&aring; helt fint, og etterp&aring; kom jeg til &aring; v&aelig;re million&aelig;r. Jeg slang fra meg sekken, satt meg p&aring; pinnestolen og &aring;pnet notatboka; tom. Tre millioner, hva skulle jeg bruke de p&aring;? En b&aring;t kanskje, en jeg kunne sove i. Jeg trakk til meg boka, og tok hetta av pennen. Skriv det som skjer, det var den eneste instruksjonen. S&aring; jeg skrev om kj&oslash;returen inn. Det ble ikke mer enn en halv side. Jeg skulle til &aring; lukke boka, men bestemte meg for &aring; skrive om tr&aelig;rne ogs&aring;, om hvordan de omtrent vokste seg m&oslash;rkere og tettere over hodet p&aring; meg.</p>\r\n<p>Etter &aring; ha pakket ut kl&aelig;rne og b&oslash;kene, bestemte jeg meg for &aring; g&aring; ut, for &aring; se om jeg kunne bli mer komfortabel med skogen. Ti meter inn mellom tr&aelig;rne, oppdaget jeg at veien tilbake var borte. Et vindkast rusket gjennom skogen: &laquo;Vekk.&raquo; Hjertet dunket, som om kroppen min med ett kom p&aring; alt den kunne d&oslash; av. Jeg kavet meg vei tilbake mellom de laveste greinene, snublet bakover, ut p&aring; plassen ved hytta. Med luft p&aring; alle kanter, la jeg meg p&aring; ryggen i gresset og stirret p&aring; himmelen h&oslash;yet der oppe, til hjertet slo normalt igjen.</p>\r\n<p>Skogen var unaturlig stille hele kvelden. Bodde det ingen fugler her? N&aring;r jeg tenkte meg om, hadde jeg ikke sett et eneste dyr heller. Ikke en gang en mygg, bare d&oslash;de fluer. Var det bare meg og tr&aelig;rne her? Jeg gr&oslash;sset. Alene i byen var en ting, det var jeg vant til. Den skogen her, derimot. M&oslash;rket tetnet, og noe utenfor krafset oppetter veggene, over taket, mot ytterd&oslash;ren. Jo mer jeg pr&oslash;vde &aring; ignorere det, jo h&oslash;yere ble det. Det var sikkert bare greiner, men til slutt gikk jeg for &aring; l&aring;se d&oslash;ren, bare for &aring; bli minnet p&aring; at den ikke hadde noen l&aring;s. Trengte vel ikke det, hvis det ikke var noen levende her ute. Jeg kr&oslash;p under dyna, og ble liggende &aring; stirret ut i m&oslash;rket. Grafsingen ga seg ikke. F&oslash;rst neste morgen kom jeg p&aring; at ingen tr&aelig;r sto n&aelig;r nok til &aring; rekke frem til hytteveggen. Jeg skrev det ned i boka og lot som om jeg ikke gruet meg til neste natt.</p>\r\n<p>Jeg sov ikke de tre neste nettene heller, og kveldene, n&aring;r det m&oslash;rknet, fylte hodet mitt med hvisking, mer som vage bilder enn som ord; av r&aring;tne greiner, dryppende lav, og svart m&oslash;rke. S&aring; jeg sov p&aring; formiddagene i stedet. Og skrev i boka p&aring; ettermiddagene. Det var ikke noe &aring; skrive om annet enn hva jeg spiste, og hva jeg h&oslash;rte tr&aelig;rne si. August kom til &aring; tro jeg var gal, men det var ikke en del av betingelsene at jeg skulle fremst&aring; rasjonell og fornuftig. Hva han mente om meg, bekymret meg ikke. Den fjerde natten orket jeg ikke mer, det luktet s&aring; kraftig frykt av senget&oslash;yet at jeg ikke fikk meg til &aring; legge meg i sengen. Isteden tok jeg p&aring; meg ulljakken som hang p&aring; knaggen ved d&oslash;ren, stakk f&oslash;ttene i et par slagst&oslash;vler, trakk pusten dypt og skubbet d&oslash;ren opp med hoften. Det var beksvart, umulig &aring; skjelne noe, men grafsingen stoppet i det jeg gikk ut. Med en h&aring;nd p&aring; den ru hytteveggen, snublet jeg rundt hele hytta. Ingen greiner rispet meg p&aring; kinnet eller lugget meg i h&aring;ret. Tilbake ved d&oslash;ren kikket jeg opp. Stjerner blinket p&aring; himmelen, gule og gr&oslash;nne, lilla og r&oslash;de. Jeg sank ned p&aring; trammen og fortsatte &aring; stirre p&aring; dem. F&oslash;rst da jeg hakket tenner, gikk jeg inn. Det var helt stille ute, da jeg la meg under dyna igjen.</p>\r\n<p>Neste morgen bestemte jeg meg for &aring; g&aring; inn i skogen igjen. &Aring; gjemme seg i hytta gjorde meg frynsete. Jeg markerte veien med brukne greiner, som pekte tilbake mot forrige brukne grein. Det bl&aring;ste kraftig, men nede p&aring; skogbunnen var det like vindstille som alltid. Det var ingen stemmer i tr&aelig;rne, og det ble raskt kjedelig, og for &aring; gj&oslash;re ting verre, startet det &aring; regne. Det var juni, men dr&aring;pene var iskalde, og jeg var gjennomv&aring;t innen jeg kom tilbake til hytta. For &aring; varme meg, bestemte jeg meg for &aring; fyre i peisen. Mellom vedkubbene l&aring; det en lapp. &laquo;Ikke hogg eller sank annen ved enn den som er i stabelen utenfor.&raquo; Jeg tillot meg ikke &aring; tenke p&aring; hva som var grunnen. Med et pledd over skuldrene, skrev jeg i boka mens jeg tinte foran flammene. Kl&aelig;rne dampet fra stolen ved siden av meg. Det var nesten som om jeg hadde selskap. Jeg kjente det p&aring; meg da, hvor alene jeg var her ute. Hvis noe skjedde, kom ingen til &aring; f&aring; vite det f&oslash;r August kom for &aring; se hva som skjedde.</p>\r\n<p>Det sluttet ikke &aring; bl&aring;se den natten. Jeg l&aring; der i dypet av tr&aelig;rne og h&oslash;rte vinden ruske i trekronene. Det var som om jeg l&aring; under jorda, og var en del av r&oslash;ttene. Selv om det virket umulig, m&aring; jeg ha sovnet, for r&oslash;ttene begynte &aring; snakke til meg. Eller, jeg begynte &aring; forst&aring; hva som fylte stillheten mellom dem. Forst&aring; hvor levende jorda var, hvor rikt regnvannet var. En f&oslash;lelse av &aring; aldri trenge &aring; bevege meg igjen, bare suge opp n&aelig;ringen og vokse. Av &aring; v&aelig;re forbundet med hele skogen, s&aring; enorm at den f&oslash;ltes altoppslukende. S&aring; klar over alt som var der ute, uten &aring; trenge &aring; gj&oslash;re noe. Jeg kjente inni meg, den &aring;pne plassen hytta st&aring;r p&aring;, r&oslash;ttene som l&aring; under og som holdt nye spirer fra &aring; gro der. Det var en avtale her et sted, plassen ble holdt av. Men det lille bankende hjertet der inne, var ikke del av avtalen, ikke del av skogen. F&oslash;rst da jeg v&aring;knet skj&oslash;nte jeg at det var meg selv jeg hadde f&oslash;lt.</p>\r\n<p>Bare &aring; kle seg, og spise, var en enorm mengde bevegelser, etter &aring; ha kjent hvor stille r&oslash;ttene l&aring;, &aring;r etter &aring;r. Jeg tok med notatboka og satte meg i gresset inntil hytteveggen. Kroppen sank ned mot jorda, og jeg l&aring; der og levde, helt til ettermiddagssolen forsvant bak tretoppene. Boksidene var kr&oslash;llete av fukt da jeg gikk inn. Resten av kvelden satt jeg foran peisen, med ullpledd over kn&aelig;rne. Men jeg fyrte ikke opp, jeg spiste ingenting. Drakk bare litt, f&oslash;r jeg sovnet. S&aring;nn fortsatte jeg &aring; leve, mens lyset kom og gikk, uten en eneste verbal tanke, bare f&oslash;lelsen av luft og jord og vann. En ettermiddag jeg l&aring; p&aring; ryggen p&aring; gresset utenfor hytta, fuktig p&aring; genserryggen og med lukkede &oslash;yne, gikk det et st&oslash;t gjennom oss. Det var som om vi ble revet opp, hver og en av oss, mistet taket i jorda og braste gjennom oss selv, mens kvistene sprakte og brakk rundt oss. Et dr&oslash;nn, s&aring; ble det stille. Ingen trakk pusten. Jeg satte meg opp og ristet jord ut av h&aring;ret. Kikket ned p&aring; de nakne f&oslash;ttene, s&oslash;lete og kalde, p&aring; hendene, s&oslash;rgerender under neglene. Hvor lenge hadde jeg ligget der, overbevist om at jeg var et tre? Kroppen var seig og treg da jeg stavret meg inn i hytta. Jeg styrtet et glass med lunket vann, og smaken av myr fikk meg til &aring; grine p&aring; nesen. Jeg skrubbet hendene og f&oslash;ttene, tok p&aring; meg rene kl&aelig;r og pusset tennene. S&aring; tok jeg en romtemperert &oslash;l fra sekspakningen p&aring; kj&oslash;kkenbenken og &aring;pnet notatboka. Pennen f&oslash;ltes rar i fingrene. F&oslash;rst greide jeg bare &aring; krafse noen streker, men sakte husket kroppen min at den var et menneske. Jeg skrev til fingrene var stive av &aring; holde pennen, jeg pr&oslash;vde &aring; f&aring; mening ut av det som hadde skjedd. Men det ble bare vas, og jeg ble bare mer forvirret, s&aring; til slutt lukket jeg boka. August fikk lese det han greide ut av det. Jeg skrudde p&aring; mp3-spilleren og la meg p&aring; senga. Skrudde volumet s&aring; h&oslash;yt jeg orket og lukket &oslash;ynene. Den var tom for batteri da jeg v&aring;knet neste morgen. Desperat etter &aring; holde p&aring; f&oslash;lelsen av &aring; v&aelig;re en person, drakk jeg to kopper kaffe, og spiste en hel pakke bacon, f&oslash;r jeg kledde meg og plukket opp &oslash;ksa ved inngangsd&oslash;ren. Med &oslash;ksa over skulderen, marsjerte jeg inn i skogen og pr&oslash;vde &aring; ignorere svetten som piplet frem i h&aring;ndflaten. Jeg tok meg ikke bryet med &aring; merke veien, jeg ville ikke innr&oslash;mme det, men jeg kunne ikke g&aring; meg vill n&aring;, etter &aring; ha levd med r&oslash;ttene. Det ble tyngre og tyngre &aring; g&aring;. Greinene tettet seg, festet seg i kl&aelig;rne mine. Til slutt kom jeg ikke lenger. S&aring; fikk det bli her. Jeg heftet &oslash;ksa, trakk pusten, og l&oslash;ftet den over hodet. Den hektet seg i en grein. Hendene mine kom tomme ned. Jeg rygget bakover, snudde og l&oslash;p.</p>\r\n<p>Det tok flere dager f&oslash;r jeg v&aring;get meg ut p&aring; trammen igjen, og da var det fordi jeg hadde f&aring;tt nok av alt. Jeg sm&aring;l&oslash;p bort til bilen og slang meg inn. Hvis jeg kj&oslash;rte ut n&aring;, skrev noe v&aring;s i boka, og kj&oslash;rte tilbake igjen den siste dagen, kunne August umulig vite at jeg hadde v&aelig;rt vekk. Det var bare &eacute;n ting, n&aring; som jeg satt der og s&aring; p&aring; dashbordet. Jeg hadde ikke nok bensin til &aring; kj&oslash;re frem og tilbake s&aring;nn. Med et sukk, sank jeg tilbake i setet. Jeg satt til det m&oslash;rknet.</p>\r\n<p>Den natta krafset det verre enn noen gang, det var som om greinene var under senga, og i taket p&aring; rommet. Da jeg sto opp hadde jeg risper oppetter armene, noen s&aring; forsiktige at huden knapt var hvit, andre s&aring; dype at bloddr&aring;per hadde piplet frem og st&oslash;rknet. Det var som &aring; stryke fingrene over bark. Leggene og l&aring;rene mine var like oppskrapet. Jeg trakk av meg T-skjorten; rispene gikk i kryss og tvers over magen. Jeg hadde ikke dr&oslash;mt noe i natt, knapt sovet. Hendene mine skalv da jeg satt over vann til kaffen. Det hadde ikke v&aelig;rt noen stemmer i natt, ingen bilder. F&oslash;ttene mine var rene, jeg hadde ikke g&aring;tt i s&oslash;vne. Jo mer jeg pr&oslash;vde &aring; finne en naturlig forklaring, jo mer plaget huden meg. Den kl&oslash;dde s&aring; jeg nesten ikke klarte &aring; tenke. Jeg pr&oslash;vde &aring; fortelle meg selv at det var fordi s&aring;rene grodde, men det f&oslash;ltes mer ut som om huden strakk seg, gjorde plass til at jeg skulle vokse, sprakk opp. Og jeg ble bare t&oslash;rstere og t&oslash;rstere. Til slutt m&aring;tte jeg bort til vannb&oslash;tta. Tom. Jeg ville ikke ut, men jeg kunne ikke vente, t&oslash;rsten var desperat. Jeg tok med b&oslash;tta, stakk f&oslash;ttene i skoene, og med &oslash;ynene stivt festet p&aring; bakken, som om jeg var redd for blikkontakt, skyndet jeg meg nedover mot elven. Vannet rant klart og kaldt over steinbunnen, og jeg hadde ikke t&aring;lmodighet til &aring; g&aring; tilbake, s&aring; jeg la meg p&aring; magen og drakk til det verket i tennene. Kl&oslash;ingen ga seg. Med et sukk rullet jeg over p&aring; ryggen. Fri for ubehaget, ble jeg oppmerksom p&aring; en ny f&oslash;lelse. Jeg var helt klart ikke alene her ute. Men jeg var heller ikke en inntrenger. Jeg pustet ikke gjennom h&aring;ret, og drakk ikke med t&aelig;rne, men jeg var ikke s&aring; annerledes heller. Ikke her jeg l&aring; med oppsprukket hud og sevje som rant langsomt gjennom &aring;rene. Jeg greide ikke &aring; skille mellom hva som var meg, og hva som var skogen, men ulikt sist, visste jeg at jeg var noe, selv om jeg var en del av alt det andre. Ikke lenger redd, bar jeg b&oslash;tta tilbake og begynte &aring; pakke en sekk. Hvis krafsende greiner skulle holde meg v&aring;ken i natt, ville jeg se dem.</p>\r\n<p>Ingen greiner holdt meg igjen, ingen r&oslash;tter spente bein. Jeg gikk ikke fort, men det var tungt &aring; g&aring; likevel. Til slutt rullet jeg ut teppene, spiste, og la meg til &aring; sove. Jeg v&aring;knet av at jeg var gjennomv&aring;t. Med hakkende tenner og panneluggen i &oslash;ynene, kr&oslash;p jeg sammen inntil en stamme og ventet p&aring; at det skulle lysne. Men regnet ga seg ikke, og sakte mistet jeg f&oslash;lelse i fingrene og t&aelig;rne. Jeg m&aring;tte tilbake til hytta og peisen. Med tak rundt en lav grein, halte jeg meg opp p&aring; beina. Pr&oslash;vde &aring; puste sakte, beholde roen. Men hvilke retning skulle jeg g&aring;? Skogen var like svart enten jeg hadde &oslash;ynene &aring;pne eller lukket. Med h&aring;ndflaten mot sleip bark, sank jeg ned p&aring; kne, og lente hodet mot stammen. Jeg kom til &aring; d&oslash; her ute, bli tatt opp av tr&aelig;rne, leve videre for alltid, blant dem.</p>\r\n<p>Jeg l&aring; naken i sengen, pakket inn i tre dyner og to pledd. Kanskje b&aring;ten hadde bl&aring;st p&aring; land? Nei, jeg var fortsatt i hytta, i skogen. Tr&aelig;rne var stille. Jeg trakk av meg dynene, huden min var helt glatt. Hadde jeg dr&oslash;mt alt? Ved kj&oslash;kkenbenken l&aring; haugen med v&aring;te kl&aelig;r og sekken jeg hadde hatt med. Jeg gjorde det eneste jeg kunne her ute, n&aring;r jeg ikke hadde noen &aring; diskutere med. Jeg skrev i notatboka, ute p&aring; trammen, med et pledd over skuldrene og en rykende kopp kaffe ved siden av meg. Jeg vet ikke hvor lenge jeg hadde stirret &aring;ndesl&oslash;s mot tr&aelig;rne, da jeg h&oslash;rte lyden av en bilmotor. Like etter humpet en st&oslash;vete Mercedes opp til hytta. Ut hoppet August. Han s&aring; yngre ut her ute, enn p&aring; bildet i avisen. Ren, velstelt, nesten som om han var laget av plast. Han luktet ikke noe heller, da han kom bort til meg p&aring; trammen. Det var som om det skjedde s&aring; mye p&aring; en gang, s&aring; fort, at jeg ikke hang med. Han rakk h&aring;nda frem etter boka. Jeg ga ham den. Fingrene hans bladde tre sider tilbake, til han s&aring; dagens dato, f&oslash;r han nikket og holdt den inntil brystet.</p>\r\n<p>&laquo;Er du sulten?&raquo; Selv stemmen hans var kvikk.</p>\r\n<p>Jeg nikket.</p>\r\n<p>&laquo;Jeg skal lage noe til oss.&raquo;</p>\r\n<p>Han forsvant inn. Jeg lot alt synke inn. Jeg var ferdig, kunne dra hjem. Men ferdig med hva? Hjem til hva? Og hva var det jeg etterlot meg her? Han s&aring; p&aring; meg over bordet.</p>\r\n<p>&laquo;S&aring;, hvordan har det v&aelig;rt?&raquo;</p>\r\n<p>Jeg kl&oslash;dde meg i h&aring;ret, ristet p&aring; hodet, b&oslash;rstet vekk barn&aring;lene som ramlet ned.</p>\r\n<p>&laquo;Det var det jeg trodde, h&aring;pet.&raquo; Stemmen hans var ivrig.</p>\r\n<p>&laquo;H&aring;pet? Hva mener du?&raquo;</p>\r\n<p>&laquo;Nei, si det. La meg heller sp&oslash;rre deg om en ting. Hva syns du om skogen her ute?&raquo;</p>\r\n<p>Jeg trakk p&aring; skuldrene, men blikket hans var innstendig. Det var noe han trengte &aring; h&oslash;re.</p>\r\n<p>&laquo;Skogen lever.&raquo;</p>\r\n<p>Han nikket for &aring; f&aring; meg til &aring; fortsette.</p>\r\n<p>&laquo;Den er en del av meg. Jeg vet ikke. Den snakker. Ikke med ord, jeg er ikke gal.&raquo;</p>\r\n<p>Han lo: &laquo;Hvis ikke du er det, s&aring; er ikke jeg det heller.&raquo;</p>\r\n<p>Lettelsen i latteren hans forklarte en hel del. Tre millioner var mye &aring; betale for en mental helsesjekk.</p>\r\n<p>&laquo;Men hvorfor meg?&raquo; Jeg satte blikket i ham. &laquo;Det m&aring; ha v&aelig;rt vanvittig mange som ville vinne de pengene.&raquo;</p>\r\n<p>&laquo;Ta det med ro, pengene er dine. Og det var ingen andre. Bare du fikk annonsen. Det m&aring;tte v&aelig;re deg.&raquo;</p>\r\n<p>&laquo;Fordi jeg ikke har noen &aring; fortelle det til?&raquo;</p>\r\n<p>&laquo;Det var en bonus. Landets rikeste kan ikke ha rykter g&aring;ende om at han er gal, men nei, ikke derfor. Det var farfaren din som bygde hytta.&raquo;</p>\r\n<p>&laquo;Men farfar d&oslash;de ung.&raquo;</p>\r\n<p>&laquo;Nei, farfaren din forsvant ung. Han forsvant her ute. Stemmer det for deg, som for meg, at du aldri f&oslash;lte deg alene her ute?&raquo;</p>\r\n<p>Jeg nikket og sank tilbake i stolen. Jeg hadde aldri f&oslash;lt meg s&aring; lite alene som da jeg trodde jeg var en del av skogen. Selv om jeg holdt p&aring; &aring; d&oslash; av frykt. August rev meg tilbake: &laquo;S&aring;, hva skal du bruke pengene p&aring;?&raquo;</p>\r\n<p>Jeg trakk inn duften av v&aring;t jord og barn&aring;ler.</p>\r\n<p>&laquo;Hvor mye skal du ha for hytta?&raquo;</p>','/storage/blog/1587477282.jpeg','Tuva Tovslid','/storage/blog/author/1587477282.png',1,NULL,'2020-04-21 13:54:42','2020-04-21 13:54:42'),(29,1064,'Tottos kamp','<p><img src=\"/photos/Untitled design.jpg\" alt=\"\" width=\"2800\" height=\"1400\" /></p>\r\n<p>&nbsp;</p>\r\n<p>Jeg har dr&oslash;mt om &aring; bli forfatter siden jeg var 16 &aring;r, men har unng&aring;tt utdanning og jobber der skriveferdighetene kunne blitt stimulert eller utviklet. Jeg ble cand. polit. med statsvitenskap som hovedfag, og har jobbet i Hydro, Kv&aelig;rner og Statoil &ndash; en hel karriere med statistikk, \"tallknusing\" og programmering.</p>\r\n<h2><strong>En historie trenger seg p&aring; ...</strong></h2>\r\n<p>Rundt 2010 var jeg mettet, samtidig som historien om nr. 27 begynte &aring; trenge seg p&aring;. En redakt&oslash;r i Oktober Forlag r&aring;det meg til &aring; skrive en roman fremfor en erindringshistorie, og slik tvang jeg meg ut av komfortsonen. Etter hvert klarte jeg &aring; lage et manus av historien, men trengte hjelp til &aring; komme i m&aring;l.&nbsp;</p>\r\n<h2>S&oslash;kte profesjonell hjelp</h2>\r\n<p>Da jeg hadde pr&oslash;vd &aring; skrive p&aring; egenh&aring;nd en stund kom jeg over Forfatterskolen (forfatterskolen.no). Hvordan jeg fant skolen klarer jeg ikke &aring; erindre, men jeg husker godt <em>hvorfor</em>. Jeg trengte hjelp fra folk som var kyndige innen skriving og litteratur.</p>\r\n<p>Forfatterskolen kunne tilby all den hjelpen jeg trengte &ndash; jeg tok romanskrivekurs, meldte meg p&aring; webinarpakken og bestilte redakt&oslash;rvurdering av manus. Det var ogs&aring; artig &aring; v&aelig;re med i det lukkede skriveforumet underveis (red. anm: Forfatterskolens skriveforum p&aring; Facebook)..</p>\r\n<h2>Konkret og konstruktiv tilbakemelding</h2>\r\n<p>Tilbakemeldingen p&aring; manus var detaljert og konkret &ndash; og til betydelig hjelp i skriveprosessen.</p>\r\n<p>Resultatet av kurs og tilbakemelding, egen innsats og Forfatterskolens st&oslash;tte, resulterte i utgivelse av min debutroman: Nr. 27. Endelig!</p>\r\n<h2>Ferdig bok mellom hendene</h2>\r\n<p>I &aring;r kom boken ut, og dette er historien:</p>\r\n<p>Totto er fra Vormedal. P&aring; v&aring;ren i sitt tolvte leve&aring;r, like f&oslash;r 17. mai, f&aring;r han voldsomme magesmerter og blir innlagt p&aring; Haugesund sykehus. Derfra blir han sendt videre til Oslo og skrevet inn som pasient nr. 27 p&aring; Radiumhospitalet. Lenge kjemper han for livet, men til slutt havner han i sykehusets &laquo;d&oslash;dsbunke&raquo;. Sjefslegen og fagteamet hevder han er uhelbredelig syk. M&aring; faren gi opp dr&oslash;mmen om at s&oslash;nnen vil bli frisk? Gud virker uinteressert og lite hjelpsom. Totto gir likevel ikke opp h&aring;pet om at han en dag skal f&aring; komme tilbake til Vormedal og spille fotball med kameratene.</p>\r\n<p>Her kan du lese mer &ndash; smugkikke p&aring; et par kapitler &ndash; og bestille boken, hvis du vil:</p>\r\n<p><a href=\"https://boldbooks.no/bokhandel/nr-27/.\">Nr. 27 av Karl Otto Vibran</a></p>\r\n<h2>Aldri utl&aelig;rt</h2>\r\n<p>Karl Otto sier: Jeg har ikke sluttet p&aring; skolen enn&aring;, og vet ikke n&aring;r jeg eventuelt skal gj&oslash;re det. Det er stadig noe nytt &aring; l&aelig;re.</p>\r\n<p>Forfatterskolen sier: Vi er superstolte av Karl Otto, og gleder oss til &aring; f&oslash;lge ham videre!</p>','/storage/blog/1598339396.jpeg','Karl Otto Vibran','/storage/blog/author/1598263294.jpeg',1,'2020-08-24','2020-08-24 10:01:34','2020-09-02 09:06:05'),(30,1064,'Pappas hemmelighet','<p><img src=\"/photos/Idas beste serieromantios! (1).png\" alt=\"blog-30\" width=\"2350\" height=\"1970\" /><em>Hvordan har det v&aelig;rt &aring; jobbe s&aring; tett p&aring; din egen far og hva har det gjort med forholdet deres?</em></p>\r\n<p><em>N&aring;r fikk du ideen? </em></p>\r\n<p><em>Hvordan er det &aring; tenke p&aring; at s&aring; mange vet s&aring; mye om deg og din familie?</em></p>\r\n<p>Den siste m&aring;neden har flere journalister stilt meg sp&oslash;rsm&aring;l som ligner disse.</p>\r\n<p>Det er kanskje ikke s&aring; rart. Nylig utga jeg sakprosaboken <em>Pappas hemmelighet &ndash; </em>en bok som handler om hvordan overgrepene min far ble utsatt for som barn har preget b&aring;de pappa, meg og resten av familien.</p>\r\n<p>Siden mange (og stadig flere?) skriver historier om eget liv, tenkte jeg &aring; dele noen av mine erfaringer og tanker rundt min prosess.</p>\r\n<p>Men aller f&oslash;rst m&aring; jeg ta dere med tilbake til der alt startet.</p>\r\n<h3>Sjokket</h3>\r\n<p>Jeg var 20 &aring;r da jeg fikk vite at pappa hadde blitt utsatt for seksuelle overgrep &ndash; fra han var ni til han var seksten. Pappa var 49 &aring;r og hadde b&aring;ret p&aring; sin hemmelighet i 40 &aring;r uten &aring; si det til en sjel. Det pappa fortalte kom som et sjokk. Historien passet ikke inn i mitt bilde av hvem min ressurssterke pappa var. Den gang s&aring; jeg for meg at &laquo;det typiske overgrepsofferet&raquo; var en kvinne eller en person som var &laquo;&oslash;delagt&raquo; p&aring; grunn av det hen hadde blitt utsatt for. Og min far var jo ikke &oslash;delagt.</p>\r\n<p>I &aring;rene som fulgte ble jeg mer oppmerksom p&aring; saker om overgrep i mediene. Kanskje fordi jeg plutselig erkjente at det angikk meg? Relativt raskt la jeg merke til at mange av sakene som ble laget handlet om kvinnelige utsatte. Det motiverte meg til &aring; skrive en kommentar i Aftenposten, der jeg tok til orde for at ogs&aring; ressurssterke menn blir utsatt for seksuelt misbruk <em>(innlegget ble selvf&oslash;lgelig delt med pappas tillatelse).</em></p>\r\n<h3>Responsen</h3>\r\n<p>Responsen var overveldende. B&aring;de pappa og jeg ble kontaktet av utsatte menn som vurderte &aring; fortelle sine n&aelig;rmeste hva de hadde blitt utsatt for. Det gjorde at jeg for alvor inns&aring; hvor mange mannlige overgrepsutsatte som finnes der ute.</p>\r\n<p>Erkjennelsen ble enda klarere for meg da pappa og jeg deltok p&aring; krisekonferansen i 2017 &ndash; et seminar for helsepersonell. Pappa holdt foredrag om sine erfaringer. I etterkant h&oslash;rte vi et foredrag av overgrepsforsker Torbj&oslash;rn H. Andersen, som forklarte hvordan usynliggj&oslash;ringen av utsatte menn har gjort at mannlige utsatte tier om sine erfaringer. <br /><br />Han viste en video av en mann og en kvinne som &laquo;sl&aring;ss&raquo; mot hverandre p&aring; &aring;pen gate for &aring; se reaksjonen til folk. Da mannen var skyld i sl&aring;ssingen reagerte tilskuere med &aring; si ifra, mens da kvinnen opptr&aring;dte p&aring; samme m&aring;te lo de som var vitne til hendelsen.</p>\r\n<p>Thorbj&oslash;rn stilte f&oslash;lgende sp&oslash;rsm&aring;l: Hva gj&oslash;r at en manns vold mot en kvinne er en tragedie, mens en kvinnes vold mot en mann er komisk?</p>\r\n<p>Han ville utfordre v&aring;re m&aring;ter &aring; forst&aring; kategoriene offer og overgriper p&aring;.</p>\r\n<h3>Skammen</h3>\r\n<p>Jeg noterte flittig. Handlet pappas fortielse om en slags mannlig skam, om &aelig;re? Hadde han et spr&aring;k for hva som hadde skjedd, da han som ni&aring;ring fikk en manns lem mellom beina en natt i juleferien? Var det frykten for &aring; forbli et offer som gjorde at pappa ikke ville snakke med en psykolog? Hvordan hadde hans skam p&aring;virket meg, s&oslash;strene mine og oss som familie?&nbsp;&nbsp;</p>\r\n<p>P&aring; toget tilbake til Oslo den ettermiddagen hamret jeg l&oslash;s p&aring; tastaturet. Jeg ble irritert da kondukt&oslash;ren avbr&oslash;t meg for &aring; sjekke billetten. Torbj&oslash;rns foredrag fikk meg til &aring; innse at det m&aring;tte skrives noe mer enn et debattinnlegg om overgrep mot menn.</p>\r\n<h3>Avgj&oslash;relsen</h3>\r\n<p>Da toget stoppet p&aring; Kjels&aring;s, hadde jeg bestemt meg: Jeg skulle skrive bok om pappas historie. Jeg ville gi min far st&oslash;tten han aldri fikk som barn.</p>\r\n<p>Derfor f&oslash;ltes det som skjebnen da jeg kort tid etter konferansen kom over et norsk forlag som s&oslash;kte deltagere til et sakprosakurs. Jeg sendte inn s&oslash;knad og eksempelkapittel, og fikk til min store overraskelse plass.</p>\r\n<p>Det neste halv&aring;ret hadde vi m&aring;nedlige samlinger der vi leste hverandres tekster og l&aelig;rte om sakprosasjangeren. Det viktigste innspillet jeg fikk var viktigheten av &aring; flette den personlige historien sammen med det samfunnskritiske. En god sakprosabok m&aring; v&aelig;re noe mer enn en personlig fortelling (med mindre du skriver biografien til en stjerne).</p>\r\n<p>Jeg begynte &aring; lese b&oslash;ker av forfattere som p&aring; ulike m&aring;ter hadde mestret kunsten &aring; balansere personlig fortelling med samfunnskritikk. Forfattere som hadde skrevet gode sakprosab&oslash;ker med utgangspunkt i sine foreldres historier. Mine favoritter var &laquo;G&aring;r du n&aring;, er du ikke lenger min datter&raquo; av Anne Bitschog &laquo;Mysteriet mamma&raquo; av Trude Lorentzen (har du ikke lest dem, anbefaler jeg deg &aring; gj&oslash;re det).</p>\r\n<h3>Traumer i arv</h3>\r\n<p>Tanken var &aring; skrive pappas historie. Jeg ville formidle hvordan det hadde v&aelig;rt for ham &aring; g&aring; gjennom &aring;rene i barndommen helt alene. Men p&aring; seminarene ble det tydelig for meg at en vel s&aring; interessant fortelling var hvordan pappas historie hadde preget meg og resten av familien. Sagt p&aring; en annen m&aring;te: Det finnes en del b&oslash;ker om hvordan seksuelle overgrep kan prege et menneske, men ytterst f&aring; som sier noe om hvordan traumer kan g&aring; i arv.</p>\r\n<p>I l&oslash;pet av sakprosaseminarene gikk jeg fra &aring; skulle skrive boken om pappa til &aring; flette tre fortellinger sammen i &eacute;n bok:</p>\r\n<ul>\r\n<li>Samfunnshistorien om mannlige utsatte og hvordan de har blitt m&oslash;tt og forst&aring;tt gjennom tidene</li>\r\n<li>Pappas historie</li>\r\n<li>Min historie</li>\r\n</ul>\r\n<p>S&aring; &ndash; hvor begynner man?</p>\r\n<h3>S&oslash;kte st&oslash;tte</h3>\r\n<p>Jeg inns&aring; ganske kjapt at jeg trengte tid. Derfor sendte jeg s&oslash;knad om midler fra organisasjonene NFFO og Fritt Ord (v&aring;ren 2018). Jeg brukte lang tid p&aring; &aring; skrive en god s&oslash;knad og fikk innspill fra folk som allerede hadde f&aring;tt st&oslash;tte av organisasjonene.</p>\r\n<p>Mens jeg ventet p&aring; svar begynte jeg &aring; gj&oslash;re research. Jeg hadde tross alt bestemt meg for at boka skulle bli en realitet &ndash; uavhengig av om jeg fikk &oslash;konomisk st&oslash;tte eller ei.</p>\r\n<p>For &aring; finne frem til aktuell litteratur kontaktet jeg overgrepsforsker Torbj&oslash;rn. Han serverte meg lange, nyanserte artikler som utfordret, og gjorde meg bedre forberedt p&aring; samtalene jeg etterhvert innledet med pappa.</p>\r\n<h3>Samtalene med pappa</h3>\r\n<p>De f&oslash;rste samtalene med pappa handlet om hvordan overgrepene artet seg &ndash; hva han tenkte og f&oslash;lte som barn. Jeg ville <em>forst&aring;</em>. Gj&oslash;re godt igjen det som gikk feil den gangen, og ingen var der for ham. Med hele meg h&oslash;rte jeg p&aring; det han fortalte. Lyttet til historien om det f&oslash;rste overgrepet. Om hvordan det var &aring; v&aelig;re ni &aring;r og v&aring;kne av at du kjenner noe stort og hardt mellom bena.</p>\r\n<p>Det var sterk kost. Selv om jeg lyttet, var det akkurat som at en del av meg koblet litt ut for &aring; beskytte meg selv. Jeg tror kanskje at jeg litt ubevisst inntok en journalist-rolle.</p>\r\n<p>I l&oslash;pet av v&aring;re f&oslash;rste samtaler laget pappa og jeg to regler for bokprosjektet &ndash; regler som skulle ivareta v&aring;r relasjon som far og datter gjennom prosessen:</p>\r\n<ul>\r\n<li>Vi skulle si fra hvis vi opplevde at det ble for mye bok og for lite far og datter.</li>\r\n<li>Vi kunne begge avbryte prosjektet n&aring;r som helst. Begge var enige om at v&aring;r relasjon skulle komme f&oslash;rst.</li>\r\n</ul>\r\n<h3>De gode nyhetene</h3>\r\n<p>I juni 2018 fikk jeg bekreftet at jeg hadde f&aring;tt stipend fra <em>b&aring;de</em> NFFO og Fritt Ord. Det bet&oslash;d at jeg kunne dedikere meg enda mer til prosjektet. Det betydde ogs&aring; at flere enn meg mente at dette var en viktig historie. Omtrent samtidig fikk jeg en annen glad-beskjed: Et stort norsk forlag sa at de ville trykke boken.</p>\r\n<p>St&oslash;tten fra Fritt Ord og NFFO innebar at jeg kunne legge jobben til side. Jeg valgte likevel &aring; forsette som journalist. Jeg f&oslash;lte meg avhengig av &aring; ha et fellesskap rundt meg. I tillegg liker jeg f&oslash;lelsen av &aring; fullf&oslash;re noe &ndash; gjerne i l&oslash;pet av en arbeidsdag. Det har du muligheten til som journalist, men sjelden som forfatter.</p>\r\n<h3>Opps&oslash;kte barndomsvenner</h3>\r\n<p>Jeg tok sommerferie, men det bet&oslash;d ikke at bokprosjektet sto p&aring; vent. Juni 2018 opps&oslash;kte jeg pappas barndomsvenner. Jeg ville finne ut av hvem pappa var i vennegjengen og hvilke idealer de levde opp til den gangen. Det var stas &aring; m&oslash;te menneskene som hadde befolket pappas oppvekst &ndash; kompiser og ten&aring;ringskj&aelig;rester som jeg hadde h&oslash;rt historier om. Samtalene hjalp meg &aring; forst&aring; hvordan det var &aring; v&aelig;re barn og ungdom p&aring; 70 &ndash; og 80-tallet, og jeg fikk flere nyanser til historiene som pappa hadde fortalt. Jeg oppdaget ogs&aring; at det &aring; skrive sakprosa er mer sosialt enn &aring; skrive roman &ndash; man m&oslash;ter og prater med ganske mange under researcharbeidet.</p>\r\n<h3>Mistet oversikten</h3>\r\n<p>Utover sommeren fortsatte samtalene med pappa. Etterhvert som vi jobbet oss fremover i tid ble det ogs&aring; p&aring; tide &aring; prate med mamma og s&oslash;strene mine. P&aring; dette tidspunktet hadde jeg innhentet s&aring; mye stoff at jeg f&oslash;lte jeg mistet oversikten. Sammen med min redakt&oslash;r i forlaget laget jeg derfor en disposisjon for hvordan boka skulle struktureres, og hva som var form&aring;let med hvert kapittel. Sett i retrospekt er dette noe av det viktigste jeg gjorde for &aring; komme i m&aring;l. Kanskje skyldes det at jeg er en analytisk skribent som liker &aring; ha en mal &aring; jobbe ut fra? Jeg f&oslash;lte i alle fall at disposisjonen ga en f&oslash;lelse av kontroll og en retning for prosjektet.</p>\r\n<h3>Skriveprosessen starter ...</h3>\r\n<p>Da disposisjonen var klar begynte skriveprosessen. Siden det er vanskelig &aring; vite hvor man skal begynne n&aring;r man skal skrive et par hundre sider, benyttet jeg meg av &laquo;shut up and write&raquo;-metoden. Det innebar at jeg skrev i 45-50 minutter &ndash; uten &aring; v&aelig;re kritisk til det jeg rablet ned. Etter femti minutter hadde jeg pause i 10 minutter. Slik holdt jeg p&aring; i fire runder, f&oslash;r jeg gikk gjennom alt jeg hadde skrevet.</p>\r\n<p>Jeg slettet det meste av innholdet, men tok med meg episoder og ideer som jeg ville jobbe videre med. Her er det verdt &aring; nevne at jeg produserte og skrev best n&aring;r jeg var alene i leiligheten til mamma og pappa p&aring; Synnfjellet. N&aring;r jeg er i Oslo har jeg en lei tendens til &aring; f&aring; d&aring;rlig samvittighet for alt, noe som gj&oslash;r at skrivingen gjerne nedprioriteres. P&aring; Synnfjellet er det sv&aelig;rt lite som skjer, s&aring; der er jeg mer produktiv..</p>\r\n<h3>Pappas reaksjon</h3>\r\n<p>S&aring; kom nedturene. 28. september 2018 kom den f&oslash;rste smellen. Pappa hadde lest de fire f&oslash;rste kapitlene. Han var knust og sendte en mail der han blant annet skrev at &laquo;teksten fikk ham til &aring; &oslash;nske at vi ikke hadde hatt ham som far.&raquo; Jeg var overbevist om at dette bet&oslash;d starten p&aring; slutten. Det kommer ikke til &aring; bli bok, tenkte jeg.</p>\r\n<p>Det tok likevel ikke mange timene f&oslash;r pappa erkjente at det jeg beskrev var slik det hadde v&aelig;rt. <br /><br />Selv om erkjennelsen m&aring; ha v&aelig;rt vond &aring; ta innover seg, tror jeg samtidig det fikk pappa til &aring; innse noe viktig: Som barn hadde vi lagt merke til hans kroppsforakt, depresjoner og prestasjonsstreben &ndash; selv om han i alle &aring;r fors&oslash;kte &aring; sk&aring;ne oss for det.</p>\r\n<h3>Smell nummer to</h3>\r\n<p>Fire m&aring;neder senere, i februar 2019, kom smell nummer to. I forkant hadde jeg skrevet og sendt inn de f&oslash;rste 100 sidene av manus til forlaget. I mailen jeg fikk tilbake sto det at de s&aring; seg n&oslash;dt til &aring; trekke seg fra samarbeidet. De ville ikke utgi \"Pappas hemmelighet\" fordi historien var \"for alvorlig, betent og fersk til at den egnet seg for utgivelse.&raquo;</p>\r\n<p>Jeg gikk rett i kjelleren. Jeg f&oslash;lte meg som et talentl&oslash;st null.</p>\r\n<h3>Vonde f&oslash;lelser ble til motivasjon</h3>\r\n<p>Etter noen samtaler med pappa, min samboer Jan Axel og gode venninner ble de vonde f&oslash;lelsene til sinne og motivasjon. Jeg har alltid v&aelig;rt grunnleggende uenig i premisset om at man m&aring; inneha en viss alder eller erfaring for &aring; dele sine tanker og refleksjoner rundt et tema. Jeg tror vi i for liten grad lytter til perspektivene til unge mennesker.</p>\r\n<p>Jeg visste at jeg ikke ville vente eller gro p&aring; meg erfaring. Jeg ville utgi \"Pappas hemmelighet\" &ndash; sammen med pappa. Boka skulle v&aelig;re en samtale mellom oss &ndash; ikke min fortelling den dagen pappa var for gammel til &aring; delta i prosjektet.</p>\r\n<p>Avslaget gjorde meg enda mer bestemt p&aring; at jeg skulle fullf&oslash;re. Drivkraften var vissheten om at v&aring;r historie kunne hjelpe andre i samme situasjon.</p>\r\n<h3>Nytt utkast</h3>\r\n<p>Jeg laget et nytt utkast &ndash; denne gangen med mer fokus p&aring; faglitteratur. Deretter betalte jeg en uavhengig redakt&oslash;r, Roger Pihl, for &aring; lese og komme med tilbakemeldinger. Han kom med flere konstruktive tilbakemeldinger, og var samtidig klar p&aring; at dette var en historie som var verdt &aring; fortelle. Han s&oslash;rget for at jeg fikk troen p&aring; meg selv som skribent igjen, selv om han var klar p&aring; at manuset m&aring;tte jobbes med.</p>\r\n<p>Etter tilbakemeldingene fra Roger skrev jeg enda et utkast av manuset. Underveis hadde jeg min trofaste pilotleser og samboer Jan Axel ved min side. N&aring;r jeg tenker tilbake p&aring; det, lurer jeg p&aring; hvor mange versjoner av boken han faktisk har lest (det er en grunn til at jeg kaller mannen i mitt liv for en ildsjel).</p>\r\n<p>Samtidig som jeg skrev dette utkastet kontaktet jeg fagpersoner som kunne si noe om barn som p&aring;r&oslash;rende, siden dette var en av de &aring;penbare svakhetene med den forrige versjonen av manus.</p>\r\n<h3>M&oslash;tet med forlaget</h3>\r\n<p>Da siste punktum var nok en gang satt. N&aring; var jeg usikker p&aring; hva jeg skulle gj&oslash;re og hvem jeg skulle kontakte. P&aring; dette tidspunktet hadde jeg innsett at jeg var helt avhengig av en engasjert, dedikert og &aelig;rlig redakt&oslash;r for at boken skulle bli best mulig. En redakt&oslash;r som tok meg p&aring; alvor og som hadde tid til meg og min personlige historie. En som ikke ga meg f&oslash;lelsen av &aring; v&aelig;re \"en av forfatterne i bunken\".</p>\r\n<p>Jeg hadde f&aring;tt h&oslash;re at Gerd Johnsen i Res Publica var en s&aring;nn redakt&oslash;r. Derfor kontaktet jeg henne.</p>\r\n<p>Etter litt mailing frem og tilbake sendte jeg manus, og to uker senere fikk jeg svar:</p>\r\n<p>Gerd var klar p&aring; at store grep m&aring;tte gj&oslash;res dersom boken skulle bli bra nok for en utgivelse. Hun syntes likevel historien var viktig, og var villig til &aring; ta en prat om boken over en kaffe.</p>\r\n<h3>Mot utgivelse ...</h3>\r\n<p>P&aring; m&oslash;tet ble vi enige om at Gerd skulle n&aelig;rlese de tre f&oslash;rste kapitlene slik at jeg s&aring; hvordan hun jobbet som redakt&oslash;r. Deretter skulle jeg redigere en del av manus f&oslash;r forlaget tok en avgj&oslash;relse p&aring; om de ville g&aring; videre med prosjektet &ndash; og forplikte seg til utgivelse.</p>\r\n<p>Store deler av jula 2019 gikk med til skriving. Jeg ville vise at jeg var villig til &aring; jobbe hardt og dedikert for &aring; komme i m&aring;l.</p>\r\n<p>13. januar sendte jeg det redigerte manuset, og i slutten av januar fikk jeg beskjeden: Res publica ville utgi Pappas hemmelighet!</p>\r\n<p>Fra januar til mai handlet det mye om &aring; kutte og omskrive. Det var mange versjoner av manus, frem og tilbake, og jeg tror vi til sammen fjernet 60 sider. Teksten som ble fjernet var i hovedsak historier fra barndommen som egentlig ikke hadde noen hensikt. Det var &laquo;meg-stoff&raquo; som m&aring;tte lukes ut.</p>\r\n<h3>Distanse, n&aelig;rhet og etiske utfordringer</h3>\r\n<p>Mitt beste r&aring;d til deg som skriver tett opp til eget liv er &aring; ha en redakt&oslash;r som hjelper deg med &aring; luke ut \"meg-stoffet\". Det kan v&aelig;re vanskelig &aring; ha den n&oslash;dvendige distansen til en tekst som er s&aring; n&aelig;r deg selv.</p>\r\n<p>En annen viktig oppgave var &aring; gj&oslash;re fagstoffet mer tilgjengelig. Gerd p&aring;pekte viktigheten av &aring; bevare min egen stemme, ogs&aring; i partiene der jeg flettet inn fagstoff.</p>\r\n<p>F&oslash;r boken ble sendt i trykken snakket jeg med flere redakt&oslash;rer i forlaget om de etiske utfordringene vi sto overfor. Vi diskuterte blant annet hvordan pappas overgriper skulle omtales for &aring; ivareta personvernet, og som journalist satte jeg stor pris p&aring; at forlaget tok dette p&aring; alvor.</p>\r\n<p>I tillegg fikk de som hadde blitt sitert og intervjuet i boken, mulighet til &aring; lese gjennom delene av teksten der de var nevnt.</p>\r\n<h3>Den kjedelige korrekturen</h3>\r\n<p>Til sist var det klart for det jeg synes er kjedeligst med &aring; skrive bok: Korrekturen. Det var trolig vissheten om at min bok-baby snart var f&oslash;deklar som motiverte meg til &aring; &laquo;st&aring; han av&raquo;.</p>\r\n<p>I slutten av juni satt vi igjen med nesten 200 sider tekst og den endelige utgangen av Pappas hemmelighet.</p>\r\n<h3>Opp&ndash; og nedturer</h3>\r\n<p>Jeg kunne se tilbake p&aring; opp&ndash; og nedturer. Krevende samtaler, avslag og heiarop. Helger i ensom majestet p&aring; Synnfjellet, skriving i ferier og i leiligheten p&aring; Manglerud. Faglige input fra folk som satte av tid til &aring; prate med meg uten &aring; f&aring; en krone for det.</p>\r\n<p>Konklusjon: Det er ekstremt mye som har skjedd siden jeg tok fatt p&aring; prosjektet. Det er litt som nybakte m&oslash;dre om &aring; bli mor for f&oslash;rste gang: Det kan ikke beskrives &ndash; du m&aring; oppleve det selv.</p>\r\n<p>&Aring; skrive Pappas hemmelighet tok lenger tid enn jeg hadde trodd og hele f&oslash;lelsesregisteret ble aktivert underveis. Jeg har til og med konfrontert pappas overgriper.&nbsp;Dessuten har jeg vunnet kunnskap og f&oslash;lelsen av &aring; forst&aring; min egen far &ndash; s&aring;nn p&aring; ordentlig.</p>\r\n<p>S&aring; da er det vel sant som de sier: &laquo;What does&rsquo;nt challenge you, does&rsquo;nt change you.&raquo;</p>\r\n<p>---</p>\r\n<p><em>Forfatterskolen sier: Vi er stolte av deg, Vilde &ndash; og ser frem til &aring; lese din fine og viktige bok. Gratulerer s&aring; mye med utgivelsen! </em></p>\r\n<p>Her kan du bestille boken selv: <a href=\"https://respublica.no/produkter/pappas-hemmelighet/\">Pappas hemmelighet</a></p>\r\n<p>Lenker til artikler om boken i media:</p>\r\n<p><a href=\"https://www.dagsavisen.no/nyheter/innenriks/faren-til-vilde-tiet-om-overgrepene-i-40-ar-hvorfor-hadde-han-ikke-sagt-noe-for-1.1754197\">Dagsavisen</a></p>\r\n<p><a href=\"https://www.vg.no/forbruker/helse/i/lABm4y/familiehemmeligheten-som-endret-alt\">VG</a></p>\r\n<p><a href=\"https://www.aftenposten.no/meninger/sid/i/bOKA/jeg-var-overbevist-om-at-jeg-kjente-pappa-saa-falt-alt-paa-plass\">Aftenposten</a></p>\r\n<p><a href=\"https://psykologisk.no/2020/08/pappas-hemmelighet/\">Psykologisk</a></p>','/storage/blog/1599130099.png','Vilde Bratland Hansen','/storage/blog/author/1599130099.jpeg',1,'2020-09-03','2020-09-03 10:48:19','2022-01-13 06:08:27'),(31,1064,'Ny sjanger: Feelgood yogaroman','<p><img src=\"/photos/Untitled design.png\" alt=\"blog 31\" width=\"2240\" height=\"1120\" /></p>\r\n<p>&nbsp;</p>\r\n<p>Aner vi en ny sjanger? <em>Ellas Tilstedev&aelig;relse</em> er en underholdningsbok &ndash; en feelgood yogaroman som handler om &aring; t&oslash;rre &aring; st&aring; p&aring; egne bein og satse, om vennskap og yoga og den store kj&aelig;rligheten.&nbsp;</p>\r\n<p>Boken er skrevet av Gunn Helene Arsky, som er utdannet ern&aelig;ringsfysiolog fra Universitetet i Oslo og har en yogal&aelig;rerutdannelse fra Yin Yang Yoga-Akademiet. Gunn Helene har ogs&aring; tatt romankurset til Forfatterskolen &ndash; og n&aring; sitter hun alts&aring; med sin <em>egen</em> roman mellom hendene.</p>\r\n<h3>Valgte eget forlag</h3>\r\n<p>&ndash; Boken kom ut 16. juni, p&aring; eget forlag, smiler Gunn Helene, og forklarer valget slik:</p>\r\n<p>&ndash; Forlagsbransjen i Norge sliter, og jeg er en ut&aring;lmodig sjel. Derfor startet jeg <em>Delfin forlag</em>. Jeg har mange b&oslash;ker i hodet, s&aring; det kan bli flere utgivelser fra Halden fremover.</p>\r\n<p>Handlingen begynner i Oslo, men flyttes raskt til Halden.&nbsp;Vi f&oslash;lger Ella (27) gjennom en vinter og en v&aring;r. Idet vi m&oslash;ter Ella har hun tilsynelatende alt; en kj&aelig;reste hun elsker, en trygg bolig og dr&oslash;mmejobben i en bokhandel p&aring; Karl Johan. I l&oslash;pet av &eacute;n novemberdag snus alt p&aring; hodet, og Ella havner tilfeldigvis i Halden. Her m&aring; hun pr&oslash;ve &aring; bygge et nytt liv som yogal&aelig;rer, noe som selvsagt ikke skjer uten komplikasjoner. Yoga er et sentralt tema i boken &ndash; og vennskap, selvutvikling og kj&aelig;rlighet. For skal vi egentlig tro p&aring; Ella n&aring;r hun sier at hun aldri kan elske noen igjen?</p>\r\n<h3>Handling i Halden</h3>\r\n<p>&ndash; I boken har jeg brukt egne erfaringer med &aring; flytte fra Oslo til Halden, &aring; skape et yogastudie og alle de fine menneskem&oslash;tene, sier den nybakte forfatteren.&nbsp; &nbsp;&ndash; Men Ella er p&aring; ingen m&aring;te meg, jeg har ikke erfart det hun opplever. Ingen av bokens karakterer er bygget p&aring; virkelige personer. Men oppskriften p&aring; Ayas energikuler, de er 100 prosent fra meg.</p>\r\n<p>Arsky valgte &aring; legge handlingen til Halden av flere grunner.</p>\r\n<p>&ndash; For det f&oslash;rste at Halden er en trivelig by, med vakre steder, gater og parker. Det skapte en perfekt ramme rundt en hyggelig yogaroman. I tillegg syns jeg romaner fungerer godt n&aring;r de foreg&aring;r p&aring; mindre steder &ndash; b&aring;de for de som kan kjenne seg igjen i beskrivelsene og for de som ikke kjenner stedet s&aring; godt. Et tett og lite milj&oslash; gir ofte mer n&aelig;rhet til karakterene.</p>\r\n<h3>Elvas rolle</h3>\r\n<p>Tista-elven st&aring;r sentralt i boken. Det er et sted Ella stadig vender tilbake til n&aring;r hun trenger en tenkepause. Trehusbebyggelsen i sentrum, den stolte festningen og flere av byens kafeer og spisesteder er med. I tillegg fungerer Busterudparken som ramme for et lite oppgj&oslash;r &ndash; og Ella svipper innom blant annet K&oslash;hn bokhandel, Rema 1000 og Clas Ohlson.</p>\r\n<p><em>Ellas Tilstedev&aelig;relse</em> er til salgs&nbsp;n&aring; for alle som vil lese. her kan du skaffe deg et eksemplar av Gunn Helenes feelgood yogaroman: <a href=\"https://gunnhelenearsky.no/ellas-tilstedevaerelse-yogaroman/\">Ellas tilstedev&aelig;relse</a></p>\r\n<p>Forfatterskolen sier: <em>Vi er skikkelig stolte av deg, Gunn Helene &ndash; og gleder oss til &aring; f&oslash;lge forfatterskapet ditt videre :-)</em></p>\r\n<p><img src=\"/photos/Skjermbilde 2020-09-10 kl. 09.21.28.png\" alt=\"blog 31\" width=\"484\" height=\"730\" /></p>','/storage/blog/1599722193.png','Gunn Helene Arsky','/storage/blog/author/1599722193.jpeg',1,NULL,'2020-09-10 07:16:33','2022-01-13 06:09:52'),(32,1064,'Eventyr om Gud og Satan','<div>\r\n<p><img src=\"/photos/Renato Bartolomei.png\" alt=\"blog 32\" width=\"2800\" height=\"1400\" /></p>\r\n<p>Renato Bartolomei begynte &aring; skrive romaner i 2006,&nbsp;noen uker etter sin fars d&oslash;d. Han satt huket over et lavt bord p&aring; hybelen, med utsikt over hele Oslo, og skrev et eventyr p&aring; over tusen sider. Narkomane og kriminelle bodde p&aring; begge sider av hybelen, noen ganger klatret de forbi p&aring; balkongen, men han lot seg ikke ense med det.</p>\r\n<h3>Skriverush</h3>\r\n<p>&ndash; De f&oslash;rste skriveukene var et rush, og denne perioden ga meg energi til &aring; st&aring; bokl&oslash;pet ut. Etterp&aring; skrev jeg i to &aring;r uten inspirasjon, forkastet seks romaner, og i 2010 begynte jeg p&aring;&nbsp;<em>Etter Gud</em>. I &aring;r ble den ferdig.</p>\r\n<p>Renato begynte &aring; skrive om Gud som et vanlig menneske. Gud, eller Gustav blant kjente, er en ganske avbalansert og samvittighetsfull person, men han har en hund som skjuler Satan.</p>\r\n<p>&ndash; Slik begynte jeg p&aring; historien &ndash; Gud og Satan bor i samme hus og ingen av dem vet det.</p>\r\n<h3>Surrealistisk eventyr</h3>\r\n<p><span style=\"font-size: 14px;\">Det var tonen han fikk i de sm&aring; stykkene om Gud, og milj&oslash;et rundt, som ga Renato lyst til &aring; fortsette.</span></p>\r\n<p>&ndash; En ekspedisjon ble utstyrt for &aring; finne spor etter Gud. M&oslash;rke krefter som tjente <em>dyret</em> ble utstedt sidel&oslash;pende for &aring; utslette den hellige &ndash; og vekke Satan i hunden. Kappl&oslash;pet var i gang.</p>\r\n<div dir=\"auto\">Boken defineres som et eventyr med surrealistisk beinmarg, med hjerte av absurdisme og mysterium, blodoml&oslash;p av religi&oslash;s art, og med nervetr&aring;der av humor og ironi.</div>\r\n<h3>Gode pilotlesere</h3>\r\n<p>Bartolomei skrev ferdig boken p&aring; noen f&aring; m&aring;neder. Men som med den forrige boken hans,&nbsp;<em>Speilboken</em>, tok det ti &aring;r f&oslash;r&nbsp;<em>Etter Gud</em>&nbsp;var i m&aring;l &ndash; med redigering og ombrekk og pilotlesere og redakt&oslash;rer og trykking.</p>\r\n<p>&ndash; Kurset jeg hadde hos Forfatterskolen var til hjelp. B&aring;de der og da, og senere, i og med at jeg fikk tilgang til pilotlesere og mye mer.</p>\r\n<p>Den ene pilotleseren hos Forfatterskolen, Astrid, ga f&oslash;lgende tilbakemelding: \"Jeg blir l&aring;st fast til teksten p&aring; en god m&aring;te. Det er annerledes enn alt jeg har lest.\"&nbsp;</p>\r\n<p>&ndash; Jeg kan virkelig anbefale hva Forfatterskolen har &aring; tilby, sier den nybakte forfatteren.&nbsp; &nbsp;&ndash; Jeg f&oslash;lger stadig med p&aring; hva som kommer.</p>\r\n</div>\r\n<div class=\"book-description\">\r\n<p><em>Vi hos Forfatterskolen melder tilbake: Vi er stolte av deg, Renato &ndash; og gleder oss til &aring; lese dette spennende, religi&oslash;se eventyret!&nbsp;</em></p>\r\n<p>Her kan du bestille boken &ndash; og lese selv: <a href=\"https://www.haugenbok.no/Skjoennlitteratur/Romaner/Etter-Gud/I9788269203806\">Etter Gud</a></p>\r\n<div class=\"o9v6fnle cxmmr5t8 oygrvhab hcukyx3x c1et5uql ii04i59q\">\r\n<div dir=\"auto\">&nbsp;</div>\r\n</div>\r\n</div>','/storage/blog/1600420577.png','Renato Bartolomei','/storage/blog/author/1600420577.jpeg',1,'2020-09-18','2020-09-18 09:16:17','2022-01-13 06:10:16'),(33,1064,'Irenes serie-seier','<p><img src=\"/photos/Irene.png\" alt=\"blog 33\" width=\"2800\" height=\"1400\" /></p>\r\n<p>&nbsp;</p>\r\n<p>&ndash; B&oslash;ker har v&aelig;rt en viktig del av livet mitt &ndash; helt fra jeg som tolv&aring;ring snek meg til &aring; lese voksenromaner p&aring; Stovner Bibliotek. I b&oslash;kene fant jeg en verden som ga meg ro og glede. Mitt motto er: En dag uten en bok er ikke en god dag.</p>\r\n<h3>Flere refusjoner</h3>\r\n<p>Irene var et introvert barn og syntes det var lettere &aring; uttrykke seg skriftlig enn muntlig. Hun begynte tidlig &aring; formidle tanker og hendelser i dagb&oslash;ker og brev.</p>\r\n<p>&ndash; Som ten&aring;ring hadde jeg mange brevvenner i inn- og utland &ndash; noen av dem har jeg kontakt med den dag i dag. De fikk lange brev om alt og ingenting. Da jeg ble eldre skrev jeg en og annen tekst, men i mange &aring;r prioriterte jeg tegning og maling som uttrykksform. S&aring;&nbsp;kom \"livet kom i veien\" med jobb og alt som h&oslash;rer voksenlivet til, og jeg la bort b&aring;de tegning og skriving.</p>\r\n<p>Det var f&oslash;rst da Irene var langt opp i f&oslash;rti&aring;rene at hun begynte &aring; skrive igjen.</p>\r\n<p>&ndash; Jeg produserte en bok, s&aring; en til, og begynte p&aring; en tredje. Jeg sendte inn til forlag &ndash; og ble refusert med standardbrev. Hver eneste gang. Ingen av dem ga r&aring;d om hva jeg kunne jobbe videre med. Likevel ga jeg ikke opp. Jeg <em>ville</em> skrive &ndash; det var det eneste jeg visste.</p>\r\n<h3>Forfatterskolen ga ny giv</h3>\r\n<p>En dag s&aring; Irene en annonse for et skrivekurs p&aring; Facebook. <em>Forfatterskolen</em>. Navnet virket forlokkende ut p&aring; en med en skrivedr&oslash;m. Hun&nbsp;lastet ned mini-kurset &ndash; som var helt gratis &ndash; og likte Kristines m&aring;te &aring; formidle kunnskapen sin p&aring;. Dermed bestemte hun seg for &aring; melde meg p&aring; det utvidede skrivekurset.</p>\r\n<p>&ndash; Jeg husker hvor nerv&oslash;s jeg var f&oslash;r innsendingen av egen tekst. 1000 ord skulle vurderes av to andre elever (anonymt), og fra en profesjonell redakt&oslash;r hos Forfatterskolen. For en glede da tilbakemeldingene kom! Gode, konstruktive og tydelige r&aring;d om hva jeg kunne jobbe videre med. Det ga ny giv til videre skriving og tro p&aring; at det jeg skrev ikke var s&aring; h&aring;pl&oslash;st som jeg trodde.&nbsp;</p>\r\n<h3>Overraskende r&aring;d&nbsp;</h3>\r\n<p>Ved neste innsendelse, som var p&aring; 20 000 ord, var Irene enda mer spent. Igjen fikk hun gode tilbakemeldinger og konkrete r&aring;d, men ett innspill forundret henne.</p>\r\n<p>&ndash; I kommentaren fra Forfatterskolen sto det: \"Du er r&aring; p&aring; cliffhangere, du burde skrive krim eller serieromaner\". H&aelig;, tenkte jeg, krim eller serieromaner? Jeg, som verken leste krim eller serier. Riktignok hadde jeg lest en del krim som ung, men serieromaner hadde jeg aldri snust p&aring;. Jeg bestemte meg for &aring; ignorere r&aring;det og skrev videre p&aring; prosjektene mine. S&aring; dukket det opp tre ulike serieroman-konkurranser som det ble referert til p&aring; Forfatterskolens skriveforum. R&aring;det fra redakt&oslash;ren poppet opp i hodet. Skulle jeg pr&oslash;ve, tro?</p>\r\n<h3>Sendte inn til serieroman-konkurranse</h3>\r\n<p>I utlysningstekstene var et av kriteriene at historien skulle v&aelig;re lagt tilbake i tid, helst 1800-tallet eller tidlig 1900-tall. Det m&aring;tte v&aelig;re en kvinnelig protagonist (hovedperson) og en sterk kj&aelig;rlighetshistorie.</p>\r\n<p>&ndash; Jeg begynte &aring; tenke p&aring; oldeforeldrene mine, som levde p&aring; denne tiden og som jeg visste s&aring; lite om. Hvordan artet livet seg for dem i Kristiania? Jeg begynte &aring; se p&aring; bilder og arkiv p&aring; nettet, leste gamle aviser og begynte &aring; se for meg en historie. S&aring; kom tvilen: Kunne jeg, som aldri hadde lest en serieroman, ha en sjanse i en slik konkurranse?</p>\r\n<h3>... og vant!</h3>\r\n<p>Irene bestemte seg for &aring; pr&oslash;ve &ndash; og begynte p&aring; historien om Ingeborg. Hun&nbsp;sendte inn manus til konkurransen, og kort tid etter kom svaret.</p>\r\n<p>&ndash; Jeg vant! Blant 200 innsendinger hadde de valgt <em>mitt&nbsp;</em>manus. Dermed startet en helt ny hverdag: Skriving, innsending til redakt&oslash;r, kommentarer, tilbakemeldinger og rettelser, redigering og innsending tilbake. Frem og tilbake, frem og tilbake. Oppmuntrende og krevende p&aring; en gang, men mest av alt inspirerende og g&oslash;y.</p>\r\n<h3>Skriver hver dag</h3>\r\n<p>N&aring; skriver Irene hver dag. Hun st&aring;r opp klokken fem og skriver en times tid f&oslash;r hun g&aring;r p&aring; jobb. N&aring;r hun kommer hjem skriver hun litt til, selv om hun understreker at morgen&oslash;kten er mest effektiv.</p>\r\n<p>&ndash; Periodene med skriving er den beste tiden p&aring; d&oslash;gnet. Det er <em>min</em> tid &ndash; og jeg elsker den. N&aring; som jeg har begynt skal jeg aldri slutte &aring; skrive. Gjennom Forfatterskolen traff jeg dessuten en herlig gjeng med damer, og vi bestemte oss for &aring; danne en liten skrivegruppe. Hver m&aring;ned m&oslash;tes vi og leser hverandres tekster, gir r&aring;d og tilbakemeldinger. Utrolig nyttig og veldig koselig. Anbefales!</p>\r\n<p><em>Forfatterskolen sier: Vi er skikkelig stolte av deg, Irene &ndash; og gleder oss til &aring; f&oslash;lge b&aring;de serien og forfatterskapet ditt videre! </em></p>\r\n<p>Her kan du se serien hennes: <a href=\"https://www.bladkiosken.no/produkt/ingeborgs-verden-5?gclid=CjwKCAjw5Kv7BRBSEiwAXGDElSXrm2t2WdNNwDayUvlI0PRLoBhsaduWGEl52rBDfLN0XMeMMxiSIhoCLX4QAvD_BwE&amp;gclsrc=aw.ds\">Ingeborgs verden</a></p>','/storage/blog/1600855076.png','Kristine Henningsen','/storage/blog/author/1600854324.png',1,'2020-09-23','2020-09-23 09:36:52','2022-01-13 06:10:34'),(34,1064,'Fra refusjon til elgende suksess','<p style=\"padding-left: 90px;\"><img src=\"/photos/Elgelgelg.png\" alt=\"Elg\" width=\"533\" height=\"853\" /></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>Jorunn Kj&oslash;de, som er stolt trebarnsmor av&nbsp;<em>Elg-b&oslash;kene</em>, har v&aelig;rt lidenskapelig opptatt av skriving fra ung alder. Hun var fascinert over mormoren, som skrev lange og flotte dikt.</p>\r\n<h1>Fra barnerim til bryllupssanger</h1>\r\n<p>&ndash; Etter hvert begynte jeg &aring; dikte selv. Jeg startet som fem&aring;ring med &aring; finne p&aring; ord med rim. Med &aring;rene utviklet jeg dette og skrev sanger til konfirmasjoner, bryllup, og andre merkedager. Dessuten elsket jeg &aring; skrive <em>fritekst</em> p&aring; skolen, og har trolig alltid hatt en forfatter i magen.</p>\r\n<p>Da Jorunn var 19 &aring;r begynte hun p&aring; \"Journalistikk og foto\" p&aring; Folkeh&oslash;gskole, for &aring; finne ut om dette var noe for henne.</p>\r\n<p>&ndash; Jeg l&aelig;rte mye nyttig, og det var et spennende &aring;r. Likevel var det noe som ikke falt p&aring; plass. Jeg pr&oslash;vde meg ogs&aring; p&aring; krim, men det var ikke helt min sjanger. S&aring; var det et &aring;r der jeg satt mye barnevakt for mine kusiner, og da skjedde det noe ...&nbsp;</p>\r\n<h1>Fra refusert elg ...</h1>\r\n<p>Jorunns kusiner fikk frem barnet i henne. Hun hadde lenge tegnet p&aring; en elgfigur, og en julaften fant hun ut at hun ville gj&oslash;re mer ut av ham.</p>\r\n<p>&ndash; Ideene kom som en flom! Jeg begynte &aring; skape en elg som var fascinert av menneskelige saker. Temaer var aking og turer i skogen, inspirert av aktiviteter som jeg gjorde sammen med kusinene mine. Etter hvert ble det en bok om elgen, der den r&oslash;de tr&aring;den var elgens nysgjerrighet p&aring; oss &ndash; og at han &oslash;nsket seg venner.</p>\r\n<p>Jeg sendte inn manuset til de store forlagene &ndash; og fikk den refusert tilbake. Likevel ga jeg ikke opp h&aring;pet. Jeg hadde f&aring;tt et tips om et forlag som het Publica, og de interesserte seg for nykommere. Jeg sendte inn manuset &ndash; og det falt i smak, med unntak av noen f&aring; justeringer. Jeg fikk ogs&aring; lov til &aring; tegne bildene selv. Det var et godt samarbeid oss i mellom, og i november 2011 fikk jeg utgitt min f&oslash;rste bok. &Aring; holde sin egen bok i h&aring;nden &ndash; for et stolt &oslash;yeblikk!&nbsp;</p>\r\n<h1>... til elgende trilogi</h1>\r\n<p><span style=\"font-size: 14px;\">Jorunn gjorde alt promoteringsarbeidet selv. Hun kontaktet avisene p&aring; sitt dav&aelig;rende bosted, Troms&oslash;, og bes&oslash;kte barnehager og skoler for &aring; snakke om boken. </span></p>\r\n<p><span style=\"font-size: 14px;\">&ndash; Dette var litt skummelt i starten, jeg er veldig sjenert. Etter hvert fikk jeg imidlertid mer tro p&aring; meg selv, og utviklet meg personlig. Jeg begynte &aring; leke med en oppf&oslash;lger. Hva med &aring; skrive om detektiven Elgar, som ville finne ut hva jula er?</span></p>\r\n<p><span style=\"font-size: 14px;\">Jorunn brukte en julekalender som inspirasjonskilde, og laget en julekalender-bok. Kalenderboken hadde en tekst for hver dag frem til jul, der elgen kom n&aelig;rmere og n&aelig;rmere svaret.&nbsp;</span></p>\r\n<p><span style=\"font-size: 14px;\">I 2015 ga Jorunn ut sin siste bok om Elgen Elgar: En vennskapsbok. Samtidig begynte Jorunn &aring; f&oslash;le seg ensom.</span></p>\r\n<h1>Ble skriveensom</h1>\r\n<p>&ndash; Jeg hadde venner og familie som st&oslash;ttet og ga r&aring;d, og likevel f&oslash;lte jeg at noe manglet. Et par &aring;r ble det helt stopp med skrivingen.&nbsp;Jeg hadde skrivesperrer og annet i hverdagen som satte en stopper for motivasjonen.</p>\r\n<p>Jorunn pr&oslash;vde seg p&aring; en annen sjanger. Hun var gira helt til manuset ble refusert, da mistet hun skrivegleden igjen. S&aring;, i 2019, kom hun over Forfatterskolen p&aring; nett.</p>\r\n<p>&ndash; Jeg ble med p&aring; et gratis barnekurs-webinar som Kristine (rektor) holdt. Da f&oslash;lte jeg at endelig fikk det jeg hadde savnet. M&aring;ten hun fortalte om livet sitt p&aring;, om skrivekurset, jeg visste at dette var det rette stedet for meg. P&aring; Forfatterskolen visste jeg at jeg ville f&aring; l&aelig;rdom, utvikling og samhold.</p>\r\n<h1>Begynt p&aring; fantasy-fortelling</h1>\r\n<p>Jorunn ble med p&aring; barnebokkurs med Gro Dahle &ndash; og opplevde kurset som g&oslash;y, inspirerende og motiverende.&nbsp;</p>\r\n<p>&ndash; Ideene begynte &aring; komme tilbake! Denne gangen har jeg startet p&aring; en historie i sjangeren <em>fantasy</em>. Jeg har jobbet med karakterer og handling, og skriver p&aring; den fortsatt.&nbsp;Jeg er s&aring; glad for at jeg kastet meg p&aring; dette kurset. N&aring; f&oslash;ler jeg at historien min vokser til nye h&oslash;yder.</p>\r\n<p>Skriving har alltid v&aelig;rt en del av meg, sier Jorunn, men det er takket v&aelig;re Forfatterskolen den utvikles videe.</p>\r\n<p>&ndash; Jeg har f&aring;tt masse motivasjon! Det viktigste av alt: Jeg opplever et godt samhold der jeg blir inspirert av andre, og kan inspirere tilbake. N&aring; f&oslash;ler jeg ikke lenger p&aring; skriveensomheten.</p>\r\n<p><em>Forfatterskolen sier: Vi er s&aring; stolte av deg, Jorunn &ndash; og gleder oss til &aring; f&oslash;lge forfatterskapet ditt videre!</em></p>','/storage/blog/1637837545.jpeg','Jorunn Kjøde','/storage/blog/author/1606301472.jpeg',1,'2020-11-25','2020-11-25 10:43:29','2021-11-25 10:52:25'),(36,5004,'Tretten bøker på ti år!','<p>I f&oslash;lge sikre kilder er Frode Eie Larsen Norges snilleste krimforfatter. Og mandag 17.januar 2022 kan du m&oslash;te ham live p&aring; Forfatterskolens mentorm&oslash;te! Da skal han snakke om det &aring; forf&oslash;lge en forfatterdr&oslash;m og &aring; realisere den. Vi gleder oss!</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">Tusen ord om dagen</span></strong></p>\r\n<p>Tretten b&oslash;ker p&aring; ti &aring;r! Det er en imponerende produksjon. Hvordan greier du&nbsp;&aring; skrive s&aring; mange b&oslash;ker? Da lurer jeg b&aring;de p&aring; hvor inspirasjonen&nbsp;kommer fra og hvordan du strukturer dagene dine?</p>\r\n<p>Tusen takk, og det rakk faktisk &aring; bli 13 b&oslash;ker, f&oslash;r jubileums&aring;ret 2021 takket for seg. Desember 2019 tok jeg valget &aring; bli forfatter p&aring; heltid, og det har selvsagt gitt mye mer tid til skriving. Jeg skriver (mer eller mindre) hver dag, mandag som s&oslash;ndag, 17. mai, julaften og ferier, og blir det i snitt 1.000 ord p&aring; en &oslash;kt, har man jo f&oslash;rsteutkastet p&aring; en roman klar p&aring; to-tre m&aring;neder. Innimellom skrivingen g&aring;r jeg tur med hunden, og disse turene er helt n&oslash;dvendig for &aring; f&aring; ideer, og l&oslash;se opp i tekstfloker</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">Den utl&oslash;sende hendelsen</span></strong></p>\r\n<p>Du var jo voksen da du debuterte. N&aring;r skj&oslash;nte du at det var forfatter&nbsp;du ville bli?</p>\r\n<p>Jeg kommer til &aring; snakke mer om dette i Mentor-m&oslash;tet. Jeg har ingen litter&aelig;r bakgrunn, har ikke alltid dr&oslash;mt om &aring; bli forfatter, men jeg har alltid v&aelig;rt glad i &aring; skrive. Det ble s&aring;dd et fr&oslash; p&aring; midten av nitti-tallet, og s&aring; skjedde det noe dramatisk f&oslash;rste &aring;r i det nye &aring;rtusen, som vel var da jeg virkelig forsto at jeg ville bli forfatter. De som er nysgjerrige p&aring; hva som skjedde, f&oslash;r lytte til mentorm&oslash;tet :)</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">&Aring; jobbe som forfatter</span></strong></p>\r\n<p>Dr&oslash;mmen er jo &aring; bli forfatter! Hva er det beste med &aring; v&aelig;re det?</p>\r\n<p>For meg er det aller beste &aring; f&aring; drive med det jeg elsker. Jeg f&oslash;ler meg privilegert, samtidig er det ikke til &aring; komme fra at det er hard jobbing. Jeg skriver som nevnt hver dag, og i tillegg kommer tingene man gj&oslash;r for &aring; komme ut til leserne med boken man har skrevet.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Et yrke for spesielt interesserte</strong></span></p>\r\n<p>Og hva er det verste? Hvis noe s&aring;nt fins, da.</p>\r\n<p>Jeg vil ikke si at det er noe \"det verste\" med &aring; v&aelig;re forfatter. Men jeg pleier &aring; si at det er et yrke for spesielt interesserte. Man m&aring; gj&oslash;re dette av de rette grunnene, for lysten og gleden ved &aring; skrive. Om man dr&oslash;mmer om &aring; bli forfatter for rikdom og kjendisstatus, tror jeg de fleste blir skuffet.</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">Vil gjerne inspirere!</span></strong></p>\r\n<p>Har du noen tips til andre som dr&oslash;mmer om bok?</p>\r\n<p>Etter &aring; ha lyttet til mentorm&oslash;tet h&aring;per jeg flere sitter igjen med noen tips, om ikke annet har latt seg inspirere av min historie.</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">Mange prosjekter</span></strong></p>\r\n<p>Skriver du p&aring; noe n&aring;?</p>\r\n<p>Jeg skriver alltid p&aring; noe, og akkurat n&aring; har jeg seks prosjekter i litt ulike faser av prosessen.</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">Lenge leve faghandelen!</span></strong></p>\r\n<p>Og hvor kan vi finne b&oslash;kene dine?</p>\r\n<p>Begge barne-seriene mine er tilgjengelig fysisk hos alle bokhandlere i landet, ellers s&aring; er det bare &aring; sp&oslash;rre etter b&oslash;kene hos din lokale bokhandler. Jeg heier p&aring; &aring; handle i faghandel - og lokalt!</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">Ingenting er umulig!</span></strong></p>\r\n<p>Vi gleder oss vilt til &aring; se deg live hos Forfatterskolen! Men for de&nbsp;som ikke kjenner deg s&aring; godt enda, hvorfor b&oslash;r alle f&aring; med seg&nbsp;mentorm&oslash;tet med deg?</p>\r\n<p>Jeg h&aring;per min historie kan v&aelig;re til inspirasjon for de som &oslash;nsker &aring; gi ut bok. Det vil v&aelig;re lite fokus p&aring; skrivetekniske ting, men mer p&aring; hva jeg har gjort for &aring; forf&oslash;lge dr&oslash;mmen min - og realisere den. Som forfatter-partneren min p&aring; Mot og Mysterier-serien sier: Ingenting er umulig, det umulige tar bare litt lengre tid.</p>\r\n<p>&nbsp;</p>\r\n<p>Frode Eie Larsen skriver for b&aring;de barn og voksne. Han debuterte i 2011 p&aring; Liv forlag med krimromanen &laquo;Hemmeligheten&raquo;. Siden har han utgitt ytterligere sju krimromaner for voksne og fem spenningsb&oslash;ker for barn sammen med Dag Otto Lauritzen. Han har ogs&aring; skrevet en rekke noveller, vunnet S&oslash;lvkniven og blitt nominert til Bokslukerprisen.&nbsp;</p>\r\n<p>&nbsp;</p>','/storage/blog/1642415202.jpeg',NULL,'/storage/blog/author/1642415202.jpeg',1,'2022-01-17','2022-01-17 10:26:42','2022-01-17 10:26:42'),(39,5004,'Å følge forfatterdrømmen','<div>&nbsp;</div>\r\n<div>\r\n<p class=\"v1msonormal\">Du debuterte jo som voksen. Betyr det at forfatterdr&oslash;mmen kom seint&nbsp;til deg eller l&oslash;sna det bare ikke f&oslash;r da?</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">Forfatterdr&oslash;mmen har v&aelig;rt der helt siden jeg som liten gutt slukte samtlige 105 b&oslash;ker om Hardy-guttene,&nbsp;+ det aller meste av Bobsey-Barna og Fr&oslash;ken Detektiv. Jeg elsket &aring; lese, og ingenting var mer hellig for meg enn matfriminuttet p&aring; barneskolen da fr&oslash;ken leste h&oslash;yt til oss. Jeg husker spesielt at hun las Kong Salomos miner og Robinson Crusoe til oss. Fantastisk! I ungdommen leste jeg alt jeg kom over fra Cappelens spenningsserie Cap, og forfatterdr&oslash;mmen levde fremdeles. S&aring; kommer livet inn fra sidelinja, og det ble utdanning, barn, ekstrajobber og alle mulige andre ting som opptar tiden. Men, i 2009 satt jeg og min kone Agnes Matre p&aring; en strand i Frankrike og snakket om hvor vi s&aring; livene v&aring;re om fem &aring;r. Begge var enige om at n&aring; skulle vi oppfylle forfatterdr&oslash;mmen vi begge bar p&aring; i barndommen og ungdommen, og slik ble det.</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">&nbsp;</p>\r\n<p class=\"v1msonormal\"><span style=\"font-size: 18pt;\">Lesing skal v&aelig;re spennende!</span></p>\r\n<p class=\"v1msonormal\">Hva var det med krimsjangeren som tiltrakk deg?</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">Det har alltid st&aring;tt et stort ER-LIK TEGN mellom lesing og spenning hos meg. Som sagt helt fra de f&oslash;rste b&oslash;kene jeg husker at jeg leste, via alt jeg klarte &aring; hoste opp av spenningslitteratur i ungdom og voksen alder. For meg skal alts&aring; lesing v&aelig;re spennende. Om ikke s&aring; kan det bare v&aelig;re. Derfor har jeg aldri funnet glede i &aring; lese ordin&aelig;re skj&oslash;nnlitter&aelig;re b&oslash;ker, selv om jeg har lest mye av det ettersom jeg er norskl&aelig;rer. Det er bare s&aring; d&oslash;rgende kjedelig n&aring;r historien bare handler om hverdagslige ting. Jeg M&Aring; ha noe spennende som driver plottet for &aring; f&aring; leseglede.<br /><br /></p>\r\n<p class=\"v1msonormal\"><span style=\"font-size: 18pt;\">Kombinasjonen forfatter og fulltidsjobb</span></p>\r\n<p class=\"v1msonormal\">Hvordan vil du beskrive skriverutinene dine?</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">Jeg er en lystbetont skriver som skriver sv&aelig;rt mye s&aring; lenge jeg har tid og overskudd til det, men samtidig s&aring; er jeg i hundre prosent stilling som l&aelig;rer, og derfor er jeg ofte for sliten til &aring; skrive s&aring; mye som jeg egentlig har lyst til. Heldigvis s&aring; har jeg da en ukuelig evne til &aring; skrive noe likevel, selv om jeg merker at det jeg skriver ikke n&oslash;dvendigvis blir veldig bra. (Det kan redigeres senere). Jeg skriver alltid kronologisk fra begynnelse til slutt, og har gjerne klare skrivem&aring;l&nbsp;p&aring; hvor mye jeg skal skrive hver dag.</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">&nbsp;</p>\r\n<p class=\"v1msonormal\"><span style=\"font-size: 18pt;\">Sett deg skrivem&aring;l!</span></p>\r\n<p class=\"v1msonormal\">Har du noen tips til andre som dr&oslash;mmer om bok?</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">Litt som det jeg sa i sted. Du m&aring; ha LYST til &aring; skrive, men du f&aring;r aldri til noen bok dersom du skal skrive p&aring; lysten alene. Det kommer til &aring; komme perioder der du hater manuset ditt h&oslash;yere enn noe annet p&aring; jord, og du er sikker p&aring; at det er det st&oslash;rste skvipet noen noensinne har skrevet ned p&aring; et tastatur. Derfor m&aring; du ha skrivem&aring;l, og f&oslash;lge dem slavisk. Get the job done, om dere forst&aring;r. Skriver du 250 ord hver dag s&aring; har du alts&aring; et ferdig manus til en bok p&aring; 300 sider&nbsp;+ i l&oslash;pet av et &aring;r. 250 ord er for de fleste av oss gjort unna p&aring; 15-20 minutter. Selv har jeg vanligvis et skrivem&aring;l&nbsp;p&aring; ca 1000-1500 ord hver gang jeg setter meg ned, og det tar gjerne et par timer.</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">&nbsp;</p>\r\n<p class=\"v1msonormal\"><span style=\"font-size: 18pt;\">Plotter, ikke pantser</span></p>\r\n<p class=\"v1msonormal\">Skriver du plottdrevet eller f&oslash;ler du deg mer frem?</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">Veldig plottdrevet&nbsp;for min del. Hver eneste scene er planlagt p&aring; forh&aring;nd, og samlet f&oslash;r jeg skriver f&oslash;rste setning p&aring; boka. Jeg har alts&aring; 60-80 scener planlagt f&oslash;r jeg skriver noe som helst p&aring; et manus.<br /><br /></p>\r\n<p class=\"v1msonormal\"><span style=\"font-size: 18pt;\">Mange baller i luften!</span></p>\r\n<p class=\"v1msonormal\">Skriver du p&aring; noe n&aring;?</p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">Ja, jeg har tre prosjekter i gang, samt et som venter om ikke s&aring; lenge. Jeg driver redigeringsarbeid p&aring; \"La alt h&aring;p fare\" som kommer p&aring; Vigmostad &amp; Bj&oslash;rke i august, og er et bidrag til deres serie p&aring; ti kortromaner i spenningssjangeren basert p&aring; de ti budene i Bibelen. I tillegg jobber jeg med andre bok i Gabriel Fjell-serien som jeg regner med kommer v&aring;ren 2022&nbsp;+ at jeg planlegger/skriver p&aring; en ungdomsserie p&aring; tre b&oslash;ker som jeg ikke vet om jeg f&aring;r antatt enn&aring;. Det ventende prosjektet er sesong 2 av lydserien&nbsp;\"Bygda\" som jeg har skrevet for Fabel sammen med krimforfatter &Oslash;rjan Nordhus Karlsson. I tillegg har jeg og Agnes en krimnovelle klar til Bonniers p&aring;skekrimhefte&nbsp;for 2022.</p>\r\n<p class=\"v1msonormal\">&nbsp;</p>\r\n<p class=\"v1msonormal\"><span style=\"font-size: 18pt;\">Og hvor kan vi finne b&oslash;kene dine?</span></p>\r\n</div>\r\n<div>\r\n<p class=\"v1msonormal\">Overalt hvor det finnes b&oslash;ker :) \"Bygda\" kan du lytte til p&aring; Fabel. De fire andre b&oslash;kene b&oslash;kene mine (Maestro, Hjerteknuser, D&oslash;d manns tango og Vargtimen) er alle gitt ut p&aring; Gyldendal, og b&oslash;r kunne finnes p&aring; alle bokhandlere i Norge. Alle mine b&oslash;ker er innkj&oslash;pt av Kulturr&aring;det, s&aring; jeg regner ogs&aring; med at de er &aring; finne i alle landets biblioteker.</p>\r\n<p class=\"v1msonormal\">&nbsp;</p>\r\n<p class=\"v1msonormal\"><span style=\"font-size: 18pt;\">Om forfatteren</span></p>\r\n<p class=\"v1msonormal\">Geir Tangen debuterte i 2016 og har siden gitt ut ytterligere tre kriminalromaner. Han har ogs&aring; gitt ut den spennende lydserien &laquo;Bygda&raquo; sammen med &Oslash;rjan N. Karlsson. B&oslash;kene hans er kritikerroste og oversatt til femten spr&aring;k. Geir har blitt nominert til Maurits Hansenprisen - Nytt blod, ThrillZone Awards og Hebbanprisen i Nederland. Han driver ogs&aring; bloggen bokbloggeir.com, der han raust deler lese- og serietips for den som elsker krim. Absolutt verdt &aring; sjekke ut!</p>\r\n</div>','/storage/blog/1642671631.png','Geir Tangen','/storage/blog/author/1642672584.jpeg',1,NULL,'2022-01-20 09:40:31','2022-01-20 09:56:24'),(40,5004,'Skriv mer, tenk mindre!','<p><span style=\"font-size: 18pt;\"><strong>Knalldebut!</strong></span><br />Hvis jeg har regna riktig, s&aring; var du 21 da du debuterte. Hva vet du n&aring; som du skulle &oslash;nske du visste da?<br />Jeg hadde en knalldebut, og solgte masse b&oslash;ker og hadde det superg&oslash;y! Hvis jeg skulle sendt en hemmelig melding til Ida, 21, s&aring; ville det v&aelig;rt f&oslash;lgende: Du er S&Aring; FLINK og gj&oslash;r S&Aring; BRA jobb, den frykten du har om at forlaget kommer til &aring; si \"Pr&aelig;h&aelig;, k&oslash;dda!\" og la v&aelig;re &aring; utgi boken helt p&aring; tampen, er fullstendig UBEGRUNNET. Den kommer til &aring; komme tilbake hver utgivelse, og den er aldri sann.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Forfatterskapet kommer f&oslash;rst</strong></span><br />Hvordan vil du beskrive skriverutinene dine?<br />Jeg har skriving som jobb nr 1, s&aring; jeg skriver hver dag. Jeg skriver tre sider for h&aring;nd hver morgen for &aring; varme opp, og s&aring; skriver jeg p&aring; det som er dagens prosjekt, enten det er En Bok eller Tekster Til Internett. Alt annet kommer senere. Men det viktigste er ikke &aring; ha en skriverutine, men en skrivededikasjon. Forfatterskapet mitt og jeg har en relasjon som kommer f&oslash;r f.eks - relasjonen til alle som har sendt meg en e-post.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Det hemmelige trikset</strong></span></p>\r\n<p>Jeg har fors&oslash;kt &aring; telle over antall b&oslash;ker du har skrevet og kommer frem til 26 b&oslash;ker siden debuten din i 2008. Hvordan greier du &aring; v&aelig;re s&aring; produktiv?</p>\r\n<p>Det er 30, det er noen som har glippet p&aring; listen der! Trikset er &aring; skrive Hver Dag. (Du ser ikke mine 980 blogginnlegg og mange, mange tusen e-poster og innlegg i aviser og to tonn notatboksider der, men mye utgitte b&oslash;ker henger sammen med Enda Flere Ikke-Utgitte tekster produsert.)&nbsp;</p>\r\n<p><br /><span style=\"font-size: 18pt;\"><strong>Om &aring; v&aelig;re forfatter</strong></span><br />Dr&oslash;mmen er jo &aring; bli forfatter! Hva er det beste og verste med &aring; v&aelig;re det?<br />Jeg kommer ikke p&aring; noen f&aelig;le ting med det. Det er best.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>B&oslash;ker m&aring; skrives!</strong></span><br />Har du noen tips til folk som fantaserer om &aring; utgi bok?<br />Du kan ikke fantasere ut en bok. Skriv mer, tenk mindre</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Heier p&aring; alle som vil skrive!</strong></span></p>\r\n<p>Vi gleder oss s&aring; mye til &aring; se deg live hos Forfatterskolen! Men<br />For dem som ikke kjenner deg s&aring; godt enda, hvorfor b&oslash;r alle f&aring; med seg<br />mentorm&oslash;tet med deg?<br />At jeg heier veldig, veldig p&aring; alle som vil skrive, og at kallet mitt er &aring; f&aring; folk til &aring; skj&oslash;nne at de er mer enn bra nok, og at det bare er &aring; begynne - eller fortsette der du slapp.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>Ida Jackson er forfatter og blogger. Hun har v&aelig;rt nominert til Brageprisen med ungdomsromanen Danielle og med Morfar, Hitler og jeg for voksne. Brillebj&oslash;rnserien hennes har solgt over 150.000 eksemplarer. Ida er ikke bare en produktiv og kritikerrost forfatter, hun er ogs&aring; en mester i &aring; forl&oslash;se andres skrivedr&oslash;mmer. Med andre ord: Dette mentorm&oslash;tet vil du ikke g&aring; glipp av!</p>','/storage/blog/1643277640.png','Ida Jackson',NULL,1,NULL,'2022-01-27 09:54:59','2022-01-27 10:00:40'),(41,5004,'Inngikk pakt med redaktøren','<p><span style=\"font-size: 18pt;\">F&oslash;lelsen av at noe st&aring;r p&aring; spill</span></p>\r\n<p><em>Gratulerer med den fantastiske mottakelsen av T&oslash;yeneffekten! Det er et sinnsykt tr&oslash;kk i den boka! Og kanskje en annen motor enn i dine tidligere b&oslash;ker? Hvordan var prosessen med denne boka sammenligna med dine tidligere b&oslash;ker?</em></p>\r\n<p>Den store forskjellen er at jeg denne gang har lagt handlingen til et navngitt sted - T&oslash;yen. Romanen tar opp i seg virkelige hendelser som mange har et forhold til. Dette er med andre ord ikke bare min historie. Dette valget skapte en sterk forpliktelse til virkeligheten, et ansvar, som faktisk var veldig stimulerende for kreativiteten. Jeg vil jo gjerne ha f&oslash;lelsen av at noe st&aring;r p&aring; spill n&aring;r jeg skriver. Det kjentes som om en annen motor overtok fra det &oslash;yeblikket jeg bestemte meg for &aring; navngi stedet.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Pakt med redakt&oslash;ren&nbsp;</span></p>\r\n<p><em>Og n&aring;r vet du at en bok er ferdig?</em></p>\r\n<p>Den blir egentlig aldri ferdig. Jeg tror jeg kunne ha fortsatt &aring; skrive i det uendelige. S&aring; her trenger jeg hjelp fra min redakt&oslash;r. Jeg inngikk en pakt med ham tidlig p&aring; &aring;ret om at denne h&oslash;sten g&aring;r vi for en utgivelse. Da satte vi en deadline. Denne fikk jeg skj&oslash;vet og skj&oslash;vet p&aring; etter hvert, og da den absolutt ikke kunne flyttes mer, var romanen ferdig, ganske enkelt fordi den m&aring;tte v&aelig;re det. Jeg hadde da jobbet med den i seks &aring;r, men jeg tror at minst halve romanen ble skrevet i l&oslash;pet av de siste to m&aring;nedene. Slutten kom natta f&oslash;r levering.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Lesing er en viktig del av jobben</span></p>\r\n<p><em>Hvordan vil du beskrive skriverutinene dine?</em></p>\r\n<p>Jeg bearbeider mye. Jeg har stor tro p&aring; selve prosessen, at stoffet trenger &aring; modnes f&oslash;r jeg finner ut hva jeg egentlig vil skrive. Jeg jobber hver dag. Liker &aring; begynne om morgenen, etter &aring; ha f&aring;tt barna av g&aring;rde p&aring; skolen, setter jeg meg i senga med en kaffekopp. Innimellom har jeg ensomme opphold p&aring; skrivestua i Hadeland. Da skriver jeg hele dagen, bare avbrutt av en tur, og om kvelden leser jeg. Jeg holder lesingen som en viktig del av jobben - det &aring; hele tida f&aring; ny input, og kjenne hvordan god litteratur virker i meg.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">En tyrann til sjef</span></p>\r\n<p><em>Dr&oslash;mmen er jo &aring; v&aelig;re forfatter! Hva er det beste og verste med det?</em></p>\r\n<p>&Aring; v&aelig;re sin egen sjef er b&aring;de det beste og det verste!&nbsp; Det er en stor frihet, men sjefen kan ogs&aring; bli en f&aelig;l tyrann, og det blir han. I lengden er det noks&aring; utfordrende alltid &aring; v&aelig;re overlatt til seg selv.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Lytt til tilbakemeldinger</span>&nbsp;</p>\r\n<p><em>Har du noen tips til folk som fantaserer om &aring; utgi bok?</em></p>\r\n<p>Det er viktig &aring; f&aring; et annet blikk p&aring; det du skriver. F&aring; inn en eller flere lesere som du stoler p&aring; underveis i prosessen. Lytt til deres tilbakemeldinger, og bruk dem produktivt. Det du selv er mest forn&oslash;yd med, er sjelden det beste i teksten. Men ofte oppst&aring;r det interessante ting du kanskje ikke hadde forutsett selv. N&aring;r en leser peker p&aring; dette, kan du forf&oslash;lge det, og dermed er du midt i en interessant arbeidsprosess, hvor det du skriver former seg litt utenfor din kontroll. Det blir ofte det beste! Og s&aring; er det viktig &aring; lese masse - ogs&aring; den typen litteratur som kan inneb&aelig;re arbeid &aring; komme gjennom. Da strekker du deg.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Elsker &aring; undervise skrivelystne mennesker!</span></p>\r\n<p><em>Du har jo v&aelig;rt en veldig popul&aelig;r mentor hos Forfatterskolen flere ganger. Men for de som enn&aring; ikke kjenner deg, hvorfor skal de se p&aring; mentorm&oslash;te med deg?</em></p>\r\n<p>Jeg har jobbet som forfatter p&aring; fulltid i over tjue &aring;r, og v&aelig;rt gjennom b&aring;de oppturer og nedturer. Jeg tror jeg har viktige erfaringer &aring; dele med andre som vil skrive, b&aring;de n&aring;r det gjelder det h&aring;ndverksmessige og det mer eksistensielle som ligger bakenfor skrivetrangen. Jeg elsker &aring; undervise skrivelystne mennesker, s&aring; jeg h&aring;per &aring; treffe flest mulig p&aring; mentorm&oslash;tet!</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Om Bjarte Breiteig&nbsp;</span></p>\r\n<p><em>Bjarte Breiteig er en av Norges beste novellister og en kritikerrost romanforfatter. Han har vunnet Aschehougs debutantstipend, Anders Jahres kulturpris, Mads Wiel Nygaards legat og Ungdommens kritikerpris. T&oslash;yeneffekten er hans sjuende bok og vi vil bli overraska om det ikke kommer et lite prisdryss i den anledning ogs&aring;. Vi gleder oss til mentorm&oslash;tet mandag 29.08.2022!</em></p>','/storage/blog/1643879774.png','Bjarte Breiteig',NULL,1,'2022-08-25','2022-02-03 09:13:51','2022-08-25 11:39:03'),(42,5004,'Glemte bort skrivinga i tjuefem år','<p><span style=\"font-size: 18pt;\">Skriving h&oslash;rte skolen til</span></p>\r\n<p><em>N&aring;r skj&oslash;nte du at du ville bli forfatter?</em></p>\r\n<p>Som liten tenkte jeg ikke p&aring; at det var folk som lagde b&oslash;kene, jeg bare leste dem. Skriving h&oslash;rte skolen til og jeg reflekterte ikke over hvor godt jeg likte det. S&aring; n&aring;r jeg slutta p&aring; skolen, glemte jeg bort skrivinga i tjuefem &aring;r. Da jeg kom p&aring; det igjen, begynte jeg &aring; skrive.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Den viktigste skrivestunden</span></p>\r\n<p><em>Hvordan vil du beskrive skriverutinene dine?</em></p>\r\n<p>De er nesten litt rigide. Jeg st&aring;r opp hver dag klokka sju. S&aring; lager jeg kaffe til meg og kj&aelig;resten og s&aring; skriver vi i hvert v&aring;rt rom til vi blir sultne. Da g&aring;r vi og spiser frokost og leser bok. Jeg skriver i flere bolker utover dagen, men dette er den viktigste stunden. &Aring; f&aring; lov til &aring; f&oslash;lge seg selv ut av s&oslash;vnen og inn i teksten, det er veldig fint. Det er vanskelig &aring; v&aelig;re kritisk n&aring;r man ikke er v&aring;ken. Alt er liksom litt loddent og jeg ser med snille &oslash;yne p&aring; det som drysser ned p&aring; papiret.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Forfatter h&oslash;res s&aring; stort ut!</span></p>\r\n<p><em>Dr&oslash;mmen er jo &aring; v&aelig;re forfatter! Hva er det beste og verste med det?</em></p>\r\n<p>Det beste er &aring; skrive. For meg er skriving en m&aring;te &aring; v&aelig;re i livet p&aring;, en m&aring;te &aring; tenke og v&aelig;re p&aring;. Jeg elsker &aring; tenke i tekst, &aring; kunne forf&oslash;lge en tanke over flere dager. Jeg tror ikke jeg kommer p&aring; noe som er verst med det. Kanskje er det selve tittelen, jeg f&oslash;ler ikke at jeg har vokst helt inn i den enda. Forfatter h&oslash;res s&aring; stort ut, som noe som ang&aring;r noen andre. Men jeg f&aring;r vel bare ta meg selv i nakken og b&aelig;re den med stolthet. N&aring; er jeg forfatter.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><em>Har du noen tips til folk som fantaserer om &aring; utgi bok?</em></span></p>\r\n<p>For meg har det funka best &aring; tenke motsatt. &Aring; tenke at jeg velger skrivelivet, uavhengig av om jeg noensinne f&aring;r ut en bok. Om m&aring;let bare er &aring; kalle seg forfatter, f&oslash;les det som et tomt m&aring;l. S&aring; kanskje det er et tips? &Aring; velge skrivelivet, &aring; velge skrivinga. N&aring;r det er sagt, s&aring; var det &aring; utgi bok selvsagt ogs&aring; et m&aring;l. Men ikke utelukkende. Mer et resultat av &aring; velge skrivelivet. Rent praktisk vil jeg si at man m&aring; skrive s&aring; mye man kan, lese s&aring; mye man kan. Skrive p&aring; nye steder, nye m&aring;ter, lese ting du liker og ting du ikke forst&aring;r. B&oslash;ker er som folk, man kan ikke bare omgi seg med dem som ligner en selv. Da f&aring;r du ingen motstand.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><em>Hvorfor skal folk se mentorm&oslash;tet med deg?</em></span></p>\r\n<p>For meg kjennes det ut som om jeg har et lite b&aring;l inni meg som brenner for det &aring; skrive og det &aring; skape. Det er denne gl&oslash;den jeg vil dele med de skriveglade folka p&aring; Forfatterskolen. Jeg er ikke bare forfatter, jeg er ogs&aring; Kaospilot. Kreativitet og skapende prosesser er noe av det mest spennende jeg vet om. Og s&aring; tenker jeg at det er et poeng at jeg forel&oslash;pig bare har gitt ut &eacute;n bok. Jeg vet godt hvordan det er &aring; bare skrive for seg selv og nesten m&aring;tte tvinge folk til &aring; lese det du har skrevet.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><em>Og hvor kan vi finne boka di?</em></span></p>\r\n<p>Du kan bestille den p&aring; cappelendamm.no. Eller bare l&aring;ne den p&aring; biblioteket. Jeg elsker bibliotek. Tenk at s&aring;nne steder fins, at man bare kan g&aring; dit og v&aelig;re der uten &aring; m&aring;tte kj&oslash;pe noe. Vi er heldige.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><em>Camilla Bogetun Johansen er forfatter og utdannet Kaospilot. Debutromanen </em>Egen maske f&oslash;rst<em> kom p&aring; Cappelen Damm i 2021. Vi gleder oss til mentorm&oslash;tet 14.02.2022!</em></p>\r\n<p>&nbsp;</p>','/storage/blog/1644493509.png','Camilla Bogetun Johansen','/storage/blog/author/1644493391.jpeg',1,NULL,'2022-02-10 11:43:11','2022-02-10 11:45:09'),(43,5004,'Skriving for søppelbøtta er ikke fånyttes!','<p>S&aring; g&oslash;y at du skal v&aelig;re mentor hos Forfatterskolen! Du har jo en hel br&aring;te av b&oslash;ker bak deg. Mange b&oslash;ker for barn, men ogs&aring; krim og noveller for voksne.&nbsp;</p>\r\n<p>Hvordan kom du til skrivinga?</p>\r\n<div>Da jeg var ungdom, var jeg veldig sjenert og redd for &aring; si ting i timene. Da begynte jeg &aring; skrive mye, sikkert for &aring; f&aring; uttrykt meg. (Den gangen kunne jeg ikke i mine villeste dr&oslash;mmer tenkt at jeg som voksen dro rundt og holdt foredrag!) Jeg fors&oslash;kte for &oslash;vrig &aring; bli forfatter i mange, mange &aring;r, f&oslash;r jeg endelig klarte det som 32-&aring;ring. Da hadde jeg sikkert 7-8 havarerte manus bak meg. Men samtidig hadde all skrivingen for s&oslash;pleb&oslash;tta ikke v&aelig;rt f&aring;nyttes, men ogs&aring; bra trening!</div>\r\n<div><br />Hvordan ser en typisk skrivedag ut for deg?</div>\r\n<div>Jeg rigger meg til i kjellerstua n&aring;r kone og barn har dratt p&aring; jobb og skole, og s&aring; skriver jeg fram til lunsj. Etter lunsj gj&oslash;r jeg ofte andre ting, som for eksempel &aring; lese gjennom det jeg har skrevet -- eller andre sm&aring; og store gj&oslash;rem&aring;l som f&oslash;lger med forfatteryrket.<br /><br /></div>\r\n<div>Hva syns du er forskjellen p&aring; &aring; skrive for barn og for voksne?</div>\r\n<div>Ingenting og alt. Begge deler handler om &aring; formidle en historie eller et stoff i riktig \"h&oslash;yde\".&nbsp;<br /><br /></div>\r\n<div>Har du noen gode r&aring;d til de som dr&oslash;mmer om &aring; bli publisert?<br />Den viktigste ingrediensen i kreativitet, er t&aring;lmodighet!</div>\r\n<div>&nbsp;</div>\r\n<div>Hvorfor skal folk se p&aring; mentorm&oslash;tet med deg?<br />Det m&aring; jo v&aelig;re om de har lyst til &aring; l&aelig;re noe.</div>\r\n<div>&nbsp;</div>\r\n<div>Og hvor kan vi finne b&oslash;kene dine?</div>\r\n<div>Foruten p&aring; nettbokhandeler og p&aring; bibliotek, kan de jo finne litt om b&oslash;kene mine p&aring; hjemmesiden min: <a href=\"http://larsmahle.no/\" target=\"_blank\" rel=\"noopener noreferrer\">larsmahle.no</a></div>\r\n<div>Og her er familien Vamp: <a href=\"https://www.norli.no/familien-vamp?queryID=d33c6824d77ec4faa9315a6e705aee3e&amp;objectID=273324&amp;indexName=norli_default_products\">https://www.norli.no/familien-vamp?queryID=d33c6824d77ec4faa9315a6e705aee3e&amp;objectID=273324&amp;indexName=norli_default_products</a>&nbsp;</div>','/storage/blog/1645783205.jpeg','Lars Mæhle',NULL,1,'2022-02-25','2022-02-25 10:00:05','2022-02-25 10:00:05'),(44,5004,'Spennende å eie prosessen selv!','<p class=\"v1p1\"><span class=\"v1s1\" style=\"font-size: 18pt;\">Orket ikke vente p&aring; forlagene </span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">S&aring; g&oslash;y at du skal v&aelig;re mentor hos Forfatterskolen! Du har jo g&aring;tt en spennende vei til publisering, du tok rett og slett ikke et nei for et nei og bestemte deg for &aring; gj&oslash;re jobben selv. Det er s&aring; kult!&nbsp;</span><span class=\"v1s1\">Kan du si litt mer om det?</span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">\"Tusen takk! Jeg var p&aring; et sted i livet hvor jeg trengte &aring; kjenne p&aring; mestringsf&oslash;lelsen, og orket rett og slett ikke vente 4-52 uker p&aring; eventuelle avslag fra forlagene, og syntes det h&oslash;rtes spennende ut &aring; kunne eie hele prosessen selv. N&aring; er jeg heldigvis p&aring; et sted i karrieren hvor jeg synes det er veldig kult &aring; gj&oslash;re det p&aring; denne m&aring;ten, men det har ogs&aring; v&aelig;rt perioder med mye tvil.\"</span></p>\r\n<p class=\"v1p1\">&nbsp;</p>\r\n<p class=\"v1p1\"><span class=\"v1s1\" style=\"font-size: 18pt;\">Har du bestandig hatt et &oslash;nske om &aring; skrive?</span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">\"Ja, jeg oppdaget gleden ved historiefortelling da jeg var 9-10 &aring;r. Hadde en fantastisk barneskolel&aelig;rer som ga mye plass til lek og historiefortelling.\"</span></p>\r\n<p class=\"v1p2\">&nbsp;</p>\r\n<p class=\"v1p1\"><span class=\"v1s1\" style=\"font-size: 18pt;\">Hvordan ser en typisk skrivedag ut for deg?</span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">\"Det kan v&aelig;re alt fra 20 minutter til 8 timer. Det kommer veldig an p&aring; hvor i prosessen jeg er. Jeg liker &aring; ha hjemmekontor med andre i samme situasjon, og hvis det ikke lar seg gj&oslash;re starter jeg gjerne dagen p&aring; telefon med mamma over en kopp kaffe.\"</span></p>\r\n<p class=\"v1p2\">&nbsp;</p>\r\n<p class=\"v1p1\"><span class=\"v1s1\" style=\"font-size: 18pt;\">Har du noen gode r&aring;d til de som dr&oslash;mmer om &aring; bli publisert?</span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">\"Finn en venn, et familiemedlem eller en kollega som vil deg vel, men som du vet gir &aelig;rlige tilbakemeldinger s&aring; du kan vokse og utvikle deg. Tenk at all kritkken er gull verdt f&oslash;r utgivelse. Og ikke gi deg. Det ser ut til &aring; v&aelig;re n&oslash;kkelen i de aller fleste kreative yrker.\"</span></p>\r\n<p class=\"v1p2\">&nbsp;</p>\r\n<p class=\"v1p1\"><span class=\"v1s1\" style=\"font-size: 18pt;\">Hvorfor skal folk se p&aring; mentorm&oslash;tet med deg?</span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">\"Min prosess fra det f&oslash;rste manuset til hvordan jeg i dag har startet AS og skal gi ut den f&oslash;rste boka skrevet av noen andre enn meg selv. S&aring; reisen fra h&aring;pefull forfatterspire til forlegger og forfatter p&aring; fulltid, rett og slett.\"</span></p>\r\n<p class=\"v1p2\">&nbsp;</p>\r\n<p class=\"v1p1\"><span class=\"v1s1\" style=\"font-size: 18pt;\">Og hvor kan vi finne b&oslash;kene dine?</span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">\"Alle steder de selger eller har b&oslash;ker. St&aring;r den ikke i hylla, s&aring; bestiller de bak kassa den for deg.\"</span></p>\r\n<p class=\"v1p1\"><span class=\"v1s1\">Silje Regine Br&aring;ten er forfatter av fantasyromanene Lysveven og Stedfortrederen. Hun har ogs&aring; skrevet ungdomsromanen Mye er d&aring;rlig, noe er fint. Alle b&oslash;kene hennes har f&aring;tt gode anmeldelser.</span></p>','/storage/blog/1646389191.jpeg','Silje Regine Bråthen','/storage/blog/author/1646389191.webp',1,'2022-03-04','2022-03-04 10:19:51','2022-03-04 10:19:51'),(45,5004,'Ikke vær så flink jente!','<p><span style=\"font-size: 18pt;\">Hvordan kom jeg til skrivinga, sp&oslash;r du?</span></p>\r\n<p>&nbsp;</p>\r\n<p>Lang historie om at jeg ikke klarte &aring; snakke som barn,&nbsp;</p>\r\n<p>at jeg hadde et d&aring;rlig utvikla muntlig spr&aring;k og mange lyder jeg ikke klarte &aring; si.</p>\r\n<p>Derfor ble skrivingen en m&aring;te &aring; vise at jeg ikke var s&aring; dum som jeg virka,&nbsp;</p>\r\n<p>at jeg kunne tenke og uttrykke meg, at ja, jeg hadde gjort leksa,&nbsp;</p>\r\n<p>at jeg var med, jeg ogs&aring;.</p>\r\n<p>S&aring;nn sett var skrivinga en m&aring;te &aring; overleve p&aring; &ndash; og en viktig del av identiteten min.</p>\r\n<p>Men hele skolegangen og studentdagene var jeg svak muntlig og sterk skriftlig.</p>\r\n<p>Jeg str&oslash;k i muntlige framf&oslash;ringer b&aring;de p&aring; videreg&aring;ende og p&aring; universitetet og fikk beste karakter skriftlig.&nbsp;Derfor trodde alle l&aelig;rere og&nbsp;utdannelsessystemer&nbsp;at jeg juksa,</p>\r\n<p>og det ble granskninger og m&oslash;ter om jeg hadde juksa og ubehageligheter og beskyldninger.</p>\r\n<p>Til slutt trodde jeg at jeg hadde juksa.</p>\r\n<p>S&aring;nn sett ble skrivinga en m&aring;te &aring; jukse i verden p&aring;, &aring; bl&oslash;ffe p&aring;,</p>\r\n<p>For hvis den ekte m&aring;ten &aring; v&aelig;re menneske p&aring; var den muntlige&nbsp;framtoning,</p>\r\n<p>s&aring; var det skriftlige jeget en bl&oslash;ffmaker.</p>\r\n<p>Jovisst var det en m&aring;te &aring; kommunisere og uttrykke meg p&aring;, ja</p>\r\n<p>&nbsp;&nbsp;&ndash; men det var ogs&aring; en snarvei fram dit jeg ville, et hull i veggen!</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Hvorfor jeg begynte &aring; skrive b&oslash;ker,</span> derimot, handler om noe helt annet.</p>\r\n<p>Det var mer et &oslash;nske om &aring; f&aring; meg et yrke, en rolle, &aring; tjene penger.</p>\r\n<p>Det var en n&oslash;dl&oslash;sning og en siste utvei da jeg ikke fikk til noen av mine andre fors&oslash;k.</p>\r\n<p>Ikke kunstner, for jeg kom ikke inn p&aring; kunst og&nbsp;h&aring;ndverksskolen,</p>\r\n<p>dyrlege, ikke psykolog, for jeg falt av,&nbsp;hoppet av etter noen &aring;r, ikke l&aelig;rer,&nbsp;</p>\r\n<p>for jeg orket ikke l&aelig;rerv&aelig;relsene, overlevde bare en uke og ga opp l&aelig;rergjerningen.</p>\r\n<p>Og hva skulle jeg da bli?</p>\r\n<p>S&aring;nn sett var forfatterrollen en slags redning for meg,</p>\r\n<p>da det faktisk funka det med &aring; skrive&nbsp;b&oslash;ker.</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Hvordan ser en typisk skrivedag ut for deg?</span></p>\r\n<p>Det er ingen typiske&nbsp;skrivedager, for jeg har mye kurs,</p>\r\n<p>Noen p&aring; kvelden, noen p&aring; dagen,</p>\r\n<p>og jeg har voksne barn og familie og hunder som jeg er mye sammen med,</p>\r\n<p>S&aring; jeg skriver n&aring;r jeg har tid og mulighet.</p>\r\n<p>I g&aring;r skrev jeg fra klokka ti p&aring; kvelden til klokka to.</p>\r\n<p>I dag fra klokka tre &ndash; antageligvis.</p>\r\n<p>S&aring;nn sett prioriterer jeg familie, kurs og hunder framfor skrivinga,</p>\r\n<p>Men ikke venner eller hus,</p>\r\n<p>ikke&nbsp;oppvaskmaskinen, gulvene, vaskemaskinen, st&oslash;vsugeren, rotet,</p>\r\n<p>Ellers ville jeg ikke f&aring;tt gjort noe skrivearbeid i det hele tatt.</p>\r\n<p>&nbsp;</p>\r\n<p>Jeg pr&oslash;ver ofte &aring; skrive p&aring; kvelden, seint p&aring; kvelden, rett f&oslash;r jeg legger meg,</p>\r\n<p>for da jobber hodet med spr&aring;k og avsnitt, mens jeg sover.</p>\r\n<p>Og jeg pr&oslash;ver ogs&aring; &aring; skrive litt f&oslash;r jeg g&aring;r p&aring; tur med hundene,</p>\r\n<p>for da ogs&aring; tumler spr&aring;ket, mens f&oslash;ttene mine f&oslash;lger stiene</p>\r\n<p>rundt Skr&aring;levika eller om Pirane og S&oslash;nsteg&aring;rd.</p>\r\n<p>Da kommer jeg ofte hjem med et ferdigtygd avsnitt.</p>\r\n<p>&nbsp;</p>\r\n<p>I igangsettingsperioder (som ofte kan strekke seg over m&aring;neder, av og til &aring;r)</p>\r\n<p>jobber jeg med friskrift og projeksjoner (tilfeldige utgangspunkt).</p>\r\n<p>Da&nbsp;lar jeg armen skrive, og jeg fors&oslash;ker &aring; ikke tenke,&nbsp;</p>\r\n<p>jeg f&oslash;lger bare etter&nbsp;spr&aring;ket som l&oslash;per foran&nbsp;gjennom busker og gress og kratt,</p>\r\n<p>pr&oslash;ver ikke styre, pr&oslash;ver &aring; slippe taket, nysgjerrig p&aring; hvor spr&aring;ket vil,</p>\r\n<p>overrasket over hvor jeg ender.</p>\r\n<p>Det er en teknikk som tar litt tid &aring; l&aelig;re seg,&nbsp;</p>\r\n<p>Det handler mest om &aring; trene seg til &aring; ikke v&aelig;re i forkant med tanken, &aring; ikke ha retning eller m&aring;l,</p>\r\n<p>men &aring; slippe spr&aring;ket fri til &aring; snuse seg fram uten &aring; vite hva eller hvor eller hvordan.</p>\r\n<p>Mest kaos, selvf&oslash;lgelig,</p>\r\n<p>men noe som glitrer innimellom,&nbsp;</p>\r\n<p>som jeg kan&nbsp;bruke, bygge videre p&aring;, hente fram.</p>\r\n<p><br /><br /></p>\r\n<p><span style=\"font-size: 18pt;\">Hva syns du er forskjellen p&aring; &aring; skrive for barn og for voksne?</span></p>\r\n<p>Det sp&oslash;rs hva jeg skriver for barn.</p>\r\n<p>N&aring;r jeg skriver barnedikt for barn, skriver jeg p&aring; samme m&aring;te som for voksne,</p>\r\n<p>tenker minst mulig, bare&nbsp;bobler og friskriver uten &aring; vite hvor jeg skal.</p>\r\n<p>Da vet jeg heller ikke om det er barnedikt&nbsp;eller voksendikt jeg skriver,</p>\r\n<p>Diktsamlinga&nbsp;&laquo;H&aring;pe, sa g&aring;sa&raquo; var opprinnelig del av et diktprosjekt for voksne.</p>\r\n<p>&nbsp;</p>\r\n<p>N&aring;r jeg jobber med barneprosa, derimot, m&aring; jeg tenke analytisk p&aring; struktur,</p>\r\n<p>for barneleserne er sjelden t&aring;lmodige,&nbsp;</p>\r\n<p>og da handler det om motor og dramaturgi, om driv, om handling,</p>\r\n<p>Om igangsettende hendelser, hva som er det verste som kan skje n&aring;,&nbsp;</p>\r\n<p>spenningskurven og&nbsp;overraskelser og vendepunkt.</p>\r\n<p>&nbsp;</p>\r\n<p>Bildeb&oslash;ker krever en helt annen tiln&aelig;rmingsm&aring;te,</p>\r\n<p>for de er for b&aring;de&nbsp;voksne, ungdommer og barn, det er allalder-litteratur,</p>\r\n<p>Og der jobber jeg med flere historier p&aring; &eacute;n gang:&nbsp;</p>\r\n<p>ett eventyrplan i overflaten for barneleseren &nbsp;&ndash;</p>\r\n<p>og dybder med dimensjoner for ungdommer og voksne,</p>\r\n<p>Der jobber jeg med &aring; finne spr&aring;klige bilder,&nbsp;</p>\r\n<p>som fabler, allegorier, metaforer, besjelinger, allusjoner,</p>\r\n<p>som kan ha mange rom og undertekst &aring; tolke.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Har du noen gode r&aring;d til de som dr&oslash;mmer om &aring; bli publisert?</span></p>\r\n<p>Hm, det med publisering er noe annet enn&nbsp;skrivinga , dessverre,</p>\r\n<p>det handler om s&aring; mye mer enn om dette er et bra manus eller ikke,</p>\r\n<p>Det handler om dette er gjort f&oslash;r, om noe lignende allerede fins,</p>\r\n<p>om hva forlag er p&aring; jakt etter til sin utgivelsesportef&oslash;lje,&nbsp;</p>\r\n<p>om hvem du er som person og bakgrunn,</p>\r\n<p>hvem du er som forfatter, hva du jobber med av temaer, av spr&aring;klige grep, av fortellinger,</p>\r\n<p>Og ikke mins handler det om at prosjektet p&aring; et eller annet vis overrasker,</p>\r\n<p>som prosjekt, ide, konsept, som spr&aring;k, som tema eller som tekst helt innledningsmessig.</p>\r\n<p>s&aring;nn sett handler det ogs&aring; om tid og trend og mangel,&nbsp;</p>\r\n<p>ikke bare om &aring; ha skrevet et helt ok manus som fungerer greit som tekst.</p>\r\n<p>&nbsp;</p>\r\n<p>Men selvf&oslash;lgelig: et oppsiktvekkende manus vil fanges opp.&nbsp;</p>\r\n<p>Ikke alltid&nbsp;&laquo;bare&raquo;.&nbsp;Et godt manus, men noe som springer ut fra dokumentet</p>\r\n<p>griper tak i leseren uten &aring; slippe.</p>\r\n<p>Jeg har opplevd det noen ganger som forlagskonsulent, et umiddelbart JA,</p>\r\n<p>at manuset griper tak i meg og gj&oslash;r noe med meg, forandrer min m&aring;te &aring; se verden p&aring;.</p>\r\n<p>Og da griper jo forlaget tak i et slikt manus &ndash; og straks.</p>\r\n<p>&nbsp;</p>\r\n<p>Men hva kan dere gj&oslash;re, dere som skriver?</p>\r\n<p>Mitt beste r&aring;d er &aring; referere til skrivel&aelig;reren min p&aring; forfatterstudiet i B&oslash;, dikterdronningen Eldrid Lunden, og hva hun sa til meg:</p>\r\n<p><em>Kast det og begynn p&aring; nytt</em>&nbsp;(Min tolkning: ikke bli sittende og gnure p&aring; et halvgodt manus).</p>\r\n<p><em>Ikke v&aelig;r s&aring;&nbsp;flink jente</em>&nbsp;( Min tolkning: ikke fors&oslash;ke &aring; skrive riktig og bra, men br&oslash;le eller tulle eller gj&oslash;re dumt og skrive d&aring;rlig og rart)</p>\r\n<p><em><u>Du f&aring;r v&aelig;re den du er til det g&aring;r over av seg sj&oslash;l</u></em>&nbsp;(Min tolkning: &aring; ikke fors&oslash;ke &aring; skrive som noen andre, men &aring; pr&oslash;ve &aring; finne seg sj&oslash;l, sitt spr&aring;k, sin m&aring;te &aring; tenke p&aring;, sin m&aring;te &aring; v&aelig;re i verden p&aring;, finne sitt eget st&aring;sted, sitt eget uttrykk, det mest personlige i en sj&oslash;l og ta&nbsp;utgangspunkt i det, og som min&nbsp;venn Camilla Bogetun uttrykker i et bilde: &aring; bli sin egen knagg!&Aring; henge verden opp p&aring; denne knaggen!)</p>\r\n<p>Og til slutt:&nbsp;<em>G&aring; dit det brenner!&nbsp;</em>(Min tolkning: at noe skal st&aring; p&aring; spill, at det p&aring; en eller annen m&aring;te har en farlighet, noe som trykker)</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Hvorfor skal folk se p&aring; mentorm&oslash;tet med deg?</span></p>\r\n<p>Det er ingen som trenger &aring; se p&aring; mentorm&oslash;tet med meg.</p>\r\n<p>Jeg har f&aring;tt som bestilling &aring; snakke om dikt.</p>\r\n<p>Kanskje noen er interessert i det &ndash; hva dikt er?</p>\r\n<p>Ja, for hva s&oslash;ren er dikt?!! Det syns jeg er interessant sj&oslash;l i hvert fall!</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\">Og hvor kan vi finne b&oslash;kene dine?</span></p>\r\n<p>P&aring; biblioteket! &ndash; og jo, i papirinnsamlingen,&nbsp;</p>\r\n<p>for jeg praktiserer virkelig r&aring;det fra Eldrid Lunden:&nbsp;&laquo;Kast det og begynn p&aring; nytt!&raquo;, ha ha!</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\" data-originalfontsize=\"12pt\" data-originalcomputedfontsize=\"16\">Om Gro Dahle</span></p>\r\n<p><span data-originalfontsize=\"12pt\" data-originalcomputedfontsize=\"16\">Gro Dahle har skrevet dikt, dramatikk, prosa og egentlig det meste. Hun er en av Norges mest produktive forfattere og har f&aring;tt mange priser, blant annet Brageprisen og Kritikerprisen. Hun er lest og elsket av store og sm&aring; og er en sjeldent god formidler. Norges beste skrivel&aelig;rer er hun blitt kalt, og det er vanskelig &aring; v&aelig;re uenig.&nbsp;</span></p>\r\n<p><span data-originalfontsize=\"12pt\" data-originalcomputedfontsize=\"16\">Velkommen til et gnistrende raust og l&aelig;rerikt mentorm&oslash;te mandag 14.mars 2022!</span></p>\r\n<p>Foto: Line Fresti</p>','/storage/blog/1646903110.jpeg','Gro Dahle','/storage/blog/author/1646903110.jpeg',1,'2022-03-10','2022-03-10 09:05:10','2022-03-10 09:20:14'),(46,5004,'Fra rollespilleder til forfatter','<p><span style=\"font-size: 18pt;\"><strong>Hvordan kom du til skrivinga?</strong></span></p>\r\n<p>Den viktigste veien min inn i skrivingen var gjennom rollespillene jeg spilte i ten&aring;rene. Etter hvert skrev jeg alle spillhistoriene selv, og designet store univers kameratene mine kunne spille i (forestill deg Dungeons and Dragons-varianten gjengen spiller i \'Stranger Things\'). Behovet for &aring; improvisere har nok gitt meg den intuitive tiln&aelig;rming til skriving.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Hvordan ser en typisk skrivedag ut for deg?</strong></span></p>\r\n<p>Jeg skriver best f&oslash;r lunsj: P&aring; mine vanlige arbeidsdager skiver jeg mellom 0600-0800. P&aring; ettermiddagen leser jeg ofte gjennom dagens tekst og gj&oslash;r justeringer.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Hvordan f&aring;r du b&oslash;kene dine til &aring; bli spennende?</strong></span></p>\r\n<p>Det m&aring; st&aring; noe p&aring; spill som leseren kan identifisere seg med. Tydelige personer og interessante konflikter. Og s&aring; har jeg et knippe grep jeg bruker til &aring; lage mange sm&aring; spenningsbuer under den buen som strekker seg fra begynnelse til slutt. P&aring; den m&aring;ten h&aring;per jeg leseren synes det er vanskelig &aring; legge fra seg boken.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Har du noen gode r&aring;d til de som dr&oslash;mmer om &aring; bli publisert?</strong></span></p>\r\n<p>Det beste r&aring;det jeg kan gi, annet enn at for &aring; skrive bra s&aring; m&aring; du ogs&aring; lese mye (og variert), er &aring; dele teksten med noen som du vet vil gi deg en konstruktiv tilbakemelding. Det er den enste m&aring;ten &aring; bli bedre p&aring;.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 18pt;\"><strong>Hvorfor skal folk se p&aring; mentorm&oslash;tet med deg?</strong></span></p>\r\n<p>Jeg har etter hvert skrevet noen b&oslash;ker, og h&aring;per de erfaringene jeg har gjort meg vil v&aelig;re til hjelp for andre som skriver. Jeg er spesielt opptatt av m&aring;ter for &aring; skape driv- og spenning p&aring; ulike niv&aring;er i en roman, samt hvordan man kan f&aring; dialogen til &aring; fungere innenfor fortellingens kontekst.</p>\r\n<p>&nbsp;</p>\r\n<p><strong><span style=\"font-size: 18pt;\">Og hvor kan vi finne b&oslash;kene dine?</span></strong></p>\r\n<p>De fleste kan bestilles p&aring; nettet, de tre siste titlene (i alle fall) er &aring; finne i bokhandlerne. S&aring; er de fleste titlene p&aring; Storytel eller Fabel, og som ebok.</p>\r\n<p>&nbsp;</p>\r\n<p>&Oslash;rjan Nordhus Karlsson har skrevet tjue romaner, en rekke noveller og&nbsp;tre oversettelser. Han har skrevet krim, spenning og sci-fi og skriver&nbsp;like lett for ungdom som for voksne. B&oslash;kene hans f&aring;r sv&aelig;rt gode&nbsp;anmeldelser og b&aring;de femmere og seksere trilles om hverandre n&aring;r han&nbsp;kommer med en utgivelse. &Oslash;rjan ble ogs&aring; nominert til S&oslash;lvkniven for&nbsp;spenningsromanen R&oslash;d stjerne. Det er bare &aring; glede seg til mentorm&oslash;tet&nbsp;28.mars!</p>\r\n<p>&nbsp;</p>','/storage/blog/1648117323.jpeg','Ørjan N. Karlsson','/storage/blog/author/1648117323.jpeg',1,'2022-03-24','2022-03-24 10:22:03','2022-03-24 10:22:03'),(47,5004,'Leste 173 bøker på et år!','<p><span style=\"font-size: 14pt;\">Hva betyr b&oslash;ker og lesing for deg?</span><br />- Det betyr avslappning, hvile, kunnskap, eventyr og s&aring; mye mer. Jeg bruker b&oslash;kene b&aring;de til &aring; oppleve nye ting og l&aelig;re, men ogs&aring; til &aring; slappe av, koble av og f&aring; et avbrekk i en ellers hektisk hverdag.&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Hvordan starta du &aring; blogge/instagramme om b&oslash;ker?</span><br />- Jeg jobbet som butikksjef i Norli i noen &aring;r, og drev en konto for butikken min. Jeg ble kjent med s&aring; mange fine folk og syns det var g&oslash;y &aring; holde meg oppdatert p&aring; andres tanker og lesevaner, men da jeg skulle bytte butikk m&aring;tte jeg jo ogs&aring; bytte konto. Da fikk jeg et behov for &aring; lage mitt eget lille hj&oslash;rne p&aring; internet som ble readygoread.&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Hvor mange b&oslash;ker leser du i &aring;ret og hvordan i alle dager rekker du det?</span><br />- Det blir fort 100-150 b&oslash;ker i &aring;ret, og ja, jeg inkluderer lydb&oslash;ker i den utregningen. Litteraturen er noe jeg prioriterer i hverdagen, s&aring; jeg pr&oslash;ver &aring; f&aring; lest litt hver dag, i tillegg til at jeg har en ganske h&oslash;y lesehastighet. Jeg pr&oslash;ver &aring; fokusere mindre p&aring; antall b&oslash;ker og antall sider enn jeg har gjort de siste &aring;rene, fordi det til syvende og sist skal handle om leseopplevelsene og ikke antallet. i 2020 satte jeg meg et m&aring;l om 50.000 sider, og da m&aring;tte jeg virkelig jobbe for &aring; f&aring; det til. Har fortsatt litt \"hangover\" etter det, og jobber med &aring; finne tilbake til ekte leseglede som ikke er preget av noen form for konkurranse mot meg selv og andre.&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Hva b&oslash;r en forfatter tenke p&aring; n&aring;r det kommer til sosiale medier?</span>&nbsp;<br />- &Aring; la leseren bli kjent med deg! Alle forfatterne jeg genuint liker &aring; f&oslash;lge p&aring; sosiale medier lar meg v&aelig;re en del av hverdagen deres og tar meg inn i deres verden. Jeg har veldig tro p&aring; &aring; v&aelig;re personlig p&aring; sosiale medier, men det er viktig &aring; bemerke at det er forskjell p&aring; personlig og privat. Dette og mer er blant annet det jeg skal snakke om p&aring; mentorm&oslash;tet 4. april.</p>\r\n<p><span style=\"font-size: 14pt;\">Du virker som en person som leser langt bredere enn din egen</span><br /><span style=\"font-size: 14pt;\">favorittsjanger. Hvis det er tilfelle, kan du si noe om det?</span><br />- Jeg er en ekstremt allsidig leser, og vil faktisk p&aring;st&aring; at jeg leser alt. Jeg har selvf&oslash;lgelig sjangre og b&oslash;ker jeg liker bedre enn andre, men det er sjeldent noe jeg velger bort pga form og fasong. Utenom mitt \"hat\" mot romanromaner da, men det f&aring;r du nesten f&oslash;lge meg p&aring; Instagram for &aring; f&aring; vite mer om.&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Hvilket r&aring;d skulle du selv &oslash;nske du hadde f&aring;tt f&oslash;r du starta?</span><br />- Ikke v&aelig;r redd for &aring; starte en samtale med personer du f&oslash;lger og beundrer. De fleste er &aring;pne for &aring; gi r&aring;d og dele av sine erfaringer, og man l&aelig;rer mest av hverandre.&nbsp;<br />&nbsp;</p>\r\n<p>Malin Adriaensen driver litteraturkontoen @readygoread p&aring; Instagram og podcasten Boksnakk.&nbsp;<br />Hun har over fem tusen f&oslash;lgere og brenner for &aring; spre leselyst og leseglede.<br />Hun har jobbet som daglig leder i flere Norli-butikker og fikk Serviceprisen for sitt engasjement i butikken og p&aring; sosiale medier.&nbsp;<br />Ett &aring;r leste Malin hele 173 b&oslash;ker, og hun elsker &aring; dele de gode leseopplevelse sine med andre.&nbsp;<br />Det er ingen tvil om at alle skrivende mennesker som &oslash;nsker seg<br />synlighet m&aring; f&aring; med seg dette mentorm&oslash;tet om hvordan bruke sosiale<br />medier som forfatter p&aring; best mulig m&aring;te. 4.april 2022 klokken 20.00. Vel<br />m&oslash;tt!</p>','/storage/blog/1648797253.png','Malin Adriaensen','/storage/blog/author/1648797253.png',1,'2022-04-01','2022-04-01 07:11:52','2022-04-01 07:14:13'),(48,5004,'Å utvikle en egen stemme handler like mye om å lese som å skrive','<p><span style=\"font-size: 14pt;\">Hvor vanskelig kan det v&aelig;re?</span></p>\r\n<p>Jeg var en av disse ivrige elevene i norsktimene p&aring; barne- og ungdomsskolen som koste meg kraftfullt med &aring; skrive stil. Den sommeren jeg var seksten, var det umulig &aring; f&aring; seg sommerjobb p&aring; Hamar, der jeg bodde. Den gangen hadde NRK morgenk&aring;serier p&aring; radioen hver morgen. Jeg tenkte: Hvor vanskelig kan det v&aelig;re &aring; skrive en ukes morgenk&aring;serier? Og hva betaler de? Jeg satte meg ned med stoppeklokke foran radioen og tok tiden p&aring; k&aring;seriene, og skrev en serie med k&aring;serier som jeg mente m&aring;tte passe perfekt &ndash; i hvert fall var de akkurat passe lange. S&aring; sendte jeg dem til NRK. Jeg fikk brev tilbake om at dette var fine saker, og at jeg kunne komme i studio p&aring; Marienlyst og lese dem inn. S&aring; da gjorde jeg det. Jeg skj&oslash;nner virkelig ikke hvor den selvsikkerheten kom fra. Men det ble jo sommerjobb av det; de betalte ganske bra.</p>\r\n<p><br /><span style=\"font-size: 14pt;\">Skriver i ferier og om nettene&nbsp;</span><br />De fleste av mine skrivedager er helt vanlig arbeidsdager i universitetsjobben min, og handler om alt annet enn kreativ skriving. Det er mye veiledning av studenter, skriving av forelesninger og administrasjon av dette &amp; hint &ndash; helt prosaisk skriving p&aring; krever plass i hjernen p&aring; en bestemt m&aring;te. B&oslash;kene mine, derimot, skriver jeg i ferier, gjerne om nettene. Jeg m&aring; ha rom til &aring; samle tankene og roe hjertet, og til &aring; bli der en god stund, n&aring;r jeg jobber med et bokprosjekt. Og om natten er det stille og fint.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Ingen hemmelighet hvor forlagene legger lista</span><br />Vit at det &aring; utvikle en stemme og en egen stil handler like mye om &aring; lese som om &aring; skrive. De fleste amat&oslash;rskribenter jeg kjenner er mye mer opptatt av &aring; bli utgitt selv, enn av &aring; lese hva andre har utgitt. Men s&oslash;rg i det minste for &aring; orientere deg godt om hva som kjennetegner de b&oslash;kene som faktisk kommer ut &ndash; s&aelig;rlig p&aring; det forlaget du evt tenker &aring; sende manuset ditt til. Det er jo ingen hemmelighet hvor forlagene legger lista &ndash; lista finner du i b&oslash;kene de utgir. Pass p&aring; &aring; velge et forlag som faktisk ser ut til &aring; utgi den typen bok som du skriver.&nbsp;<br />Men les ogs&aring; gammel litteratur, og litteratur fra alle kanter av verden. Tenk p&aring; forfatterne bak de b&oslash;kene som allerede fins, som et velvillig laug av kolleger som er mer enn villige til &aring; gi deg tips. De fleste av dem er d&oslash;de for lenge siden. Men det betyr ikke at de ikke kan hjelpe. Det er en misforst&aring;else at den beste litteraturen er den som kommer ut akkurat n&aring;, her i v&aring;rt hj&oslash;rne av verden.&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Hva kan vi forvente av mentorm&oslash;tet med deg?</span><br />Jeg skal gj&oslash;re mitt beste for &aring; fortelle og forklare hva jeg selv har l&aelig;rt om &aring; skape fortellinger gjennom &aring; skrive dem selv, og gjennom &aring; hjelpe andre.</p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Og hvor kan vi finne b&oslash;kene dine?</span><br />P&aring; biblioteket. De to b&oslash;kene om &aring; skrive fins i bokhandelen.&nbsp;</p>\r\n<p><br />Merete Morken Andersen skriver fag- og skj&oslash;nnlitteratur, hun skriver for voksne og barn, og underviser i skriving p&aring; alle niv&aring;er. Hun har jobbet som tidsskrift- og forlagsredakt&oslash;r, og startet og ledet i sin tid Aschehoug forfatterskole. &nbsp;Hun har f&aring;tt b&aring;de Kritikerprisen og Amalie Skram-prisen, og det er hun som har skrevet den sagnomsuste Skriveboka. Hennes seneste bok er &Aring; skape fortellinger - den lille skriveboka (Aschehoug 2022). Dette mentorm&oslash;tet m&aring; du f&aring; med deg!</p>\r\n<p>Foto: Jorunn Solli</p>\r\n<p>&nbsp;</p>','/storage/blog/1651915505.jpeg','Merete Morken Andersen',NULL,1,'2022-05-07','2022-05-07 09:25:05','2022-05-07 09:25:05'),(49,5004,'Det er aldri for sent!','<p>Jeg debuterte sent, var hele femti &aring;r, men dr&oslash;mmen om &aring; skrive hadde jeg hatt i mange &aring;r. Med andre ord er jeg et levende bevis p&aring; at det aldri er for sent.</p>\r\n<p><strong><span style=\"font-size: 14pt;\">Tvinger seg selv til &aring; skrive</span></strong><br />N&aring;r jeg er i en skrivefase setter jeg meg foran tastaturet i titiden. F&oslash;r det virker ikke hodet. Uansett om det er godt eller d&aring;rlig, g&aring;r lett eller tungt, tvinger jeg meg til &aring; skrive tekst tilsvarende minst fire boksider. Som regel l&oslash;sner det underveis.</p>\r\n<p><strong><span style=\"font-size: 14pt;\">Jobb hardt og hold ut</span></strong><br />Til alle dem som dr&oslash;mmer om &aring; bli publisert; v&aelig;r t&aring;lmodig, jobb hardt og hold ut, men vit ogs&aring; at det ikke er en menneskerett &aring; bli forfatter.</p>\r\n<p><strong><span style=\"font-size: 14pt;\">Et mentorm&oslash;te fylt med konkrete r&aring;d</span></strong><br />P&aring; mentorm&oslash;tet h&aring;per jeg at jeg kan gi gode og mest mulig konkrete r&aring;d om prosessen fra id&eacute; til ferdig manus, - r&aring;d som kan v&aelig;re nyttige uavhengig av sjanger.</p>\r\n<p><strong><span style=\"font-size: 14pt;\">Og hvor kan vi finne b&oslash;kene dine?</span></strong><br />B&oslash;kene mine er lette &aring; finne, i bokhandelen, p&aring; nettet eller p&aring; biblioteket.</p>\r\n<p><br />Chris Tvedt er en anerkjent og bejublet krimforfatter. Han er mest kjent for Mikael Brenne og Edvard Matre, men han har ogs&aring; skrevet b&oslash;ker for ungdom. Han er oversatt til flere spr&aring;k og har blant annet vunnet Rivertonprisen. Om du skriver krim, s&aring; M&Aring; du f&aring; med deg dette mentorm&oslash;tet. Men det er mye &aring; l&aelig;re her uansett hva du skriver. Mandag 16.mai klokken 20.00!</p>\r\n<p>Foto: Maja Hattvang</p>','/storage/blog/1652345823.jpg','Chris Tvedt',NULL,1,NULL,'2022-05-12 08:57:03','2022-05-12 08:57:03'),(51,5004,'En måte å forstå verden på','<p>&nbsp;</p>\r\n<p>Skriving er for meg en m&aring;te &aring; forst&aring; verden p&aring;, s&aring; for meg har det&nbsp;v&aelig;rt viktig siden barneskolen. Jeg skriver i alle sammenhenger og til<br />alle tider, og ofte ikke for andre enn meg selv.</p>\r\n<p><img src=\"https://forfatterskolen.no/storage/photos/1376/Forelesere/1653034439.jpg\" alt=\"\" width=\"326\" height=\"154\" /></p>\r\n<p><span style=\"font-size: 14pt;\">Forskjellen p&aring; gode og d&aring;rlige skrivedager</span></p>\r\n<p>En god skrivedag best&aring;r av fire timer med tidvis gode strekk i&nbsp;skriving eller redigering. En d&aring;rlig skrivedag best&aring;r av fire timer&nbsp;med tankespring, tilfeldig rambling rundt p&aring; nettet og noen linjer p&aring;&nbsp;et ark som jeg er skikkelig misforn&oslash;yd med.</p>\r\n<p><br /><span style=\"font-size: 14pt;\">Skriv!</span></p>\r\n<p>Det er det vanlige: Skriv.<br />Det nytter ikke &aring; si at du vil bli publisert hvis du ikke skriver.<br />Og deretter: Les.<br />Og deretter: Lytt (til andre om skriving).</p>\r\n<p><br /><span style=\"font-size: 14pt;\">Mentorm&oslash;te mandag</span><br />En tidvis humoristisk, tidvis strukturert, tidvis dialogisk&nbsp;gjennomgang av viktige elementer &aring; tenke p&aring; n&aring;r du skal gi&nbsp;fortellingen din liv gjennom personer leseren skal m&oslash;te.<br />Jeg gleder meg!</p>\r\n<p><br />Lise Forfang Grimnes er forfatter og forteller. Hun har gitt ut&nbsp;fagb&oslash;ker, ungdomsromaner og jobber engasjert med &aring; formidle&nbsp;fortellinger. B&oslash;kene hennes er kritikerroste, h&oslash;yt elsket og hun har&nbsp;vunnet Kulturdepartementets debutantpris for beste barne- og&nbsp;ungdomsbok. Hun har ogs&aring; v&aelig;rt bokblogger, s&aring; her er det mye &aring; l&aelig;re p&aring;&nbsp;mange felt!</p>\r\n<p>Foto: Anja Ivanowitz</p>','/storage/blog/1653034439.jpg','Lise Forfang Grimnes',NULL,1,'2022-11-14','2022-05-20 08:13:59','2022-11-14 12:02:56'),(52,5004,'Ta vare på de håpløse ideene!','<p><span style=\"font-size: 14pt;\"><img src=\"https://forfatterskolen.no/storage/photos/1376/Blogg/1654764681.jpg\" alt=\"\" width=\"204\" height=\"274\" /></span></p>\r\n<p>&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Det begynte med teater</span><br />Jeg var veldig glad i &aring; spille teater da jeg var helt ung, og jeg dr&oslash;mte om &aring; bli skuespiller. S&aring; gikk jeg p&aring; flere teaterkurs og &oslash;vde p&aring; roller. En gang fikk vi i oppgave &aring; lage en egen karakter, fortelle en historie ut fra denne. Da skrev jeg en lang tekst og det var mye &aring; ta av. Det var en stor lettelse da jeg skj&oslash;nte at jeg kunne slippe &aring; st&aring; og skjelve p&aring; scenen, men faktisk sitte stille bak et skrivebord. Likevel - jeg liker veldig godt &aring; lese h&oslash;yt fra b&oslash;kene mine, da er jeg b&aring;de litt teater og bok.&nbsp;</p>\r\n<p><br /><span style=\"font-size: 14pt;\">Skriver best n&aring;r det regner og bl&aring;ser</span><br />Det beste er &aring; jobbe sammenhengende, gjerne to to-timers &oslash;kter. Men dette g&aring;r opp og ned og kommer an p&aring; hvor mye jobb jeg har ellers og hvor langt jeg er i &laquo;prosessen\". Jeg skriver best p&aring; morgen og formiddag eller etter middag/kveld. Jeg tenker ofte at jeg vil skrive mer ute blant folk, p&aring; kafe og s&aring;nn, men det f&aring;r jeg ikke til. Jeg liker best &aring; skrive p&aring; kontoret i huset jeg bor i.&nbsp;<br />Jeg liker aller best &aring; skrive n&aring;r det regner, bl&aring;ser og er d&aring;rlig v&aelig;r, men dette glemmer jeg ofte n&aring;r jeg har kommet i gang. Da er jeg inne i mitt eget. Jeg m&aring; ha kaffe og alltid notatbok og blyant ved siden av macen. Jeg vil gjerne ha andre i huset, men ikke bli stilt mange sp&oslash;rsm&aring;l om hvor ting er osv. Jeg vil v&aelig;re i fred, men er alltid glad for at der er noen n&aring;r jeg reiser meg fra skrivebordet.&nbsp;</p>\r\n<p><span style=\"font-size: 14pt;\">Ta vare p&aring; de h&aring;pl&oslash;se ideene!</span><br />Jeg vil oppmuntre folk til &aring; dele tekstene med noen de stoler p&aring;. Pr&oslash;v ogs&aring; selv &aring; bli en god leser. Det tredje r&aring;det mitt er &aring; lese egne tekster litt p&aring; avstand. Ikke les med en gang du har skrevet for &aring; se om det ble bra eller ikke. Skriv deg tom (s&aring; lenge du orker) og la teksten hvile f&oslash;r du leser. Og: Ta vare p&aring; de &laquo;h&aring;pl&oslash;se\" ideene. Kanskje det er der gullet er. &nbsp;<br />Disse r&aring;dene kan selvsagt utdypes i det uendelige!</p>\r\n<p><span style=\"font-size: 14pt;\">Hva kan vi forvente av mentorm&oslash;tet med deg?</span><br />Jeg vil fortelle om hvordan jeg selv har jobbet med &aring; bruke mine egne erfaringer i skrivinga og gi eksempler p&aring; dette. &Aring; bruke egne erfaringer betyr ikke n&oslash;dvendigvis at teksten blir selvbiografisk, men at man bruker ens eget stoff. N&aring;r vi skriver ut fra egne erfaringer p&aring;virker det spr&aring;ket, det blir mer konkret og n&aelig;rere. Det gj&oslash;r ogs&aring; noe med oss selv. Jeg h&aring;per dette kan inspirere andre skrivende!</p>\r\n<p>&nbsp;</p>\r\n<p>Laura Djupvik er forfatter, skribent og forlagsredakt&oslash;r. Hun debuterte med \"B&aring;ten er s&aring; liten\" i 2004 og har siden skrevet en rekke b&oslash;ker. Hun skriver om eksistensiell tematikk, og som oftest for barn og unge. I 2008 vant hun Guro Sandsdalens minnepris for \"Hundre appelsinar og ein fiolin\".&nbsp;</p>\r\n<p>Foto: Rolf M. Aagaard</p>','/storage/blog/1654765010.jpg','Laura Djupvik','/storage/blog/author/1654765010.jpg',1,'2022-06-09','2022-06-09 08:47:09','2022-06-09 09:02:13'),(53,5004,'Man må bestemme seg','<p style=\"font-weight: 400;\"><span style=\"font-size: 14pt;\"><strong>Hvordan kom du til skrivingen?</strong></span></p>\r\n<p style=\"font-weight: 400;\">Jeg ble veldig opptatt av tekster i ten&aring;rene, og elsket &aring; sitte p&aring; rommet &aring; skrive av l&aring;ter jeg h&oslash;rte og analysere innholdet. Jeg begynte &aring; skrive dikt og etter hvert sangtekster, og oppdaget samtidig gleden med &aring; lese romaner. Jeg har alltid hatt mange historier i meg, og tenkte ofte at jeg burde skrive dem helt ut. Jeg skrev i tjue&aring;rene noen tekster som havnet i skuffen, og s&aring; ble skrivingen liggende en god del &aring;r p&aring; grunn av studier og satsning p&aring; utdanning. Deretter var det jobb og familie som tok tiden. Men s&aring; var det disse scenene, nesten som bruddstykker av fortellinger, som stadig dukket opp i hodet og forstyrret. Denne skrivelysten ble etter hvert s&aring; sterk at jeg vet jeg ville angret om jeg aldri gjorde alvor av det. Jeg begynte &aring; 2015 &aring; skrive ut en historie om to s&oslash;stre, og bestemte meg i 2016 for &aring; gj&oslash;re et fors&oslash;k p&aring; &aring; skrive en roman. Dette endte til slutt med debutboka &laquo;Tro meg n&aring;r jeg lyver&raquo; i 2020.</p>\r\n<p style=\"font-weight: 400;\"><span style=\"font-size: 14pt;\"><strong>Hvordan ser en typisk skrivedag ut for deg?</strong></span></p>\r\n<p style=\"font-weight: 400;\">Jeg planlegger skrivingen min gjerne fra uke til uke slik at den passer inn i hverdagen med familien og jobb. Det skaper en forutsigbarhet for alle. Jeg rigger meg til p&aring; skriverommet, ofte med varmt vann med litt honning og lime, lukker d&oslash;ra og jobber med manuset. Ofte blir hunden v&aring;r Amigo med inn, og det er hyggelig. Hvor lenge jeg sitter varierer, men jeg pr&oslash;ver &aring; ta en pause etter hver time. Jeg har aldri noen konkret m&aring;l om antall ord eller sider, men m&aring;let er &aring; jobbe med manuset, helst hver dag. Ofte skriver jeg om morgningen f&oslash;r arbeidstid, eller formiddagen i helgene, men tar i bruk kvelder, ventetiden n&aring;r ungene er p&aring; en aktivitet, eller n&aring;r vi skal kj&oslash;re lenge i bil og jeg er passasjer.&nbsp; Mantraet mitt er fra Tom Egeland: &laquo;ord for ord mot m&aring;let&raquo;.</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\"><span style=\"font-size: 14pt;\"><strong>Hva skulle du &oslash;nske du hadde visst f&oslash;r du startet?</strong></span></p>\r\n<p style=\"font-weight: 400;\">Jeg m&aring; f&oslash;rst si jeg er glad jeg ikke visste hvor mye det ville kreve av meg for &aring; skrive en debutroman. N&aring;r det er sagt s&aring; ville det v&aelig;rt fint &aring; f&aring; vite mer om selve prosessen, og hvordan man kunne m&oslash;te den store arbeidsmengden i en travel hverdag. Aller mest skulle jeg &oslash;nske jeg visste mer om hvor sterk kritikeren kan bli, og hvor stor verdien av &aring; alliere seg med andre skrivende, er.</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\"><span style=\"font-size: 14pt;\"><strong>Har du noen r&aring;d til de som dr&oslash;mmer om &aring; bli forfatter?</strong></span></p>\r\n<p style=\"font-weight: 400;\">Jeg tenker mye ligger i &aring; bestemme seg. N&oslash;ler man for mye, s&aring; blir ofte kritikeren for sterk. Begynn &aring; definer dr&oslash;mmene som noe mer enn dr&oslash;mmer, og begynn &aring; definer deg selv som et skrivende menneske. Kom i kontakt med andre som skriver, eller har samme m&aring;l som deg. Det er en styrke i &aring; ha andre skrivende &aring; dele tanker, ideer, opp og nedturer med. Redakt&oslash;ren jeg hadde p&aring; f&oslash;rste bok sammenlignet skrivingen med &aring; l&oslash;pe maraton. Problemet er bare at man ikke vet hvor mange maratoner en m&aring; l&oslash;pe etter hverandre f&oslash;r man er i m&aring;l.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\"><span style=\"font-size: 14pt;\"><strong>Skriver du p&aring; noe n&aring;?</strong></span></p>\r\n<p style=\"font-weight: 400;\">Det gj&oslash;r jeg. Jeg er forfatter ved Cappelen Damm og er godt i gang med bok 2 i serien om etterforsker Lars Lukassen. Dette blir som f&oslash;rste bok, en psykologisk krimroman, der elementer fra b&aring;de politiromanen og den psykologiske thrilleren f&aring;r plass. Jeg gleder meg til &aring; kunne si mer om innholdet, men kan si s&aring; mye at dette temaet, er s&aring; langt jeg vet, ikke blitt skrevet krim om tidligere.</p>\r\n<p style=\"font-weight: 400;\">Foto: Silje Karlsrud Nyhus</p>','/storage/blog/1663923139.jpg','Ellen G. Simensen',NULL,1,NULL,'2022-09-23 08:52:19','2022-09-23 09:06:15'),(54,5004,'Det ble en besettelse','<div><span style=\"font-size: 14pt;\"><strong>Hvordan kom du til skrivingen?</strong></span></div>\r\n<div>Jeg har likt &aring; skrive, lese og fortelle historier siden jeg var veldig ung. Men, det var f&oslash;rst etter at jeg begynte &aring; studere historie at skrivingen ble til noe mer. Fra det punktet var jeg ikke i tvil om hva som var m&aring;let i livet: &Aring; skrive b&oslash;ker. &Aring; bli forfatter. Det ble en besettelse, p&aring; en god m&aring;te. </div>\r\n<div><br /><span style=\"font-size: 14pt;\"><strong>Hvordan ser en typisk skrivedag ut for deg?</strong></span></div>\r\n<div>Okei. Jeg st&aring;r opp omkring klokka &aring;tte. Drar p&aring; kontoret (jeg leier kontorplass for en billig penge) og trakter en stor kanne kaffe. F&aring;r p&aring; musikk eller en podkast p&aring; telefonen. Deretter jobber jeg til klokka fire. Jeg jobber omtrent &eacute;n time av gangen og tar forholdsvis lange pauser hvor jeg leser en bok eller noe i den duren. Om jeg st&aring;r fast i en tekst lukker jeg PCen og g&aring;r meg en tur. </div>\r\n<div><strong>&nbsp;</strong></div>\r\n<div><span style=\"font-size: 14pt;\"><strong>Hva skulle du &oslash;nske du hadde visst f&oslash;r du startet?</strong></span></div>\r\n<div>At det er et ensomt yrke &aring; v&aelig;re forfatter p&aring; heltid. Det l&oslash;nner seg &aring; leie kontorplass, slik at man har noen &aring; spise lunsj og v&aelig;re sosial sammen med.</div>\r\n<div><br /><span style=\"font-size: 14pt;\"><strong>Har du noen r&aring;d til de som dr&oslash;mmer om &aring; bli forfatter?</strong></span></div>\r\n<div>Oi. Hmm. Ikke gi opp p&aring; et prosjekt bare fordi du mister interessen. Den kommer som oftes tilbake. &Aring; v&aelig;re forfatter er en real t&aring;lmodighetspr&oslash;ve. Skriv mye og les enda mer. </div>\r\n<div><br /><strong><span style=\"font-size: 14pt;\">Skriver du p&aring; noe n&aring;?</span> <br /></strong></div>\r\n<div>Ja! Akkurat n&aring; jobber jeg med flere prosjekter. Jeg skriver en bok om norsk \"True Crime\" som kommer ut i l&oslash;pet av 2023, en biografi som er tenkt utgitt i 2024 og en roman som jeg nettopp har kommet igang med. </div>\r\n<p>&nbsp;</p>','/storage/blog/1664530623.jpg','Per Ivar Hjeldsbakken Engevold',NULL,1,NULL,'2022-09-30 09:37:03','2022-09-30 09:37:03'),(55,5004,'Brukte mastergraden til å skrive en roman','<p style=\"font-weight: 400;\"><strong><span style=\"font-size: 14pt;\">Hvordan kom du til skrivingen, Aina Basso?</span></strong></p>\r\n<p style=\"font-weight: 400;\">Eg byrja &aring; skrive veldig tidleg, d&aring; eg var rundt ni &aring;r gammal, som ein del av leiken. D&aring; herma eg etter romantiske noveller eg las i typiske jenteblad. P&aring; ungdomsskulen blei skrivinga meir seri&oslash;s, eg pr&oslash;vde &aring; vere original og tolke stiloppg&aring;vene vi fekk i norsktimane p&aring; utradisjonelle m&aring;tar. Det var ogs&aring; d&aring; eg gjekk fr&aring; &aring; skrive p&aring; bokm&aring;l til &aring; skrive stadig meir p&aring; nynorsk, som er hovudm&aring;let mitt. Det var ikkje eit medvite val, men noko eg har sett i ettertid.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">P&aring; vidareg&aring;ande fekk eg ein norskl&aelig;rar som sj&oslash;lv er forfattar, Marit Kaldhol, og ho var inspirerande, samstundes som ho stilte h&oslash;gare krav til tekstane enn det tidlegare norskl&aelig;rarar hadde gjort. D&aring; eg var 17 tipsa ho meg om at forlaget hennar, Samlaget, skulle ha eit manusseminar som kven som helst kunne sende inn tekstar til. Eg sende inn rundt tjue dikt og blei valt ut til &aring; vere med, men det skulle likevel ta meir enn ti &aring;r f&oslash;r eg debuterte som forfattar.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">D&aring; hadde eg skrive i fleire &aring;r og b&aring;de f&aring;tt oppmuntrande konsulentfr&aring;segner og refusjonar p&aring; eit manus eg sende til eit par forlag, m.a. Samlaget.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">I 2005 gjorde eg ferdig mastergraden min i historie, og det var f&oslash;rst d&aring; det losna for meg. Eg inns&aring;g at eg kunne bruke stoffet eg hadde kome til gjennom masterarbeidet til &aring; skrive ein historisk roman, og i 2008 debuterte eg som forfattar med ungdomsromanen&nbsp;Ingen m&aring; vite, nettopp p&aring; Samlaget.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\"><strong><span style=\"font-size: 14pt;\">Hvordan ser en typisk skrivedag ut for deg?</span></strong></p>\r\n<p style=\"font-weight: 400;\">Dei dagane eg har ein heil dag til skriving, set eg meg ned med ein kopp kaffi etter at eg har levert i barnehagen. S&aring; sjekkar eg e-post og ser om det er noko eg m&aring; svare p&aring; med det same, f&oslash;r eg opnar dokumentet eg arbeider med og les over og flikkar p&aring; det eg alt har skrive, ser kanskje p&aring; kommentarar fr&aring; redakt&oslash;r eller konsulent og pr&oslash;ver &aring; finne ei betre l&oslash;ysing p&aring; eit avsnitt eller utvide forteljinga, eller eg opnar eit heilt nytt dokument - anten for &aring; byrje p&aring; noko heilt nytt, eller for &aring; freiste angripe eit kapittel eller ei novelle p&aring; ein ny og frisk m&aring;te, ikkje ved &aring; redigere i ferdigskriven tekst, men ved &aring; byrje p&aring; nytt fr&aring; ein annan vinkel eller p&aring; eit anna (tids)punkt i forteljinga.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\"><strong><span style=\"font-size: 14pt;\">Hva skulle du &oslash;nske du hadde visst f&oslash;r du startet?</span></strong></p>\r\n<p style=\"font-weight: 400;\">Vanskeleg sp&oslash;rsm&aring;l! Eg veit jo no b&aring;de at det tek lang tid &aring; skrive ei bok - opptil fleire &aring;r, sj&oslash;lv om eg arbeider med ein redakt&oslash;r og har eit forlag i ryggen som &oslash;nskjer &aring; f&aring; boka utgitt - eg veit kor vanskeleg det kan vere &aring; leve av forfattarskapen sin, slik at det er n&oslash;dvendig &aring; ta andre oppdrag, som igjen tek tid fr&aring; skrivinga - halde f&oslash;redrag, reise p&aring; skulebes&oslash;k, gjere konsulentarbeid for forlag, mv. - for &aring; overleve. Eg veit ogs&aring; at eg eg i st&oslash;rsteparten av dei fjorten &aring;ra som er g&aring;tt sidan eg gav ut mi f&oslash;rste bok har kunna leve av forfattarskapen min. Ikkje av inntekter fr&aring; boksal, vel &aring; merke, det er ikkje nok for dei fleste, men av ein type mangesysleri innan litteraturen.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">Eg trur ikkje eg skulle &oslash;nskje eg hadde visst noko av dette f&oslash;r eg blei forfattar, men kanskje at dei fleste ikkje blir superkjendisar berre fordi dei gir ut ei bok, og ikkje s&aring; veldig rike, heller.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">Det er ein hard jobb &aring; skrive og f&aring; utgitt b&oslash;ker og det er ein sv&aelig;rt privilegert jobb, som dessverre ikkje passar for alle.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\"><strong><span style=\"font-size: 14pt;\">Har du noen r&aring;d til de som dr&oslash;mmer om &aring; bli forfatter?</span></strong></p>\r\n<p style=\"font-weight: 400;\">Skriv og les masse, og les breitt. D&aring; eg var student las eg heilt annan litteratur enn det eg set h&oslash;gt no, eg heldt meg gjerne til bestseljarbunkane i bokhandlane, som eg no sjeldan kj&oslash;per b&oslash;ker fr&aring;.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">Eg vil ogs&aring; r&aring;de alle til &aring; lytte til tilbakemeldingane dei f&aring;r fr&aring; konsulentar eller redakt&oslash;rar i forlag, sj&oslash;lv om det er vanskeleg &aring; \'kill your darlings\'. For viss ein ikkje lyttar og speler ball, f&aring;r ein ikkje oppfylt draumen sin om &aring; f&aring; utgitt ei bok p&aring; eit av dei seri&oslash;se, norske forlaga, heller. Det betyr ikkje at ein blindt skal g&aring; med p&aring; alle endringsforslag, men pr&oslash;ve det ut og vere opensinna.&nbsp;</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\"><strong><span style=\"font-size: 14pt;\">Skriver du p&aring; noe n&aring;?</span></strong></p>\r\n<p><span style=\"font-weight: 400;\">For tida arbeider eg b&aring;de med noveller for vaksne og ein ungdomsroman, begge med eit historisk bakteppe. Eg er no i ein fase der eg reviderer tekstane etter kloke og klartenkte kommentarar fr&aring; redakt&oslash;rane eg jobbar med, og pr&oslash;ver &aring; l&oslash;fte tekstane til det niv&aring;et dei meiner er oppn&aring;eleg for meg som forfattar. Det er krevande, g&oslash;y og frustrerande p&aring; same tid.</span></p>\r\n<p><span style=\"font-weight: 400;\">Foto: Oda Berby</span></p>','/storage/blog/1665655668.jpg','Aina Basso',NULL,1,'2022-10-13','2022-10-13 10:07:48','2022-10-13 10:07:48'),(56,5004,'Skriving er sin egen belønning','<p style=\"font-weight: 400;\">Hvordan kom du til skrivinga?</p>\r\n<p style=\"font-weight: 400;\">Jeg tror det m&aring; ha begynt med leselyst, blant annet skapt av at min mor leste mye for meg f&oslash;r jeg begynte p&aring; skolen. Skrivelysten kom i ten&aring;rene. En dag hentet jeg rett og slett opp min storebrors nedst&oslash;vede PC fra kjelleren og satte ned meg foran et tomt word-dokument. Og siden da har jeg blitt sittende.</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\">Hvordan ser en skrivedag ut for deg?</p>\r\n<p style=\"font-weight: 400;\">Jeg sover til jeg v&aring;kner og skriver til jeg gj&oslash;r teksten mer ondt enn godt. Jeg skriver i alt fra to timer til ti timer, avhengig av hvilken fase jeg befinner meg i. Redigerer jeg eller skriver jeg? Om jeg skriver, vil jeg at det skal v&aelig;re overskuddspreget. Da bruker jeg toppen tre timer. Om jeg redigerer, derimot, kan jeg holde p&aring; i timevis.</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\">Hvordan har prosessen med denne boka v&aelig;rt?</p>\r\n<p style=\"font-weight: 400;\">Rotete, som livet selv. Jeg har arbeidet med romanen i fem &aring;r, i rykk og napp. I lange perioder satte jeg alt annet arbeid til side for &aring; skrive. Andre perioder m&aring;tte jeg legge romanen helt bort for &aring; kunne tjene penger til &aring; leve. Jeg har f&aring;tt uvurderlig hjelp fra skrivel&aelig;rere ved Skrivekunstakademiet, blant annet av Pedro Carmona-Alvarez, som fortsatte &aring; lese tekstutdrag lenge etter at jeg var ferdig som elev. Redakt&oslash;ren min p&aring; Kolon Forlag har ogs&aring; v&aelig;rt en gave. Vi har samarbeidet siden januar i &aring;r.</p>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>\r\n<p style=\"font-weight: 400;\">Har du noen tips til andre som dr&oslash;mmer om &aring; bli forfattere?</p>\r\n<p>1. Tenk at skriving er sin egen bel&oslash;nning, for det er det. De som f&oslash;rst og fremst vil skrive for &aring; kunne kalle seg forfatter, vil enten gi opp eller gi ut noe som kunne v&aelig;rt langt bedre med et genuint engasjement.</p>\r\n<p style=\"font-weight: 400;\">2. Les gode og d&aring;rlige forfattere s&aring; mye at du forst&aring;r hvorfor de gode er gode og de d&aring;rlige d&aring;rlige. Da snakker jeg ikke om hvordan de f&aring;r deg til &aring; f&oslash;le deg, men hvilke teknikker de bruker. Hvilke setninger de d&aring;rlige forfatterne tillater seg &aring; skrive, som de gode ikke tillater seg &aring; skrive, for eksempel.</p>\r\n<p style=\"font-weight: 400;\">3. Omgi deg med folk som er glad nok i litteratur (og deg) til &aring; fortelle deg sannheten om hvordan de opplever teksten din. L&aelig;r deg &aring; skille mellom kunstnerisk integritet og ditt eget ego. S&aring; lenge du er &aring;pen for at du ikke har det fulle overblikket over din egen tekst (og hvem kan ha det?), har du tatt f&oslash;rste steget mot &aring; ta gode avgj&oslash;relser.</p>\r\n<p style=\"font-weight: 400;\">4. To sitater, som mer eller mindre sier det samme, har v&aelig;rt frigj&oslash;rende for min egen skriving, selv om de er litt kleine: &laquo;Writing is human, editing is divine.&raquo; Og: I can edit a bad page. I can&rsquo;t edit a blank page.&raquo; Poenget her: Selvsensur og kreativitet er krefter som sloss imot hverandre. Om du skal skape tekst, m&aring; du leke. Og s&aring; kommer det en tid hvor du skal rydde. Ikke rydd mens du leker, det er meningsl&oslash;st. Og hva betyr dette i praksis: N&aring;r du skriver et f&oslash;rsteutkast, skal du ikke sitte der og tenke: <em>Dette ligner jo ikke p&aring; litteratur, jeg m&aring; gj&oslash;re noe grunnleggende feil.</em> Allerede der har du begynt &aring; rydde og glemt leken.</p>\r\n<p style=\"font-weight: 400;\"><br />Skriver du p&aring; noe n&aring;?</p>\r\n<p style=\"font-weight: 400;\">Jeg skriver alltid, men hva det er, det aner jeg enn&aring; ikke.</p>\r\n<p style=\"font-weight: 400;\"><br />Hvor kan vi kj&oslash;pe boka di?<br /><br />I de fleste bokhandlere, vil jeg anta.</p>\r\n<p style=\"font-weight: 400;\"><a href=\"https://www.norli.no/9788205569201\">https://www.norli.no/9788205569201</a></p>\r\n<p style=\"font-weight: 400;\">Om \"Saltst&oslash;ttens s&oslash;nn\":</p>\r\n<div>\r\n<p>En by i &oslash;rkenen rammes av en&nbsp;himmelsendt straff, som gj&oslash;r de&nbsp;fleste innbyggerne om til saltst&oslash;tter.&nbsp;En mor og hennes s&oslash;nn er de eneste&nbsp;overlevende, og p&aring; sin s&oslash;ken etter&nbsp;barnets far m&aring; de ta seg frem i en&nbsp;verden som rykker stadig n&aelig;rmere&nbsp;&oslash;deleggelse.</p>\r\n</div>\r\n<div>\r\n<p><em>Saltst&oslash;ttens s&oslash;nn</em><span class=\"apple-converted-space\"><em>&nbsp;</em></span>er en historie om tap og forsoning, selvoppofrelse og jakten p&aring; en bortkommen far. Romanen er skrevet i et enkelt og klart spr&aring;k som blander gammeltestamentlig realisme, elementer av modernitet og psykedelisk fantasteri &ndash; konkret, brutalt, vakkert og lekent.</p>\r\n</div>\r\n<p style=\"font-weight: 400;\">&nbsp;</p>','/storage/blog/1667470803.jpg','Carl Henrik Berge','/storage/blog/author/1667470791.jpg',1,'2022-11-02','2022-11-02 13:52:44','2022-11-03 10:20:04'),(57,5004,'Fortalte historier til fuglene og trærne','<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\" style=\"font-size: 14pt;\">Hvordan kom du til skrivingen?&nbsp;</span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\">Jeg har alltid elsket &aring; skrive og &aring; fortelle. L&oslash;p mye rundt i skogen som barn og fortalte historier til fuglene og tr&aelig;rne og meg selv. Og s&aring; har jeg etterp&aring; fortsatt &aring; skrive og fortelle, selv om det har g&aring;tt b&aring;de opp og ned og opp igjen og ned igjen, og n&aring; satser jeg p&aring; at det holder seg mest oppe framover. &nbsp;</span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\"><br class=\"v1ContentPasted0\" /><span style=\"font-size: 14pt;\">Hvordan ser en typisk skrivedag ut for deg?&nbsp;</span></span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\">Jeg drikker kaffe i lenestolen. S&aring; setter jeg meg ved laptopen, &aring;pner manus, sjekker mail, sjekker aviser og andre ting uten at det er noen grunn til det, sjekker mail igjen uten at det er noe poeng i det heller. Men s&aring; skriver jeg, og pr&oslash;ver &aring; skrive til et m&aring;l jeg setter meg f&oslash;r jeg gj&oslash;r noe annet. M&aring;let varierer utfra hvor jeg er i prosessen. &nbsp;</span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\"><br class=\"v1ContentPasted0\" /><span style=\"font-size: 14pt;\">Hvordan vil du beskrive din prosess fra id&eacute; til ferdig bok?&nbsp;</span></span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\">Etter at jeg har f&aring;tt en ide, pleier jeg &aring; notere masse rundt det, p&aring; papir. Jeg begynner et sted og noterer meg ut i alle retninger, karakteren, historien, og begge deler i sammenheng. N&aring;r jeg f&oslash;ler at jeg ikke har mye mer &aring; legge til, s&aring; begynner jeg &aring; skrive, skriver meg gjennom et ekstra kort f&oslash;rsteutkast. S&aring; printer jeg det ut, leser det, noterer masse ut fra det igjen, helt til jeg ikke har mer &aring; legge til, og s&aring; skriver jeg et nytt utkast. Det pleier &aring; v&aelig;re mange utkast f&oslash;r det blir ferdig bok. &nbsp;</span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\"><br class=\"v1ContentPasted0\" /><span style=\"font-size: 14pt;\">Har du noen r&aring;d til de som dr&oslash;mmer om &aring; bli forfatter?&nbsp;</span></span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\">Det er det gamle kjedelige: skriv, skriv og skriv mer. Samtidig hjelper det ikke om man skriver og skriver, aldri s&aring; mye, om man ikke ser hva som kunne v&aelig;rt bedre og hva som funker d&aring;rlig. S&aring; det er ogs&aring; viktig &aring; f&aring; tilbakemeldinger fra noen.&nbsp;</span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\"><br class=\"v1ContentPasted0\" /><span style=\"font-size: 14pt;\">Skriver du p&aring; noe n&aring;?&nbsp;</span></span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\">Det kommer en ny bok fra meg til v&aring;ren, og jeg jobber intenst med den om dagen. Det er en spenningsbok for barn, 9-12, og jeg gleder meg veldig til at den er ferdig. &Aring; f&aring; boka di mellom hendene, er en fantastisk f&oslash;lelse!&nbsp;</span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\"><br class=\"v1ContentPasted0\" /><span style=\"font-size: 14pt;\">Hvor kan vi kj&oslash;pe b&oslash;kene dine?&nbsp;</span></span></p>\r\n<p class=\"v1MsoNormal\"><span class=\"v1ContentPasted0\">Magipr&oslash;ven, som er nyest, har de inne i mange bokhandlere, Vega og Br&aring;dypt, som er de to f&oslash;rste, er nok enklest &aring; bestille p&aring; nettet. Klikk deg inn p&aring; norli.no eller ark.no eller en annen nettbokhandel du liker og s&oslash;k p&aring; navnet mitt. </span>&nbsp;</p>\r\n<p>&nbsp;</p>','/storage/blog/1668681649.jpg','Elin Victoria Unstad','/storage/blog/author/1668681628.jpg',1,'2022-11-17','2022-11-17 10:26:14','2022-11-17 10:40:49'),(58,1064,'Bor det en jævel i oss alle?','<p>Debutant &Oslash;ivind Berg er ute med en roman som unders&oslash;ker hva vi mennesker er kapable til.</p>\r\n<p><strong>En sl&aring;ende ondskap</strong></p>\r\n<p>P&aring; en kor-tur til Krakow, bes&oslash;ker &Oslash;ivind Berg Auschwitz, noe som gj&oslash;r stort inntrykk. En tanke fester seg, og gir ikke slipp; bor det en j&aelig;vel i oss alle? Hendelsene under andre verdenskrig var s&aring; grusomme, at det er vanskelig &aring; forst&aring; hvordan det kunne skje. De som utf&oslash;rte disse handlingene var &lsquo;vanlige&rsquo; mennesker; familiefedre, s&oslash;nner, br&oslash;dre, og venner. Er handlingene de utf&oslash;rte noe vi selv kunne gjort?</p>\r\n<p><strong>Evig aktuelt</strong></p>\r\n<p>Det virker &aring; v&aelig;re et umettelig marked for historier om Holocaust. &Aring;rlig kommer nye titler med historier fra perioden, mange med rot i virkelige personer og hendelser. Men f&aring; skriver fra &lsquo;den andre siden&rsquo;. P&aring; biblioteket i Auschwitz sp&oslash;r bes&oslash;kende om fangene, kanskje om vaktene, men ingen sp&oslash;r om de som var h&oslash;yere opp i systemet. &Oslash;ivind sp&oslash;r. Han vil vite hva som f&oslash;rer til slike handlinger.</p>\r\n<p>- Jeg var ikke egentlig s&aring; interessert i tematikken fra f&oslash;r, forteller &Oslash;ivind, - men denne hendelsen satt en st&oslash;kk i meg. Alt j&oslash;dehatet, hvor kom det fra, hvorfor skulle vi hate dem?</p>\r\n<p>Undringen satt seg dybt i &Oslash;ivind; hvordan klarer man &aring; drepe? Hva er den mentale prosessen?</p>\r\n<p>- S&aelig;rlig hvis du ikke er truet selv, p&aring;peker han, - hvordan kommer man over de indre hindrene?</p>\r\n<p><strong>Grundig forarbeid</strong></p>\r\n<p>&Oslash;ivind satte i gang et omstendelig researcharbeid, med m&aring;l om &aring; f&aring; svar. Planen var &aring; skrive en sakprosabok om tema, men raskt utviklet teksten seg til en roman. Han introduserte b&aring;de romanse, konflikt i hierarkiet og et kameratskap blant soldatene. Da l&oslash;snet noe for &Oslash;ivind.</p>\r\n<p>- Det ble fort tungt og t&oslash;rt i sakprosa. N&aring;r jeg endret til romanformen, ble teksten levende.</p>\r\n<p>Men skrivingen ble ikke enklere av fiksjonen.</p>\r\n<p>- Det har v&aelig;rt f&aelig;lt &aring; skrive, forteller &Oslash;ivind. - Jeg har trengt pauser. Men jeg kan ikke pynte p&aring; det, det m&aring; skrives som det var.</p>\r\n<p><strong>N&oslash;dvendig refusjon</strong></p>\r\n<p>Manuset ble refusert av tre forlag, noe &Oslash;ivind n&aring; ser p&aring; som riktig: - Jeg forstod at det &aring; skrive bok er et fag.</p>\r\n<p>P&aring; romankurset inns&aring; han at jo mer du l&aelig;rer, jo mer ser du at du ikke kan.</p>\r\n<p>- Det overrasket meg hvor d&aring;rlig jeg var!</p>\r\n<p>&Oslash;ivind bega seg ut p&aring; et &aring;rskurs, og deretter var han klar for det neste steget; selvpublisering. Her ventet det store endringer, som blant annet i fortellerperspektivet.</p>\r\n<p>- F&oslash;rste tilbakemelding var sjokkerende d&aring;rlig. Tilbakemeldingen var rett og slett at dette var en tynn fortelling og ikke en roman. Redakt&oslash;ren hadde rett i det. Jeg m&aring;tte skrive den p&aring; nytt. Jeg endret til f&oslash;rsteperson for &aring; la leseren leve seg mer inn i historien.</p>\r\n<p>&Oslash;ivind skrev om hele teksten, og den ble dobbelt s&aring; lang. P&aring; mange m&aring;ter gikk han tilbake til start. &ndash; Jeg tenkte at, ok, n&aring; m&aring; jeg ta de r&aring;dene jeg fikk.</p>\r\n<p>Etter en helomvending sendte han inn p&aring; nytt, og da var tilbakemeldingen fra redakt&oslash;ren en helt annen. Etter tredje runde med redakt&oslash;ren hadde noe viktig l&oslash;snet, og det ble bok!</p>\r\n<p><strong>H&oslash;y egeninnsats</strong></p>\r\n<p>Selvpublisering er ikke for alle, mener &Oslash;ivind. Det er en stor frihet i &aring; velge denne retningen, men det er ogs&aring; en ensom prosess. &ndash; Du m&aring; selge en god del b&oslash;ker, og med et forlag i ryggen hadde jeg hatt hjelp, ikke v&aelig;rt alene om det.</p>\r\n<p>Spesielt kan prosessen v&aelig;re overveldende for en debutant, mener han: - Du er i eget hus, men g&aring;r glipp av gode r&aring;d underveis som jeg som debutant har m&aring;ttet finne ut av selv. Det er mye som skal l&aelig;res.</p>\r\n<p>&Oslash;ivind har f&aring;tt flere omtalelser av boka, noe han har jobbet iherdig for. Han har ringt rundt, brukt lokalavisen og andre publikasjoner. Han har holdt foredrag for aktuelle grupper, via bibliotek og kommunens kulturtilbud. Han har troppet opp hos bokhandlerne og holdt signeringer. &ndash; Jeg begynte i en ende og n&oslash;stet videre.</p>\r\n<p>Man m&aring; v&aelig;re proaktiv, og det viser resultater. Han har flere arrangement p&aring; blokka: - Og det er der jeg selger b&oslash;ker!</p>\r\n<p><strong>Delt respons</strong></p>\r\n<p>Retorikken i dagens samfunn er skremmende, mener &Oslash;ivind. - Vi kan se det samme bildet g&aring; igjen; hvordan man fremstiller fiender, og hvordan man omskaper uskyldige og fredelige folk til drapsmaskiner. Familiefedre, unge menn, barn.</p>\r\n<p>Det skapes et narrativ, ser han, som ikke stemmer med virkeligheten. Og det har ikke v&aelig;rt lett &aring; skrive om et s&aring; betent tema. &ndash; Jeg har m&oslash;tt motstand fra nynazister, som har kommentert p&aring; nettsiden min. Andre tok til motm&aelig;le, og det endte med en hissig diskusjon og en avissak i etterkant.</p>\r\n<p>Men dette skremmer ikke &Oslash;ivind, historien er for viktig &aring; f&aring; frem, og diskusjoner rundt det er positivt, for da kan flere se hvor aktuelt tematikken og konflikten fortsatt er.</p>\r\n<p><strong>Unge lesere</strong></p>\r\n<p>Det er flere ungdommer som har vist interesse for boken, noe &Oslash;ivind setter spesielt stor pris p&aring;.</p>\r\n<p>- Jeg vil holde historien om Holocaust i live. Jeg er en gammel mann. Det er s&aring; mye jeg selv tidligere ikke har h&oslash;rt om, som jeg &oslash;nsker &aring; dele. &nbsp;</p>\r\n<p>Romanformen er et godt format for &aring; formidle historie, mener &Oslash;ivind, med romanen kan man n&aring; flere. Og det er tydelig at boken faller i smak, det viser anmeldelsen i T&oslash;nsberg Blad, hvor det trilles en firer.</p>\r\n<p><strong>Store planer</strong></p>\r\n<p>Veien videre st&aring;r klart for forfatteren &ndash; han har allerede begynt p&aring; en oppf&oslash;lger.</p>\r\n<p>- Det blir mer en krimroman, kan &Oslash;ivind melde. &ndash; Men bakhistorien fra f&oslash;rste bok blir med videre.</p>\r\n<p>Handlingen utspiller seg i Stockholm, med spesielt fokus p&aring; etterretningstjenesten og intern spionering mellom nazister, kommunister og de allierte. Ogs&aring; her vil &Oslash;ivind holde seg tett p&aring; det historiske og faktiske, og planlegger &aring; selv reise fluktruta fra Auschwitz til Stockholm med bes&oslash;k p&aring; kafeer og smug der historien ble til.</p>\r\n<p>&ndash; Jeg vil det skal v&aelig;re autentisk, og da m&aring; jeg selv se det.</p>\r\n<p>&Oslash;ivind har ogs&aring; planer om &aring; bevege seg over i barnelitteraturen, med en bok som spiller p&aring; de tradisjonelle eventyrene. Han vil vri og vende p&aring; dem, og gi unge lesere en heltinne som skal representere viktige temaer som rasisme, feminisme og legning. Han vil krydre teksten med humor og fantasi: &ndash; Barna skal underholdes, men ogs&aring; foreldrene, forteller han.</p>\r\n<p>Det skorter ikke p&aring; ideer hos den ferske forfatteren.</p>\r\n<p><strong>Aldri for sent</strong></p>\r\n<p>&Oslash;ivind har et klart budskap til andre skrivende: - Det er ingen aldersgrense for &aring; f&aring; suksess gjennom Forfatterskolen.</p>\r\n<p>Og vi er helt enige &ndash; man blir aldri for gammel for &aring; gi ut bok!</p>\r\n<p>Forfatterskolen gratulerer &Oslash;ivind med utgivelsen &ndash; og vi gleder oss til fortsettelsen!</p>\r\n<p><img src=\"https://forfatterskolen.no/storage/photos/1376/Blogg/1673299957.jpg\" alt=\"\" width=\"725\" height=\"773\" /></p>','/storage/blog/1673345489.jpg','Øivind Berg','/storage/blog/author/1673347517.jpg',1,'2023-01-10','2023-01-09 21:32:37','2023-01-10 10:45:17'),(59,1064,'Det koster å bli forfatter','<p><img src=\"https://forfatterskolen.no/storage/photos/1064/Design uten navn (1).png\" alt=\"\" width=\"600\" height=\"600\" /></p>\r\n<p>Hilde Charlotte Blomberg er aktuell med debututgivelsen &lsquo;Min prikkete s&oslash;ster&rsquo; (Cappelen Damm, 2023). Hun vet godt hvor mye det koster &aring; realisere dr&oslash;mmen.</p>\r\n<p>Utdrag fra boken: <em>Legen sa at jeg ikke skulle jobbe. N&aring; har jeg ikke sett ham p&aring; lenge. Sykepleierne ser jeg ofte, s&aelig;rlig Grete. Av og til gir hun meg piller.</em><em>&nbsp;</em><em><br />Jeg gir dem til katten. Etterp&aring; sover hun lenge, det er digg, da sitter jeg og tegner og maler.</em></p>\r\n<p><strong>Den prikkete s&oslash;steren</strong></p>\r\n<p>- &lsquo;Min prikkete s&oslash;ster&rsquo; er ingen barnebok, selv om det kan h&oslash;res slik ut p&aring; tittelen, ler Hilde Charlotte, som i februar er aktuell med en prosadiktsamling.</p>\r\n<p>Debutboken tar for seg tema som ensomhet, psykisk helse og utenforskap, via en jeg-forteller som blant annet reiser til Japan, for &aring; finne den ber&oslash;mte kunstneren Yayoi Kusama.</p>\r\n<p>Ideer kan oppst&aring; p&aring; mange m&aring;ter, og denne startet med en tilfeldighet; Hilde Charlotte skulle p&aring; en avslutningsfest etter en fotografi-workshop. Hun skulle f&oslash;rst m&oslash;te en venninne fra workshopen, og uten &aring; samkj&oslash;re, hadde de begge p&aring; seg hver sin prikkete kjole. Hilde Charlotte br&oslash;t ut; du er min prikkete s&oslash;ster! En morsom setning som skulle bli v&aelig;rende, og avgj&oslash;rende.</p>\r\n<p><strong>&lsquo;Kan jeg sende inn det her?&rsquo;</strong></p>\r\n<p>Det var ikke gitt at det Hilde Charlotte skrev p&aring;, skulle &lsquo;bli til noe&rsquo;. Hun har aldri v&aelig;rt redd for &aring; pr&oslash;ve seg, tvert imot har hun sendt inn manus til vurdering hvert halv&aring;r, til de st&oslash;rste forlagene, i h&aring;p om at noe skulle falle i smak. Men det ble nei p&aring; nei, frem til Cappelen Damm leste &lsquo;Min prikkete s&oslash;ster&rsquo; &ndash; det prosjektet hun tenkte var et &lsquo;long shot&rsquo;.</p>\r\n<p>- Lenge skrev jeg mer seri&oslash;se dikt, h&oslash;yverdige dikt. Jeg leser mye poesi, og jeg tenkte det var slik jeg <em>skulle </em>skrive.</p>\r\n<p>&lsquo;Min prikkete s&oslash;ster&rsquo; var av en helt annen natur.</p>\r\n<p>- Dette prosjektet var jo s&aring; vilt og rart, det f&oslash;ltes nesten flaut &aring; skulle sende det fra seg.</p>\r\n<p><strong>&Aring; se det rare</strong></p>\r\n<p>De premissl&oslash;se kunstnerne har v&aelig;rt til inspirasjon for forfatteren; de som har sin egen driv, som Kusama. Flere forfattere har ogs&aring; inspirert Hilde Charlotte til &aring; finne frem til det mer absurde. &ndash; Jeg er inspirert av Gro Dahle, Patti Smith og Morten Langelands &lsquo;&AElig; &aelig; &aring;&rsquo; &ndash; da jeg leste den, lo jeg h&oslash;yt!</p>\r\n<p>Beate Grimsrud ble ogs&aring; viktig for prosessen: - Jeg ble tipset om boken &lsquo;En d&aring;re fri&rsquo;, og jeg ble helt begeistret. Det var en utrolig leseropplevelse, som nok har bidratt til &aring; finne stemmen min, og det rare blikket.</p>\r\n<p>- Ogs&aring; Max Porters &lsquo;Sorg er den greia med fj&aelig;r&rsquo; var en viktig leseropplevelse; herlig annerledes! Er det en roman, en novelle, er det poesi? Det er g&oslash;y &aring; blande sjangre &ndash; strekke dem.</p>\r\n<p><strong>Stemmen</strong></p>\r\n<p>Hovedkarakteren er en egen person, p&aring;peker Hilde Charlotte, men hun har mye til felles med andre som er litt annerledes.</p>\r\n<p>- Hun er en som lever i sin egen boble. Det var noe gjenkjennelig der, ogs&aring; i meg selv som person. Hun er 1/3 meg, 1/3 Kusama og 1/3 musikeren Aurora, ler Hilde Charlotte.</p>\r\n<p>Videre jobbet hun grundig med &aring; skape en egen stemme. Hvem var denne karakteren? Hvordan snakket hun?</p>\r\n<p>- Jeg brukte lang tid p&aring; &aring; sette meg inn i dette universet, f&oslash;r jeg skrev. Metoden min var &aring; unders&oslash;ke mye, og tenke lenge. Jeg visste ikke da hva dette skulle bli, men jeg tenkte mye p&aring; det.</p>\r\n<p><strong>Prioritering er n&oslash;kkelen</strong></p>\r\n<p>I l&oslash;pet av et halvt &aring;r deltok Hilde Charlotte p&aring; b&aring;de romankurs og diktkurs p&aring; Forfatterskolen, og her s&aring; hun at poesien var et sted hun ville oppholde seg.</p>\r\n<p>- Det halv&aring;ret var en fin opplevelse, i l&oslash;pet av den perioden fant jeg ut hvor veien min skulle g&aring; videre.</p>\r\n<p>Blant annet spilte Gro Dahle en avgj&oslash;rende rolle; fortsatt jobber hilde Charlotte med Gros metodikk.</p>\r\n<p>- Friskriving passer meg godt, jeg pr&oslash;ver &aring; ikke tenke n&aring;r jeg kladder, skrive helt fritt og se hva som kommer ut. Jeg er en intuitiv forfatter.</p>\r\n<p>Deretter fulgte behovet for forpliktelse. Hilde Charlotte har sett klart og tydelig, hva som gir avkasting; hva som skal til for &aring; oppn&aring; forfatterdr&oslash;mmen: - Om du har ambisjoner om utgivelse, som jeg hadde i mange &aring;r, m&aring; du prioritere. Jeg gikk i mange &aring;r og &lsquo;lekte&rsquo; at jeg skulle skrive, skrev litt iblant, men det holder ikke. Jeg tror ikke det holder &aring; tenke at man skal skrive litt p&aring; l&oslash;rdag formiddag, man m&aring; v&aelig;re i prosessen, holde prosjektet og spr&aring;ket i gang.</p>\r\n<p>Som mange kan kjenne seg igjen i, er det en personlig kamp &aring; gj&oslash;re slike prioriteringer.</p>\r\n<p>- Skriving f&oslash;rer til noen konsekvenser, om du tar arbeidet p&aring; alvor. Kanskje kan du ikke v&aelig;re s&aring; sosial som de rundt deg, du trenger mye skrivetid, egentid, og det er viktig &aring; bygge opp en trygghet rundt det.</p>\r\n<p>Spesielt kan perioden f&oslash;r man blir antatt og utgitt v&aelig;re krevende, n&aring;r man strengt tatt ikke kan kalle seg en forfatter, og man kan f&oslash;le p&aring; et krav om rettferdiggj&oslash;ring: Det er ingen som har gitt en &lsquo;lov&rsquo; til &aring; skrive &ndash; og mange rundt kan stusse ved slik tidsbruk. Det har ogs&aring; Hilde Charlotte kjent p&aring;, men hun mener ikke det b&oslash;r v&aelig;re en stopper for dr&oslash;mmen.</p>\r\n<p>- Men m&aring; v&aelig;re litt sta, si det som det er: jeg m&aring; skrive, jeg har det bedre om jeg skriver. Selv visner jeg vekk om jeg ikke f&aring;r v&aelig;re kreativ, det er det som gj&oslash;r at jeg vil st&aring; opp om morgenen. Jeg hadde aldri klart &aring; skrive en bok, om jeg h&oslash;rte p&aring; de stemmene som har en formening om hva jeg heller burde bruke tiden min p&aring;.</p>\r\n<p>Ogs&aring; her har Gro Dahle inspirert: - Jeg leste et intervju av Gro, hvor hun sa at ikke alle trenger venner. Det h&oslash;res ekstremt ut, men er et viktig poeng. Alle har vi ulike behov, og om skriving er viktig, b&oslash;r man eie det, uten skam. Man skal ikke tenke at man er egoistisk. Man skal respektere at andre ikke forst&aring;r, men man skal ogs&aring; forvente en respekt tilbake.</p>\r\n<p>Hilde Charlottes prosadiktsamling &lsquo;<a href=\"https://cappelendamm.no/_min-prikkete-soster-hilde-charlotte-blomberg-9788202765699\">Min prikkete s&oslash;ster</a>&rsquo; kommer ut medio februar &ndash; og vi gleder oss til &aring; lese! Forfatterskolen gratulerer med debuten!</p>','/storage/blog/1673788063.webp','Hilde Charlotte Blomberg','/storage/blog/author/1673788063.webp',1,'2023-01-15','2023-01-15 13:07:43','2023-01-15 14:38:05'),(60,1064,'Vil skape samfunnsengasjement med diktningen','<p>Forfatter Ole Skytterholm er aktuell med diktsamlingen &lsquo;Ein song for Alan Kurdi&rsquo; (Lyrikkforlaget, 2023).</p>\r\n<p><strong>&nbsp;<img src=\"https://forfatterskolen.no/storage/photos/1064/Alan.png\" alt=\"\" width=\"600\" height=\"600\" /></strong></p>\r\n<p><strong>En igangsettende opplevelse</strong></p>\r\n<p>&ndash; Livet er fullt av tilfeldigheter, utbryter Ole.</p>\r\n<p>Det var f&oslash;rst som pensjonist at han virkelig fikk skrevet. Han har lenge hatt tekster liggende i skrivebordsskuffen, som man sier. Men med flere hektiske lederstillinger strakk ikke tiden til.</p>\r\n<p>&ndash; Jeg har puslet litt med tekst, og i ungdommen trodde jeg at jeg skulle bli forfatter, det er det vel mange som tror, ler Ole.</p>\r\n<p>Men s&aring; ble det ikke slik. Han fikk h&oslash;ye stillinger, mye ansvar, og jobbene var spennende.</p>\r\n<p>Skrivingen ble lagt til side, frem til m&oslash;tet med flyktningkrisen. Som frivillig i en gresk flyktningleir ser Ole katastrofen p&aring; n&aelig;rt hold. Menneskene han m&oslash;ter setter i gang en kreativ prosess.</p>\r\n<p>&ndash; Det var grusomme tilstander i leirene, ikke minst for barna. Noen kom med fjerne slektninger, eller fremmede, noen kom alene. Det var vel dette som ble utl&oslash;sende for skrivingen.</p>\r\n<p><strong>Et bredt dikterlandskap </strong></p>\r\n<p>Den r&oslash;de tr&aring;den i samlingen er klar. &ndash; Jeg har alltid v&aelig;rt samfunnsengasjert, og diktene tar opp tema som milj&oslash;, rasisme og menneskerettigheter.</p>\r\n<p>I diktene m&oslash;ter vi p&aring; flere nyere hendelser som sier noe om samfunnets tilstand. De fleste kjenner navnet Alan Kurdi, og husker bildet av 3-&aring;ringen som druknet p&aring; flukt over havet. Denne sterke hendelsen, og flere andre, har inspirert diktene.</p>\r\n<p>&ndash;Jeg vil n&aring; ut med noen politiske holdninger.</p>\r\n<p>Kultursektoren har det ansvaret, mener Ole. &ndash; Jeg synes forfatterne b&oslash;r skrive om samfunnet v&aring;rt. Vi har et ansvar. Med samlingen &oslash;nsker jeg &aring; p&aring;virke leseren, s&aring; et samfunnsengasjement smitter over, det hadde v&aelig;rt fint.</p>\r\n<p>Men det er ogs&aring; et stort spenn i diktene, p&aring;peker Ole. I samlingen finner man ogs&aring; dikt som tar for seg hyggeligere temaer: &ndash; Jeg h&aring;per leseren ogs&aring; kan trekke litt p&aring; smileb&aring;ndet.</p>\r\n<p><strong>God mottagelse og musikalsk samarbeid</strong></p>\r\n<p>&lsquo;Ein song for Alan Kurdi&rsquo; har allerede h&oslash;stet gode tilbakemeldinger, blant annet fra Tom Egeland, som sier om boken; &lsquo;Dikt som vil gripe deg &ndash; og vekke undring og ettertanke&rsquo;. Kritiker Anne Sch&auml;ff er ogs&aring; begeistret for samlingen; &lsquo;Forfatteren skriver vart om de vergel&oslash;se. Med humor og krass refs r&oslash;sker han opp i sin generasjons synder og unnfallenhet i en diktsamling som spenner vidt.&rsquo;</p>\r\n<p>Oles dikt har allerede bevegd seg ut i andre kunstarter.</p>\r\n<p>&ndash; Verkene er ikke publisert enn&aring;, men det er blitt skrevet musikk av profesjonelle musikere og komponister.</p>\r\n<p>Ett av diktene er alt arrangert for kor med full besetning. At musikere vil jobbe med diktene, er ikke s&aring; rart; Ole bruker musikk aktivt i skrivingen. &ndash; N&aring;r jeg skriver tenker jeg ofte p&aring; diktene som sanger. De skal ha god rytme, og det har nok bidratt til at de som skriver musikk har blitt begeistret for diktene.</p>\r\n<p><strong>Viktig med en motivator</strong></p>\r\n<p>&Aring; skrive er hardt arbeid, det er Ole klar p&aring;.</p>\r\n<p>&ndash; F&oslash;r jeg sendte noe til forlaget, p&aring;spanderte jeg meg b&aring;de skrivekurs og manusvurderinger.</p>\r\n<p>Koblingen til skolen har v&aelig;rt viktig for Ole: &ndash; Det er ensomt &aring; skrive. Da er det viktig med slike overskuddsmennesker som Kristine. Jeg er en stor tilhenger av henne, hun er en sv&aelig;rt inspirerende pedagog. Ikke bare har hun skrevet mye selv, men hun gir gode &lsquo;push&rsquo;.</p>\r\n<p>Til aspirerende forfattere, presenterer han et viktig perspektiv: &ndash; &Aring; skrive, om du blir utgitt eller ikke, kan v&aelig;re god terapi, der kan du f&aring; gitt uttrykk for f&oslash;lelsene dine, og tankene dine rundt livet, for dine n&aelig;rmeste og for deg selv.</p>\r\n<p>Det kan v&aelig;re fint i seg selv, mener Ole. - Uansett hvor flink du er, kan det v&aelig;re fint bare &aring; sende et dikt til en annen, eller en sang. Man kan vise omtanke og kj&aelig;rlighet ved &aring; sende fra seg noen ord.</p>\r\n<p><strong>Godt &aring; bidra</strong></p>\r\n<p>Ole vil gjerne bidra til det viktige arbeidet han s&aring; i Hellas. Forfatterens bokinntekter g&aring;r derfor til organisasjonen &lsquo;Dr&aring;pen i havet&rsquo;.</p>\r\n<p>&ndash; N&aring;r du har v&aelig;rt der og opplever dette, du kommer fra den norske bobla, p&aring; en m&aring;te utenfor verden, og du ser hvor t&oslash;ft livet kan v&aelig;re for andre; da er det med lett hjerte du st&oslash;tter disse folkene.</p>\r\n<p>Boken kan kj&oslash;pes hos alle nettbokhandlere, Lyrikkforlaget, Nynorsk Kultursentrum og i en rekke bokhandler. &nbsp;</p>\r\n<p><em>Forfatterskolen gratulerer Ole med debuten!</em></p>\r\n<p><img src=\"https://forfatterskolen.no/storage/photos/1064/einsongforalankurdi_forside_small.jpeg\" alt=\"\" width=\"794\" height=\"1211\" /></p>\r\n<p><strong>Utdrag dikt:</strong></p>\r\n<p>Ikkje tilgjev, Alan Kurdi</p>\r\n<p>at vi ikkje var ein bror</p>\r\n<p>lat oss dr&oslash;yme draumen saman</p>\r\n<p>om ei trygg og kriglaus jord</p>\r\n<p>om ein b&aring;t som sj&oslash;lv i stormen</p>\r\n<p>reddar deg og far og mor</p>\r\n<p>(fra&nbsp; diktet &laquo;Ein song for Alan Kurdi&raquo;)</p>\r\n<p><strong>-</strong></p>\r\n<p>N&aring;r vi er saman</p>\r\n<p>har vi alltid</p>\r\n<p>s&aring; mykje</p>\r\n<p>&aring; snakke om</p>\r\n<p>&nbsp;</p>\r\n<p>men aller best</p>\r\n<p>har vi det</p>\r\n<p>n&aring;r vi kan</p>\r\n<p>teie saman</p>\r\n<p>&nbsp;</p>\r\n<p>det har vi snakka</p>\r\n<p>mykje om</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>','/storage/blog/1674467144.jpg','Ole Skytterfulm','/storage/blog/author/1674467144.jpg',1,NULL,'2023-01-23 09:45:44','2023-01-23 10:11:20'),(61,1064,'Veien til fiksjonen og forfatterskapet','<p><img src=\"https://forfatterskolen.no/storage/photos/1064/Gratis minikurs (2).png\" alt=\"\" width=\"600\" height=\"600\" /></p>\r\n<p>Indieforfatter Eli Aga er aktuell med en spenningsroman med et historisk bakteppe.</p>\r\n<p><em>Moskva, august 1991. Sovjetunionen er i ferd med &aring; falle fra hverandre. Mens kuppet mot president Gorbatsjov utspiller seg, m&aring; kunstneren Liva risikere livet for &aring; redde familien fra en felle som hun selv har v&aelig;rt med p&aring; &aring; legge ut for dem.</em></p>\r\n<p><strong>Fiksjon med utgangspunkt i egne opplevelser</strong></p>\r\n<p>Kultur, historie og formidling er ikke nytt for Eli Aga, som er utdannet filolog. Det ble likevel egne opplevelser som ble utl&oslash;sende for skrivingen.</p>\r\n<p><em>- </em>Jeg bodde tre &aring;r i Moskva mellom 1991 og 1994, og to uker etter at vi kom, skjedde kuppet mot Gorbatsjov. Da kj&oslash;rte v&aring;r lille familie inn mot Moskva sentrum sammen med tanksene.</p>\r\n<p>Elis mann jobbet i et oljeselskap, og i det de flyttet til Sovjetunionen, falt den sammen. Det var en urolig tid i Russland, med sterke opplevelser og en aktiv mafiavirksomhet.</p>\r\n<p>- I etterkant f&oslash;lte jeg veldig for &aring; skrive om det, jeg hadde et behov for &aring; formidle det jeg hadde sett og opplevd.</p>\r\n<p>Eli begynte p&aring; &lsquo;Det russiske egget&rsquo; for 15 &aring;r siden. Da hadde den en annen form; en skildring av eget liv og en viktig epoke i historien. F&oslash;rst senere fikk historien en skj&oslash;nnlitter&aelig;r drakt:</p>\r\n<p>- En journalist jeg kjenner fortalte meg at det burde bli en spenningsroman isteden, at jeg burde fjerne det som var mitt, og skape fiksjon.</p>\r\n<p>Det historiske m&aring;tte likevel f&aring; mye plass.</p>\r\n<p>- Alle de historiske detaljene er riktige, det er viktig for meg, jeg jukser ikke med historien.</p>\r\n<p><span style=\"text-decoration: underline;\">Utdrag fra boken:</span></p>\r\n<p><em>Mannen &aring;pnet lokket til den svarte fl&oslash;yelsesken. Liva stivnet da hun s&aring; gjenstanden som l&aring; p&aring; en gulnet, drapert silkeseng. Den skinte av bl&aring; emalje, gull, og noe som m&aring;tte v&aelig;re edle steiner, og liknet et Faberg&eacute; p&aring;skeegg.</em><em><br />&laquo;Hva vil du ha for det da?&raquo;, spurte hun, og visste med det samme at hun hadde gjort en tabbe.&nbsp;</em></p>\r\n<p><strong>&Aring; l&aelig;re seg h&aring;ndverket</strong></p>\r\n<p>Researchprosessen var ikke krevende for Eli, som ved hjelp av studier og &aring;rene i Russland, alt hadde materialet klart. Utfordringen ble &aring; finne formen. Forfatterskolen har v&aelig;rt en viktig del av prosessen for Eli.</p>\r\n<p>- Jeg visste ikke hvordan jeg skulle skrive en roman eller en spenningsroman. Jeg begynte med romankurset, jeg m&aring;tte l&aelig;re meg de mest element&aelig;re tingene. Og det hadde jeg god nytte av. Uten dere hadde jeg ikke klart det!</p>\r\n<p>Hun kontaktet forlag og fikk gode tilbakemeldinger, men var likevel ikke i m&aring;l. Krimkurset ble neste steg p&aring; veien.</p>\r\n<p>- Jeg har s&oslash;kt kunnskap flere steder, men den viktigste har jeg f&aring;tt hos dere. Akkurat de spesielle tingene som g&aring;r p&aring; &aring; skrive krim og spenning, spenningsoppbygging osv. har v&aelig;rt viktig. I begynnelsen fikk jeg mye tilbakemelding p&aring; at ting ikke hang helt sammen, det &aring; f&aring; alt fra begynnelse til slutt til &aring; henge sammen i en helhet har v&aelig;rt en utfordring. Det &aring; l&aelig;re ting som show, don&rsquo;t tell har ogs&aring; v&aelig;rt viktig. Det tok en stund f&oslash;r jeg knakk den koden.</p>\r\n<p><strong>Viktig med motstand</strong></p>\r\n<p>- Refusjon har gjort teksten bedre hver gang, p&aring;peker Eli.</p>\r\n<p>F&oslash;r hun gikk p&aring; Forfatterskolen fikk hun blank refusjon, som selvsagt kan v&aelig;re demotiverende.</p>\r\n<p>- Man blir lei seg, teksten kommer jo fra deg selv, og du kan f&oslash;le du blir slaktet som person.</p>\r\n<p>Det siste avslaget fra Cappelen Damm var tungt; - Da hadde jeg jo kommet s&aring; langt, og f&aring;tt gode tilbakemeldinger p&aring; alt som burde p&aring; plass.</p>\r\n<p>Men Eli har ogs&aring; f&oslash;lt seg heldig i m&oslash;te med forlag; - Jeg har f&aring;tt flere konsulentuttalelser, og alle uttalelser, betalt og ikke, har gjort boken mye bedre. Tilbakemelding har f&aring;tt meg til &aring; tenke i andre baner, og det har gitt ny inspirasjon.</p>\r\n<p>Eli prioriterte skrivingen, og sakte men sikkert n&aelig;rmet m&aring;llinjen seg.</p>\r\n<p><strong>Boken skal ut!</strong></p>\r\n<p>Etter &aring; ha g&aring;tt og tenkt og s&oslash;kt tilbakemelding p&aring; flere kanter, f&oslash;lte Eli seg klar.</p>\r\n<p>- P&aring; et tidspunkt kjente jeg at boken var s&aring; bra som jeg kan f&aring; den, jeg hadde gjort s&aring; mange endringer de siste to &aring;rene, og jobbet n&aelig;rmest fulltid fordi jeg er pensjonist, s&aring; jeg f&oslash;lte at n&aring;, n&aring; er den s&aring; god den kan bli, jeg vil ikke h&oslash;re snakk om at den ikke skal ut!</p>\r\n<p>Da skolen tilb&oslash;d selvpublisering via et samarbeid med Giutbok, &aring;pnet det seg en d&oslash;r: - Da slo jeg til!</p>\r\n<p>Opplevelsen var god, og som tidligere selvstendig n&aelig;ringsdrivende, hadde Eli det som trengtes til &aring; mestre den nye forfattertilv&aelig;relsen.</p>\r\n<p>- Jeg drar rundt til bokhandler og biblioteker, og jeg har laget et kurs om russisk historie, sett gjennom billedkunsten; et foredrag jeg holder p&aring; biblioteker, og p&aring; Norli bokhandel.</p>\r\n<p>Man m&aring; v&aelig;re &lsquo;p&aring;&rsquo;, mener Eli. - Ogs&aring; m&aring; du ikke v&aelig;re redd for &aring; by p&aring; deg selv!</p>\r\n<p>Hun har klare tips til andre som &oslash;nsker &aring; gi ut selv: - Man skal ikke hoppe ut i selvutgivelse for tidlig. Det m&aring; v&aelig;re veldig godt gjennomarbeidet, ellers kan man angre.</p>\r\n<p>Og det er ikke alltid like lett &aring; vurdere egen tekst.</p>\r\n<p>- F&oslash;r var jeg sikker p&aring; at det var bra, dette kan utgis, tenkte jeg. Men jeg er veldig glad for alle rundene jeg har hatt med tilbakemeldinger, og at jeg har jobbet s&aring; n&oslash;ye med spr&aring;k og innhold; da kan du med stolthet presentere produktet.</p>\r\n<p>Og det merker man, mener Eli, n&aring;r boka er gitt ut, og har et eget liv.</p>\r\n<p>- N&aring;r jeg kommer til et bibliotek eller en bokhandel og leverer ut leseeksemplar, s&aring; har jeg en selvsikkerhet, og det tror jeg de merker.</p>\r\n<p>Det krever mye arbeid &aring; gi ut selv.</p>\r\n<p>&nbsp;- Men det er kjekt arbeid, p&aring;peker Eli. &ndash; Jeg er blitt godt mottatt, jeg hadde ikke forventet at bokhandlene og bibliotekene skulle v&aelig;re s&aring; positive til en selvutgitt bok, jeg er forbauset over hvor mye vennlighet og nysgjerrighet jeg har blitt m&oslash;tt med!</p>\r\n<p>Det er ogs&aring; store variasjoner hos selvpubliseringsleverand&oslash;rer, forteller Eli, og man b&oslash;r unders&oslash;ke disse forskjellene.</p>\r\n<p>- Hos Giutbok ble boka registrert i Sentraldistribusjonen. Siden den ligger der, er det mye enklere for bokhandlere &aring; ta inn boka, mange har bestilt den n&aring;r jeg har bes&oslash;kt dem. En stor fordel!</p>\r\n<p><strong>Kun starten</strong></p>\r\n<p>En styrke ved selvpublisering er at man kommer tett p&aring; leserne sine.</p>\r\n<p>&ndash; Flere av dem skriver til meg, forteller Eli. - Ord som &lsquo;velskrevet&rsquo;, &lsquo;lettlest&rsquo; og &lsquo;spennende&rsquo; g&aring;r igjen, og leserne er b&aring;de voksne og unge.</p>\r\n<p>N&aring; er karrieren er i gang, og neste bok er allerede p&aring;begynt: - Jeg har en id&eacute; til en ny historisk spenningsroman, den skal foreg&aring; i Norge p&aring; 1870-tallet. Et mord skjedde rundt denne tiden, og det mordet skal jeg spinne videre p&aring;. At d&oslash;dsfallet var et mord, ble klart f&oslash;rst nylig.</p>\r\n<p>&lsquo;Det russiske egget&rsquo; finner du i flere fysiske bokhandlere, og p&aring; alle nettbokhandlere.</p>\r\n<p><em>Forfatterskolen gratulerer Eli med utgivelsen &ndash; og vi gleder oss allerede til neste bok!</em></p>','/storage/blog/1677325419.webp','Eli Aga','/storage/blog/author/1677325419.jpg',1,'2023-02-25','2023-02-25 11:43:39','2023-02-25 12:01:44'),(62,1064,'Prosaens superkraft','<p><img src=\"https://forfatterskolen.no/storage/photos/1064/Happy Mother\'s Day (Facebook Cover).png\" alt=\"\" width=\"719\" height=\"405\" /></p>\r\n<p>&nbsp;</p>\r\n<h2><strong>Skummelt &aring; g&aring; solo</strong></h2>\r\n<p>Anne Hilde Vassb&oslash; Hagen er aktuell med den popul&aelig;rvitenskapelige boka <em>Superkraften i alle foreldre &ndash; om f&oslash;lelser, grenser og kunsten &aring; si unnskyld. </em></p>\r\n<p>Boken er ikke forfatterens f&oslash;rste utgivelse. Sammen med tre andre skrev hun en fagbok om emosjonsfokusert ferdighetstrening for foreldre. Det ble en bok til, og Anne Hilde syntes det var trygt at de var flere forfattere.</p>\r\n<p>S&aring; lurte forlaget p&aring; om hun ikke ville skrive en mer popul&aelig;rvitenskapelig bok &ndash; alene. Dette ble&nbsp; til <em>Sinte barn og voksne &ndash; slik forst&aring;r og h&aring;ndterer du sinne (Gyldendal, 2021).</em></p>\r\n<p>&ndash; Boken var det f&oslash;rste jeg skrev alene, og det syntes jeg var pisse skummelt, sier Anne Hilde.</p>\r\n<h2><strong>Deler egne tabber</strong></h2>\r\n<p>Likevel, solo-karrieren var i gang, og n&aring; er &aring;rets utgivelse her: <em>Superkraften i alle foreldre.</em></p>\r\n<p>I boken tar psykologen for seg vanskelige f&oslash;lelser hos barn og voksne. Hun mener foreldres egne f&oslash;lelser kan komme i veien for superkraften i hver enkelt, og et av m&aring;lene med boka er &aring; hjelpe leserne med &aring; hente frem denne kraften.</p>\r\n<p>Trebarnsmoren deler bekreftelse, innsikt og praktiske r&aring;d&nbsp; og presenterer tre sentrale foreldreferdigheter: Validering av f&oslash;lelser, grensesetting og det &aring; si unnskyld.</p>\r\n<p>Stoffet er trolig gjenkennelig for de fleste foreldre, og forfatteren deler raust av egne \"tabber\".</p>\r\n<h2><strong>Fra fag til fiksjon</strong></h2>\r\n<p>Rett f&oslash;r utgivelsen skjedde det noe uventet. Anne Hilde kjente en spirende interesse for &aring; skrive barnelitteratur.</p>\r\n<p>&ndash; Plutselig fikk jeg lyst til &aring; skrive en barnebok, noe helt annet, og dette er jeg p&aring; ingen m&aring;te skolert i. Jeg ville skrive mer implisitt. I stedet for &aring; si <em>n&aring; skal du l&aelig;re om f&oslash;lelser</em>, ville jeg skrive en historie.</p>\r\n<p>Trebarnsmoren tok utgangspunkt i datteren p&aring; 8 &aring;r, og en tegning hun hadde laget.</p>\r\n<p>Boken ble refusert. Anne Hilde forsto at om hun skulle skrive denne boka, m&aring;tte hun l&aelig;re seg sjangeren. Hun meldte seg p&aring; Forfatterskolens barnebokkurs med Gro Dahle, og der fikk hun en konkret innf&oslash;ring i det &aring; skrive for barn.</p>\r\n<h2><strong>Ble en bedre forfatter</strong></h2>\r\n<p>&ndash; Det var noe helt annet enn &aring; skrive fag og sakprosa. For meg, som ikke hadde erfaring med denne typen skriving, var det en bratt l&aelig;ringskurve.</p>\r\n<p>Barneboken er lagt til side, enn s&aring; lenge, men kurset var p&aring; ingen m&aring;te forgjeves. Anne Hilde fikk god nytte av de nye prosakunnskapene da hun fullf&oslash;rte sakprosaprosjektet.</p>\r\n<p>&ndash; Jeg ble en bedre forfatter, rett og slett, og den nyeste boka ble bedre enn de andre.&nbsp;</p>\r\n<h2><strong>H&aring;ndbok for terapeuter</strong></h2>\r\n<p>Etter kurset fikk Anne Hilde ogs&aring; en id&eacute; til et nytt samarbeid p&aring; jobben: Hun ville skrive en h&aring;ndbok for terapeuter. Psykologen fikk med seg kollegaer fra flere hold, ogs&aring; folk som aldri hadde skrevet tidligere. For &aring; komme godt i gang fra start, bestilte hun nok et skrivekurs hos Forfatterskolen, holdt av Bjarte Breiteig, Gro Dahle og rektor Kristine S. Henningsen.</p>\r\n<p>&ndash; Alle ble gira og inspirerte til skriving, og fikk motivasjon for &aring; hive seg over prosjektet. Vi hadde nok ikke hadde turt &aring; v&aelig;re s&aring; kreative og frie i sakprosaskrivingen, uten kurset. &nbsp;Det ble varme og levende tekster. Vi forsto at vi ogs&aring; kunne v&aelig;re litt v&aring;gale, ogs&aring; innenfor fag. Det har blitt et veldig kult prosjekt!</p>\r\n<h2><strong>Skrev i etapper</strong></h2>\r\n<p>Anne Hilde har god fleksibilitet i jobben. Skrivingen ble derfor gjort i etapper &ndash; p&aring; hyttetur, innimellom fulle arbeidsdager med kollegaer, av og til i hele arbeidsuker.</p>\r\n<p>&ndash; Jeg hadde en id&eacute; om at jeg m&aring;tte ha en hel dag for &aring; komme godt inn i arbeidet, men jeg kjente at det ble for vanskelig. S&aring; h&oslash;rte jeg om varianten som ble nevnt p&aring; kurset: Skriv litt hver dag.</p>\r\n<p>Det ble en halvtime, eller en time, p&aring; morgenen, og Anne Hilde ble overrasket over at de korte &oslash;ktene ble til en hel bok.</p>\r\n<p>&ndash; N&aring;r jeg hadde lange &oslash;kter brukte jeg mye tid p&aring; &aring; rive meg i h&aring;ret, det f&oslash;ltes som om motstanden var st&oslash;rre, mens de korte &oslash;ktene var effektive og fylt med overskudd. Jeg hadde friskt mot og friske &oslash;yne. Det var ogs&aring; lettere &aring; finne en halvtime her og der, og kontinuiteten f&oslash;rte til &oslash;kt produksjon. Ved de lengre &oslash;ktene gikk det kanskje noen uker imellom, n&aring; var jeg mye mer <em>i </em>prosjektet.</p>\r\n<h2><strong>Friskt blikk p&aring; sjangeren</strong></h2>\r\n<p>&Aring; finne frem til riktig metode, ble det viktigste grepet n&aring;r Anne Hilde skulle skrive bok. N&aring; vet hun hva som skal til for &aring; komme i m&aring;l.</p>\r\n<p>&ndash; Det viktigste er at du skriver om noe du er genuint interessert i. Noe du er veldig nysgjerrig p&aring;, du m&aring; skrive der det <em>brenner</em>.</p>\r\n<p>Hun mener ogs&aring; det er viktig for sakprosaforfattere &aring; ha et friskt blikk p&aring; sjangeren.</p>\r\n<p>&ndash; Skriv medrivende, tenk spenningsroman, tillat deg noen \"cliffhangere\" &ndash; stjel grep fra skj&oslash;nnlitteraturen. Del dryppvis med leseren, skap forventning til hva som skal komme, pr&oslash;v &aring; skrive en <em>pageturner</em>. Og husk n&aelig;rheten til leseren.</p>\r\n<h2>Vil fortsatt skrive for barn</h2>\r\n<p>Forfattere har heller ikke lagt vekk &oslash;nsket om &aring; skrive ren prosa.</p>\r\n<p>&ndash; Jeg har fortsatt lyst til &aring; skrive til barn. Kanskje andre skj&oslash;nnlitter&aelig;re prosjekter ogs&aring;?</p>\r\n<p><em>Superkraften i alle foreldre &ndash; om f&oslash;lelser, grenser og kunsten &aring; si unnskyld</em> er n&aring; tilgjengelig i bokhandel og p&aring; nett.</p>\r\n<p><strong>Forfatterskolen gratulerer Anne Hilde med utgivelsen. Vi gleder oss stort til &aring; f&oslash;lge forfatterkarrieren hennes videre!</strong></p>\r\n<p><img src=\"https://forfatterskolen.no/storage/photos/1064/remote.axd.jpeg\" alt=\"\" width=\"324\" height=\"486\" /></p>\r\n<p><em>Foto: Cecilie Bannow</em></p>','/storage/blog/1684236975.jpg','Anne Hilde Vassbø Hagen','/storage/blog/author/1684236975.jpg',1,'2023-05-16','2023-05-16 11:36:15','2023-05-16 12:25:16'),(63,1064,'Kosekrim på Cappelen Damm','<h3 class=\"tve-droppable\">Vi gratulerer Gunn Helene Arsky, tidligere elev p&aring; Forfatterskolen, med utgivelse p&aring; Cappelen Damm!</h3>\r\n<p class=\"tve-droppable\">La deg inspirere av hennes vei mot realisering av forfattedr&oslash;mmen:</p>\r\n<h3 class=\"tve-droppable\">Fortell litt om deg selv!</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0a8\">Jeg er Gunn Helene Arsky, mor til tre fantastiske unge mennesker og kj&aelig;reste med Juha i over 30 &aring;r. Av utdannelse er jeg ern&aelig;ringsfysiolog, yogal&aelig;rer, helseveileder og forfatter.&nbsp; Jeg har nettopp fylt 56 &aring;r og er full av skapertrang og kreativitet som bare vil UT! For litt over 7 &aring;r siden sa jeg opp jobben, vi solgte huset v&aring;rt i Oslo og flyttet til rolige, vakre Halden der vi ikke kjente noen. Men det gj&oslash;r vi n&aring;, og det er en glede &aring; f&aring; nye venner i voksen alder. Jeg har g&aring;tt fra fast stilling til &aring; v&aelig;re frilanser. Det jeg ikke tjener i penger, f&aring;r jeg igjen i form av samv&aelig;r, n&aelig;rhet, tid og ro.</p>\r\n<h3 class=\"tve-droppable\">N&aring;r begynte du &aring; skrive? Har du alltid hatt en forfatterdr&oslash;m, eller hvordan kom skrivingen til?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0ab\">Lesing og skriving betyr utrolig mye for meg. Jeg har skrevet og lest siden jeg var en neve stor, jeg brukte sparepengene mine p&aring; &aring; handle b&oslash;ker p&aring; loppemarked da jeg var liten, og jeg har heldigvis f&aring;tt skrevet masse opp gjennom &aring;rene som ern&aelig;ringsfysiolog. B&aring;de for nettsiden i bedriftene jeg har jobbet, men ogs&aring; i form av en rekke skole- og faktab&oslash;ker om ern&aelig;ring og helse, og ikke minst som fast skribent i flere ukeblader og tidsskrifter.</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0ac\">Jeg leser alltid p&aring; en bok, kanskje to, og jeg har en liten instagramkonto (@gunnheleneleser) der jeg deler det jeg leser. M&aring;let er &aring; lese en bok i uken i gjennomsnitt. Jeg leser i hovedsak chick lit, hyggelige samtidsromaner, krim og koselig krim.</p>\r\n<h3 class=\"tve-droppable\">Hva slags sjanger skriver du i, og hvorfor?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0ae\">Etter &aring; ha selvpublisert to godt mottatte feelgoodromaner om yogal&aelig;reren Ella, f&oslash;lte jeg at tiden var inne for &aring; snuse litt p&aring; kosekrimsjangeren. Den har gitt meg s&aring; mange gode lesestunder opp igjennom. Samtidig opplevde jeg at de fleste b&oslash;kene foregikk i Irland, Skottland, England eller USA &ndash; mens Norge var skuffende frav&aelig;rende. Jeg gikk i gang med godt mot, og jeg bygget p&aring; det jeg hadde l&aelig;rt meg av de to f&oslash;rste romanene mine. S&aring; da f&oslash;rsteutkastet var ferdig, sendte jeg det til alle de store forlagene &ndash; og fikk, etter et hyggelig m&oslash;te med redakt&oslash;r &ndash; napp hos Cappelen Damm.</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0af\">Kosekrim er en sjanger som har kommet for &aring; bli, tror jeg, og spesielt n&aring;, som verden er litt skakk. De fleste av oss liker et frydefullt gys, slik vi fikk fra barndommens eventyr, men uten blod, g&oslash;rr og triste eller grusomme detaljer som trigger uhelse mentalt.</p>\r\n<h3 class=\"tve-droppable\">Hva er din motivasjon i skrivingen?&nbsp;</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0b1\">Skriving har gledet meg siden jeg var sv&aelig;rt liten. Gjennom hele barneskolen var norsk det morsomste faget, og engelsk, da vi begynte med det. Jeg husker fortsatt en engelskstil jeg skrev i sjuende klasse, der jeg diktet opp en mann som het Mr Swansteth. Jeg husker fryden ved &aring; ikke bare finne p&aring; en historie, men ogs&aring; ha &lsquo;makten&rsquo; til &aring; dikte opp navn &ndash; jeg syntes Swansteth var s&aring; fjongt!</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0b3\">Likevel er jeg ikke typen som har hatt en stabel halvskrevne manus i skrivebordsskuffen. Jeg har b&aring;ret historiene inni meg, til jeg &ndash; og livet rundt meg &ndash; var klar. Jeg fors&oslash;kte meg riktignok p&aring; en barnebok da eldstedatteren min var baby, men det manuset er nok best gjemt og glemt! Ammet&aring;ke..!</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0b4\">Som frilanser i Halden kan jeg styre tiden min selv. Noe av det f&oslash;rste jeg gjorde, var &aring; g&aring; p&aring; skrivekurs her p&aring; Forfatterskolen. Jeg brukte det jeg l&aelig;rte og satte i gang med &aring; skrive romanen&nbsp;<em>Ellas Tilstedev&aelig;relse</em>&nbsp;og deretter&nbsp;<em>Ellas Hellas</em>&nbsp;&ndash; begge selvpubliserte. Og n&aring; er det&nbsp;<em>Mord i bokhandelen</em>&nbsp;som kommer p&aring; selveste Cappelen Damm i mars!</p>\r\n<h3 class=\"tve-droppable\">Hva slags bok har du skrevet?&nbsp;</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0b6\">Mord i bokhandelen &ndash; Engel &amp; Luna nr. 1 er en skikkelig kosekrim med alle de rette ingrediensene: Katter, cupcakes, bokhandler, romantikk, magi og et mystisk d&oslash;dsfall. Her er et kort sammendrag:</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0b7\">N&aring;r fargerike Minna Gabler blir funnet d&oslash;d ved foten av trappen i sin alternative bokhandel i Halden, tror alle at den eldre kvinnen d&oslash;de av fallet. Kryptokryssordforfatteren Engel og s&oslash;steren hennes, Isa-Linn, er tante Minnas eneste arvinger, til tross for at de aldri kjente henne. Nyskilte Engel tar med seg sin kloke siameserkatt, Luna, for &aring; starte p&aring; nytt i den sjarmerende sm&aring;byen. Men ganske snart finner Engel ut at hun ikke bare har arvet en bokhandel som s&aring;rt trenger en kj&aelig;rlig h&aring;nd og kl&oslash;ktig markedsf&oslash;ring &ndash; tante Minna har ogs&aring; etterlatt seg et forsvunnet arvestykke som Isa-Linn skal arve, og med det, et ul&oslash;st mysterium. For var Minnas d&oslash;dsfall egentlig helt naturlig? Hvem tok egentlig livet av tante Minna, og hva skjuler seg mellom boksidene i den gamle bokhandelen?</p>\r\n<h3 class=\"tve-droppable\">Har du gitt ut boken selv? Hvordan var det, i s&aring; fall?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0b9\">Jeg har publisert de to f&oslash;rste romanene selv, og det gikk fint. Jeg gjorde alt selv, utenom &aring; kj&oslash;pe manusutvikling fra Forfatterskolen og f&aring; designhjelp til &aring; lage omslaget. Alt annet ordnet jeg selv. Det var veldig l&aelig;rerikt, og derfor setter jeg n&aring; enormt stor pris p&aring; at jeg ikke trenger &aring; gj&oslash;re det denne gangen!</p>\r\n<h3 class=\"tve-droppable\">Hvordan var det &aring; sitte med sin egen bok mellom hendene?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0bb\">N&aring; har ikke&nbsp;<em>Mord i bokhandelen</em>&nbsp;g&aring;tt i trykken enn&aring;, i skrivende stund, s&aring; jeg m&aring; svare basert p&aring; tidligere erfaringer. Som forfatter av b&aring;de fagb&oslash;ker og skj&oslash;nnlitteratur, vet jeg at det er noe helt eget ved &aring; st&aring; med en roman i hendene &ndash; et produkt av ens egen fantasi. Jeg har alltid dr&oslash;mt om &aring; se navnet mitt p&aring; en roman, til og med p&aring; en roman utgitt p&aring; et av Norges st&oslash;rste forlag. N&aring; er dr&oslash;mmen virkelig!</p>\r\n<h3 class=\"tve-droppable\">Hvordan har mottakelsen v&aelig;rt, og hva er planene videre for boken?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0be\">Alle leserne av de to f&oslash;rste romanene mine venter spent p&aring; denne nye boken! Og det er helt vilt, alt som er p&aring; trappene her n&aring;. Jeg skal signere boken p&aring; Norli i Oslo 21. mars, under Krimfestivalen i Oslo. Der skal jeg ogs&aring; delta i en debutantdebatt. Et par uker senere skal jeg snakke om Mord i Bokhandelen p&aring; Feelgoodfestivalen p&aring; Cappelen Damm. Og i tillegg er det snakk om salg til utlandet, lydbok, e-bok og jeg vet ikke hva&hellip;</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0bf\">Og midt oppi dette blir det en super lanseringsfest p&aring; Kulturhuset i Halden i slutten av mars, med bokbading, gratis cupcakes til alle (og med en premie til noen heldige), h&oslash;ytlesning, boksalg ved den lokale bokhandelen og selvsagt signering av boken. Jeg gleder meg masse!</p>\r\n<h3 class=\"tve-droppable\">Har du dr&oslash;mmer, eller en konkret plan, for videre skriving?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0c1\">Det magiske er at jeg allerede har levert manuset til bok nummer to om radarparet Engel og Luna. Den skal etter planen komme allerede til h&oslash;sten. Mange av personene man blir kjent med i f&oslash;rste bok, dukker ogs&aring; opp i bok nummer to &ndash; cupcakebakeren Camilla, journalisten Adam og Engels s&oslash;ster, Isa-Linn. Men mysteriet er noe helt annet denne gangen &ndash; selvsagt!</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0c2\">Og &ndash; som om ikke det var nok&hellip; i disse dager skriver jeg i vei p&aring; nummer tre i serien om Engel og Luna, som skal komme til v&aring;ren om et &aring;r. S&aring; dette med skriving har virkelig l&oslash;snet n&aring;, og jeg h&aring;per &aring; kunne gj&oslash;re MYE mer av dette fremover!</p>\r\n<h3 class=\"tve-droppable\">Hvordan var det &aring; samarbeide med oss &ndash; Forfatterskolen og Indiemoon?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0c4\">Jeg holder fortsatt kontakten med Forfatterskolen, flere &aring;r etter at jeg var ferdig &lsquo;uteksaminert&rsquo;. Det sier litt om hvor godt jeg f&oslash;lte meg ivaretatt, b&aring;de som elev, men ogs&aring; som kunde underveis i jobbingen med de to selvpubliserte b&oslash;kene. Jeg er med i Facebookgruppen ogs&aring;, og jeg m&aring; si at det er fint &aring; kjenne seg som en del av et st&oslash;rre fellesskap. For det er unektelig et soloprosjekt &aring; sitte hjemme og skrive.</p>\r\n<h3 class=\"tve-droppable\">Hva er ditt r&aring;d til andre som dr&oslash;mmer om &aring; bli forfatter?</h3>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c19cb0c6\">Begynn &aring; skrive! &Oslash;velse gj&oslash;r mester. Og ingen mesterverk har blitt til uten &oslash;velse. Jeg liker spesielt godt det som Rektor Kristine Storli Henningsen sa en gang p&aring; webinar &ndash; at for &aring; ha en tekst &aring; redigere, s&aring; m&aring; man faktisk skrive den teksten f&oslash;rst. S&aring; &ndash; begynn i dag &ndash; det er ikke en dag for tidlig!</p>\r\n<p class=\"tve-droppable\" data-css=\"tve-u-194c1a3b86d\">Hurra for deg, Gunn Helene! Vi er s&aring; stolte av deg :-)</p>','/storage/blog/1738416618.jpg','Gunn Helene Arsky','/storage/blog/author/1738416618.jpg',1,'2025-02-01','2025-02-01 13:30:18','2025-02-01 13:31:37'),(64,6058,'Utgitt elev: Bok nummer to på Cappelen Damm','<p data-start=\"68\" data-end=\"292\">Noe av det fineste med &aring; drive Forfatterskolen, er &aring; f&aring; f&oslash;lge forfattere over tid. &Aring; se en id&eacute; bli til tekst. &Aring; se tekst bli til retning. Og til slutt: Se en bok bli virkelig, finne sin form &ndash; og finne veien ut til lesere.</p>\r\n<p data-start=\"294\" data-end=\"471\">Derfor er det ekstra g&oslash;y &aring; dele denne nyheten: Tidligere kursdeltaker <strong data-start=\"364\" data-end=\"392\">Hilde Charlotte Blomberg, som </strong><strong>har g&aring;tt p&aring; </strong><strong data-start=\"1408\" data-end=\"1437\">Forfatterskolens diktkurs og romankurs, </strong>er snart aktuell med <strong data-start=\"414\" data-end=\"431\">sin andre bok p&aring; Cappelen Damm. Forrige bok var en diktsamling (\"Min prikkete s&oslash;ster\"), mens denne boken er en roman.&nbsp;</strong></p>\r\n<p data-start=\"473\" data-end=\"932\"><strong data-start=\"487\" data-end=\"544\">&laquo;Jeg lengter etter skipskatastrofer og plutselig d&oslash;d&raquo;</strong>&nbsp;beskrives som b&aring;de poetisk og realistisk &ndash; rystende, men ogs&aring; forsonende. Hilde Charlotte skriver om hvordan det var &aring; vokse opp som s&aring;kalt ml-unge p&aring; 70-tallet, og om et mor/datter-forhold som setter spor. Moren, Wenche Blomberg, var journalist, filmkritiker, forfatter, forsker og venstreradikal aktivist &ndash; en person som satte sterke avtrykk i samtiden, og i datterens liv.</p>\r\n<p data-start=\"934\" data-end=\"1378\">Etter morens d&oslash;d opps&oslash;ker Hilde Charlotte Wenches private arkiv p&aring; Nasjonalbiblioteket. Der finner hun blant annet dagb&oslash;ker som g&aring;r helt tilbake til 1963. Ukene i arkivet gir henne en ny innsikt &ndash; ikke bare i morens liv og bakgrunn, men i det som l&aring; mellom dem. N&aring;r en forelder forsvinner, kan det f&oslash;les som om alt blir endelig. Men noen ganger &aring;pner sorgen ogs&aring; for et nytt blikk. En ny forst&aring;else. En annen sannhet enn den man vokste opp med.</p>\r\n<p data-start=\"1698\" data-end=\"1770\">Vi heier stort p&aring; Hilde Charlotte, og gleder oss til &aring; f&oslash;lge forfatterreisen hennes videre!</p>\r\n<p data-start=\"1772\" data-end=\"1822\">Du kan bestille den nye boken hennes her:</p>\r\n<p data-start=\"1772\" data-end=\"1822\"><a href=\"https://www.cappelendamm.no/boker/jeg-lengter-etter-skipskatastrofer-og-plutselig-dod-hilde-charlotte-blomberg-9788202899325\">Jeg lengter etter skipskatastrofer og plutselig d&oslash;d av Hilde Charlotte Blomberg (Cappelen Damm)</a></p>','/storage/blog/1765320056.png','Hilde Charlotte Blomberg','/storage/blog/author/1765320056.png',1,'2025-12-09','2025-12-09 22:40:56','2025-12-09 22:40:56'),(65,12,'Fra flukt til roman','<p data-end=\"405\" data-start=\"83\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important; color: rgb(4, 4, 4) !important;\">Da Anita Miric (56) flyktet fra borgerkrigen i det tidligere Jugoslavia, ante hun ikke at hun tre tiår senere skulle stå med sin egen roman i hendene. I dag bor hun i Sandefjord, jobber som tolk, og driver sitt eget forlag – MIR forlag. Navnet betyr «fred» på serbokroatisk, og nettopp fred er essensen i hennes debutbok.</span></p>\n<h3 data-end=\"405\" data-start=\"83\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Flyktet fra krigen</span></span></h3>\n<p data-end=\"669\" data-start=\"407\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">– Jeg kom til Norge som 24-åring i 1993, på flukt fra krigen. Som barn elsket jeg å skrive dagbok, men vokste opp med en streng og konservativ far. Det var lite rom for å snakke fritt. Dagboken ble min venn, et sted der jeg kunne uttrykke meg, forteller Anita.</span></span></p>\n<p data-end=\"1041\" data-start=\"671\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Hun skrev de første sidene av boken allerede i 2013, men la prosjektet på is – språket satt ikke ennå. Først under pandemien tok hun opp tråden igjen, etter å ha oppdaget en liten lapp på en dør i Sandefjord: «Vil du forbedre skriveferdighetene dine?» Noen dager senere satt hun i et kursrom sammen med sju andre – og begynte på det som skulle bli hennes første roman.</span></span></p>\n<h3 data-end=\"1041\" data-start=\"671\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">En reise i språk og identitet</span></span></h3>\n<p data-end=\"1204\" data-start=\"1043\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">– Jeg begynte å skrive på norsk for å lære språket bedre, men etter hvert ble det mye mer enn det. Skrivingen ble en reise i språk og identitet, sier hun.</span></span></p>\n<p data-end=\"1432\" data-start=\"1206\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Romanen, som er basert på virkelige hendelser, forteller historien om flukten fra Mostar til Kroatia – mens mannen og faren ble igjen i den beleirede byen. Den er skrevet som skjønnlitteratur, men med en dokumentarisk nerve.</span></span></p>\n<p data-end=\"1760\" data-start=\"1434\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Arbeidet med manuset var alt annet enn enkelt.</span></span></p>\n<p data-end=\"1760\" data-start=\"1434\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">– Jeg skrev først i jeg-form, men fikk råd om å bytte til tredje person for å få mer frihet i fortellingen. Senere måtte jeg legge til et nytt perspektiv – fra mannen min, Sebastian. Da knakk jeg helt sammen. Men jeg gjorde det, og det ble det mest lærerike i hele prosessen.</span></span></p>\n<h3 data-end=\"1760\" data-start=\"1434\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Stiftet eget forlag</span></span></h3>\n<p data-end=\"1914\" data-start=\"1762\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Deretter ble det eks–sju runder med redigering før boken endelig gikk i trykken. Hun valgte å gi den ut selv – og stiftet sitt eget forlag.</span></span></p>\n<p data-end=\"2062\" data-start=\"1916\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">– Å holde boken i hendene var som å ha gått gjennom en lang svangerskapstid. Jeg var kvalm, sliten, nervøs – men til slutt bare lykkelig og stolt.</span></span></p>\n<p data-end=\"2261\" data-start=\"2064\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Mottakelsen har vært overveldende. Forhåndsbestillingene kom inn før lansering, og hun har allerede vært invitert til å holde foredrag om boken, også for samfunnsfagselever på videregående skole.</span></span></p>\n<h3 data-end=\"2380\" data-start=\"2263\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">I gang med oppfølger</span></span></h3>\n<p data-end=\"2380\" data-start=\"2263\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">– Jeg er i gang med en oppfølger, forteller hun. – Og jeg fortsetter å skrive dikt, både på norsk og serbokroatisk.</span></span></p>\n<p data-end=\"2541\" data-start=\"2382\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Om samarbeidet med Forfatterskolen er hun tydelig:</span></span></p>\n<p data-end=\"2541\" data-start=\"2382\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">– Jeg hadde ikke kommet hit uten dem. Jeg fikk støtte hele veien, og hadde en fantastisk redaktør i Silje.</span></span></p>\n<p data-end=\"2771\" data-start=\"2543\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">Hva hun vil si til andre som drømmer om å skrive?</span></span></p>\n<p data-end=\"2771\" data-start=\"2543\"><span style=\"color: rgb(4, 4, 4) !important;\"><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important;\">– Stå på! Hvis jeg, som lærte norsk i voksen alder, kan skrive og gi ut bok, kan alle med vilje og tro på seg selv klare det. Alt begynner med ønsket – og troen på at du <em>kan</em>.</span></span></p>\n<p data-end=\"2771\" data-start=\"2543\" style=\"\"><em><span style=\"--tcb-applied-color: rgb(4, 4, 4) !important; color: rgb(4, 4, 4) !important;\">Vi gratulerer Anita så mye med spennende og viktig bok – og heier på skrivingen hennes videre!</span></em></p>\n','blog-images/fra-flukt-til-roman.png','Forfatterskolen',NULL,1,NULL,'2025-11-12 00:49:21','2026-03-27 08:36:54'),(66,12,'Fra rettssal til roman','<p data-end=\"474\" data-start=\"82\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important; color: rgb(8, 8, 8) !important;\">Kristin Juliussen, en av Forfatterskolens elever, har tatt steget fra skrivekurs til å bli antatt på Norges største forlag. I vår debuterte hun med rettssalsdramaet <em data-end=\"273\" data-start=\"252\">Enhver rimelig tvil</em> på Gyldendal – en roman som raskt ble plukket opp av de største bokhandlerkjedene og har fått mange positive reaksjoner fra leserne. Vi har tatt en prat med Kristin om skriveprosessen, debuten og veien videre.</span></p>\n<p data-end=\"316\" data-start=\"185\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"217\" data-start=\"185\">Fortell litt om deg selv!</strong>Jeg heter Kristin Juliussen, er 60 år og bor og jobber i Oslo. Jeg er utdannet jurist (advokat).</span></span></p>\n<p data-end=\"676\" data-start=\"318\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"420\" data-start=\"318\">Har du alltid hatt en forfatterdrøm, eller hvordan kom skrivingen til?</strong>Jeg begynte å skrive for omtrent seks år siden. Jeg har ikke hatt noen forfatterdrøm tidligere, men jeg har alltid hatt en kreativ side som jeg har ønsket å utvikle. Å skrive fiksjon er for meg en perfekt måte å kombinere kreativt arbeid med håndverk.</span></span></p>\n<p data-end=\"1047\" data-start=\"678\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"728\" data-start=\"678\">Hva slags sjanger skriver du i, og hvorfor?</strong>Jeg har prøvd meg litt frem, og oppdaget at jeg liker dramaturgi og plotting. Som advokat har jeg dessuten alltid interessert meg for det som skjer i rettssalen, der enkeltmennesket møter rettssystemet på godt og vondt. Rettsdramaet, hvis det kan kalles en sjanger, er et sted der jeg føler meg hjemme.</span></span></p>\n<p data-end=\"1435\" data-start=\"1049\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"1129\" data-start=\"1049\">Hva er din motivasjon i skrivingen? </strong>Jeg liker å skrive om ting som opptar meg, og det er motivasjon i seg selv. Jeg har skrevet flere manus som er blitt refusert, og det var forferdelig kjipt der og da, men det hører med. Den største oppturen var å oppdage at jeg kunne bruke jobberfaringer og temaer som interesserer meg, i romanform.</span></span></p>\n<p data-end=\"1787\" data-start=\"1437\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"1482\" data-start=\"1437\">Hva slags bok har du skrevet? </strong>&#8220;Enhver rimelig tvil&#8221; (Gyldendal) er et rettssalsdrama, sett og opplevd fra den tiltaltes ståsted. Hovedpersonen, Birgit, er en kvinnelig tannlege som står tiltalt for å ha drept sønnen sin, en profilert eiendomsmegler. Til å forsvare seg har hun en venninne som er advokat og som nå får bryne seg på sin første drapssak.</span></span></p>\n<p data-end=\"2154\" data-start=\"1789\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\">I rettssalen blir Birgits privatliv brettet ut, og hun føler at advokaten kjører sitt eget løp, lite lydhør for Birgits meninger. I desperasjon prøver hun på ulike måter å ta styringen over advokaten, men det er vanskeligere enn hun hadde trodd. I retten gjelder regler hun verken forstår eller kan godta, og nå er skjebnen hennes lagt i andres hender.</span></span></p>\n<p data-end=\"2188\" data-start=\"2156\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\">Handlingen reiser to spørsmål:</span></span></p>\n<ol data-end=\"2283\" data-start=\"2189\">\n<li data-end=\"2245\" data-start=\"2189\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\">Blir hun frikjent eller dømt til mange års fengsel?</span></span></li>\n<li data-end=\"2283\" data-start=\"2246\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\">Er hun faktisk skyldig i drapet?</span></span></li>\n</ol>\n<p data-end=\"2283\" data-start=\"2249\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\">Med romanen har jeg ønsket å vise hvordan et ganske ordinært menneske kan oppleve møtet med rettssalen når «hele livet» står på spill.</span></span></p>\n<p data-end=\"2781\" data-start=\"2534\" style=\"\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"2597\" data-start=\"2534\">Hvordan var det å sitte med sin egen bok mellom hendene?</strong>Det var mest av alt uvirkelig, og veldig stas. Jeg er også svært fornøyd med omslaget, som jeg selv har hatt lite med å gjøre, men som fanger tematikken i boken på en super måte.</span></span></p>\n<p data-end=\"3229\" data-start=\"2783\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"2855\" data-start=\"2783\">Hvordan har mottakelsen vært, og hva er planene videre for boken?</strong>Boken ble kjøpt inn av de store bokhandlerkjedene, og den ene kjeden bestilte 1500 eksemplarer og ga den ekstra god eksponering. Gjennom sommeren har jeg fått mange e-poster og meldinger fra lesere som likte boken veldig godt. Det setter jeg stor pris på. Ellers føler jeg at debutromanen nå lever sitt eget liv, og at det er på tide for meg å gå videre til neste roman.</span></span></p>\n<p data-end=\"3412\" data-start=\"3231\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"3297\" data-start=\"3231\">Har du drømmer, eller en konkret plan, for videre skriving?</strong>Jeg er i gang med førsteutkastet av neste roman og har brukt sommeren til å tenke gjennom karakterer og plott.</span></span></p>\n<p data-end=\"3715\" data-start=\"3414\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\"><strong data-end=\"3481\" data-start=\"3414\">Hvordan var det å samarbeide med Forfatterskolen?</strong>Jeg har tatt flere kurs gjennom Forfatterskolen, blant annet romankurset, og fulgt mandagswebinarene (mentormøtene). Det er alltid noe nytt å lære.</span></span></p>\n<p data-end=\"3715\" data-start=\"3414\"><span style=\"color: rgb(8, 8, 8) !important;\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important;\">Særlig viktig for meg har det vært å få tilbakemelding på manus fra Forfatterskolens redaktører. Å få et kyndig blikk på hva som kan gjøres bedre, hever kvaliteten og mulighetene for å få manuset antatt hos et forlag. Det har også vært viktig for selvtilliten å få tilbakemelding på det som allerede fungerer i teksten.</span></span></p>\n<p data-end=\"4173\" data-start=\"3948\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important; color: rgb(8, 8, 8) !important;\"><strong data-end=\"4013\" data-start=\"3948\">Hva er ditt råd til andre som drømmer om å bli forfatter?</strong>Basert på egne erfaringer må det bli følgende: Lær håndverket, invester i tilbakemeldinger på teksten fra folk som kan faget, og fremfor alt – ikke gi opp!</span></p>\n<p data-end=\"4173\" data-start=\"3948\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important; color: rgb(8, 8, 8) !important;\">Her kan du bestille Kristins bok: </span></p>\n<p data-end=\"4173\" data-start=\"3948\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important; color: rgb(8, 8, 8) !important;\">&#8220;Enhver rimelig tvil&#8221; (<a href=\"https://www.norli.no/boker/skjonnlitteratur/romaner/enhver-rimelig-tvil-9788205615663?gad_source=1&#038;gad_campaignid=17415636636&#038;gbraid=0AAAAADsxdPCfYw8kKfJ4gU3npQU4yApKe&#038;gclid=CjwKCAjw_fnFBhB0EiwAH_MfZp_dc3pSRXkyN-yMUPtht3B7rwao6CPAOqi2kgByLg0aYZzFdFRfkRoCmkAQAvD_BwE\" target=\"_blank\" style=\"outline: none;\">Enhver rimelig tvil (</a>Gyldendal) </span></p>\n<p><span></span></p>\n<p data-end=\"4173\" data-start=\"3948\"><span style=\"--tcb-applied-color: rgb(8, 8, 8) !important; color: rgb(8, 8, 8) !important;\"></span></p>\n<p></p>\n','blog-images/fra-rettssal-til-roman.jpg','Forfatterskolen',NULL,1,NULL,'2025-09-08 10:26:51','2026-03-27 08:48:34'),(67,12,'Dømt til å mislykkes – men nektet å gi opp','<h2 data-end=\"170\" data-start=\"127\"><strong data-end=\"168\" data-start=\"130\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important; color: rgb(17, 18, 18) !important;\">Forfatterskolen feirer ny debutant!</span></strong></h2>\n<p data-end=\"242\" data-start=\"171\"><em><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\"><strong data-end=\"240\" data-start=\"171\">Chris-Helén Echrehaug fra Horten debuterer med sterk selvbiografi.</strong></span></span></em></p>\n<p data-end=\"545\" data-start=\"244\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Forfatterskolen kan stolt presentere sin nyeste, utgitte forfatter: Chris-Helén Echrehaug (35) fra Horten. Til daglig jobber hun som sveiser i en høyteknologibedrift i Tønsberg, mens på fritiden er hun kunstner og skribent. Nå debuterer hun med den gripende boken <em>Dømt til å mislykkes.</em></span></span></p>\n<h2 data-end=\"594\" data-start=\"552\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\"><strong data-end=\"592\" data-start=\"555\">En historie om kamp, tap – og håp</strong></span></span></h2>\n<p data-end=\"837\" data-start=\"595\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Boken tar leseren med på en rå og ærlig reise gjennom en oppvekst preget av fosterhjem, barnevern og tapet av den eneste trygge personen i livet. Den følger også en ungdomstid fylt av flukt, institusjoner og en desperat kamp for å bli sett.</span></span></p>\n<p data-end=\"1150\" data-start=\"839\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Med sårbarhet og styrke skildrer Echrehaug hvordan det er mulig å finne veien tilbake til seg selv, selv når livet føles ødelagt. <em data-end=\"996\" data-start=\"974\">Dømt til å mislykkes</em> er en bok for alle som har kjent på ensomhet, sorg eller manglende håp – og som trenger en påminnelse om at man aldri er ferdig, bare midt i prosessen.</span></span></p>\n<h2 data-end=\"1191\" data-start=\"1157\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\"><strong data-end=\"1189\" data-start=\"1160\">Personlig og inspirerende</strong></span></span></h2>\n<p data-end=\"1407\" data-start=\"1192\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Mye av inspirasjonen til boken kommer fra rollen som mamma til en sønn på snart ti år, som bor i fosterhjem.</span></span></p>\n<p data-end=\"1407\" data-start=\"1192\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">– Vi sees jevnlig, og de stundene sammen er uvurderlige, sier hun. – Men det er også sårt å dra igjen.</span></span></p>\n<p data-end=\"1647\" data-start=\"1409\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Hun forteller at skrivingen alltid har vært en del av livet, fra barndommens dagbøker og kruseduller til tenårenes dikt og sangtekster.</span></span></p>\n<p data-end=\"1647\" data-start=\"1409\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">– Det har vært terapi for meg, og å skrive denne boken har vært en helingsprosess, sier Echrehaug.</span></span></p>\n<p data-end=\"1914\" data-start=\"1686\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">I tillegg til å skrive, maler Echrehaug spirituell, abstrakt kunst, ofte med motiver som dukker opp intuitivt.</span></span></p>\n<p data-end=\"1914\" data-start=\"1686\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">– Jeg føler maleriene mine åpner mennesker for at det finnes mer enn vi kan se med de fem sansene, forteller hun.</span></span></p>\n<h2 data-end=\"1967\" data-start=\"1921\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\"><strong data-end=\"1965\" data-start=\"1924\">Følg lidenskapen!</strong></span></span></h2>\n<p data-end=\"2118\" data-start=\"1968\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Chris-Helén oppfordrer alle med en forfatterdrøm til å satse.</span></span></p>\n<p data-end=\"2118\" data-start=\"1968\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">– Go for it! Følg lidenskapen din og våg å tro på deg selv. Det du har å dele er verdifullt.</span></span></p>\n<p data-end=\"2384\" data-start=\"2165\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Echrehaug roser samarbeidet med Forfatterskolen:</span></span></p>\n<p data-end=\"2384\" data-start=\"2165\"><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">– Jeg har fått konstruktive tilbakemeldinger som både løftet teksten og ga meg selvtillit. Det har vært et utrolig givende samarbeid, spesielt i den siste innspurten.</span></span></p>\n<p data-end=\"2518\" data-start=\"2391\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important; color: rgb(17, 18, 18) !important;\"><em data-end=\"2416\" data-start=\"2394\">Dømt til å mislykkes</em> er nå tilgjengelig i nettbutikk og hos bokhandlere for alle som vil lese. Her er mer informasjon om boken, og mulighet for å bestille:</span></p>\n<p data-end=\"2518\" data-start=\"2391\"><strong><a href=\"https://www.norli.no/forfatter/chris-helen-echrehaug\" target=\"_blank\" style=\"outline: none;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important; color: rgb(17, 18, 18) !important;\">Dømt til å mislykkes av Chris-Helèn Echrehaug</span></a></strong></p>\n<p><span></span></p>\n<p data-end=\"2518\" data-start=\"2391\" style=\"\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important; color: rgb(17, 18, 18) !important;\"></span></p>\n<p></p>\n','blog-images/domt-til-a-mislykkes-men-nektet-a-gi-opp.png','Forfatterskolen',NULL,1,NULL,'2025-08-09 18:16:41','2026-03-27 08:48:34'),(68,12,'Reiseinspirasjonsbok for kvinner','<h3><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">Inspirerer kvinner til å reise alene</span></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Vår tidligere elev, Anita Ness, har nylig gitt ut bok om å reise alene. Vi har bedt henne om å svare på noen spørsmål, som kan inspirere andre til å skrive (og reise alene, selvsagt!).</span></span></p>\n<p style=\"\"><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><em>Hvem er du?</em></span></span></p>\n<p style=\"\"><span style=\"font-weight: normal;\"><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Jeg heter Anita Ness og har alltid skrevet. Jeg elsket å skrive stil på skolen, og puslet med dikt, anmeldelser og korte tekster i ungdomsårene.&nbsp;</span></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Å bli forfatter eller journalist var en drøm jeg hadde tidlig. Jeg tok medialinje på folkehøgskole da jeg var 18 år, og var med i skoleavisa da jeg gikk på videregående. Det ble likevel en annen yrkesvei, med sosiallhøgskole og videreutdanninger.&nbsp;I mesteparten av mitt voksne yrkesliv år har jeg jobbet med ungdom og familier i barnevern, rus og psykisk helsevern.&nbsp;Jeg har også vært noe frilanser, hatt bok- og reiseblogg siden 2006, skrevet et lass med dagbøker og noen påbegynte romaner som jeg ikke greide å fullføre.&nbsp;</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Å skrive bok har vært drømmen som aldri forlot meg.&nbsp; Jeg har også ønsket å reise mer. I de siste årene, der jeg har vært fri til å styre tiden min selv, fikk jeg mer tid og råd til begge deler.&nbsp;</span></span></p>\n<p><strong><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><em>Fortell litt om din egen bok – hva den handler om og hva som fikk deg til å skrive den.</em></span></span></strong></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">&#8220;Reis Alene&#8221; er en inspirerende sakprosabok for voksne kvinner som drømmer om å reise alene, men ikke tør. Eller for de som har reist litt, men ønsker å strekke seg lenger.&nbsp;&nbsp;Den inneholder praktiske tips, hvordan man skritt for skritt kan overvinne hindringer og sperrer, eksempler og reiseskildringer.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Gjennom årene har&nbsp;jeg fått mange tilbakemeldinger fra damer som følger meg på sosiale medier og i bloggen, der de sier at de ønsker å gjøre det jeg gjør, men ikke tør. Det var det som ga meg ideen til å skrive denne boka.&nbsp;</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Det er over 1 million aleneboende i Norge. Blant disse er det mange som ikke tør å reise dit de ønsker fordi de ikke har noen å dra sammen med. Det vil jeg bidra til å endre. Å reise alene, om det så er til nærmeste by, eller på fjellet, eller en tur på kafé, gir mye frihet og mestring.&nbsp;Kan jeg, kan de!</span></span></p>\n<p><strong><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><em>Fortell litt om skriveprosessen rundt boka.</em></span></span></strong></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Jeg begynte å skrive ned ideer og en disposisjon. Det tok meg noen måneder å skrive et råmanus – men den store jobben begynte med redigeringen. For å få hjelp til fremdriften, søkte jeg på&nbsp;<em>Påbygg</em>&nbsp;på Forfatterskolen i 2024, og fikk plass. Jeg fikk god redaktørhjelp under hele prosessen. Det gikk opp og ned med motivasjonen, så det å ha frister og en fast redaktør hjalp meg til å komme i mål. Etter noen runder med forlag og avslag, bestemte jeg meg for å publisere selv og kjøpte de profesjonelle tjenestene.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><em>Hva slags kurs tok du hos Forfatterskolen, og hvordan har vi hjulpet deg på veien til utgivelse?</em></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Jeg begynte med&nbsp;<em>Romankurset</em>&nbsp;i 2021. Så vant jeg&nbsp;<em>Barnebokkurset</em>&nbsp;til Gro Dahle i en trekning, og jeg tok&nbsp;<em>Krimkurset</em>&nbsp;til Tom Egeland. Jeg tok også Forfatterskolens kurs i markedsføring, et sansekurs og flere andre kurs som jeg fikk tilgang på gjennom året på&nbsp;<em>Påbygg</em>.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Jeg har lært mye av kursene og mentormøtene. Påbygg har vært det viktigste fordi redaktøren og opplegget der faktisk hjalp meg til å komme i mål med et ferdig manus.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><em>Har du noen tips til andre aspirerende forfattere?</em></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Ikke gi opp! Å skrive bok er en berg– og dalbane-prosess. Vit at det tar tid. Fortsett å skrive. Det er så altfor lett å prokastinere med alt mulig annet!</span></span></p>\n<h3><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Her kan du bestille &#8220;Reis alene&#8221; av Anita Ness:</span></span></h3>\n<p><a href=\"https://www.ark.no/produkt/boker/hobbyboker-og-fritid/reis-alene-9788293873815\" target=\"_blank\"><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Reis alene</span></span></a></p>\n<p><span></span></p>\n<p><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">​</span></p>\n<p></p>\n','blog-images/reiseinspirasjonsbok-for-kvinner.png','Forfatterskolen',NULL,1,NULL,'2025-07-16 15:29:59','2026-03-27 08:48:34'),(69,12,'Rørende fortelling om farlige ulver ','<h1 style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Rørende fortelling om farlige ulver</h1>\n<p style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Vår nyeste utgitte elev heter Nina Marie Olsen, og er en 43 år gammel ettbarnsmor fra Fredrikstad. Til daglig jobber hun innenfor rus og psykiatri, og har en variert utdanning innen helse. Nå har hun skrevet en roman: &#8220;De farlige ulvenes verden&#8221;. Nå vil hun gjerne dele noen ord om sin egen forfatterreise.</p>\n<h3 style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Om familiebånd og den moderne verden</h3>\n<p style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Skrivingen begynte tidlig i tyveårene, og drømmen har vært å se mitt eget navn i bokhylla på biblioteket. I 2024 tok jeg et kurs hos Forfatterskolen, der jeg lærte meg noen gode skrivemetoder. Å våge å drømme om å bli forfatter satt langt inne, men nå er jeg her!</p>\n<p style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Min første utgitte bok er i feelgood-sjangeren. «De farlige ulvenes verden» er en roman som jeg håper vil vekke mange følelser hos leseren. Det er en rørende fortelling om familiebånd og kjærlighet, der jeg også forsøker å belyse et annet syn på den moderne verden.</p>\n<h3 style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Berg- og dalbane-prosess</h3>\n<p style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Å skrive et manus er en berg og dalbane-prosess. Da har det vært fantastisk å få hjelp og oppfølging av Indiemoon og Forfatterskolen. De har vært der hele veien, og spart meg for mye usikkerhet og frustrasjon. Jeg fått god veiledning, råd og støtte. Årskurset, som jeg har tatt hos Forfatterskolen, var verdt hver eneste krone, og anbefales for alle som drømmer om å gi ut en bok.</p>\n<p style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Nå sitter jeg med min egen bok i hendene, og det føles surrealistisk. Det er mange som venter på at salget skal starte, og jeg har fått flere forhåndsbestillinger.</p>\n<p style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Hvis du drømmer om å gi ut en bok – bare skriv! Blås i om du får avslag hos de store forlagene. Du kan få hjelp til utgivelse, og gjøre boken like bra uten et stort forlag i ryggen. Be om hjelp fra profesjonelle, og ha troen på deg selv.</p>\n<h3 style=\"color: rgb(10, 10, 10) !important; --tcb-applied-color: rgb(10, 10, 10) !important;\">Litt om boken:</h3>\n<p><span style=\"--tcb-applied-color: rgb(14, 14, 14) !important; color: rgb(14, 14, 14) !important;\">Peace har alltid levd et fredelig liv, skjult bort fra verden dypt inne i skogene i Telemark. Her, under den store eiken og omgitt av naturens mystikk, lærte foreldrene henne å elske livet uten å frykte døden eller verden utenfor. Men en skjult hemmelighet og morens sykdom tvinger henne ut av skogens trygge favn og inn i en virkelighet hun ikke kjenner.</span></p>\n<p><span style=\"color: rgb(14, 14, 14) !important;\"><span style=\"--tcb-applied-color: rgb(14, 14, 14) !important;\">Nå må Peace møte de «farlige ulvene» foreldrene advarte henne mot. Verden utenfor er både vakker og brutal, fylt av mennesker og sannheter som utfordrer alt hun har lært. Når hun oppdager en eske med gamle fotografier og minner, begynner en reise som vil endre henne for alltid. Hva er det foreldrene har holdt skjult, og hvem er egentlig de farlige ulvene?</span></span></p>\n<p><strong><span style=\"--tcb-applied-color: rgb(14, 14, 14) !important; color: rgb(14, 14, 14) !important;\">«De farlige ulvenes verden» er en sterk fortelling om tap, kjærlighet og mot til å oppdage hvem man er når tryggheten forsvinner. En bok som vil røre, utfordre og inspirere deg til å se verden med nye øyne.</span></strong></p>\n<p><span style=\"--tcb-applied-color: rgb(14, 14, 14) !important; color: rgb(14, 14, 14) !important;\">Gratulerer så mye med boken, Nina Maria. Vi er så stolte av deg!</span></p>\n<p><span style=\"--tcb-applied-color: rgb(14, 14, 14) !important; color: rgb(14, 14, 14) !important;\">Her kan du lese mer om boken, og skaffe deg et eksemplar:&nbsp;</span></p>\n<p><a href=\"https://shop.indiemoon.no/product/de-farlige-ulvenes-verden/\" target=\"_blank\" style=\"outline: none;\"><span style=\"--tcb-applied-color: rgb(14, 14, 14) !important; color: rgb(14, 14, 14) !important;\">De farlige ulvenes verden</span></a></p>\n<p><span></span></p>\n<p style=\"\">\n<p></p>\n','blog-images/rorende-fortelling-om-farlige-ulver.png','Forfatterskolen',NULL,1,NULL,'2025-06-22 06:21:19','2026-03-27 08:48:34'),(70,4,'Å følge nye veier – fra forsker til forfatter','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-64b560cf94a808a4be967f4a8d9d34db\" style=\"color:#c01a75\">Portrettintervju med tidligere elev</h2>\n\n\n\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-5c335ebe968adcf4215a15c5eb1a4f1e\" style=\"color:#c01a75\">Ragnhild Solheim</h2>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large\"></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Ragnhild Solheim</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>Hjerterom</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på Lyrikkforlaget i 2025</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Sjanger: Dikt </p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Debutanten Ragnhild Solheim (f. 1959) er en glad person som trives med å gå nye veier, prøve nytt og lære nytt.</strong></p>\n\n\n\n<p>Jeg har vært forsker og har hatt en yrkeskarriere som leder, og nå utforsker jeg nye sider av livet. Jeg har alltid likt å skrive. Da jeg valgte å gå av med pensjon hadde jeg en liten plan om å teste ut hva pennen ville fortelle. Jeg er nysgjerrig på forholdet mellom oss mennesker, og jeg synes det er spennende å forstå hvorfor folk tenker og reagerer forskjellig.</p>\n\n\n\n<p><strong>Solheim trodde først hun kom til å skrive noveller, men veien hennes ble en annen. Det var dikt hun endte opp med.</strong></p>\n\n\n\n<p>Jeg skrev egentlig bare for å skrive, men jeg erfarte snart at jeg hadde lyst å skrive mer. Da var veien til å lære om skrivekunsten kort. Jeg hadde ingen plan om å gi ut bok eller bli forfatter. Men, etter å ha fått konstruktive tilbakemeldinger fra Forfatterskolen, tenkte jeg at «kanskje jeg skal prøve meg på en diktsamling». Jeg skjønte at jeg måtte finne ut mer om hva det innebar, og satte i gang med å lese mer dikt, lytte og sjekke, ja, du vet – lære om alt fra hvordan en diktsamling kan se ut: hvor mange dikt en bør ha, hva gjør de anerkjente, hvem kan inspirere, hvordan er utgivelsesprosessen og hvordan markedsføre boka.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large\"></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-d5fbbd65f2fa45d6b3cfd08191410963\" style=\"color:#c01a75;font-size:29px\">Kurs Ragnhild Solheim tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/course/57\">Diktkurs med Gro Dahle</a></p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/shop-manuscript\">Manusutvikling</a></p>\n\n\n\n<p>Jeg startet med å sende inn et par dikt for kommentarer, så fulgte jeg Gro Dahles svært nyttige diktkurs (flere ganger) og alt annet jeg kunne komme over som hadde med dikt å gjøre. Jeg har deltatt på webinarer med redigering på direkten, og jeg har vært en svamp for alt om tekst, ord, dikt og lyrikk!</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-873ba9c4cd2ea6aaba381773fbe801fc is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om <em>Hjerterom</em></summary>\n<p>Diktene skildrer hverdagsøyeblikk, og de beskriver følelser og inntrykk fra ulike situasjoner i flere av livets faser. Noen dikt handler om å gi plass til seg selv, å stole på seg selv og å være stolt av seg selv. Andre dikt handler om gleden og kjærligheten i og til hverdagens hendelser. Andre igjen handler om tap og det å føle seg alene.</p>\n\n\n\n<p>Jeg har forsøkt å samle dikt som skildrer stemninger og følelser, å ha en lett tone, men også et preg av alvor. I arbeidet har jeg kjent at det er befriende å sette ord på opplevelser, og det har vært spennende å utfordre meg selv med noe jeg aldri har gjort før.</p>\n\n\n\n<p> </p>\n</details>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-pullquote has-text-align-center\" style=\"font-size:7px\"><blockquote><p><strong>Se og høre</strong><br> <br>hårtørreren bråkte voldsomt<br>du kunne ikke høre orda mine<br>men du kunne se<br>hva som rørte seg i meg<br>selv om du ikke alltid hører meg<br>selv når hårtørreren ikke er i bruk<br> <br></p><cite><br>Hjerterom, side 29</cite></blockquote></figure>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Skriv! Finn din sjanger, hold på det som er din idé og ditt særpreg. Lær så mye som mulig, sett deg inn i bransjen, språklige muligheter, skriveteknikk, alt du klarer. Men pass på at du fortsetter å skrive – det er jo det som er nerven. Bruk mot.</p>\n\n\n\n<p><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Det er noe i skuffen og pennen nekter å gi seg. Dette er jo gøy. Tida får vise hva det blir – jeg øver meg på å være tålmodig med meg selv. Stoffet og jeg trenger modningstid før jeg kan utvikle det videre.</p>\n','blog-images/a-folge-nye-veier-fra-forsker-til-forfatter.jpg','Forfatterskolen',NULL,1,NULL,'2025-05-14 10:37:08','2026-03-27 08:48:34'),(71,4,'Helenas metode: Veien til indre ro','<p><span></span></p>\n<p><strong><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important; color: rgb(18, 18, 18) !important;\">Fortell litt om deg selv!</span></strong></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Jeg er født og oppvokst i Sandnessjøen, har master i kjemi og jobber som lærer ved Sandnessjøen videregående skole. Jeg er gift og har to voksne barn. Jeg har tatt coachingutdannelse, og er også MOT-coach. Jeg liker å lese, skrive, lytte til musikk, være i naturen, ha dype samtaler og formidle alt om mental friskhet.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Når begynte du å skrive? Har du alltid hatt en forfatterdrøm, eller hvordan kom skrivingen til?</strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Jeg elsket å skrive stil – dikte opp historier i novelleform på barne- og ungdomsskolen. Vi var tre venninner som hadde en skriveklubb som het «Crazy girls», der vi skrev en bok med romantiske oppdiktede historier.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Jeg har alltid likt å skrive, og har skrevet mange dikt og taler som jeg har fremført i bursdager, bryllup og konfirmasjoner.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Å bli forfatter har alltid vært en drøm!</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Hva slags sjanger skriver du i, og hvorfor?</strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Akkurat nå skriver jeg lyrikk. Jeg har alltid likt rim og rytme, det får frem budskapet på en kortfattet og finurlig måte.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Hva er din motivasjon i skrivingen? </strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Jeg har periodevis slitt med depresjon, men er nå helt frisk. Jeg er opptatt av å formidle alt jeg kan om mental friskhet, og ønsker å hjelpe andre til å få mer indre ro.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Hva slags bok har du skrevet? </strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Jeg har skrevet en bok som heter <em>Veien til indre ro. D</em>er deler jeg innsikt som har gjort at jeg er kvitt 80-90 prosent av mitt tidligere tankekjør. Innsikten deles i form av korte historier, dikt og spørsmål til ettertanke. Det er også satt av plass til å skrive egne refleksjoner rundt ulike temaer.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Dette er ikke en oppskriftsbok, men en refleksjonsbok som kan hjelpe deg på <em>din</em> vei til indre ro.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Har du gitt ut boken selv, eller gjennom et forlag?</strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Jeg har gitt ut boken ved hjelp av <em>Tekst forlag.</em></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Hvordan var det å sitte med sin egen bok mellom hendene?</strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Det var veldig emosjonelt å sitte med sin egen bok mellom hendene. Boken er så fin, som et lite smykke!</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Det har fortsatt ikke gått helt opp for meg at boken har kommet ut.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Hvordan har mottakelsen vært, og hva er planene videre for boken?</strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Mottakelsen har vært formidabel. Jeg forhåndssolgte 170 bøker, og bestemte meg derfor for å kjøpe inn 300 bøker selv. Boken er lettlest, og jeg fikk positive tilbakemeldinger på <em>messenger</em> dagen etter at folk hadde mottatt boken. Jeg har fått omtrent 80 positive tilbakemeldinger på boken, der en av dem er slik: «Hei, Helena! For en fantastisk bok du har skrevet. Kan jeg bestille et par til? Jeg skal gi den i gave».</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Mange som har lest boken, har kjøpt flere bøker for å gi i gave. En person har kjøpt hele seks bøker. I tillegg har jeg blitt intervjuet av lokalavisen, holdt et foredrag for en revmatikerforening, og nå skal jeg snart ha foredrag på et bibliotek. Jeg håper på flere oppdrag med foredrag om indre ro.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Har du drømmer, eller en konkret plan, for videre skriving?</strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Ja, jeg kommer til å skrive mye mer. Nå ønsker jeg å skrive noveller.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Hvordan var det å samarbeide med Forfatterskolen?</strong></span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Det var fantastisk å samarbeide med Forfatterskolen. Jeg bestemte meg for å delta på så mange webinarer jeg kunne, og lytte til rådene jeg fikk på årskurset. Det var skummelt å la andre lese og vurdere tekstene mine, men jeg hadde bestemt meg på forhånd for at jeg skulle dele så mye tekst som mulig. Jeg var veldig fornøyd med alt på Forfatterskolen – rektors redigeringswebinarer, redaktøren min, foredragsholderne, og ikke minst at vi fikk være med i en antologi!</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\">Jeg begynte med en sakprosa, men rektor mente jeg heller burde satse på diktene. Og det var først da jeg sendte inn diktene, at jeg fikk napp hos et forlag.</span></span></p>\n<p><span style=\"color: rgb(18, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important;\"><strong>Hva er ditt råd til andre som drømmer om å bli forfatter?</strong></span></span></p>\n<p><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important; color: rgb(18, 18, 18) !important;\">Våg å la andre lese tekstene dine, og lytt til tilbakemeldingen. Ta til deg råd fra fagfolk. Skriv masse, og bruk mye tid på redigering av egen tekst. Vær tålmodig og ikke gi opp, selv om du får mange avslag fra forlag.</span></p>\n<p><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important; color: rgb(18, 18, 18) !important;\">Trykk her for å komme til boken:&nbsp;</span><a href=\"https://www.norli.no/boker/dokumentar-og-fakta/livssyn-og-selvutvikling/selvutvikling/veien-til-indre-ro-9788284740010\" target=\"_blank\" style=\"outline: none;\"><span style=\"--tcb-applied-color: rgb(18, 18, 18) !important; color: rgb(18, 18, 18) !important;\">Veien til indre ro</span></a></p>\n<p><span></span></p>\n','blog-images/helenas-metode-indre-ro.jpeg','Forfatterskolen',NULL,1,NULL,'2025-04-30 13:20:49','2026-03-27 08:48:34'),(72,4,'Kunsten å skrive om katter','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-08de8e281264c6fa4452f8d79d2aafe2\" style=\"color:#c01a75\">Portrettintervju med tidligere elev </h2>\n\n\n\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-6389355332145575e3b84bccb6ced3b5\" style=\"color:#c01a75\">Inger Strålberg</h2>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large\"></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Inger Strålberg</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>Kloke Kasper kattepus</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på Bookea i 2025</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Illustrert av Ragnhild Johannesen </p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Barnebok fra 3-9 år</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Inger Strålberg har lenge ønsket å fortelle historien om Kloke Kasper kattepus. Da hun som pensjonist endelig fikk mer tid til å følge skrivedrømmen sin, debuterte hun som barnebokforfatter på eget forlag. Hun forteller:</strong></p>\n\n\n\n<p>Etter et langt yrkesliv med ulike typer jobber, stort sett innen helse- og sosialsektoren, gikk jeg av med pensjon for noen år siden. Selv om jeg likte jobben min godt, nyter jeg pensjonistlivet og det å kunne disponere dagen min helt selv. Nå har jeg endelig både tid og overskudd til andre interesser.&nbsp;</p>\n\n\n\n<p><strong><em>Kloke Kasper kattepus </em>er en bok som passer for barn og voksne i alle aldre som er glad i katter. Strålberg beskriver boken som en illustrert fortelling inndelt i femten kapitler. Som tittelen vedkjenner, er bokens hovedperson en katt. Inspirasjonen til kattene stammer helt tilbake fra forfatterens barndom.</strong></p>\n\n\n\n<p>Kjærligheten til katter har jeg hatt fra tidlig barndom. Hver sommer var vi på besøk hos min familie i Alvdal. Det var nesten alltid kattunger der og jeg elsket å sitte foran peisen med en katt i fanget.</p>\n\n\n\n<p>Boken er i høyeste grad inspirert av katter jeg har kjent, spesielt av en av dem, hvis personlighet jeg håper boken gjenspeiler.</p>\n\n\n\n<p><strong>Det er Strålbergs søster, Ragnhild Johannesen, som har illustrert boken. Men før utgivelsen lå et stort skrivearbeid til grunn.</strong></p>\n\n\n\n<p>Det har vært en lang prosess og underveis har jeg vurdert å gi opp prosjektet.</p>\n\n\n\n<p>Takket være tips fra en god venninne, deltok jeg på et av Forfatterskolens gratis skrivekurs om det å skrive barnebøker, og derfra var veien kort til å melde seg på barnebokkurset med Gro Dahle. Etter kurset kjøpte jeg redaktørbistand gjennom Manusutvikling og forsøkte deretter å få boken antatt på flere forlag uten å lykkes.</p>\n\n\n\n<p>Jeg ville ikke gi meg og begynte derfor å undersøke hvordan jeg kunne gi ut selv. Dette endte med selvutgivelse gjennom Bookea. Boken foreligger nå både som innbundet papirbok, lydbok (jeg har lest inn boken selv) og som ebok. Den kan fås tak i eller bestilles i alle bokhandlere. På noen av nettbokhandlene kan man også lytte til første kapittel av lydboken.</p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large\"></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-3299fd1a70370f3b35abc8e3840025de\" style=\"color:#c01a75;font-size:29px\">Inger Strålbergs vei med Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/course/109\">Barnebokkurs med Gro Dahle</a></p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/shop-manuscript\">Manusutvikling</a></p>\n\n\n\n<p>Barnebokkurset var veldig inspirerende og nyttig for meg. Jeg fikk god undervisning om blant annet oppbygging og redigering, samt mange praktiske skrivetips. Det ga meg inspirasjon og mot til å forsøke å få boken utgitt. Den redaktørbistanden jeg kjøpte etter kurset var også nyttig. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-f3f259cee5551818089e908e95e9617c is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om <em>Kloke Kasper kattepus</em></summary>\n<p>Kloke Kasper kattepus er både en vanlig og en litt uvanlig katt. Han er litt engstelig, liker ikke å slåss, er romantisk, litt poetisk, ganske klok og usedvanlig kosete.</p>\n\n\n\n<p>Boken er skrevet ut fra Kaspers perspektiv og starter med at han ikke kan bli boende hos sine første eiere. Dette gjør ham både fortvilet og redd. Vi følger ham på veien til å finne et nytt hjem og hvordan han har det der, videre i kontakten med vennene sine som han leker med hver dag. Han medvirker til at hans beste venn, Felix, blir reddet ned fra et tak.</p>\n\n\n\n<p>Etter hvert erfarer han at ikke alle andre katter er like fredsommelige som ham selv. Han blir skadet i slåsskamp og må til dyrlegen. En dag møter han frøken Sot og blir veldig forelsket, men det viser seg at det er flere som er opptatt av henne. Kasper erfarer hvordan det er å ha kjærlighetssorg.</p>\n\n\n\n<p>Videre får vi høre om de mange utfordringer han møter i forbindelse med en ferietur til Vestlandet. Det er langt fra fritt for dramatikk der heller og Kasper går gjennom mye før han kommer tilbake til byen.</p>\n\n\n\n<p>Lykkelig over å være tilbake i det kjente og kjære treffer han igjen alle vennene, også frøken Sot.&nbsp;</p>\n</details>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-pullquote has-text-align-left\" style=\"font-size:7px\"><blockquote><p>Det var langt på natt og ganske mørkt. Fra fjorden kjente han<br>lukten av sjø. Det blåste så kraftig at Kasper følte at han kunne<br>bli blåst av gårde selv. Samtidig var han nysgjerrig på å se seg<br>omkring. Han gikk et stykke mot skogkanten. Plutselig kom<br>det to svære hvite fugler stupende ned mot ham. Kasper løp<br>så fort han kunne inn i skogen og gjemte seg under et tre med<br>kraftige greiner. Han var skjelven og pustet fort.<br><br><em>“Hva var det som skjedde? Hva skal jeg gjøre nå?</em><br><em>Jeg kan ikke gå tilbake for da kommer de etter meg</em><br><em>på nytt.”</em><br><br>Han gikk lenger inn i skogen. Han skvatt da han hørte en ukjent<br>lyd i treet over seg.<br></p><cite><br>Kloke Kasper kattepus, side 67</cite></blockquote></figure>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Jeg opplevde det som litt vanskelig å ikke bli antatt av et forlag, men jeg har lært at det er mer vanlig enn det motsatte og at de fleste som skriver har opplevd dette, gjerne flere ganger.&nbsp;</p>\n\n\n\n<p>Men, det å ha en historie man virkelig ønsker å fortelle, kombinert med nok tid og ro til å fullføre prosjektet, har vært avgjørende for meg. Det viste seg at det å være selvutgiver rent økonomisk ikke var så avskrekkende som jeg trodde.&nbsp;</p>\n\n\n\n<p><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Jeg vurderer å skrive en ny bok om Kloke Kasper kattepus. Det er mer stoff å ta av. Samtidig har jeg tenkt litt på andre temaer. Om noe av dette blir noe av er for tidlig å si. Det er så mange ting i livet som er viktige, blant annet å kunne nyte livet her og nå, ta vare på helsen, være åpen for hva som kommer og å være takknemlig for hver dag man får.</p>\n','blog-images/kunsten-a-skrive-om-katter.jpg','Forfatterskolen',NULL,1,NULL,'2025-04-23 14:12:57','2026-03-27 08:48:34'),(73,4,'Livsveiens mysterier','<p><strong><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important; color: rgb(7, 7, 7) !important;\">INTERVJU MED FORFATTER GUNHILD WETTERHUS – BOKAKTUELL MED DIKTSAMLINGEN&nbsp;</span></strong></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Fortell litt om deg selv!</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg heter Gunhild Wetterhus og er 52 år. Jeg er mamma til tre voksne barn, og bor på Lillehammer. Jeg er utdannet sykepleier med videreutdanning i livsstyrketrening og mestringsfremmende kommunikasjon, og er instruktør i mindfulness. Jeg har også, fra yngre dager, en mastergrad i ressursøkonomi og bygdeutvikling. Etter noen år som sykepleier og lokalmatgründer, tok livet en ny retning og de to siste årene har jeg jobbet som guide på forfatterhjemmene til Bjørnstjerne Bjørnson og Sigrid Undset. Men hele tiden har mammarollen vært min viktigste, mest utfordrende og givende oppgave, og i mitt tilfelle har det betydd ekstra omsorgsoppgaver da to av barna har en svært sjelden medfødt sykdom. Akkurat nå jobber jeg med noen prosjekter som ikke er helt klare for publisering enda.<strong> </strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Når begynte du å skrive? Har du alltid hatt en forfatterdrøm, eller hvordan kom skrivingen til?</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg har elsket å dikte historier, først muntlig og deretter skriftlige tekster, så lenge jeg kan huske. Da jeg var liten fikk vi barna en kassettspiller der vi kunne gjøre opptak. Jeg leste inn selvdiktede historier og gjorde intervju med mine søsken. Spørs om jeg sådde en forfatterspire da, for drømmen om å bli forfatter har fulgt meg siden. Senere, da mine barn var små, jobbet jeg litt som frilansjournalist, og det tok meg nok nærmere tanken på å gi ut bok.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>&nbsp;</strong><strong>Hva slags sjanger skriver du i, og hvorfor?</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg skriver mest poesi, men liker også godt å skrive lengre historier. Jeg begynte for alvor å skrive dikt i småbarnsperioden for 20 år siden, av den enkle grunn at jeg hadde liten tid til å skrive. Da fant jeg glede i å bare skrive ned små setninger eller vers som kom opp i hodet. Etterhvert ga det mening å beskrive følelser og opplevelser med så sanne og få ord som mulig. I enhver sterk opplevelse ligger det et dikt, hørte jeg Unni Lindell si. Jeg synes det er givende å formidle dikt med en dypere mening, samt å få til så god rytme som mulig.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Hva er din motivasjon i skrivingen? Og del gjerne noen oppturer og nedturer!</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Min motivasjon er å dykke ned i livets mysterier og beskrive det jeg erfarer så godt jeg kan. Det er nesten umulig å finne eksakte ord som beskriver følelser, men jeg liker utfordringen i å lete etter ordene som ligger nærmest. Noen ganger er dette også frustrerende, av samme grunn. Det var lenge skummelt å la andre lese, så diktene lå i en skuff i mange år. Da jeg startet å dele dikt, forsto jeg at mine ord kunne gi noe til andre også, og nå er det å dele blitt en del av min motivasjon. Det er terapi for meg å skrive, akkurat som det er terapi for andre å lese.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Hva slags bok har du skrevet?&nbsp;</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg har skrevet en diktsamling som heter <em>Livsveiens Mysterium</em>. Diktene handler om å se bakenfor det ytre, der vi kan gjenkjenne noe i oss som er sant. Jeg skriver om å være mamma, det fine og skjøre i annerledeshet, sårbarhet, relasjoner, om å søke naturens visdom. Det er rett og slett en samling vers om livets mysterier – om å gå livsveien uten tildelt kart, for kartet må vi forme selv mens vi går. I mitt liv har det å være mamma til to barn som er annerledes krevd en ekstra innsats i orientering, noe som gjenspeiles i flere av mine dikt. Hvert dikt er illustrert med vakre malerier av kunstmaler Halldis Kjomme Lied, som er fra samme dalføre som meg. Det var spesielt å oppdage hennes malerier, fordi de passet inn i landskapet til mine dikt. Da Haldis sa ja til at jeg kunne bruke bildene, ble jeg kjempeglad. Og jeg var så heldig å få ha boklansering på hennes maleriutstilling under høstutstillingen i Stavern.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Hvordan var det i å gi ut boken selv?</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg ga ut boken selv, med Indiemoon som forlag, noe jeg synes var en veldig god løsning. Ettersom dette er min debutbok er det vanskelig å komme inn hos de store forlagene. Derfor er det en ypperlig mulighet å gi ut selv ved hjelp av Forfatterskolen og Indiemoon. Det som er fint, er at man kan selge bøker selv og få all fortjenesten, i motsetning til at forlagene tar den største biten. Når man gir ut selv har man også mer kontroll over prosessen, og er delaktig i alle avgjørelser. Forfatterskolen og Indiemoon har vært suverene til å hjelpe meg å ta vanskelige valg underveis. Jeg vil anbefale samarbeidet til alle som lurer på hvordan de skal gi ut sin første bok</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Hvordan var det å sitte med sin egen bok mellom hendene?</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg glemmer ikke dagen da jeg hentet pappeskene med bøkene hos Sentraldistribusjonen. Det var mye spenning i forkant, ettersom de akkurat rakk&nbsp; å komme til Norge før boklanseringen. Det var sprøtt, skummelt og ulidelig spennende å løfte lokket av pappesken, og jeg torde nesten ikke åpne boken og se inni. Utenpå synes jeg den var så vakker, og jeg ble kjempefornøyd. Da jeg begynte å bla, og det sank inn at denne boken er <em>min</em>, ble jeg stolt og glad. Jeg la noen bøker utover bordet da jeg kom hjem, og bare så på dem. En drøm jeg hadde hatt i veldig mange år hadde endelig gått i oppfyllelse. Det å sitte blant de vakre maleriene til Haldis og ha min egen boklansering sammen med henne, var også en stor dag for meg.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Hvordan har mottakelsen vært, og hva er planen videre for boken?</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Mottakelsen har vært over all forventning! Folk fra nær og fjern har bestilt signerte bøker, i tillegg til salget hos bokhandlere, og de første to ukene solgte jeg 100 bøker. Bøkene selges også hos en kunstbutikk, og hos en landhandel. Planen videre er å fortsette å reklamere for boken min, og å selge den inn hos flere butikker, i tillegg til å bruke den hvis jeg skal holde kurs i mindfulness.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg har fått så fine kommentarer om at diktene går inn og berører leserne følelsesmessig, fordi de kjenner seg igjen. Diktene forsøker å få frem sårbarheten som ligger i det å være menneske, og det er stort å oppleve at mine ord berører andre på denne måten.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Har du drømmer, eller en konkret plan, for videre skriving?</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Jeg har noen skriveprosjekt som har ligget litt på vent og noen ideer til nye, og noen dikt som jeg har begynt å samle. Neste utgivelse blir kanskje noveller?</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>&nbsp;</strong><strong>Hvordan var det å samarbeide med Forfatterskolenog Indiemoon?</strong></span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\">Det har vært avgjørende for meg som debutant å samarbeide med de profesjonelle, dyktige og positive folkene i Forfatterskolen og Indiemoon. På forhånd var jeg inne på tanken om at jeg ikke trengte redaktør, for jeg følte alt var ferdig, men så feil kunne man ta. Det var et kjempesteg å gå gjennom redaktørprosessen, hvor jeg opplevde at diktene mine ble behandlet med dyp respekt, samtidig som jeg måtte innse at de kunne gjøres bedre. Hun utfordret meg så jeg kjente det i magen i særlig et par eldre tekster som betydde mye for meg, men som egentlig ikke var dikt, med det resultat at de løftet seg til ekte, fine dikt. Det var et stort høydepunkt da jeg fikk tilbake forslag på brekking og design av omslag, og jeg ble nesten slått i bakken over hvor fint det ble. Oppsummert har det vært en berg- og dalbane som har skiftet mellom frykt og mistet tro på meg selv, til begeistring og stolte øyeblikk! Og hele veien har Forfatterskolen holdt tak i meg, noe jeg er svært takknemlig for.</span></span></p>\n<p><span style=\"color: rgb(7, 7, 7) !important;\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important;\"><strong>Hva er ditt råd til andre som drømmer om å bli forfatter?</strong></span></span></p>\n<p><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important; color: rgb(7, 7, 7) !important;\">Hvis det stadig dukker opp en lengsel etter å gi ut egne tekster, er mitt råd å ta små skritt mot målet om å bli forfatter. På veien bør man utfordre seg til å la andre lese, og ta til seg konstruktive tilbakemeldinger. Det er verdt å betale profesjonelle også, slik at man ikke går i de tradisjonelle fellene. Ikke gi opp! En dag sitter du med din egen bok i hånden – drømmen er oppfylt!</span></p>\n<p><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important; color: rgb(7, 7, 7) !important;\">Vil du bestille Gunhilds bok? Her kan du gjøre det:</span></p>\n<p><a href=\"https://www.norli.no/boker/skjonnlitteratur/lyrikk-og-drama/lyrikk/livsveiens-mysterier-9788294111107\" target=\"_blank\"><span style=\"--tcb-applied-color: rgb(7, 7, 7) !important; color: rgb(7, 7, 7) !important;\">Livsveiens mysterier</span></a></p>\n<p><span></span><span style=\"\"></span></p>\n','blog-images/livsveiens-mysterier.jpg','Forfatterskolen',NULL,1,NULL,'2024-12-11 15:27:18','2026-03-27 08:48:34'),(74,4,'Spenning og tålmodighet – veien til ferdig bok!','<p style=\"\">Linda Eloise Pedersen er aktuell med ungdomsromanen <em>Den kvelden vi ble ekte.</em></p>\n<p><span></span><span></span></p>\n<p>Hvem er forfatteren bak boka?</p>\n<p>Jeg bor i Stavanger, er gift og mor til to voksne barn. Jeg er en kreativ sjel, som liker å ha prosjekter å holde på med. Enten det er skriving, sying, musikk, sang, lesing. Og så har jeg hund, og går tur. Jeg er utdannet førskolelærer og spesialpedagog.</p>\n<p>Fortell om boka!</p>\n<p>Mange som skriver har ofte hatt en drøm om å skrive hele livet. Det har ikke jeg. Jeg visste ikke at jeg likte å skrive. Ideen om å skrive bok dukket gradvis opp i 2010 (ja, det er så lenge siden), da jeg måtte slutte i den nye jobben som spesialpedagog, pga. av at helsen ikke tillot det. Og det var grunnen til at jeg fant skrivingen. Kunne jeg bruke utdannelsen min på en annen måte? Og dermed vokste ideen om et spennende plot til en ungdomsbok gradvis frem.</p>\n<p><em>Den kvelden vi ble ekte</em> er en ungdomsroman beregnet for 12-16 år, men jeg vil si den passer like godt for voksne som liker å lese om ungdommer. Boken handler om Elvira som bytter skole midt i tiende klasse. Alt hun vil er å få venner. Men noe er ikke som vanlig på det den nye skolen. Det finnes en hemmelig butikk, og allerede første dagen blir hun utfordret til en ‘challenge’; å få en gutt i klassen til å bli forelsket i henne, og så dumpe han. Det tar ikke lang tid før Elvira vikler seg inn i situasjoner det er vanskelig å komme ut av. Snart er hun omringet av mørke hemmeligheter som gradvis avsløres, både hjemme og på skolen. Den handler også om: en mystisk blogg, å si ja når du mener nei, en kjærlighetshistorie, og du får både alvor og humor underveis.</p>\n<p><em>«Den kvelden vi ble ekte er en fortelling om vennskap, svik og kjærlighet – og om å tørre å stå opp for seg selv.» (sitat fra baksideteksten.)</em></p>\n<p>Fortell litt om skriveprosessen!</p>\n<p>Veien til bok har vært lang og kronglete. Jeg kunne jo ikke noe om å skrive bok, og det ble mye prøving og feiling, med flere avslag, en konsulentuttalelse og noen runder med et forlag, som endte med et nei. Det har vært lange pauser innimellom, pga. livet som skjer. Men skrivingen ble også et kreativt fristed og «et flytsonested», jeg hadde noe å gjøre, jeg hadde et mål.</p>\n<p>&nbsp;&nbsp;&nbsp; I 2018 tok jeg det store krimkurset hos Forfatterskolen, hvor jeg endret hele manuset. Jeg valgte dette kurset fordi jeg ville lære mer om å bygge spenning og driv. Jeg beholdt det opprinnelige hovedplottet, kastet resten, og mikset inn et nytt manus jeg hadde begynt på. Det ble et nytt miljø, mer spenning og mer drama. Jeg hadde to pilotlesere, og sendte en ny versjon tilbake til forlaget jeg hadde kontakt med, men etter noen runder ble det et høflig nei. Veien videre ble å sende til andre forlag, men det ble igjen avslag.&nbsp;</p>\n<p>&nbsp;&nbsp; Så fulgte en lang skrivesperre av ulike grunner, man blir lei, livet skjer, man skriver på noe annet. Men i 2022, tok jeg frem manuset igjen. Et siste forsøk? Og sendte inn til fire nye forlag, og det kom nesten som et sjokk at et forlag ville gi ut boken min. Å jobbe sammen med redaktør har vært veldig inspirerende og lærerikt, og jeg er utrolig takknemlig for det fine samarbeidet, og hjelpen for å få boken ut i verden. Det ble også en aldri så liten utsettelse underveis, manuset trengte å bli kortere. Det kunne kanskje ha føltes litt kjipt, men det var helt rett, og jeg er glad for den ekstra jobben som ble gjort.</p>\n<p>&nbsp;</p>\n<p>Du er tidligere elev hos oss &#8211; har vi hjulpet deg på veien til utgivelse?</p>\n<p>Jeg tok det store krimkurset høsten 2018, fordi jeg hadde lyst å skrive mer spenning. Kurset var en stor hjelp i å bygge opp den nye versjonen av historien. I tillegg var det mange inspirerende webinarer og forfattere å lytte til. Dette er ikke en krimbok, men det er likevel et slags mysterie der, når det dukker opp flere hemmeligheter som avsløres. Å være med på kurs hos forfatterskolen var veldig fint, det ga mestring og det var givende å bli med i et skrivemiljø, og jeg sitter igjen med å ha lært veldig mye om skrivehåndverket, og har fått kontakt med mange andre som skriver.&nbsp;&nbsp;</p>\n<p>&nbsp;</p>\n<p>Har du noen tips til andre aspirerende forfattere?</p>\n<p>Det første er nok å lære mer om skrivehåndverket. Det er ikke gjort i en fei, og alt er en prosess og man må like å være i prosessen, og like å være i det miljøet du skriver om. Du skal tross alt være der ganske lenge. Og det er helt ok og nødvendig å tørre å skrive et dårlig førsteutkast, og redigere mange runder. Pauser fra manuset er også en fin ting, la ting modne og se det i nytt lys. Skriv noe nytt. Går tur, skriv morgensider. En annen ting jeg husker godt fra kurset er: Det er bare de som ikke gir opp, som klarer det, og nå kan jeg jo si at det stemmer. For jeg var flere ganger ganske nært til å gi opp. Hvis jeg skal oppsummere tre ting som har vært viktige for meg i prosessen med å skrive bok: <em>Tålmodighet, tid og ikke minst en indre driv.</em> Og husk, mange bittesmå steg fører også til målet.</p>\n<p>Skriver du på noe nå?</p>\n<p>Ja, jeg har et ferdig manus på en ny ungdomsbok, som snart er klart til å sendes til forlag. Det blir veldig spennende. Og så har jeg noen påbegynte prosjekter, som jeg har lyst til å gjøre ferdig, blant annet noe som kan bli en krimbok for voksne, og en idé til en barnebokserie for mellomskolealder.</p>\n<p><strong>Forfatterskolen gratulerer Linda Eloise med debuten!</strong></p>\n','blog-images/spenning-og-talmodighet-veien-til-ferdig-bok.jpeg','Forfatterskolen',NULL,1,NULL,'2024-05-07 11:42:55','2026-03-27 08:48:34'),(75,4,'Et moderne folkeeventyr','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-08de8e281264c6fa4452f8d79d2aafe2\" style=\"color:#c01a75\">Portrettintervju med tidligere elev </h2>\n\n\n\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-ad4beb266cbac44558a74c7f2723bd5e\" style=\"color:#c01a75\">Øivind Berg</h2>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"><figcaption class=\"wp-element-caption\">Foto: Privat</figcaption></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Øivind Berg</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>De kalte henne Lesben Askepott: Et moderne folkeeventyr</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på Fjorden forlag i 2024</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Tidligere utgivelser: <em>Bor det en jævel i oss alle</em>? (2022)</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>I oppveksten på Ekeberg i Oslo ble Øivind Berg presentert for Asbjørnsen og Moes folkeeventyr gjennom stemningsfulle lesninger fra faren på sengekanten søndag morgen.</strong></p>\n\n\n\n<p>Mange av disse fortellingene handler om Espen Askeladd, en ung mann som &#8220;ville aldri gjøre noe, bare ligge og grave i Aske&#8221;. Men når han endelig bestemmer seg for å søke lykken, viser han vennlighet mot alle han møter, og som belønning får han både kloke råd og gode hjelpere. Til slutt overvinner han alle hindringer på sin vei, vinner prinsessens hånd og halve kongeriket attåt. Moralen er klar: Vær snill og god, så vil lykken smile til deg.</p>\n\n\n\n<p>Problemet er at alle karakterene er hvite, mennene er store og sterke, mens kvinnene kan være alt fra ei gammel kjerring med nesa i en trestubbe, til pesten som kommer til bygda, eller i beste fall ei klok kone som gir råd. Det er til og med en historie der mannen til slutt drukner kjerringa fordi hun er så sta, og vi blir fascinert av at hun, selv etter sin død, flyter mot strømmen. Og hva med prinsessa, den vakreste i landet? Hun blir gitt bort som premie og tvangsgiftet med Askeladden.</p>\n\n\n\n<div style=\"height:71px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full is-resized\"><figcaption class=\"wp-element-caption\">Foto: Fra <em>De kalte henne Lesben Askepott </em>(Privat)</figcaption></figure>\n</div>\n\n\n<div style=\"height:66px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Etter å ha reflektert over mangelen på mangfold i disse folkeeventyrene, bestemte Berg seg for å skrive et nytt, moderne folkeeventyr som var mer i tråd med dagens samfunnsutvikling.</strong></p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-7ba217f2054c11696805a8e0e23a5548\" style=\"color:#c01a75;font-size:29px\">Kurs Øivind Berg tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/course/100\">Romankurs</a></p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/course/99\">Årskurs</a></p>\n\n\n\n<p>Etter å ha skrevet en stund på min første roman gikk alt i stå. Romankurs, tenkte jeg, men etter tre måneder der, forsto jeg at jeg hadde mye å lære. Jeg meldte meg da på årskurset. Uten all hjelp og kunnskap derfra hadde det ikke blitt en bok som har solgt ut opplaget på 500 eksemplarer.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-64ba7f555e61b6a76c45b98144f4df31 is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om <em>De kalte henne Lesben Askepott</em></summary>\n<p>Gullborg er ikke svart eller hvit. Hennes far kom som slave med vikingene fra et tokt i Middelhavet, og hun blir født som et &#8220;uekte barn». Hun vokser seg sterk og vakker. Men da hun avviser frieriet fra selveste odelsgutten på Storgården, gir han henne det nedlatende tilnavnet &#8220;Lesben Askepott&#8221;.</p>\n\n\n\n<p>Vi følger henne på flukten fra storgårdens krigere som blir sendt ut for å drepe henne. Underveis hører hun om en konkurranse ved Soria Moria slott, og bestemmer seg for å delta. Men før hun når fram må hun overvinne store utfordringer i kamper mot hekser og troll. Hennes trofaste følgesvenn, ravnen, sammen med andre gode hjelpere, bidrar til at hun når fram. Ved slottet deltar hun i kappestrider for å vinne prinsessa og halve kongeriket. Men enden på historien er ikke som vi er vant til fra folkeeventyrene.</p>\n\n\n\n<p><strong>Berg forteller om arbeidet i forkant av utgivelse:</strong></p>\n\n\n\n<p>Fortellingen begynte som en historie fra Kong Salomos tid. Jeg blandet inn elementer fra norske folkeeventyr og ble rådet av min redaktør til å velge det ene eller det andre. Det ble da et moderne norsk folkeeventyr.</p>\n\n\n\n<p>På leting etter illustratør traff jeg Christoffer Gundersen på Gründeriet i Sandefjord. Vi ble enige om at han skulle designe bildene ved hjelp av kunstig intelligens. Det resulterte i en prosess der vi satt sammen og finslipte til begge var fornøyd.</p>\n</details>\n\n\n\n<figure class=\"wp-block-pullquote alignright has-text-align-left\"><blockquote><p>Ved det store, brune eikebordet i midten av rommet sto<br>odelsgutten. Han kom henne i møte med et vennlig smil, men da blikkene deres møttes, fikk<br>Gullborg en klump i halsen. Hva vil han meg? tenkte hun. Han vinket tjenestepiken bort med<br>en håndbevegelse. Da døren lukket seg bak henne, tok han begge hendene til Gullborg. Hun<br>prøvde å vri seg løs fra det faste grepet.<br>– Kan du slippe? sa hun.<br>– Nei, aldri om jeg gjør. Du skal bli min hustru, sa han og prøvde å fange blikket<br>hennes, men hun snudde seg bort.<br>– Jeg forstår at du synes det er for godt til å være sant, men jeg mener det, og slik blir<br>det, fortsatte han.<br>– Blir det? Tror du jeg vil?<br>– Du er enda vakrere når du tuller med meg på den måten. Jeg kan forstå at ei jente fra<br>en husmannsplass ikke kommer på å rope ut et rungende «ja, jeg vil!»</p><cite><br><em>De kalte henne Lesben Askepott</em>, side 19</cite></blockquote></figure>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"><figcaption class=\"wp-element-caption\">Foto: Cover <em>De kalte henne Lesben Askepott </em>(Privat)</figcaption></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Ikke tro at det å være flinkt til å skrive er nok. Du har mye å lære.</p>\n\n\n\n<p>Det tar mange uker å få avslag fra et etablert forlag på boka di. Er du unntaket som forlaget vil ha, må du regne med å stå bakerst i køen når det gjelder ressurser til markedsføring.</p>\n\n\n\n<p>Å utgi i eget forlag er dyrt og krevende, men du beholder til gjengjeld det meste av omsetningen selv, samt alle rettigheter. Når boka kommer fra trykkeriet begynner den store jobben: Markedsføring, PR og salg.</p>\n\n\n\n<p>Ikke slutt i jobben for å bli forfatter.</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full is-resized\"><figcaption class=\"wp-element-caption\">Foto: Fra <em>De kalte henne Lesben Askepott </em>(Privat)</figcaption></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Min neste bok er en oppfølger til debutromanen min, der tre sentrale karakterer er med videre. Blant dem protagonisten og antagonisten. Handlingen er lagt til «Spionstaden» Stockholm 1941-45, der alle sider var representert gjennom deres delegasjoner. I tillegg hadde den svenske underrettelsestjenesten hendene fulle med å overvåke nazister, kommunister og allierte.</p>\n\n\n\n<p>Boken blir en spenningsroman basert på virkelige hendelser, noe som krever interessant research-arbeid. Jeg har kommet et stykke på vei, og målet er utgivelse senhøsten 2024.</p>\n','blog-images/et-moderne-folkeeventyr.jpg','Forfatterskolen',NULL,1,NULL,'2024-04-23 09:42:00','2026-03-27 08:48:34'),(76,4,'Å gi en stemme til naturen','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-08de8e281264c6fa4452f8d79d2aafe2\" style=\"color:#c01a75\">Portrettintervju med tidligere elev </h2>\n\n\n\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-38e17c376d9e1f5074b76499828184eb\" style=\"color:#c01a75\">Marina Görtz</h2>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Marina Görtz</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>Naturens helter</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på Spartacus i 2024</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Illustrert av Line Renslebråten</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Sjanger: Barn/ungdom</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Da biologen Marina Görtz begynte å lese om historiske personer som hadde bidratt til glede og kunnskap om naturen, forsto hun raskt at dette var et tema hun ville skrive barnebok om. Hun innså at hun visste lite om enkelte av personene, og på grunn av de fascinerende livene de hadde levd, ønsket hun å spre kunnskapen om disse ut til flere.</strong></p>\n\n\n\n<p>Jeg synes det er interessant å reflektere over hva en naturhelt egentlig er, og ønsket å vise at man kan gi en stemme til naturen på mange forskjellige måter. &nbsp;</p>\n\n\n\n<p><strong>Men arbeidet og skriveprosessen for å komme til en ferdig utgivelse, ble lang:</strong></p>\n\n\n\n<p>Jeg begynte med å lese og samle fakta om mange forskjellige naturhelter. Så valgte jeg ut de som gjorde mest inntrykk på meg og fokuserte på å skrive om dem.&nbsp;</p>\n\n\n\n<p>Jeg skrev flere&nbsp;versjoner og lekte med struktur for å finne ut hva som kunne passe. Til slutt sendte jeg inn en prosjektbeskrivelse og prøvekapitler til flere forlag. Når det gjelder sakprosa ønsker mange forlag å være med og utforme nesten fra starten av, så det kan være&nbsp;greit å tenke på. &nbsp;</p>\n\n\n\n<p>Jeg fikk et positivt svar fra Gyldendal og jobbet med dem i ca. ett år. Der fikk jeg gode tilbakemeldinger som hjalp meg med struktur og tekstlengde. Dessverre ønsket de ikke å gå videre med utgivelsen likevel.&nbsp;</p>\n\n\n\n<p>Men siden jeg allerede hadde jobbet med bokprosjektet så lenge, hadde jeg ikke tenkt å gi opp. Jeg gjorde enda mer research, men denne gangen om hvordan man kan bruke skjønnlitterære verktøy i sakprosa. Jeg skrev om kapitlene flere ganger før&nbsp;jeg igjen sendte inn til forlag. &nbsp;</p>\n\n\n\n<p>Jeg var så heldig at Spartacus forlag var interessert og ønsket å jobbe med meg. De fikk med Line Renslebråten som illustratør, noe jeg syntes var veldig stas, og plutselig ble det bok.  </p>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-cb0b125537d0d60d6b809f63bd6910d2\" style=\"color:#c01a75;font-size:29px\">Kurs Marina Görtz tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/course/17\">Mentormøter</a></p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/course/98\">Barnebokkurs med Gro Dahle</a></p>\n\n\n\n<p>På Forfatterskolen startet jeg med et kurs med mentormøter, som har hjulpet meg med å få en god forståelse for hvordan ting fungerer i forlagsbransjen, samtidig som jeg fikk masse inspirasjon fra forskjellige forfattere. &nbsp;</p>\n\n\n\n<p>Barnebokkurset med Gro Dahle ga meg skriveverktøy som jeg kunne bruke for å gjøre fortellingene om naturheltene mer levende. </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-41a0baa296c1c74aa87ccc4b659c2469 is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om <em>Naturens helter</em></summary>\n<p>Naturens helter er en sakprosabok for barn. I denne boken møter leseren femten kvinner og menn, som på hver sin måte kjemper eller har kjempet for natur og miljø. I hvert kapittel finner man også en aktivitet knyttet til naturhelten. </p>\n</details>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-pullquote has-text-align-center\"><blockquote><p>Vi velger å beskytte det vi elsker, sa Jacques, og mente at hvis folk lærer å elske havet, vil de også beskytte det.</p><cite><em>Naturens helter</em>, side 64</cite></blockquote></figure>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Mitt tips er å tørre å prøve forskjellige måter å skrive på, leke med ord og struktur, og se hva som allerede finnes på markedet. Samt å tørre å sende inn til forlag, å bli refusert og prøve igjen.  </p>\n\n\n\n<p><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Nå skriver jeg på en skjønnlitterær bok for ungdom. &nbsp;</p>\n','blog-images/a-gi-en-stemme-til-naturen.jpeg','Forfatterskolen',NULL,1,NULL,'2024-04-11 10:05:35','2026-03-27 08:48:34'),(77,4,'Når bygdas lokalhistorie blir til romanserie','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-08de8e281264c6fa4452f8d79d2aafe2\" style=\"color:#c01a75\">Portrettintervju med tidligere elev </h2>\n\n\n\n<h3 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-10be5384970cb4874cd6d6406cae0433\" style=\"color:#c01a75\">Liz Skardal</h3>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full is-resized\"></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Liz Skardal</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>Vilda fra Verket</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Romanserie utgitt på Bladkompaniet. Første bok, <em>Det hjertet vil</em>, utgitt i 2023</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Tidligere utgitte bøker: <em>I hårløsninga </em>(Lanser forlag 2011)</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Da det ble utlyst serieromankonkurranser fra tre forlag i 2018, tok Liz Skardal sats og meldte seg på. Selv om bidragene ikke nådde helt opp, likte samtlige forlag ideen bak boken. Skardal bestemte seg for å fortsette med arbeidet etter de oppmuntrende ordene. Fem år etterpå lanseres første bok i romanserien om bygdejenta Vilda, som lever på Ulefoss, bygda forfatteren selv vokste opp i. Hun forteller om skriveprosessen disse årene:</strong></p>\n\n\n\n<p>Det var ikke lett. Mange opp- og nedturer. Jeg strevde blant annet med å forstå sjangeren, for jeg hadde aldri lest en hel romanserie noen gang. Jeg var vant til å lese enkeltstående romaner.</p>\n\n\n\n<p>Jeg var samtidig elev ved Forfatterskolen, og hadde her tatt et skjønnlitterært kurs. Da det ble arrangert romanseriekurs, heiv jeg meg på. Det var lurt. Jeg lærte mye, samtidig som jeg stod på og omskrev manuset mitt. Etter hvert fikk jeg tegnet intensjonsavtale med et forlag, og fortsatte å jobbe målrettet fram til det endelig ble kontrakt. I november 2023 ble serien lansert. Det er en kortserie på åtte bøker, som jeg fortsatt holder på å skrive.</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full is-resized\"></figure>\n</div>\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-46e920e27dff07b6fdd0b33db8cd73c6\" style=\"color:#c01a75;font-size:29px\">Kurs Liz Skardal tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/course/100\">Romankurs</a></p>\n\n\n\n<p class=\"has-text-align-center\"><a href=\"https://www.forfatterskolen.no/shop-manuscript\">Manusutvikling</a></p>\n\n\n\n<p>Det å være elev ved Forfatterskolen har vært veldig nyttig, både fordi jeg har lært mye om skrivekunsten og skriveverktøyet, og fordi det er inspirerende å ha kontakt med andre som skriver. Har tegnet meg på de ukentlige webinarene og mentormøtene hvert år, og deltar enten live eller ser reprisene etterpå, ettersom det passer.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-bdbcc2472ca55ad20f653e8106cde573 is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om <em>Vilda fra Verket</em>:</summary>\n<p>Vilda er nitten år i 1887, da de første smellene fra utbyggingen av Telemarkskanalen kunne høres på Ulefoss. Framtiden ser lys ut for den unge jenta fra arbeidermiljøet på Verket, men uforutsette og mørklagte hendelser skal komme til å sette Vilda og hennes kjære på store prøvelser.</p>\n\n\n\n<p><strong>Etter å ha bodd utenbygds i tjue år, flyttet forfatteren tilbake til Ulefoss, der hun oppdaget en ny interesse for bygdas lokalhistorie. Hun forteller om bygda som bakteppe for romanserien:</strong></p>\n\n\n\n<p>Ulefoss’ historie er spennende, med jernverks- og sagbruksarbeiderne på hver sin side av elva, alle avhengige av to rike godseiere for å kunne forsørge seg selv og sine familier. Arbeiderne og godseierne bodde ikke langt fra hverandre, men det enorme klasseskillet utgjorde naturligvis en høy og ugjennomtrengelig sosial mur mellom dem.</p>\n\n\n\n<p>Skrivegleden og interessen for lokalhistorien fikk meg til å skrive serien om Vilda. Fortellingen er fri fantasi, med oppdiktede personer, men jeg har gjort mitt beste for å beskrive omgivelsene historisk og geografisk så korrekt som mulig. Skjønt, noen nødvendige kunstneriske grep har jeg tillatt meg å ta.</p>\n</details>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<blockquote class=\"wp-block-quote has-text-align-right is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"has-text-align-center\">«Du skal ha mange takk,» svarte han. «Det hadde ikke vært så enkelt å stelle dette såret selv.»</p>\n\n\n\n<p class=\"has-text-align-center\">«Det va det minste jeg kunne gjøra som takk.» Vilda kunne ikke dy seg, nå som de snakket om sår … «Unnskyld, men … arra i ansiktet ditt …» I det samme skammet hun seg litt over å ha spurt.</p>\n\n\n\n<p class=\"has-text-align-center\">«Å, de. Ja, det er lenge siden, men jeg forstår at du spør. Arrene ser ikke fine ut.»</p>\n\n\n\n<p class=\"has-text-align-center\">«Nei, nei, jeg meinte det ikkje slik. Det skjemmer så aldeles ikkje … du e jo uansett så … jeg meiner …» Vilda ble varm i ansiktet igjen. Nå var det rett før hun hadde røpet at hun syntes han var kjekk. Hun skulle ikke ha spurt.</p>\n\n\n\n<p class=\"has-text-align-center\">Lavrans Elvestad smilte. «Du lurer vel på hvordan jeg fikk dem?»</p>\n\n\n\n<p class=\"has-text-align-center\">Vilda visste ikke hva hun skulle si. Det ville høres frekt ut uansett hva hun svarte nå. Hun nikket likevel.</p>\n<cite>Vilda fra Verket: Det hjertet vil, side 19-20 </cite></blockquote>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Det må være å ikke gi seg hvis de har et prosjekt de brenner for. Jobbe på. Lære seg å tåle å bli refusert, for det blir de aller fleste, kanskje opptil flere ganger. Se mulighetene i kritisk tilbakemelding. All tilbakemelding kan brukes til noe, det er veldig lærerikt. Tålmodighet er en bra ting, og så lenge en ikke stanser opp, går det jo framover.</p>\n\n\n\n<p><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Jeg skriver fremdeles på Vilda-serien. Bok nr. 4 kommer ut 22. mars, og jeg ligger noen hakk foran.</p>\n','blog-images/nar-bygdas-lokalhistorie-blir-til-romanserie.jpg','Forfatterskolen',NULL,1,NULL,'2024-03-21 12:48:17','2026-03-27 08:48:34'),(78,4,'Barnebok fra Gran Canaria','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-64b560cf94a808a4be967f4a8d9d34db\" style=\"color:#c01a75\">Portrettintervju med tidligere elev</h2>\n\n\n\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-6183de34b82cdb31f4363d8b0c57906a\" style=\"color:#c01a75\">Karen Anna Børresen</h2>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-full is-resized\"></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Karen Anna Børresen</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>Anna, øya og småkrypene</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på Firfisla forlag i 2023</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Sjanger: Barnebok</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Inspirert av sin boplass, Gran Canaria, der hun snart har bodd i tjuefire år, har Karen Anna Børresen skrevet barneboken <em>Anna, øya og småkrypene.</em> Hun har alltid likt å skrive og har opp igjennom årene tatt flere skrivekurs:</strong></p>\n\n\n\n<p>Jeg gikk noen forfatterkurs på nittitallet i Norge før jeg flyttet hit, men det ble kun inspirasjon som har ligget og godgjort seg til tida var inne.</p>\n\n\n\n<p>Jeg har en variert bakgrunn og utdannelse. Som familie bodde vi tretten år på et småbruk og kollektiv som vi kalte «et tilfluktsted for mennesker i livskriser». Deretter flyttet vi for oss selv og tok videre utdannelse. Det ble psykologi og barnehagelærer på meg i første omgang. Siden har jeg bygd på etter hvert med diverse fag jeg syntes at jeg trengte. Som man forstår, liker jeg å lære.</p>\n\n\n\n<p>De første ti årene her på øya jobbet jeg som lærer på Den Norske Skolen, og siden startet jeg barnehage i noen av skolens lokaler. Firfisla barnehage ble et populært sted for barn på kortere eller lengre opphold i varmen. Mange med helseutfordringer i familien. Vi kjøpte noen brakker og utvidet etter hvert med tilbud til korttidselever. Det var en fin tid, men alt har sin tid. Vi stengte i 2019, rett før Corona. Nå er jeg pensjonist.  </p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-31cea191838a6c16b6f7974d2cb45801\" style=\"color:#c01a75;font-size:29px\">Kurs Karen Anna Børresen tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center has-medium-font-size\"><a href=\"https://www.forfatterskolen.no/course/99\">Årskurs</a></p>\n\n\n\n<p>I prosessen med å lære mer, og i søket etter kurs, oppdaget jeg Forfatterskolen. De hadde mange inspirerende kurs. Til å begynne med meldte jeg meg på alt som var gratis. Det ga mersmak, og etter hvert satset jeg og begynte som elev på årskurset. Boka om småkrypene var jo omtrent ferdig, så jeg begynte på et nytt manus. Det var morsomt og utfordrende å satse på et større prosjekt enn det jeg hadde skrevet på til da. Jeg oppdaget at min tidligere redaktør fra BoldBooks, Espen Selmer-Torgersen, også var redaktør på Forfatterskolen og det var en stor glede.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<div style=\"height:98px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<figure class=\"wp-block-image size-large is-resized\"></figure>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-9cccd310f375cc9b83e38562dfd3594d is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om <em>Anna, øya og småkrypene</em></summary>\n<p>Anna bor på Gran Canaria sammen med faren sin; ei øy der det også lever mange småkryp og insekter. Sammen med venner og andre hun treffer på øya, lærer hun om alle småkrypene og hvordan de lever og oppfører seg der. I samspill med fine og korte historier om Anna, får leseren bli med på en lærerik reise rundt øya og hvordan livet der er.</p>\n\n\n\n<p><strong>Karen Anna forteller om bokens skriveprosess:</strong></p>\n\n\n\n<p>Boka om småkryp har vært under arbeid i flere år. Temaet har vært et årlig innslag med skolebarn og barnehagebarn. Den opprinnelige tanken var å skrive små lett-les hefter, deretter tenkte jeg en illustrert bok om hvert kryp. Det ble for dyrt. Til slutt landet jeg på formen boka har fått i dag med hjelp av redaktør.</p>\n\n\n\n<p>Jeg brukte lang tid på å sende inn manus til forlag og å vente på svar. Det ble å skrive om og forbedre manus og sende inn til annet forlag etter hvert som jeg fikk avslag. Innimellom heiv jeg meg på alt av gratiskurs og slik kom jeg først i kontakt med BoldBooks, og siden Forfatterskolen. I ventetiden skrev jeg også en liten bok om min mor (<em>Oldemor forteller</em>). Kursene jeg fulgte ga meg inspirasjon og mot til å satse. Jeg ga opp forlagene, fikk hjelp av min sønn i Bergen som var villig til å drive forlaget; Firfisla forlag. Jeg er stolt og glad for at vi har beholdt det fine navnet fra barnehagen.</p>\n</details>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<blockquote class=\"wp-block-quote has-text-align-right is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"has-text-align-center\">I veldig, veldig gamle dager», fortsetter jeg, «før disse øyene ble oppdaget av europeere, bodde det folk her som spiste firfisler. Men de spiste ikke så mange, og de spiste bare de store, så det gjorde ingen skade. Det er det som er så viktig på jorden. At vi ikke må bli grådige og ta for mye, det sier alltid pappa.</p>\n<cite><em>Anna, øya og småkrypene, </em>side 24</cite></blockquote>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Hiv deg på alt du finner av gratiskurs i første omgang. Etter hvert også betalte kurs om du kan. Når du har skrevet ferdig manus, så langt du synes at du kan, ta kontakt med en manuskonsulent/redaktør. Det er verdt pengene. Du må regne med å bruke en del penger for å få manus så bra som det fortjener å bli. Sjekk ut kunstgjødsel/søknadsjubel. Her kan du få hjelp til å finne stipend etc. Har du anledning, så anbefaler jeg <a href=\"https://www.forfatterskolen.no/course/99\">Årskurset</a> her på Forfatterskolen. Så må du ikke glemme å lage en plan for hvordan du skal promotere den ferdige boka. Selv om du kommer på et forlag, må du tenke på dette. Det hjelper ikke å ha skrevet en glimrende bok, om ingen vet om den. Her må i alle fall jeg hive meg ut på dypet, langt utenfor komfortsona. Men det må til.</p>\n\n\n\n<div style=\"height:70px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:70px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Jeg fortsetter med det manuset jeg begynte på Årskurset, men ikke så intenst som under kurset. Jeg leser tilbakemeldingene fra min redaktør om igjen og tenker og noterer. Det var seks innsendinger og tilbakemeldinger, så det er nok å ta tak i. Jeg har laget en plan for hvordan jeg skal fortsette dette året, og kanskje jeg melder meg på et oppfølgingskurs neste år om jeg trenger det. Forfatterskolen tilbyr også videre redaktørhjelp, så jeg er ikke alene.</p>\n\n\n\n<p>Samtidig samler jeg informasjon og ideer i et eget dokument for en oppfølger til Anna hvor hun besøker de andre Kanariøyene. Denne boka har jo en form, så det er innholdet jeg må velge ut. Det er morsomt.</p>\n','blog-images/barnebok-fra-gran-canaria.jpg','Forfatterskolen',NULL,1,NULL,'2024-02-27 13:55:54','2026-03-27 08:48:34'),(79,4,'Hva jenter kan få til!','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-08de8e281264c6fa4452f8d79d2aafe2\" style=\"color:#c01a75\">Portrettintervju med tidligere elev </h2>\n\n\n\n<h3 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-78f5e7c333e2c087419c69d6a8201cfc\" style=\"color:#c01a75\">Aud Helene Våge Johannessen</h3>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Hun var en av de første kvinnene som fikk jobb på oljeplattform, ble adoptert bort som lita jenta til en onkel og tante som ikke hadde egne barn og er i dag pensjonist og har utgitt bok om sitt eget liv. Vi har tatt en prat med vår tidligere elev, Aud Helene Våge Johannessen</strong>.</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Aud Helene Våge Johannessen</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>En dråpe fra havet</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på Giutbok.no i 2023</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Sjanger: Selvbiografi</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Da Aud Helene nettopp hadde begynt på boken, skjedde det noe som satte skriveprosessen på pause. Året var akkurat gått over til 2019 da hun fikk hjerneslag. Det var først da koronapandemien rammet verden at skrivingen igjen tok fart. Hun forteller oss om skriveprosessen:</strong></p>\n\n\n\n<p>Jeg hadde notert mye av bokens innhold tidligere fordi jeg ønsket å fortelle min historie til mine barn og barnebarn. Jeg har hatt en liten almanakk med meg der jeg har skrevet ned stikkord til hva som skulle med. Underveis i skrivingen, hadde jeg også en perm der jeg la inn stikkord til hvert av årstallene som skulle med. Da hadde jeg også all dataen som trengtes for at boken skulle skrives, noe som hjalp meg mye i skriveprosessen.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"></figure>\n\n\n\n<p><strong>Men skrivearbeidet har ikke alltid vært enkelt. Aud Helene forteller om spesielt ett kapittel som var vanskelig å komme igjennom. Kapittelet handlet om en tid da hun hadde mulighet til å skape nye arbeidsplasser til lokalbefolkningen ved Skifjorden. Ved hjelp av utviding av hyttefeltet og servicebygg for kurs og konferanse, kunne det bli helårsdrift. I stedet for støtte, møtte hun mye motgang i bygda, og hun opplevde janteloven som sterkt inngrodd blant disse.</strong></p>\n\n\n\n<p>Jeg brukte tre måneder på å komme meg igjennom kapittelet fordi det var så tøft å ta det opp igjen; det å være i det og skrive det. Men dette kapittelet har også fått veldig gode tilbakemeldinger i ettertid.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-86c045b0d38341e6780ac859ea928d64\" style=\"color:#c01a75;font-size:29px\">Kurs Aud Helene Våge Johannessen tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center has-medium-font-size\"><a href=\"https://www.forfatterskolen.no/course/99\">Årskurs</a></p>\n\n\n\n<p>Årskurset på Forfatterskolen var helt perfekt for meg og veldig spennende. Det var en opplevelse den dagen vi skulle få tilbake tilbakemeldingen på innleveringene. Jeg var alltid veldig spent. Redigeringswebinarene til Kristine var også helt supre! Fra skolen fikk vi mye oppmuntring hvis vi begynte å gå lei. Dette hjalp mye.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<div style=\"height:98px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-36d64f184364f6c2b00b3949f336a32c is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om En dråpe fra havet </summary>\n<p>Boken handler om å vokse opp på ei øy og kystkulturen fra hennes fødsel i 1943, under krigsårene, og livet frem til i dag. Leseren får følge Aud Helene fra hennes første år på Steinsundholmen, adopsjonen av onkelen og tanten (etter det hetende «mor» og «far») på Saltskåren, hennes oppvekst og møter med tragiske dødsfall, lykkelige dager med familie og barn og karrieren som en av Norges første kvinnelige arbeidere på oljeplattform.</p>\n\n\n\n<p><strong>Aud Helene forteller om hennes motivasjon bak boken:</strong></p>\n\n\n\n<p>Jeg ønsket å gi noe tilbake til ungene. De spurte jo om jeg kunne skrive bok fordi jeg hadde opplevd så mye, så da lagde jeg en rød tråd med hva som skulle være med. Med boken var jeg opptatt av å ha med hva jenter kan, fordi det ikke var så mange jenter i begynnelsen som jobbet med olje. Jeg var også med i politikken, og dette ble et aktuelt tema. I tillegg ville jeg ha med historie og kultur rundt øyene der jeg vokste opp.</p>\n</details>\n\n\n\n<p></p>\n\n\n\n<p></p>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Det viktigste tipset er å ikke gi opp. Hvis du er lei, legg det litt vekk. Gjør noe helt annet, for eksempel lese en god bok i stedet, da tenker du bedre. Det er også kjempekjekt å få oppmuntring fra skolen. Det er så lite som skal til, og ord som «dette klarer du!» og «du er godt i gang!» hjalp mye for motivasjonen min.</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<blockquote class=\"wp-block-quote has-text-align-right is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"has-text-align-center\"><em>Vi var møtt opp på kaia for å vinke og se gjestene vel hjem. Det var så trist at Klemet måtte reise, og jeg felte noen tårer. Da jeg tok opp et lommetørkle fra vesken min, falt et lite speil ut og knuste i mange biter. «Syv års ulykke», var det noen som sa, som så det. Jeg ville ikke høre eller tenke på det. Men jeg glemte ikke ordene.</em></p>\n<cite>En dråpe fra havet, side 109</cite></blockquote>\n\n\n\n<p></p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p><strong><em>En dråpe fra havet </em></strong><strong>har fått veldig god mottagelse etter utgivelse, der en kundeanmeldelse på Norlis nettsider omtaler bokens tema som «Jenter som kan». Så helt til slutt, skriver hun på noe nå?</strong></p>\n\n\n\n<p>Jeg trenger en pause akkurat nå, men det kommer noen små ideer. Og jeg fortsetter å følge Forfatterskolens webinarer.</p>\n\n\n\n<p></p>\n','blog-images/hva-jenter-kan-fa-til.jpg','Forfatterskolen',NULL,1,NULL,'2024-02-27 09:29:29','2026-03-27 08:48:34'),(80,4,'Et møte som fikk manuset ut av skrivebordsskuffen','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-08de8e281264c6fa4452f8d79d2aafe2\" style=\"color:#c01a75\">Portrettintervju med tidligere elev </h2>\n\n\n\n<h3 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-d2674c36011c39cbbde08d56b6c31855\" style=\"color:#c01a75\">Grete Syvertsen</h3>\n\n\n\n<figure class=\"wp-block-gallery has-nested-images columns-default is-cropped wp-block-gallery-1 is-layout-flex wp-block-gallery-is-layout-flex\">\n<figure class=\"wp-block-image size-large\"></figure>\n</figure>\n\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-left\"><strong>Som ung likte Oslo-jenta Grete Syvertsen seg godt på mormor og morfars bondegård i Østerdalen der hun tilbrakte alle sommerferiene. Her nøt hun det vakre landskapet ved Glomma og den gåtefulle skogen like ved. Men det aller beste, var selve atmosfæren: Alle de gode menneskene, dyrene og de yngre kusinene hun sang og diktet for.</strong></p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Grete Syvertsen</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>Øyeblikk av lykke</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på Forlagshuset Vest AS i 2023</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Sjanger: Lyrikk</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-left\"><strong>Hele livet fortsatte hun å skrive og dikte, fra stiler på skolen til historier og dikt som oppsto under fortellerkurs på Moreno Instituttet der hun utdannet seg som psykodramaterapeut.</strong></p>\n\n\n\n<p class=\"has-text-align-left\"><strong>Likevel resulterte skrivingen i det samme: Flere manus som bare ble liggende.</strong></p>\n\n\n\n<p class=\"has-text-align-left\"><strong>Grete måtte bli pensjonist før hun endelig ble oppdaget:</strong></p>\n\n\n\n<p>Ved en tilfeldighet traff jeg en dame som er forfatter, hun anmodet meg om å sende inn mitt manus og til min store overraskelse ble jeg antatt av forlagshuset Publica. De ville trykke min lille diktsamling.</p>\n\n\n\n<p>Da tidsfristene var utfordrende, roet jeg meg ned ved å gå på tur. Jeg fikk en ny innsikt med lagene og fargene i naturen, og jeg foreviget inntrykkene med fotografier.</p>\n\n\n\n<p>Jeg&nbsp;valgte ut noen av bildene som hadde et motiv som inspirerte meg. Når jeg satt med lukkede øyne kunne jeg for mitt &#8220;indre øye&#8221; gå inn i en fantasi, og ordene kom til meg intuitivt.&nbsp;</p>\n\n\n\n<p>Etterpå beskrev jeg det jeg så og det jeg følte. Det som rørte meg. Jeg lærte også å lytte til min egen stemme, og å være tro mot den.</p>\n\n\n\n<p>Redigeringsfasen ble intens og krevende. Det var litt vanskelig å stryke setninger jeg likte godt selv. Men jeg ble fornøyd med resultatet.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-64776781e952fc97c1fcda4ddd4280b9\" style=\"color:#c01a75;font-size:29px\">Kurs Grete Syvertsen tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center has-medium-font-size\"><a href=\"https://www.forfatterskolen.no/course/100\">Romankurs</a> (2020)</p>\n\n\n\n<p class=\"has-text-align-center has-medium-font-size\"><a href=\"https://www.forfatterskolen.no/shop-manuscript\">Manusutvikling</a> (2022)</p>\n\n\n\n<p>Etter en omfattende tilbakemelding fra manusutviklingen, har romanen blitt liggende fordi jeg ikke har hatt energi til å gå inn i den igjen. Jeg har hatt stor glede av webinarene, og Gro Dahles webinarer fikk meg til å ta frem diktene jeg hadde liggende og skrive videre på disse.</p>\n\n\n\n<p>Forfatterskolen har lært meg mye fra de konstruktive tilbakemeldingene jeg fikk på innleveringer, blant annet forskjellen på «show» og «tell», strukturere og bygge opp fortellingen, skrive synopsis og å arbeide med karakteroppbygging. Jeg lærte også hvor virkningsfullt det var å stryke unødvendige småord og setninger som overforklarer.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<div style=\"height:98px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n<div class=\"wp-block-image\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-group\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<div class=\"wp-block-columns is-layout-flex wp-container-core-columns-is-layout-9d6595d7 wp-block-columns-is-layout-flex\">\n<div class=\"wp-block-column is-layout-flow wp-block-column-is-layout-flow\" style=\"flex-basis:100%\">\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-b81d3a96a1e32580fff7de674806d81c is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om <em>Øyeblikk av lykke</em></summary>\n<p>Diktene handler om menneskene og naturen, og samspillet mellom naturkreftene og menneskets indre krefter. Diktene prøver å speile menneskenes sårhet og lengsler, håp og kjærlighet vevet sammen med naturens sårbarhet, skjønnhet og mangfold.</p>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n</details>\n</div>\n</div>\n</div></div>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center\"><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Jeg liker å roe ned med skogsturer, yoga, meditasjon, eller lytte til musikk. Jeg øver stadig på å åpne sansene og være til stede i øyeblikkene: Hva ser jeg? Hva hører jeg? Hva lukter jeg?</p>\n\n\n\n<p>Ta vare på og beskrive følelsene i disse øyeblikkene, og tro på din egen stemme.</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<blockquote class=\"wp-block-quote has-text-align-right is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"has-text-align-center\">FUGLEN OG DRÅPEN</p>\n\n\n\n<p class=\"has-text-align-center\">Fuglen speiler seg</p>\n\n\n\n<p class=\"has-text-align-center\">i duggdråpen</p>\n\n\n\n<p class=\"has-text-align-center\">som klamrer seg fast</p>\n\n\n\n<p class=\"has-text-align-center\">I blomsten</p>\n\n\n\n<p class=\"has-text-align-center\">Snart faller jeg</p>\n\n\n\n<p class=\"has-text-align-center\">tenker dråpen</p>\n\n\n\n<p class=\"has-text-align-center\">Så vakker jeg er</p>\n\n\n\n<p class=\"has-text-align-center\">tenker fuglen</p>\n\n\n\n<p class=\"has-text-align-center\">i det den drikker</p>\n\n\n\n<p class=\"has-text-align-center\">bildet av seg selv</p>\n<cite><em>Øyeblikk av lykke</em>, side 7&nbsp;&nbsp;</cite></blockquote>\n\n\n\n<p>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</p>\n\n\n\n<p class=\"has-text-align-center\"><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Nei, men jeg har planer om a ta frem romanmanuset mitt igjen og vurdere det på nytt.</p>\n','blog-images/et-mote-som-fikk-manuset-ut-av-skrivebordsskuffen.jpg','Forfatterskolen',NULL,1,NULL,'2024-02-16 13:13:25','2026-03-27 08:48:34'),(81,4,'Fra Forfatterskolen til indieforfatter','\n<h2 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-08de8e281264c6fa4452f8d79d2aafe2\" style=\"color:#c01a75\">Portrettintervju med tidligere elev </h2>\n\n\n\n<h3 class=\"wp-block-heading has-text-align-center has-text-color has-link-color has-large-font-size wp-elements-65b377a5b5f6b453e0721d801b25c677\" style=\"color:#c01a75\">Ane Svendsen</h3>\n\n\n<div class=\"wp-block-image is-style-default\">\n<figure class=\"aligncenter size-large is-resized\"></figure>\n</div>\n\n\n<div style=\"height:144px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center has-large-font-size\"><mark style=\"background-color:rgba(0, 0, 0, 0);color:#c01a75\" class=\"has-inline-color\">HVEM? HVA? HVOR?</mark></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Ane Svendsen</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\"><em>#sommerminne</em></p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Utgitt på September forlag i 2022</p>\n\n\n\n<p class=\"has-text-align-center\" style=\"font-size:27px\">Sjanger: Ungdom (12-16 år)</p>\n\n\n\n<div style=\"height:100px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center\"><strong>Ane Svendsen er en 58 år gammel indieforfatter som i 2022 debuterte med ungdomsboka #sommerminne. Hennes sterke interesse for lesing og skriving resulterte til slutt i en roman. La oss høre litt hvordan: </strong></p>\n\n\n\n<p>Ideen til boken dukket opp helt ut av det blå, mens jeg satt ved pc-en. Da tenkte jeg at nå er det bare å åpne et blankt dokument og skrive det ned. Som tenkt så gjort. Jeg syns det var kjempegøy å skrive den, og å virkelig jobbe med teksten. Manuset ble sendt til ulike forlag, uten hell. Derfor opprettet jeg mitt eget forlag og ga boken ut der, da jeg ønsket å gi den en sjanse.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<p class=\"has-text-align-center has-text-color has-link-color wp-elements-654614741e928b1503b393df4d44bd7a\" style=\"color:#c01a75;font-size:29px\">Kurs Ane Svendsen tok på Forfatterskolen</p>\n\n\n\n<p class=\"has-text-align-center has-medium-font-size\"><a href=\"https://www.forfatterskolen.no/shop-manuscript\">Manusutvikling</a></p>\n\n\n\n<p>Da jeg sendte manuset til manusutvikling for første gang, var manuset ganske uferdig. Og etter to gode runder, begynte ting å falle på plass. Dessuten så jeg på en masse av Forfatterskolens webinarer, noe jeg fremdeles gjør og kan anbefale på det sterkeste.</p>\n\n\n\n<hr class=\"wp-block-separator has-alpha-channel-opacity\"/>\n\n\n\n<div style=\"height:98px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<div class=\"wp-block-group\"><div class=\"wp-block-group__inner-container is-layout-constrained wp-block-group-is-layout-constrained\">\n<details class=\"wp-block-details has-text-color has-link-color wp-elements-1d4973559a210610573f08aa03558460 is-layout-flow wp-block-details-is-layout-flow\" style=\"color:#c01a75;font-size:31px\"><summary>Klikk her for å lese mer om #sommerminne</summary>\n<p>Boken handler om Sølvi og den siste sommerferien hennes før ungdomsskolen. Sølvi har mistet bestevenninnen Mie til Beatrix, og det ser ut til at Sølvi blir den mest ensomme ever. Sølvi samler på ord, har interesse for horoskop og hjelper mormor med innkjøp. Dessuten, hva er det med storesøsteren Anja? Og hva med Pelle, som Sølvi stadig møter på? Det er sommeren da ulike hendelser fører til store forandringer, og lite blir slik det tidligere har vært. </p>\n\n\n\n<p>Boken er kjøpt inn av flere bibliotek. Jeg meldte den også til U-prisen, som er en flott måte å nå ut til leserne.</p>\n</details>\n</div></div>\n\n\n\n<div style=\"height:118px\" aria-hidden=\"true\" class=\"wp-block-spacer\"></div>\n\n\n\n<p class=\"has-text-align-center\"><strong>Det er mange elever på Forfatterskolen med en forfatterdrøm i magen. Hva vil du si til disse?</strong></p>\n\n\n\n<p>Stå på, les og skriv, bruk redaktørtjenester slik som Forfatterskolens Manusutvikling, ta eventuelt et skrivekurs.</p>\n\n\n\n<p>Om man ønsker å gi ut boken selv, som indie, er det viktig å la manuset bli gjennomgått av redaktør, samt språkvask og korrektur før det sendes til ønsket trykkeri.</p>\n\n\n\n<figure class=\"wp-block-pullquote has-black-color has-text-color has-link-color wp-elements-9bc58bbed5834011e7d6013b813a560a\" style=\"font-size:28px\"><blockquote><p>Kvelden var krøpet fram fra syrinbuskene. Månesigden vippet på sørhimmelen, dus og utflytende. Gnissende lyd fra gresshopper fylte luften. Med ett var noen i teltåpningen. LED-stjernene skimret bløtt over ansiktet til Mie. En liten sekk dinglet fra den ene skulderen. Kroppsvekten hvilte på venstre fot, armene i kors over brystet.<br>–&nbsp;&nbsp; Hei, tygget hun, blåste en boble.<br>–&nbsp; Kom inn da vel!<br>–&nbsp; Om det blir kjedelig kan det hende jeg drar hjem.<br>–&nbsp; Det blir ikke kjedelig. Men du må love å ikke si det til noen.</p><cite><em>#sommerminne</em>, side 68</cite></blockquote></figure>\n\n\n\n<p></p>\n\n\n\n<p class=\"has-text-align-center\"><strong>Helt til slutt, skriver du på noe nå?</strong></p>\n\n\n\n<p>Ja, det gjør jeg. Jeg har skrevet, og skriver fortsatt, på et manus til en grøsser beregnet på ungdom, der hovedpersonen er tiendeklassing, altså litt eldre enn hovedpersonen i den forrige boken. Denne ideen poppet for første gang opp da jeg var i et juleselskap i 2022. Manuset har nettopp hatt en runde med Manusutvikling hos Forfatterskolen. Målet er å gi ut boken til høsten på mitt eget forlag.</p>\n','blog-images/fra-forfatterskolen-til-indieforfatter.jpg','Forfatterskolen',NULL,1,NULL,'2024-02-13 07:22:03','2026-03-27 08:48:34'),(82,4,'Julen i novelleformat','<h2><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important; color: rgb(17, 17, 18) !important;\">Jula i novelleformat</span></h2>\n<p><span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\"><em>Hva betyr det å falle utenfor – i et rikt land som Norge?</em><em>Hvor kommer fordommene våre fra?Hvordan kan vi vise omsorg for hverandre når vi selv sliter?</em></span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Dette er spørsmål forfatter Marthe Munkhaugen Eggen tar for seg i novellesamlingen ‘Desemberfloker’. I samlingen møter vi blant annet Sivert som ikke liker ungdom, Vera og Olga som begge har mistet noen, Milla som stjeler en julegave, og flere som møter motstand i den kjære høytiden.</span></span></p>\n<h4><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Om det sårbare livet</span></span></h4>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Men hva med forfatteren selv – hva slags forhold har hun til julen?</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">– Jeg elsker jul, sier Marthe.&nbsp; &nbsp; &nbsp;–&nbsp;Men den kan også røre ved mye ubehag. Savn, ensomhet og utenforskap som man kanskje tåler bedre resten av året, og som blir forsterket i denne tida.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">‘Desemberfloker’ handler om disse utfordringene, og om hvor sårbart livet kan være.</span></span></p>\n<h4><strong><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\"><em>Artig og skummelt&nbsp;</em></span></span></strong></h4>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Forfatteren synes det er artig å gi ut bok, men også skummelt. Hun</span><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">&nbsp;har holdt på med å skrive korte tekster en stund, og da hun via kurs ble kjent med novellesjangeren klarte hun bedre å definere tekstene. Hun trivdes med å skrive i denne sjangeren, og det ble en fin pause fra de lengre prosjektene.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">– Det er deilig å skrive noveller, sier Marthe. &nbsp; &nbsp;– Du får en idé, begynner å skrive og så klarer du å fullføre historien.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Forfatteren sier at skrivingen har gått på skinner – novellene har kommet smertefritt frem, og prosessen med publisering og lansering har vært en ren glede.</span></span></p>\n<h4><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Ville gi ut selv</span></span></h4>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Marthe visste fra starten av av hun ville gi ut boken selv. </span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">– Jeg visste fra starten av at jeg ville gi ut samlingen selv. Jeg hadde en så klar idé om hvordan boka skulle bli, og ville ikke at noen skulle komme inn og forstyrre det.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Men a gi ut selv kan også være en ensom affære, og en bratt læringskurve.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">– Jeg har prøvd å by på meg selv.&nbsp;</span><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Lanseringsfesten ble en positiv opplevelse, til tross for nervene som knyttet til å skulle være hovedperson. Jeg</span><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\"> har fått så mange gode tilbakemeldinger!</span></span></p>\n<h4>Unikt skrivefellesskap</h4>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Skrivenettverket har hatt stor verdi for forfatteren, både i prosessen med skriving og utgivelse. Bokbaderen og konferansieren på lanseringsfesten er personer Marthe har møtt ved skolen. De har sin egen skrivegruppe, der de heier hverandre frem.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">– Et slikt fellesskap gir mye i henhold til å tørre. Det er godt å møtes fysisk også. Det gir mye, også i perioden etter utgivelsen.</span></span></p>\n<h4><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\"><em>Fantasy for barn</em></span></span></h4>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Novellesjangeren har gitt mersmak, og er behagelig å oppholde seg i. Nettopp derfor går Marthe vekk fra den, i hvert fall for en periode.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">– Jeg må utfordre meg, sier hun.&nbsp; &nbsp; &nbsp;– Og e</span><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">tter å ha skrevet frem både voksne og barn i &#8220;Desemberfloker&#8221;, har jeg falt for barneperspektivet.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Den nybakte forfatteren har klart et utkast til et fantasy-prosjekt for barn.&nbsp;</span><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">Boka retter seg mot tweens, barn i alderen 10-14 år. Men aller først må bølgene etter debutboken legge seg.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\">– Selv om den er ute i verden, kjenner jeg at jeg fortsatt er <em>inne</em> i den. Jeg snakker mye om boken, og klarer ikke helt å omstille meg. Så jula må avsluttes før jeg kan begynne på noe nytt.</span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\"><strong>Forfatterskolen gratulerer Marthe så mye med utgivelsen!</strong></span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\"><em>Du finner novellesamlingen i nettbokhandelen, eller på forfatterens hjemmeside: marthesbok.no. </em></span></span></p>\n<p><span style=\"color: rgb(17, 17, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 17, 18) !important;\"><em>God lesning, og god jul!</em></span></span></p>\n<p><span></span></p>\n<p style=\"\">Marthe Munkhaugen Eggan (f. 1977) er fra Trondheim. Hun har tidligere vært publisert med noveller og dikt i en rekke antologier. «Desemberfloker» er hennes første bok.</p>\n','blog-images/julen-i-novelleformat.webp','Forfatterskolen',NULL,1,NULL,'2023-12-16 12:41:01','2026-03-27 08:48:34'),(83,4,'Fra drøm til diktsamling','<h2><strong><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important; color: rgb(10, 11, 11) !important;\">Fra drøm til diktsamling</span></strong></h2>\n<h4><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Monica Evaldsdatter Dahlskjær skrev sin første bok som 3-åring. Siden forsøkte hun å skyve vekk drømmen, men det lot seg ikke gjøre – hun <em>skulle </em>bli forfatter. Nå er hun aktuell med diktsamlingen &#8220;Stemninger&#8221;.</span></span></h4>\n<p><span></span></p>\n<h3><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\"><strong>Inspirert av moren</strong></span></span></h3>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Den tidligere eleven hos Forfatterskolen er aktuell med diktsamlingen ‘Stemninger’ – men dette er langt fra hennes første bok. Monica har skrevet hele livet, og har en stor lidenskap for fortellinger. Hennes første bok skrev hun sammen med moren allerede som 3-åring, en bok om en krabbe som ikke fant huset sitt.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Jeg sprang rundt med fortellingen i hånden, og var så kry!</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Monica var, og er, inspirert av en kreativ og litteraturinteressert mor. Moren bidro til at den nybakte forfatteren både skrev og leste tidlig.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Jeg trodde likevel aldri det skulle bli til noe, sier hun. &nbsp; &nbsp;– Jeg har skrevet i flere format; dikt, noveller, roman. Som 16-åring skrev jeg en roman om en tenåring som hadde det vanskelig. Og så la jeg det bort etterpå.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Selv om Monica ikke hadde tro på prosjektet der og da, ser hun på teksten med et annet blikk nå.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Jeg ser at det faktisk ikke var så verst.</span></span></p>\n<h3><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\"><strong>Er jeg god nok?</strong></span></span></h3>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Det vokste etter hvert frem et behov for å utvikle skrivingen.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Brått kom det over meg: Jeg <em>må </em>gå på Forfatterskolen. Men har jeg råd, har jeg tid, er jeg god nok?</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Det var mye tvil, og samtidig kjentes det som noe hun <em>måtte.</em></span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Det var viktig for meg å gå fra hobbyskrivende, til å skrive med tro på at dette kunne bli noe.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Forfatterskolen leverte, og ha henne tro på egne evner. Skolen har vært springbrettet til meg som forfatter, sier Monica, det har gitt meg tro på meg selv.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Den første utfordringen var skriveoppgavene, der kursgruppen sendte tekst til anonyme medelever, og fikk tilbakemelding. Monicas nerver var på topp.</span></span></p>\n<h3><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\"><strong>Fra drøm til bok</strong></span></span></h3>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Jeg trodde det kom til å bli dømt nord og ned. Her har jeg ingenting å gjøre, tenkte jeg. Og så fikk jeg så gode tilbakemeldinger! Dette, sammen med selve kurset, var et&nbsp;viktig steg på veien for meg.&nbsp;Jeg hadde ikke vært der jeg er i dag uten Forfatterskolen.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">I etterkant av kurset hoppet Monica ut i det, og sendte tekst til flere antologier. Hun sendte dikt og novelle – og begge kom med. Det ble flere antologipubliseringer, og Monica fikk dikt på trykk.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Bidraget mitt til antologiene og tilbakemeldingene fra skrivekurset ga meg trygghet, sier hun. &nbsp; – En tanke tok mer og mer plass i hodet: Kanskje jeg kunne realisere drømmen likevel?</span></span></p>\n<h3><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\"><strong>Skriver intuitivt</strong></span></span></h3>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Monica sier hun skriver intuitivt, og at stoffet &#8220;dukker opp av seg selv&#8221;.&nbsp;Forfatteren har selv utviklet et kurs i intuitiv skriving, der hun utforsker hvordan man best kan ta imot inspirasjon, og ordene som de kommer.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– En periode måtte jeg legge vekk alle prosjektene på grunn av helsa, blant annet et romanprosjekt, sier Monica. &nbsp; –&nbsp;Men diktene ga seg ikke. De bare kommer til meg og vil ut!</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Det var slik diktet ‘Skimmer’ ble til (se nederst i artikkelen). Diktet var i Vesaas ånd, fikk forfatteren høre. Selv hadde ikke Monica lest så mye fra denne poeten. Diktet kom til Monica i sin helhet, og hun skyndte seg å taste det inn som notater på mobilen. Dette prosjektet hadde en helt egen energi – Monica følte hun fikk overskudd av tekstene.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Fotografering har også blitt en viktig del av diktarbeidet for Monica.&nbsp;</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Fotografi er for meg en slags poesi, og bildene er like viktige som diktene.</span></span></p>\n<h3><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\"><strong>Lang og humpete vei&nbsp;</strong></span></span></h3>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Etter å ha lagt fra seg drømmen flere ganger, tvilt og trodd, har Monica endelig kommet i mål.&nbsp;Det har vært en lang og humpete vei, sier forfatteren, men hun er klar på at det var verdt det harde arbeidet.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">– Jeg er veldig, veldig stolt av boken. Den ble så vakker også – designet er som et lite smykke i seg selv.</span></span></p>\n<h3><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\"><em>Forfatterskolen gratulerer Monica så mye med utgivelsen!</em></span></span></h3>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Boken er gitt ut hos Storia forlag. Forfatteren kan melde at Stjørdal bibliotek tok inn boka med en gang, og at det etter mange gode tilbakemeldinger er aktuelt med et andreopplag.</span></span><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\"><em></em></span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">Vil du bestille boken? Ta kontakt på mail (<a href=\"mailto:indrielnor@gmail.com\" style=\"outline: none;\">indrielnor@gmail.com</a>), eller send SMS til 98419205. Skriv ønsket antall bøker, og ta med ditt navn og din adresse.</span></span></p>\n<p><span style=\"color: rgb(10, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(10, 11, 11) !important;\">&#8212;&nbsp;</span></span></p>\n<p><span style=\"color: rgb(17, 18, 18) !important;\"><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important;\">Utdrag fra ‘Stemninger’</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\"><strong>SKIMMER</strong></span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Glitrande små bylgjerSkimrar i soli sine ljose kjærteikn</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Dei klukkar og ler imot megInnhyllar meg i mjuk ljod</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Eg sit i einsemd og ser</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Opnar for alt omkringInviterer synet innforbi mi inste grind</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Bylgjene helser meg med sin ljos- dans</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Glad for at akkurat eg sit her</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Sjølv om eg er trist</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">&nbsp;Det finst noko vakkert i alt</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Sjelefred òg, fortel deiEg må berre tillata meg og sjå</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Om eg berre tillèt meg sjølv</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">å dansa saman med dei no, bylgjene</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Lèt meg døpa i ljos-skimmeret</span></span></p>\n<p><span style=\"color: rgb(13, 13, 13) !important;\"><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important;\">Klukka og le litt med dei</span></span></p>\n<p><span style=\"--tcb-applied-color: rgb(13, 13, 13) !important; color: rgb(13, 13, 13) !important;\">&nbsp;Då vil eg forstå og gledja meg meir over livet.</span></p>\n<p><span style=\"--tcb-applied-color: rgb(17, 18, 18) !important; color: rgb(17, 18, 18) !important;\">&#8212;</span></p>\n<p><span></span></p>\n<p style=\"\">Nybakt forfatter: Monica Evaldsdatter Dahlskjær&nbsp;</p>\n','blog-images/nar-er-man-en-forfatter.jpg','Forfatterskolen',NULL,1,NULL,'2023-08-09 12:11:29','2026-03-27 08:48:34'),(84,4,'Kulturskiller, identitetskvaler og en forvandlet pappa','<h2><strong>Oppgjør med nordlyset</strong></h2>\n<h4>Forfatter Elena Guttormsen er aktuell med sin andre utgivelse. Barneboka &#8220;Máhtte og nordlyset&#8221; handler &nbsp;om tilhørighet og om å finne frem til seg selv.</h4>\n<p><span></span></p>\n<h3><strong><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important; color: rgb(9, 9, 9) !important;\">Oppgjør med Nordlyset</span></strong></h3>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Sentrale tema i Guttormsens bok er identitet og kulturutfordringer. Forfatteren vil formidle hvordan det kan oppleves å være både norsk og samisk, og det å måtte tilpasse seg en helt ny kultur. </span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Hovedkarakteren Máhtte går på barneskolen, og når foreldrene plutselig skiller seg må Máhtte flytte østover. Der må han finne sin plass i en ny og annerledes hverdag, med andre sosiale koder. Når man flytter vekk fra det man kjenner, hvem blir man da?&nbsp;</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; Boplassen er ikke det eneste som har endret seg. Pappa er også blitt en annen. Er han forbyttet med de underjordiske? </span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Máhtte drar nordover igjen, for å ta et oppgjør med nordlyset. Med hjelp av dyr og en avdød oldefar, leter Máhtte etter sin <em>egentlige</em> pappa.</span></span></p>\n<h3><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\"><strong>Små testkaniner</strong></span></span></h3>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Forfatteren har testet tekstene på egne barn, som har vært ivrige pilotlesere.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Det er fint å kunne prøve ut tekstene på noen jeg kjenner og stoler på, og få tilbakemelding fra &nbsp;aldersgruppen som skal lese den.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Elena har lest for barna siden de var små, og synes det er viktig at de leses for og leser selv: </span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Jeg hadde dette i tankene hele veien, at jeg ville appellere til begge grupper (red anm. høytlesning og egenlesing). Jeg ville at barna skulle få noe å reflektere over, og ikke bare bli underholdt. Dette synes jeg er en spennende balanse å jobbe med.</span></span></p>\n<h3><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\"><strong>Lærerik og tøff reise</strong></span></span></h3>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Samarbeidet med forlaget har vært svært positivt, forteller Elena. Hun gjør mye selv mye promoteringsarbeid, mens forlaget tar seg av det mer formelle og praktiske.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Det er verdifullt å samarbeide med en profesjonell part som sikrer høy kvalitet, og at vi treffer den målgruppen vi skal.</span><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">&nbsp;Jeg har følt meg godt ivaretatt hele veien.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Veien dit har likevel vært lang og tidvis ensom.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Det femte utkastet ble bok, og for hver runde skrev jeg nærmest om boken på nytt.&nbsp;</span><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Det var en lærerik prosess, men jeg er ennå ikke ferdig utlært.</span><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">&nbsp;Jeg kommer til å fortsette med kurs og selvundervisning.</span></span></p>\n<h3><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\"><strong>God hjelp fra Forfatterskolen</strong></span></span></h3>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Elena understreker at det er lettere å være forfatter når man har de rette verktøyene. Det fikk hun i stor grad gjennom Forfatterskolen.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Ingen av disse bøkene hadde sett dagens lys uten Forfatterskolens spennende, lærerike og praktiske forfatterkurs, og nyttige manuskonsultasjoner!&nbsp;</span><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Både verktøy og inspirasjon bidrar til de gode bøkene, og jeg har fått mange aha-opplevelser innen skriving, blant annet på Forfatterskolen krimkurs med Tom Egeland.&nbsp;</span><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Jeg fikk også mye ut av mentormøtene, blant annet med Geir Tangen. Jeg har adoptert hans Excel-metode!</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Det har også vært nyttig å få tilbakemelding på egen tekst.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Jeg hadde ikke delt mye tekst før, så det var litt skummelt å legge verket i andres hender. Man vet jo ikke hva slags tilbakemelding man får.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Ved læring kommer også resultater, og flere elementer kom etter hvert på plass, som plott, spenningsbygging og ikke-endimensjonale karakterer. Da&nbsp;</span><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Elena leste gjennom første og siste utkast før utgivelsen, så hun at hun hadde hatt god nytte av Forfatterskolens romankurs.</span></span></p>\n<h3><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\"><strong>Holder skrivetiden hellig</strong></span></span></h3>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">I tillegg til gode verktøy, trenger man <em>tid</em> til å skrive. Tiden strekker ikke til, det er kjent for de fleste skrivende; den må rett og slett lages.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Skrivetiden min er hellig. Jeg setter meg ned på et satt tidspunkt. Det kan selvsagt dukke opp ting, og da noterer jeg, men det viktigste er å holde skrivetiden hellig. Da skal jeg ikke forstyrres, og det vet de hjemme.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Forfatteren skriver to timer hver dag, uavhengig om hun er inspirert eller ikke. Stopper det opp, skriver hun på noe annet så lenge.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Man skal ikke vente på inspirasjon, det er en jobb. Den innstillingen må ha, sier Elena.</span></span></p>\n<h3><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\"><strong>Fra barnebok til voksenkrim &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</strong></span></span></h3>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Neste prosjekt er i gang allerede, og det blir intet mindre enn en krimtrilogi. Krimmen tar også for seg livet i nord, og handlingen lagt til Svalbard.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Det er spennende å gjøre research til krimprosjektet. Hos Forfatterskolen fikk jeg en skikkelig øyeåpner for hvor mye research man må gjøre før man i det hele tatt setter i gang med skrivingen. Det er mye som skal sjekkes, sendes til eksperter, testleses og så videre.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Heldigvis synes Elena researchen er en givende og interessant prosess.</span></span></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">– Research utvider horisonten, og beriker livet ellers.</span></span></p>\n<p><strong><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\">Forfatterskolen gratulerer Elena så mye med ny bok!</span></span></strong></p>\n<p><span style=\"color: rgb(9, 9, 9) !important;\"><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important;\"><em>Boken er gitt ut på Gaveca forlag, 15. juni 2023, og er i</em><em>llustrert av Jane Helen Klepp.</em><em> Boken kan kjøpes </em><em>gjennom </em><em>Biblioteksentralen og Gávpi.</em></span></span><em><span style=\"--tcb-applied-color: rgb(9, 9, 9) !important; color: rgb(9, 9, 9) !important;\">&nbsp;Fra tidligere har forfatteren gitt ut boka &#8220;Espen og de hoppende dinosaurene&#8221; på eget forlag (2021).</span> </em></p>\n','blog-images/kulturskiller-identitetskvaler-og-en-forvandlet-pappa.jpg','Forfatterskolen',NULL,1,NULL,'2023-08-08 20:09:40','2026-03-27 08:48:34'),(85,4,'Å gå med ordene','<h2><strong>Å gå med ordene</strong></h2>\n<h3>Forfatter Kari Valberg er aktuell med diktsamlingen ‘Dikt og forbainna tøv’ – en bok om natur og aldring, skildret med humor og alvor.</h3>\n<p><span></span></p>\n<h3 style=\"\"><strong>Vandrende inspirasjon</strong></h3>\n<p style=\"\">Det er ikke mange ukene siden forfatter Kari Valberg holdt boken sin for første gang. I juni kom diktsamlingen ut hos <em>Lyrikkforlaget</em>, og i september er det lansering.</p>\n<p style=\"\">Kari kan melde at prosessen har vært en fin opplevelse. Det har vært et godt samarbeid med forlaget, og den nye tilværelsen som forfatter har mye spennende å by på. Diktene er kommet frem i fin flyt, via en god katalysator – spaserturer. De små fortellingene har dukket opp på Karis jevnlige gåturer i nabolaget, en aktivitet som gir mye inspirasjon.</p>\n<p style=\"\">– Plutselig ser jeg noe, og må stoppe opp og skrive det ned på mobilen. Så skriver jeg det ordentlig ut når jeg kommer hjem. Jeg har ingen faste rutiner eller metoder, bare slipper til inspirasjonen. Naturen er også viktig for forfatteren, noe som gjenspeiles i diktene. &nbsp;</p>\n<h3 style=\"\"><strong>Humoristisk om aldring</strong></h3>\n<p style=\"\">Den røde tråden i diktsamlingen er aldring.&nbsp;</p>\n<p style=\"\">– Jeg tar for meg det å bli gammel; å få ‘vondter’, kjenne på slitasje, og alt det man ser rundt seg som er til irritasjon, sier Kari muntert.</p>\n<p style=\"\">Det er flere temaer i boken, og fellesnevneren er humor. Kari ser mye verdi i det aktive grepet:&nbsp;</p>\n<p style=\"\">– Humor er et fint våpen i disse tider. Man må selvsagt passe seg litt så man ikke overstiger grensene, blir spydig, men heller lener seg mot det folkelige. Humoren bidrar til at jeg treffer med det jeg vil ha frem.</p>\n<p style=\"\">Humoren glimter også til i det visuelle. Boka er illustrert av Karis sønn, og illustrasjonene understreker den humoristiske tonen, med morsomme og sjarmerende karikaturer.</p>\n<h3 style=\"\">Dikt på trykk</h3>\n<p><span style=\"--tcb-applied-color: rgb(22, 22, 22) !important; color: rgb(22, 22, 22) !important;\">&#8220;Dikt og forbainna tøv&#8221; er Karis første bok, men ikke hennes første publisering. Ved flere anledninger har hun fått dikt på trykk i avisa <em>Nordland</em>.</span></p>\n<p style=\"\">– Det var veldig gøy å se sine egne dikt på trykk, og jeg har fått mange tilbakemeldinger fra både kjente og ukjente. Det var dette som ga meg ideen om å samle diktene, og flere sa de gjerne ville kjøpe en samling.</p>\n<p style=\"\">Og samlingen var så godt som klar – 80 sider tekst og flere illustrasjoner var allerede på plass.</p>\n<p><span></span></p>\n<h3 style=\"\"><strong>Fra noveller til dikt</strong></h3>\n<p style=\"\">– Jeg har alltid hatt interesse for skriving, sier Kari.</p>\n<p style=\"\">Hun har skrevet sanger og små tekster, og lenge hatt en forfatter i magen, men tiden har ikke strukket til. Det var først som pensjonert byplanlegger skrivingen fikk blomstre. Så måtte motet bli stort nok til å gå ut i verden med ordene.</p>\n<p style=\"\">I 2018 bestemte hun seg for å melde seg på Forfatterskolens romankurs.</p>\n<p style=\"\">&#8211; Jeg har også fulgt novellekurset, og diktkurset med Gro Dahle. Først tenkte jeg at jeg vil skrive noveller, begynne med det. Det første jeg gjorde var å lese mange noveller, få mye inspirasjon.</p>\n<p style=\"\">Likevel var det diktene som ble først ut, bokstavelig talt. Nå har Kari har flere prosjekter på blokka.</p>\n<h3 style=\"\">&#8230; til krim?</h3>\n<p style=\"\">– Jeg har fortsatt lyst til å skrive noveller, og deretter en krimroman. Jeg leser mye krim, og tenker hele tiden på forskjellige plot. Jeg finner mye inspirasjon fra lesningen.</p>\n<p style=\"\">Kari ser likevel på romanformen som en utfordring.</p>\n<p style=\"\">– Det er et større lerret å bleke. Når jeg får en idé til et dikt går det fort å skrive det, mens en roman krever mye mer.</p>\n<p style=\"\">Først og fremst: Nå skal diktene ut til leserne, og leve sitt eget liv. Deretter vil kanskje den vandrende inspirasjonen og de mange tenkte plottene føre med seg lengre tekster?&nbsp;</p>\n<p style=\"\"><strong>Forfatterskolen gratulerer Kari så mye med utgivelsen!</strong></p>\n<p style=\"\">Samlingen &#8220;Dikt og forbainna tøv&#8221; kan kjøpes hos Lyrikkforlaget (<a href=\"http://www.lyrikkforlaget.no\" style=\"outline: none;\">www.lyrikkforlaget.no</a>), og i bokhandel (<a href=\"http://www.norli.no\" style=\"outline: none;\">www.norli.no</a>).</p>\n<p><span></span></p>\n','blog-images/a-ga-med-ordene-2.jpg','Forfatterskolen',NULL,1,NULL,'2023-08-08 17:16:27','2026-03-27 08:48:34'),(86,4,'Ellinors edderkoppvise','<h3><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">Debuterer med edderkopp-bok for barn</span></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><strong>&nbsp;</strong><strong>Fortell litt om deg selv, du nybakte forfatter!</strong></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Jeg heter Anette Natland, er snart 44 år og&nbsp;er godt i gang med&nbsp;å leve ut forfatterdrømmen. Jeg vokste opp i den lille bygda&nbsp;Sigdal, med skogen tett på og fantasien i fri dressur. Nå bor jeg&nbsp;i et gult hus med lyseblå dør i Tønsberg. Herfra skriver jeg historier, og driver Sjøbadet Badstue midt på brygga. Etter et karriereskifte har jeg fått mer rom for å skrive, og nå har jeg endelig min første barnebok mellom hendene.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><strong>Når begynte du å skrive? Har du alltid hatt en forfatterdrøm, eller hvordan kom skrivingen til?</strong></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">I 2018, da jeg flyttet med mann og barn inn i ei hytte på Hovden i Setesdalen, bestemte jeg meg for å ta forfatterdrømmen på alvor. Jeg sa opp den trygge lærerjobben og begynte å skrive på heltid. Etter to år og korona, så ble det to manus – en roman og ei barnebok.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><strong>Hva slags bok har du skrevet?&nbsp;</strong></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Da jeg vokste opp var jeg kjemperedd for edderkopper. Frykten vokste seg større&nbsp;med årene. Det hjalp ikke at jeg som student bodde i kjellerleiligheter der edderkoppene var like store som hybelkaniner. Derfor skrev jeg en sang om å være redd for edderkopper, og slik ble&nbsp;<em>Ellinors Edderkoppvise</em>&nbsp;til.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><em>Ellinors Edderkoppvise</em>&nbsp;startet som en litt tullete sang, og er nå blitt en sang og ei bok som inviterer til samtaler med barn om hva de er redde for. Med boken ønsker jeg å formidle følgende: Selv om noe er skummelt, betyr det ikke nødvendigvis at det er farlig. Husk at dersom vi skal kunne vise mot, så må vi også være redde for noe.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><strong>Har du drømmer, eller en konkret plan, for videre skriving?</strong></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Akkurat nå drømmer jeg om at&nbsp;<em>Ellinors Edderkoppvise&nbsp;</em>skal bli en stor suksess. Jeg skal kontakte barnehager og skoler, og håper de vil ha besøk av meg under neste skoleår. Jeg skal også ha et event i Kristiansand på Spiren Kafé, og på Hovden i Setesdalen, der Linné – som har laget de fine tegningene i boka – bor. Aller først blir det boklansering på selveste Tønsbergdagen, der jeg skal selge boka og synge sangen fra pop-up scenen. Etter dette er planen å bli helt ferdig med romanen, som har en lignede tematikk, men er ment for unge voksne.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><strong>Hvordan var det&nbsp;å samarbeide med oss i Forfatterskolen og Indiemoon?</strong></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Jeg kunne ikke ha skrevet så godt uten hjelp og veiledning fra dere hos Forfatterskolen, og jeg har satt stor pris på å være elev hos dere.</span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><strong>Hva er ditt råd til andre som drømmer om å bli forfatter?</strong></span></span></p>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\">Som Ellinor i boka, lager vi noen ganger frykten vår større enn den behøver å være. Det er ikke bare små barn som kjenner på frykt. Det er bedre å angre på noe du har skrevet, enn å angre på at du aldri turte å begynne. Summa summarum: Hvis du drømmer om å bli forfatter – bare gjør det!</span></span></p>\n<p style=\"\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">Gratulerer så mye, Anette! Vi er skikkelig stolte av deg </span></p>\n<p style=\"\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">Her kan du bestille boken om Ellinor Edderkopp:</span></p>\n<p style=\"\"><a href=\"https://shop.indiemoon.no/product/ellinors-edderkoppvise/\" target=\"_blank\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">Ellinors Edderkoppvise</span></a></p>\n<p><span></span></p>\n','blog-images/ellinors-edderkoppvise.png','Forfatterskolen',NULL,1,NULL,'2025-06-20 23:02:53','2026-03-27 08:48:34'),(87,4,'Utgitt på Cappelen Damm!','<p><span></span><span style=\"\"></span></p>\n<h3 style=\"\">Vi gratulerer Gunn Helene Arsky, tidligere elev på Forfatterskolen, med utgivelse på Cappelen Damm!</h3>\n<p style=\"color: rgb(12, 13, 13) !important; --tcb-applied-color: rgb(12, 13, 13) !important;\">La deg inspirere av hennes vei mot realisering av forfattedrømmen:</p>\n<h3 style=\"\">Fortell litt om deg selv!</h3>\n<p style=\"\">Jeg er Gunn Helene Arsky, mor til tre fantastiske unge mennesker og kjæreste med Juha i over 30 år. Av utdannelse er jeg ernæringsfysiolog, yogalærer, helseveileder og forfatter.&nbsp; Jeg har nettopp fylt 56 år og er full av skapertrang og kreativitet som bare vil UT! For litt over 7 år siden sa jeg opp jobben, vi solgte huset vårt i Oslo og flyttet til rolige, vakre Halden der vi ikke kjente noen. Men det gjør vi nå, og det er en glede å få nye venner i voksen alder. Jeg har gått fra fast stilling til å være frilanser. Det jeg ikke tjener i penger, får jeg igjen i form av samvær, nærhet, tid og ro.</p>\n<h3 style=\"\">Når begynte du å skrive? Har du alltid hatt en forfatterdrøm, eller hvordan kom skrivingen til?</h3>\n<p style=\"\">Lesing og skriving betyr utrolig mye for meg. Jeg har skrevet og lest siden jeg var en neve stor, jeg brukte sparepengene mine på å handle bøker på loppemarked da jeg var liten, og jeg har heldigvis fått skrevet masse opp gjennom årene som ernæringsfysiolog. Både for nettsiden i bedriftene jeg har jobbet, men også i form av en rekke skole- og faktabøker om ernæring og helse, og ikke minst som fast skribent i flere ukeblader og tidsskrifter.</p>\n<p style=\"\">Jeg leser alltid på en bok, kanskje to, og jeg har en liten instagramkonto (@gunnheleneleser) der jeg deler det jeg leser. Målet er å lese en bok i uken i gjennomsnitt. Jeg leser i hovedsak chick lit, hyggelige samtidsromaner, krim og koselig krim.</p>\n<h3 style=\"\">Hva slags sjanger skriver du i, og hvorfor?</h3>\n<p style=\"\">Etter å ha selvpublisert to godt mottatte feelgoodromaner om yogalæreren Ella, følte jeg at tiden var inne for å snuse litt på kosekrimsjangeren. Den har gitt meg så mange gode lesestunder opp igjennom. Samtidig opplevde jeg at de fleste bøkene foregikk i Irland, Skottland, England eller USA – mens Norge var skuffende fraværende. Jeg gikk i gang med godt mot, og jeg bygget på det jeg hadde lært meg av de to første romanene mine. Så da førsteutkastet var ferdig, sendte jeg det til alle de store forlagene – og fikk, etter et hyggelig møte med redaktør – napp hos Cappelen Damm.</p>\n<p style=\"\">Kosekrim er en sjanger som har kommet for å bli, tror jeg, og spesielt nå, som verden er litt skakk. De fleste av oss liker et frydefullt gys, slik vi fikk fra barndommens eventyr, men uten blod, gørr og triste eller grusomme detaljer som trigger uhelse mentalt.</p>\n<h3 style=\"\">Hva er din motivasjon i skrivingen?&nbsp;</h3>\n<p style=\"\">Skriving har gledet meg siden jeg var svært liten. Gjennom hele barneskolen var norsk det morsomste faget, og engelsk, da vi begynte med det. Jeg husker fortsatt en engelskstil jeg skrev i sjuende klasse, der jeg diktet opp en mann som het Mr Swansteth. Jeg husker fryden ved å ikke bare finne på en historie, men også ha ‘makten’ til å dikte opp navn – jeg syntes Swansteth var så fjongt!</p>\n<p style=\"\">Likevel er jeg ikke typen som har hatt en stabel halvskrevne manus i skrivebordsskuffen. Jeg har båret historiene inni meg, til jeg – og livet rundt meg – var klar. Jeg forsøkte meg riktignok på en barnebok da eldstedatteren min var baby, men det manuset er nok best gjemt og glemt! Ammetåke..!</p>\n<p style=\"\">Som frilanser i Halden kan jeg styre tiden min selv. Noe av det første jeg gjorde, var å gå på skrivekurs her på Forfatterskolen. Jeg brukte det jeg lærte og satte i gang med å skrive romanen <em>Ellas Tilstedeværelse</em> og deretter <em>Ellas Hellas</em> – begge selvpubliserte. Og nå er det <em>Mord i bokhandelen</em> som kommer på selveste Cappelen Damm i mars!</p>\n<h3 style=\"\">Hva slags bok har du skrevet?&nbsp;</h3>\n<p style=\"\"><a href=\"http:// https://bok.norli.no/mord-i-bokhandelen\" target=\"_blank\">Mord i bokhandelen – Engel &amp; Luna nr. 1</a> er en skikkelig kosekrim med alle de rette ingrediensene: Katter, cupcakes, bokhandler, romantikk, magi og et mystisk dødsfall. Her er et kort sammendrag:</p>\n<p style=\"\">Når fargerike Minna Gabler blir funnet død ved foten av trappen i sin alternative bokhandel i Halden, tror alle at den eldre kvinnen døde av fallet. Kryptokryssordforfatteren Engel og søsteren hennes, Isa-Linn, er tante Minnas eneste arvinger, til tross for at de aldri kjente henne. Nyskilte Engel tar med seg sin kloke siameserkatt, Luna, for å starte på nytt i den sjarmerende småbyen. Men ganske snart finner Engel ut at hun ikke bare har arvet en bokhandel som sårt trenger en kjærlig hånd og kløktig markedsføring – tante Minna har også etterlatt seg et forsvunnet arvestykke som Isa-Linn skal arve, og med det, et uløst mysterium. For var Minnas dødsfall egentlig helt naturlig? Hvem tok egentlig livet av tante Minna, og hva skjuler seg mellom boksidene i den gamle bokhandelen?</p>\n<h3 style=\"\">Har du gitt ut boken selv? Hvordan var det, i så fall?</h3>\n<p style=\"\">Jeg har publisert de to første romanene selv, og det gikk fint. Jeg gjorde alt selv, utenom å kjøpe manusutvikling fra Forfatterskolen og få designhjelp til å lage omslaget. Alt annet ordnet jeg selv. Det var veldig lærerikt, og derfor setter jeg nå enormt stor pris på at jeg ikke trenger å gjøre det denne gangen!</p>\n<h3 style=\"\">Hvordan var det å sitte med sin egen bok mellom hendene?</h3>\n<p style=\"\">Nå har ikke <a href=\"http:// https://bok.norli.no/mord-i-bokhandelen\" target=\"_blank\"><em>Mord i bokhandelen</em></a> gått i trykken ennå, i skrivende stund, så jeg må svare basert på tidligere erfaringer. Som forfatter av både fagbøker og skjønnlitteratur, vet jeg at det er noe helt eget ved å stå med en roman i hendene – et produkt av ens egen fantasi. Jeg har alltid drømt om å se navnet mitt på en roman, til og med på en roman utgitt på et av Norges største forlag. Nå er drømmen virkelig!</p>\n<h3 style=\"\">Hvordan har mottakelsen vært, og hva er planene videre for boken?</h3>\n<p style=\"\">Alle leserne av de to første romanene mine venter spent på denne nye boken! Og det er helt vilt, alt som er på trappene her nå. Jeg skal signere boken på Norli i Oslo 21. mars, under Krimfestivalen i Oslo. Der skal jeg også delta i en debutantdebatt. Et par uker senere skal jeg snakke om Mord i Bokhandelen på Feelgoodfestivalen på Cappelen Damm. Og i tillegg er det snakk om salg til utlandet, lydbok, e-bok og jeg vet ikke hva…</p>\n<p style=\"\">Og midt oppi dette blir det en super lanseringsfest på Kulturhuset i Halden i slutten av mars, med bokbading, gratis cupcakes til alle (og med en premie til noen heldige), høytlesning, boksalg ved den lokale bokhandelen og selvsagt signering av boken. Jeg gleder meg masse!</p>\n<h3 style=\"\">Har du drømmer, eller en konkret plan, for videre skriving?</h3>\n<p style=\"\">Det magiske er at jeg allerede har levert manuset til bok nummer to om radarparet Engel og Luna. Den skal etter planen komme allerede til høsten. Mange av personene man blir kjent med i første bok, dukker også opp i bok nummer to – cupcakebakeren Camilla, journalisten Adam og Engels søster, Isa-Linn. Men mysteriet er noe helt annet denne gangen – selvsagt!</p>\n<p style=\"\">Og – som om ikke det var nok… i disse dager skriver jeg i vei på nummer tre i serien om Engel og Luna, som skal komme til våren om et år. Så dette med skriving har virkelig løsnet nå, og jeg håper å kunne gjøre MYE mer av dette fremover!</p>\n<h3 style=\"\">Hvordan var det å samarbeide med oss – Forfatterskolen og Indiemoon?</h3>\n<p style=\"\">Jeg holder fortsatt kontakten med Forfatterskolen, flere år etter at jeg var ferdig ‘uteksaminert’. Det sier litt om hvor godt jeg følte meg ivaretatt, både som elev, men også som kunde underveis i jobbingen med de to selvpubliserte bøkene. Jeg er med i Facebookgruppen også, og jeg må si at det er fint å kjenne seg som en del av et større fellesskap. For det er unektelig et soloprosjekt å sitte hjemme og skrive.</p>\n<h3 style=\"\">Hva er ditt råd til andre som drømmer om å bli forfatter?</h3>\n<p style=\"\">Begynn å skrive! Øvelse gjør mester. Og ingen mesterverk har blitt til uten øvelse. Jeg liker spesielt godt det som Rektor Kristine Storli Henningsen sa en gang på webinar – at for å ha en tekst å redigere, så må man faktisk skrive den teksten først. Så – begynn i dag – det er ikke en dag for tidlig!</p>\n<p style=\"\">Hurra for deg, Gunn Helene! Vi er så stolte av deg </p>\n<p style=\"\">Her er lenke til bestilling av boken:&nbsp;<a href=\"https://bok.norli.no/mord-i-bokhandelen\" style=\"outline: none;\">Mord i bokhandeleren</a></p>\n<p><span><a href=\"http:// https://bok.norli.no/mord-i-bokhandelen\"></a></span></p>\n','blog-images/utgitt-pa-cappelen-damm.jpg','Forfatterskolen',NULL,1,NULL,'2025-02-01 14:12:32','2026-03-27 08:48:34'),(88,4,'Å opne hjartet på nytt','<p><strong><span data-contrast=\"auto\" lang=\"NB-NO\" style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">INTERVJU MED INGUNN FLØLO – AKTUELL MED BOKEN &#8220;Å OPNE HJARTET PÅ NYTT&#8221;!</span></strong></p>\n<h3><strong><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NB-NO\">Fortell litt om deg selv!</span><span data-contrast=\"auto\" lang=\"NN-NO\">​</span></span></span></strong></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NN-NO\">Eg heiter Ingunn Flølo og bur i Lillehammer, med mann og &nbsp;barn. Eg har mine røter frå Nordfjord, der kjærleiken til både natur og nynorsken kjem frå. Eg er pedagog, forfattar og yogalærar, med utdanning innan pedagogikk, kommunikasjon, sosiologi , trening og helse. Eg har jobba med barn og unge i over 25 år, då og menneske i alle aldrar og livssituasjonar, noko som både har forma og utvikla meg.</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></p>\n<h3><strong><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{&quot;335559685&quot;:720}\">​</span><span data-contrast=\"auto\" lang=\"NB-NO\">Når begynte du å skrive? Har du alltid hatt en forfatterdrøm, eller hvordan kom skrivingen til?&nbsp;</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></strong></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{&quot;335559685&quot;:720}\">​</span><span data-contrast=\"auto\" lang=\"NN-NO\">Draumen om å gi ut bok har vore der lenge. Skrive har eg gjort so lenge eg kan huske. Å sette ord på det eg ser og opplever og gi utløp for fantasien starta med dikt og eventyr, seinare songar, historier, foto og tekstar både i sosiale media og avis.</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span></span></span></p>\n<h3><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NN-NO\">​</span><strong><span data-contrast=\"auto\" lang=\"NB-NO\">Hva slags bok har du skrevet?&nbsp;</span></strong></span></span></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{&quot;335559685&quot;:720}\">​</span><span data-contrast=\"auto\" lang=\"NB-NO\">Eg har skrevet ei bok om balansekunsten det er å være menneske i ei verd som syns å gå alt for fort, der vi knapt rekk å ta oss tid til å tenke etter og ha ro nok til å lytte innover, slik at vi høyrer oss sjølve meir enn vi høyrer alle andre.&nbsp;</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">​</span><span data-contrast=\"auto\" lang=\"NN-NO\">Boka har eit utval tekstar eg har delt på sosiale media over mange år. Det er dikt, ordtak og små og store tekstar om det å være menneske, i kvardagen, i følelsane og i tida vi lever i.&nbsp;</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span><span data-contrast=\"auto\" lang=\"NN-NO\">Med å sette ord på dette og stille spørsmål som kan sette i gang refleksjonar kring oss sjølv og livet vi lever, håper eg, eg gir dykk mogelegheita til ei stund i ro til å tenkje etter kor de er, kva de har og kva de vil.&nbsp;</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span></span></span></p>\n<h3><strong><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{&quot;335559685&quot;:720}\">​</span><span data-contrast=\"auto\" lang=\"NB-NO\">Hvordan var det å gi ut boken selv?&nbsp;</span></span></span></strong></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NN-NO\">Eg har gitt ut boka sjølv, med Indiemoon og i samarbeid med Forfatterskolen.&nbsp;</span><span data-ccp-props=\"{}\">&nbsp;</span></span><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NN-NO\">Det er ei bratt læringskurve og ein god del jobb, men med gode, tolmodige og dyktige mennesker i Forfatterskolen &nbsp;og gode støttespelarar er dette ein god måte å gi ut bok.</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></p>\n<h3><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{}\">​</span><span data-contrast=\"auto\" lang=\"NB-NO\">Hvordan var det å sitte med sin egen bok mellom hendene?</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{&quot;335559685&quot;:720}\">​</span><span data-contrast=\"auto\" lang=\"NN-NO\">Det er ein heilt utruleg &nbsp;god følelse å ha boka i hendene.&nbsp;</span><span data-contrast=\"auto\" lang=\"NB-NO\">Det kjentes virkelig og uvirkelig på same tid. Det er stort og verdt all jobben som er lagt ned.&nbsp;</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span></span></span></p>\n<h3><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{}\">​</span><span data-contrast=\"auto\" lang=\"NB-NO\">Hvordan har mottakelsen vært, og hva er planene videre for boken?&nbsp;</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NN-NO\">Det har vert ein heilt fantastisk mottaking! Eg er så takknemleg for alle gratulasjonar og gode tilbakemeldingar.&nbsp; Det blir videre sal av og samarbeid med boka utover i det nye året.</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></p>\n<h3><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NB-NO\">Har du drømmer, eller en konkret plan, for videre skriving?</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span><span data-contrast=\"auto\" lang=\"NN-NO\">Det blir meir skriving. Det er nokre prosjekt på trappene, som blir spennande å sjå korleis former seg.</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span></span></span></p>\n<h3><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-ccp-props=\"{&quot;335559685&quot;:720}\">​</span><span data-contrast=\"auto\" lang=\"NB-NO\">Hvordan var det å samarbeide med oss i Indiemoon?</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></h3>\n<p><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NB-NO\">Det har vert heilt supert å jobbe med Indiemoon. Det har gjort prosessen med utgivelse trygg og dokke har gjort ein so fin jobb med boka.&nbsp;</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span></p>\n<h3><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NB-NO\">Hva er ditt råd til andre som drømmer om å bli forfatter?</span><span data-ccp-props=\"{}\">&nbsp;</span></span></span>&nbsp;</h3>\n<ol>\n<li><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NN-NO\">Om du ikkje skal gjere det no, når skal du gjere det då?</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span></span></span></li>\n<li><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NB-NO\">Ta akkurat passe risiko, slik at fallhøgda er noko du kan tåle.</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span></span></span></li>\n<li><span style=\"color: rgb(11, 11, 11) !important;\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NN-NO\">Anten går det eller so går det ikkje, det veit du ikkje før du har prøvd.&nbsp;</span><span data-ccp-props=\"{&quot;335559685&quot;:720}\">&nbsp;</span></span></span></li>\n</ol>\n<p><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">Gratulerer så mye, Ingunn! Vi er kjempestolte av deg og boken din, og gleder oss til å følge forfatterkarrieren din videre </span></p>\n<p><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\">Her kan du bestille&nbsp;<span data-contrast=\"auto\" lang=\"NB-NO\">å opne hjartet på nytt:</span></span></p>\n<p><a href=\"https://www.ark.no/produkt/boker/hobbyboker-og-fritid/a-opne-hjartet-pa-nytt-9788294111121?utm_source=chatgpt.com\" target=\"_blank\"><span style=\"--tcb-applied-color: rgb(11, 11, 11) !important; color: rgb(11, 11, 11) !important;\"><span data-contrast=\"auto\" lang=\"NB-NO\">Å opne hjartet på nytt av Ingunn Kristin Flølo</span></span></a></p>\n<p><span></span></p>\n<p style=\"\">\n','blog-images/a-opne-hjartet-pa-nytt.jpg','Forfatterskolen',NULL,1,NULL,'2024-12-11 22:16:06','2026-03-27 08:48:34');
